/**
 * Lead CRM — v4 frontend
 * Full-featured SPA over POST /api.
 */

const CRM = {
  // Slug-aware token key — prevents one tenant's token from being read on
  // another tenant's /t/<slug>/ page. e.g. token for /t/vserve/ is stored
  // under 'crm_token_vserve', not the shared 'crm_token'.
  _slug: (function() {
    try {
      const m = (location.pathname || '').match(/\/t\/([^\/]+)\//);
      return m ? m[1] : '';
    } catch (_) { return ''; }
  })(),
  // Read scoped key first; fall back to the legacy 'crm_token' once for
  // a smooth migration of users already signed in pre-fix.
  token: (function() {
    try {
      const m = (location.pathname || '').match(/\/t\/([^\/]+)\//);
      const slug = m ? m[1] : '';
      if (slug) {
        const t = localStorage.getItem('crm_token_' + slug);
        if (t) return t;
      }
      return localStorage.getItem('crm_token') || null;
    } catch (_) { return localStorage.getItem('crm_token') || null; }
  })(),
  user: null,
  config: { company_name: 'Lead CRM', company_logo_url: '', base_url: location.origin },
  cache: {},
  prefs: {
    columns: JSON.parse(localStorage.getItem('crm_cols') || '["name","phone","source","status","stage","assigned","followup","last_change","remark","created"]'),
    filters: JSON.parse(localStorage.getItem('crm_filters') || '{}'),
    showHeader: (function () {
      /* LEADS_FILTER_CLOSED_DEFAULT_v1 — mobile: ignore localStorage
         and use window._mobileLeadsFilterOpen as the only source of
         truth. Without this, an old crm_show_header='1' value kept
         re-opening the status-chip header on every render. Desktop:
         unchanged — respect localStorage, default to visible. */
      var isMobile = false;
      try { isMobile = (window.innerWidth < 900); } catch (_) {}
      if (isMobile) {
        try { localStorage.removeItem('crm_show_header'); } catch (_) {}
        return !!window._mobileLeadsFilterOpen;
      }
      var v = localStorage.getItem('crm_show_header');
      if (v === '0') return false;
      if (v === '1') return true;
      return true;
    })()
  }
};

// PERM_ONBOARDING_SOFT_v1 (2026-05-28) — soft top-banner instead of hard
// redirect to the permission onboarding activity. The Android side now
// shows the onboarding ONCE per install (Done OR Skip OR Back all count
// as seen). On every subsequent app boot the user lands straight in the
// CRM and, if any critical permission is still missing, we render this
// little chip at the top of the screen with a "Fix" button.
function _renderPermSoftBanner() {
  try {
    if (!window.LeadCRMNative || typeof LeadCRMNative.getPermissionsStatus !== 'function') {
      if (window._debugPermBanner) console.log('[perm-banner] no LeadCRMNative.getPermissionsStatus — bail');
      return;
    }
    let st;
    try { st = JSON.parse(LeadCRMNative.getPermissionsStatus() || '{}'); } catch (_) { st = {}; }
    if (window._debugPermBanner) console.log('[perm-banner] permissionsStatus =', st);
    if (!st || !st.anyMissing) {
      // perms ok — remove any stale banner
      const ex = document.getElementById('perm-soft-banner'); if (ex) ex.remove();
      // Reset the folder-lost flag so a future revocation re-shows as critical
      try { sessionStorage.removeItem('perm_folder_lost_seen'); } catch (_) {}
      return;
    }

    // PERM_LOST_BANNER_v1.1 (2026-05-29) — fire RED whenever folderOk is
    // false, regardless of onboardingSeen. The original gate required
    // onboardingSeen===true (so it would only be 'revocation' not
    // 'first-time setup'), but PERM_ONBOARDING_SOFT_v1 stopped forcing
    // users through the onboarding activity, so onboardingSeen stays
    // false forever on many devices. Net effect: red banner never
    // triggered. Now: any time the folder isn't readable -> red.
    // The user can also force-show via window._forcePermBanner = true
    // for testing (Test button on Settings -> Backend health).
    const folderLost = (st.folderOk === false) || window._forcePermBanner === true;

    if (!folderLost) {
      // Soft (orange) — battery / storage / first-time folder. Dismissable.
      if (sessionStorage.getItem('perm_banner_dismissed') === '1') return;
    }
    if (document.getElementById('perm-soft-banner')) return;

    const missing = [];
    if (!st.batteryOk)  missing.push('battery');
    if (!st.storageOk)  missing.push('storage');
    if (!st.folderOk)   missing.push('recording folder');

    const bar = document.createElement('div');
    bar.id = 'perm-soft-banner';
    if (folderLost) {
      bar.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:99998;background:#fee2e2;border-bottom:2px solid #ef4444;color:#7f1d1d;padding:.6rem .8rem;font:600 .85rem -apple-system,Segoe UI,Roboto,sans-serif;display:flex;align-items:center;gap:.6rem;box-shadow:0 1px 3px rgba(0,0,0,.1);';
      bar.innerHTML =
        '<span style="font-size:1.15rem">⚠️</span>' +
        '<span style="flex:1">Recording folder access lost — recordings are NOT syncing. Tap to re-pick.</span>' +
        '<button id="perm-soft-fix" style="padding:.35rem .8rem;border:none;border-radius:5px;background:#dc2626;color:#fff;font-weight:700;cursor:pointer;font-size:.8rem">Re-pick folder</button>';
      try { sessionStorage.setItem('perm_folder_lost_seen', '1'); } catch (_) {}
    } else {
      const msg = 'For best call-tracking, finish setting up: ' + missing.join(', ') + '.';
      bar.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:99998;background:#fff7ed;border-bottom:1px solid #fdba74;color:#7c2d12;padding:.5rem .8rem;font:500 .82rem -apple-system,Segoe UI,Roboto,sans-serif;display:flex;align-items:center;gap:.6rem;box-shadow:0 1px 2px rgba(0,0,0,.05);';
      bar.innerHTML =
        '<span style="font-size:1rem">⚙️</span>' +
        '<span style="flex:1">' + msg + '</span>' +
        '<button id="perm-soft-fix" style="padding:.3rem .7rem;border:none;border-radius:5px;background:#ea580c;color:#fff;font-weight:600;cursor:pointer;font-size:.78rem">Fix</button>' +
        '<button id="perm-soft-dismiss" aria-label="Dismiss" style="background:none;border:none;color:#9a3412;font-size:1.1rem;cursor:pointer;padding:0 .3rem">×</button>';
    }
    document.body.appendChild(bar);
    const fixBtn = document.getElementById('perm-soft-fix');
    if (fixBtn) fixBtn.addEventListener('click', () => {
      try { LeadCRMNative.openRecordingSetup(); } catch (_) {}
    });
    const dismissBtn = document.getElementById('perm-soft-dismiss');
    if (dismissBtn) dismissBtn.addEventListener('click', () => {
      try { sessionStorage.setItem('perm_banner_dismissed', '1'); } catch (_) {}
      bar.remove();
    });
  } catch (_) { /* never throw on a UX nicety */ }
}
// PERM_LOST_BANNER_v1 — re-check on boot, every 60s (catches mid-session
// revocations), and on visibility change (catches the "I just opened
// settings and changed something" round-trip).
if (typeof window !== 'undefined') {
  if (document.readyState === 'complete' || document.readyState === 'interactive') {
    setTimeout(_renderPermSoftBanner, 800);
  } else {
    document.addEventListener('DOMContentLoaded', () => setTimeout(_renderPermSoftBanner, 800));
  }
  setTimeout(_renderPermSoftBanner, 5000);
  setInterval(_renderPermSoftBanner, 60000);
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible') {
      setTimeout(_renderPermSoftBanner, 300);
    }
  });
  // PERM_LOST_BANNER_v1.1 — expose two test helpers on window so admin
  // can verify the banner is wired up without having to actually revoke
  // the folder permission. Call from Backend health -> Test banner.
  window.testPermFolderLostBanner = function () {
    try { sessionStorage.removeItem('perm_banner_dismissed'); } catch (_) {}
    try { sessionStorage.removeItem('perm_folder_lost_seen'); } catch (_) {}
    try { const ex = document.getElementById('perm-soft-banner'); if (ex) ex.remove(); } catch (_) {}
    window._forcePermBanner = true;
    window._debugPermBanner = true;
    _renderPermSoftBanner();
    setTimeout(() => { window._forcePermBanner = false; }, 30000);
    console.log('[perm-banner] forced banner; will release force in 30s');
  };
  window.permBannerStatus = function () {
    if (!window.LeadCRMNative || typeof LeadCRMNative.getPermissionsStatus !== 'function') {
      return { error: 'no LeadCRMNative bridge (web mode?)' };
    }
    try { return JSON.parse(LeadCRMNative.getPermissionsStatus() || '{}'); }
    catch (e) { return { error: e.message }; }
  };
}

// Save the auth token + API base into Android SharedPreferences so the
// native PhoneStateReceiver can POST call events directly to
// /api/call_event_native without depending on the WebView being alive.
// Safe no-op on web.
function _syncNativeCallEventCreds() {
  try {
    if (!window.LeadCRMNative || typeof LeadCRMNative.saveCallEventCreds !== 'function') return;
    const tok = CRM.token || localStorage.getItem('crm_token') || '';
    // Strip /t/<slug>/ — the native POST goes to top-level /api/call_event_native
    // which resolves the tenant from the token itself.
    const base = (CRM.config && CRM.config.base_url) ||
                 location.origin;
    LeadCRMNative.saveCallEventCreds(base, tok);
    // REC_BG_SYNC_v1 — also hand the creds to the recordings background worker
    // so it can upload while the WebView is dead. tenant-scoped URL (with
    // /t/<slug>/) so /api/recordings auth resolves to the right tenant.
    if (typeof LeadCRMNative.registerBgSyncCreds === 'function') {
      const tenantBase = String(location.origin + location.pathname).replace(/\/$/, '').replace(/\/#.*$/, '');
      // location.pathname is e.g. /t/vserve/ — strip trailing slash to match server expectations.
      try { LeadCRMNative.registerBgSyncCreds(tenantBase, tok); } catch (_) {}
    }
  } catch (_) {}
}

/* ---------------- API helper ---------------- */
// Global "in-flight" counter — drives the top loading bar.
let _apiInFlight = 0;
function _bumpApiLoader(delta) {
  _apiInFlight = Math.max(0, _apiInFlight + delta);
  let bar = document.getElementById('global-loader');
  if (!bar) {
    bar = document.createElement('div');
    bar.id = 'global-loader';
    bar.innerHTML = '<div class="gl-fill"></div>';
    document.body.appendChild(bar);
  }
  bar.classList.toggle('active', _apiInFlight > 0);
}

// Endpoints we DON'T want to show the top loader for (background pollers):
const _SILENT_FNS = new Set([
  'api_notifications_mine', 'api_call_logEvent', 'api_company_info'
]);

// Endpoints that are background pollers / non-critical reads. If
// CRM.token is missing for any reason (login screen, SSO bootstrap,
// race during view transition), we skip the call entirely. Hitting
// /api without a token returns 'No token', and stale builds used to
// match that against the logout regex and yank the user out — the
// exact bug behind 'click Leads → instant logout'.
const _POLL_OR_OPTIONAL_FNS = new Set([
  'api_attendance_mine',
  'api_notifications_mine',
  'api_announcements_active',
  'api_company_info',
  'api_call_logEvent',
  'api_fcm_register', 'api_fcm_userDiag',
  'api_push_subscribe',
  'api_push_publicKey'
]);

// ============================================================
// CRM_PERF_v1 — performance diagnostic engine
// ============================================================
// Captures API call timings, long-task warnings, navigation timings and
// periodic memory snapshots. All events persist in localStorage so they
// survive reloads. Open via Ctrl+Shift+P or window.crmPerf.show().
//
// Goals:
//   - Zero overhead in the happy path (just performance.now() bookkeeping)
//   - Surface slow API calls (>1s) and very slow ones (>3s) in the topbar
//   - Give the user a copy-paste-able JSON dump for support
// ============================================================
window.crmPerf = (function () {
  const STORE_KEY = 'crm_perf_log_v1';
  const MAX_EVENTS = 200;
  const SLOW_MS = 1000;
  const VERY_SLOW_MS = 3000;
  let events = [];
  try {
    const raw = localStorage.getItem(STORE_KEY);
    if (raw) events = JSON.parse(raw) || [];
  } catch (_) { events = []; }
  let slowCount = 0;
  function _save() {
    try {
      if (events.length > MAX_EVENTS) events = events.slice(-MAX_EVENTS);
      localStorage.setItem(STORE_KEY, JSON.stringify(events));
    } catch (_) {}
  }
  function _push(ev) {
    ev.t = ev.t || Date.now();
    events.push(ev);
    if (ev.type === 'api' && ev.ms >= SLOW_MS) {
      slowCount++;
      _refreshBadge();
      try {
        console.warn('[CRM_PERF] slow API ' + ev.fn + ' ' + ev.ms + 'ms' + (ev.ms >= VERY_SLOW_MS ? ' (VERY SLOW)' : ''));
      } catch (_) {}
      // CRM_PERF_v1_AUTO — auto-upload the dump once we hit 3 slow calls or
      // a very slow call, throttled to once per 10 min so we don't spam.
      try { _maybeAutoUpload(ev); } catch (_) {}
    }
    _save();
  }
  function recordApi(fn, ms, ok, errMsg, payloadKb) {
    _push({ type: 'api', fn: fn, ms: Math.round(ms), ok: !!ok, err: errMsg ? String(errMsg).slice(0, 200) : null, kb: payloadKb ? Math.round(payloadKb) : undefined, view: (CRM && CRM.currentView) || '' });
  }
  function recordLongTask(ms, name) {
    _push({ type: 'longtask', ms: Math.round(ms), name: name || 'task' });
  }
  function recordMemory() {
    if (!performance.memory) return;
    _push({ type: 'mem', mb: Math.round(performance.memory.usedJSHeapSize / 1048576) });
  }
  function recordEvent(label, extra) {
    _push(Object.assign({ type: 'event', label: label }, extra || {}));
  }
  function clear() { events = []; slowCount = 0; _save(); _refreshBadge(); }
  function _buildPerfDump() {
    // Capture device + environment context too so APK-side issues are easy
    // to spot (Capacitor flag, network type, OS, viewport, online state).
    let net = '';
    try { net = (navigator.connection && navigator.connection.effectiveType) || ''; } catch (_) {}
    let plat = 'web';
    try { if (window.Capacitor || /Capacitor|wv|CapacitorWebView/i.test(navigator.userAgent)) plat = 'apk'; } catch (_) {}
    return {
      when: new Date().toISOString(),
      user: (CRM.user && (CRM.user.email || CRM.user.id)) || 'anon',
      user_id: (CRM.user && CRM.user.id) || null,
      tenant: (CRM.tenant && CRM.tenant.slug) || (CRM.brand && CRM.brand.slug) || '',
      platform: plat,
      apk_version: (window.Capacitor && window.Capacitor.appVersion) || (window.CRM_VERSION) || '',
      ua: (navigator.userAgent || '').slice(0, 240),
      online: navigator.onLine,
      network: net,
      viewport: window.innerWidth + 'x' + window.innerHeight,
      visibility: document.visibilityState,
      view: (CRM && CRM.currentView) || '',
      events: events.slice(-200)
    };
  }
  function _refreshBadge() {
    const b = document.getElementById('crm-perf-badge');
    if (!b) return;
    if (slowCount > 0) { b.hidden = false; b.textContent = String(slowCount); }
    else b.hidden = true;
  }
  let _lastAutoUpload = 0;
  let _slowSinceUpload = 0;
  function _maybeAutoUpload(ev) {
    _slowSinceUpload++;
    const now = Date.now();
    // PERF_HEALTH_DB_PERSIST_v1 — On APK, auto-upload on EVERY slow call,
    // throttled to once per 60 seconds. Users on phones never tap Send to
    // support — we have to be proactive. On web, keep the old conservative
    // behaviour (3 calls or 1 ≥3s call, throttled to 10 min).
    const isApk = !!(window.Capacitor && (Capacitor.isNativePlatform && Capacitor.isNativePlatform()))
      || /capacitor|wv\)/i.test(String(navigator.userAgent || ''));
    const MIN_GAP_MS = isApk ? 60 * 1000 : 10 * 60 * 1000;
    const trigger = isApk
      ? (ev.ms >= 1000)
      : ((ev.ms >= VERY_SLOW_MS) || (_slowSinceUpload >= 3));
    if (!trigger) return;
    if (now - _lastAutoUpload < MIN_GAP_MS) return;
    _lastAutoUpload = now;
    _slowSinceUpload = 0;
    // Fire-and-forget — fall silently if the network is down or endpoint is
    // missing. The point is to surface data when it's available, not to
    // surface errors when it isn't.
    try {
      const dump = _buildPerfDump();
      dump.auto = true;
      const _tok = (function(){ try {
        return CRM.token || (CRM._slug ? localStorage.getItem('crm_token_' + CRM._slug) : null) || localStorage.getItem('crm_token') || '';
      } catch(_) { return ''; } })();
      fetch('/api/perf-report', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer ' + _tok,
          'x-auth-token': _tok
        },
        body: JSON.stringify(dump),
        keepalive: true
      }).catch(() => {});
    } catch (_) {}
  }
  function show() {
    const recent = events.slice(-200).reverse();
    const apiEvents = events.filter(e => e.type === 'api');
    const slow = apiEvents.filter(e => e.ms >= SLOW_MS).sort((a, b) => b.ms - a.ms).slice(0, 20);
    const byFn = {};
    apiEvents.forEach(e => {
      const k = e.fn || 'unknown';
      if (!byFn[k]) byFn[k] = { n: 0, total: 0, max: 0 };
      byFn[k].n++; byFn[k].total += e.ms; if (e.ms > byFn[k].max) byFn[k].max = e.ms;
    });
    const topAvg = Object.entries(byFn).map(([fn, s]) => ({ fn, n: s.n, avg: Math.round(s.total / s.n), max: s.max })).sort((a, b) => b.avg - a.avg).slice(0, 15);
    const lt = events.filter(e => e.type === 'longtask');
    const mem = events.filter(e => e.type === 'mem').slice(-10);
    const m = h('div', { class: 'modal-backdrop',
      onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
    const modal = h('div', { class: 'modal modal-lg', style: { maxWidth: '900px', maxHeight: '88vh', overflow: 'auto' } });
    modal.appendChild(h('div', { class: 'modal-head' },
      h('h3', { style: { margin: 0 } }, '⚡ Performance diagnostics'),
      h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
    ));
    const body = h('div', { class: 'modal-body', style: { padding: '1rem 1.4rem', fontSize: '.82rem' } });
    body.appendChild(h('div', { class: 'muted', style: { marginBottom: '.6rem' } },
      'Slow API calls (>1s) get logged here. Send this dump to support if the CRM feels sluggish. Last 200 events kept.'));
    body.appendChild(h('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px,1fr))', gap: '.4rem', marginBottom: '.85rem' } },
      _stat('Total events', events.length),
      _stat('API calls', apiEvents.length),
      _stat('Slow (≥1s)', slow.length),
      _stat('Very slow (≥3s)', apiEvents.filter(e => e.ms >= VERY_SLOW_MS).length),
      _stat('Long tasks', lt.length),
      _stat('Latest mem (MB)', mem.length ? mem[mem.length - 1].mb : '—')
    ));
    body.appendChild(h('h4', { style: { marginTop: '.6rem' } }, 'Top 15 slowest API endpoints (by avg)'));
    body.appendChild(_table(['fn', 'calls', 'avg ms', 'max ms'], topAvg.map(r => [r.fn, r.n, r.avg, r.max])));
    body.appendChild(h('h4', { style: { marginTop: '.85rem' } }, 'Top 20 slowest individual calls'));
    body.appendChild(_table(['fn', 'ms', 'view', 'when'], slow.map(e => [e.fn, e.ms, e.view || '', new Date(e.t).toLocaleTimeString()])));
    body.appendChild(h('h4', { style: { marginTop: '.85rem' } }, 'Recent events (last 50)'));
    body.appendChild(_table(['type', 'fn / label', 'ms / mb', 'when'],
      recent.slice(0, 50).map(e => [e.type, e.fn || e.label || '', e.ms || e.mb || '', new Date(e.t).toLocaleTimeString()])));
    modal.appendChild(body);
    modal.appendChild(h('div', { class: 'modal-actions', style: { padding: '.7rem 1.4rem', borderTop: '1px solid #e2e8f0', display: 'flex', gap: '.5rem', justifyContent: 'flex-end' } },
      h('button', { class: 'btn primary', style: { background:'#0ea5e9', borderColor:'#0ea5e9' }, onclick: async () => {
        // CRM_PERF_v1_APK — one-tap upload of the diagnostic dump to the
        // server. Works inside the APK where the user can't open DevTools.
        try {
          const payload = _buildPerfDump();
          const r = await fetch('/api/perf-report', { method: 'POST', headers: { 'Content-Type':'application/json' }, body: JSON.stringify(payload) });
          if (r.ok) {
            toast('Report sent to support 👍');
          } else {
            toast('Send failed: HTTP ' + r.status, 'err');
          }
        } catch (e) { toast('Send failed: ' + e.message, 'err'); }
      } }, '📤 Send to support'),
      h('button', { class: 'btn ghost', onclick: () => {
        try {
          const txt = JSON.stringify(_buildPerfDump(), null, 2);
          if (navigator.clipboard && navigator.clipboard.writeText) {
            navigator.clipboard.writeText(txt).then(() => toast('Copied — paste to support'));
          } else {
            const ta = document.createElement('textarea'); ta.value = txt; document.body.appendChild(ta); ta.select(); document.execCommand('copy'); ta.remove();
            toast('Copied — paste to support');
          }
        } catch (e) { toast('Copy failed: ' + e.message, 'err'); }
      } }, '📋 Copy JSON'),
      h('button', { class: 'btn ghost', onclick: () => { clear(); m.remove(); toast('Cleared'); } }, '🗑 Clear log'),
      h('button', { class: 'btn primary', onclick: () => m.remove() }, 'Close')
    ));
    m.appendChild(modal);
    document.body.appendChild(m);
  }
  function _stat(lbl, val) {
    return h('div', { style: { background: '#f8fafc', border: '1px solid #e2e8f0', borderRadius: '8px', padding: '.5rem .65rem' } },
      h('div', { style: { fontSize: '.7rem', color: '#64748b' } }, lbl),
      h('div', { style: { fontSize: '1.05rem', fontWeight: 700, color: '#0f172a' } }, String(val)));
  }
  function _table(cols, rows) {
    const tbl = h('table', { style: { width: '100%', borderCollapse: 'collapse', fontSize: '.78rem' } });
    const head = h('tr', {}, ...cols.map(c => h('th', { style: { textAlign: 'left', padding: '.35rem .5rem', borderBottom: '1px solid #e2e8f0', color: '#475569', background: '#f8fafc' } }, c)));
    tbl.appendChild(head);
    rows.forEach(r => {
      const tr = h('tr', {}, ...r.map(c => h('td', { style: { padding: '.3rem .5rem', borderBottom: '1px solid #f1f5f9' } }, String(c))));
      tbl.appendChild(tr);
    });
    return tbl;
  }
  // Environment event capture — APK-specific signals
  try {
    window.addEventListener('online',  () => recordEvent('online'));
    window.addEventListener('offline', () => recordEvent('offline'));
    document.addEventListener('visibilitychange', () => recordEvent('visibility:' + document.visibilityState));
    // Capacitor lifecycle hooks (if present)
    if (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App) {
      try { window.Capacitor.Plugins.App.addListener('appStateChange', ev => recordEvent('appState', { active: ev && ev.isActive })); } catch (_) {}
      try { window.Capacitor.Plugins.App.addListener('pause',  () => recordEvent('apk:pause')); } catch (_) {}
      try { window.Capacitor.Plugins.App.addListener('resume', () => recordEvent('apk:resume')); } catch (_) {}
    }
  } catch (_) {}

  // Long-task observer
  try {
    if (typeof PerformanceObserver === 'function') {
      const po = new PerformanceObserver(list => {
        list.getEntries().forEach(e => {
          if (e.duration >= 200) recordLongTask(e.duration, e.name || 'task');
        });
      });
      po.observe({ entryTypes: ['longtask'] });
    }
  } catch (_) {}
  // Periodic memory snapshot
  setInterval(recordMemory, 60_000);
  // Global key binding: Ctrl+Shift+P opens the panel
  document.addEventListener('keydown', ev => {
    if (ev.ctrlKey && ev.shiftKey && (ev.key === 'P' || ev.key === 'p')) {
      ev.preventDefault();
      show();
    }
  });
  return { recordApi, recordLongTask, recordMemory, recordEvent, show, clear, _refreshBadge };
})();

// Inject the ⚡ Perf pill into the topbar once the shell is rendered.
function _initPerfBadge() {
  if (document.getElementById('btn-crm-perf')) return;
  const helpBtn = document.getElementById('btn-help');
  if (!helpBtn || !helpBtn.parentNode) return;
  const b = document.createElement('button');
  b.id = 'btn-crm-perf';
  b.className = 'btn ghost';
  b.title = 'Performance diagnostics — Ctrl+Shift+P';
  b.style.cssText = 'position:relative;';
  b.innerHTML = '<span>⚡</span><span class="badge" id="crm-perf-badge" hidden style="background:#dc2626;">0</span>';
  b.onclick = () => window.crmPerf.show();
  helpBtn.parentNode.insertBefore(b, helpBtn);
  window.crmPerf._refreshBadge();
}

// MOBILE_PERF_v1 (2026-05-30): one-time APK detection. Used to (a) gate
// background polls and (b) auto-inject { mobile: true } into 4 heavy
// endpoints so the backend ships a trimmed payload.
const _IS_APK = (function() {
  try {
    if (window.Capacitor && window.Capacitor.isNativePlatform && window.Capacitor.isNativePlatform()) return true;
    if (window.Capacitor) return true;
    if (/Capacitor|CapacitorWebView/i.test(navigator.userAgent || '')) return true;
  } catch (_) {}
  return false;
})();
try { CRM.isApk = _IS_APK; } catch (_) {}

// APK_AUTO_UPDATE_v1 (2026-05-31): on APK boot, fetch the server-side version
// metadata and compare to the installed APK's versionCode. If the server has a
// newer build, render a yellow banner pinned to the top of the page with a
// Download button that takes the user to the install flow. No-op on web.
window._apkUpdateCheck = async function _apkUpdateCheck() {
  try {
    if (!_IS_APK) return;
    const App = (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App) || null;
    if (!App || !App.getInfo) return;
    const info = await App.getInfo();              // { version, build, name, id }
    const installedCode = Number(info.build || 0);
    if (!installedCode) return;
    // Cache-busting fetch — same-origin path. Server-relative so it follows the tenant prefix shim.
    const r = await fetch('/LeadCRM.apk.version.json?_=' + Date.now(), { cache: 'no-store' });
    if (!r.ok) return;
    const meta = await r.json();
    const latestCode = Number(meta.versionCode || 0);
    if (!latestCode || latestCode <= installedCode) return;
    // Stash for the banner button.
    try { window.__LATEST_APK_META = meta; window.__INSTALLED_APK_CODE = installedCode; } catch (_) {}
    _renderApkUpdateBanner(installedCode, meta);
  } catch (_) { /* network error → silent */ }
};
// Kick off the first check on script load.
try { window._apkUpdateCheck(); } catch (_) {}

function _renderApkUpdateBanner(installedCode, meta) {
  // APK_AUTO_UPDATE_v2 (2026-05-31): a centered modal popup is the right UX
  // for an app-update prompt - banners get ignored, modals don't. Shows on
  // app boot AND when the app comes back from background. "Later" dismisses
  // for this session only; it reappears next launch if a newer build exists.
  if (document.getElementById('apk-update-modal')) return;
  try {
    if (sessionStorage.getItem('apk_update_dismissed') === String(meta.versionCode)) return;
  } catch (_) {}

  const backdrop = document.createElement('div');
  backdrop.id = 'apk-update-modal';
  backdrop.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(15,23,42,.6);display:flex;align-items:center;justify-content:center;padding:20px;font:600 15px/1.4 system-ui,-apple-system,sans-serif;';

  backdrop.innerHTML =
    '<div style="background:#fff;border-radius:18px;max-width:380px;width:100%;padding:28px 24px 22px;box-shadow:0 24px 64px rgba(0,0,0,.4);text-align:center;animation:apkmodalin .2s ease-out;">' +
      '<div style="font-size:48px;margin-bottom:8px">🆕</div>' +
      '<h2 style="margin:0 0 6px;font-size:22px;font-weight:800;color:#0f172a">Update Available</h2>' +
      '<p style="margin:0 0 18px;color:#475569;font-size:14px;font-weight:500">A newer version of the app is ready.</p>' +
      '<div style="background:#f1f5f9;border-radius:10px;padding:10px 14px;margin-bottom:20px;font-size:13px;color:#334155;font-weight:600">' +
        'Latest: ' + (meta.versionName || '') + ' · build ' + meta.versionCode +
        '<br><span style="opacity:.7;font-weight:500">You have: build ' + installedCode + '</span>' +
      '</div>' +
      '<button id="apk-update-dl" style="background:#4f46e5;color:#fff;border:none;border-radius:12px;padding:14px 18px;font-weight:800;font-size:16px;cursor:pointer;width:100%;box-shadow:0 8px 16px rgba(79,70,229,.3)">⬇️ Update Now</button>' +
      '<button id="apk-update-later" style="background:transparent;border:none;color:#64748b;font-size:14px;font-weight:600;cursor:pointer;padding:12px;margin-top:6px;width:100%">Later</button>' +
    '</div>' +
    '<style>@keyframes apkmodalin{from{opacity:0;transform:scale(.92)}to{opacity:1;transform:scale(1)}}</style>';

  document.body.appendChild(backdrop);

  document.getElementById('apk-update-dl').onclick = () => {
    const relUrl = (meta && meta.url) || '/LeadCRM.apk';
    // Absolute URL so the system browser opens it correctly even if we
    // got here via a tenant-prefixed page.
    const fullUrl = relUrl.startsWith('http')
      ? relUrl
      : (location.origin + relUrl);

    // APK_AUTO_UPDATE_DIRECT_v1 (2026-06-03): try the in-app installer FIRST.
    // installApk uses DownloadManager + FileProvider to download silently
    // and pop the system installer when complete — no browser detour.
    let bridgeCalled = false;
    try {
      if (window.LeadCRMNative && typeof window.LeadCRMNative.installApk === 'function') {
        window.LeadCRMNative.installApk(fullUrl);
        bridgeCalled = true;
        // Replace the modal contents with a friendly "downloading" indicator
        // so the user knows something's happening (DownloadManager runs in bg).
        try {
          backdrop.innerHTML =
            '<div style="background:#fff;border-radius:18px;max-width:340px;width:100%;padding:32px 24px;box-shadow:0 24px 64px rgba(0,0,0,.4);text-align:center;">' +
              '<div style="font-size:44px;margin-bottom:10px">⬇️</div>' +
              '<h2 style="margin:0 0 8px;font-size:20px;font-weight:800;color:#0f172a">Downloading update…</h2>' +
              '<p style="margin:0;color:#475569;font-size:14px;font-weight:500">When the download finishes, Android will ask you to install. Tap <b>Install</b>.</p>' +
              '<button id="apk-update-close" style="background:transparent;border:none;color:#64748b;font-size:13px;font-weight:600;cursor:pointer;padding:12px;margin-top:14px">Close</button>' +
            '</div>';
          document.getElementById('apk-update-close').onclick = () => { try { backdrop.remove(); } catch (_) {} };
        } catch (_) {}
      }
      // Fallback to OLD bridge (browser launch) for older APK builds.
      else if (window.LeadCRMNative && typeof window.LeadCRMNative.downloadApk === 'function') {
        window.LeadCRMNative.downloadApk(fullUrl);
        bridgeCalled = true;
      }
    } catch (_) {}
    if (bridgeCalled) return;

    // Path 2: try an anchor click (some Capacitor configs route _blank to system browser)
    let anchorTried = false;
    try {
      const a = document.createElement('a');
      a.href = fullUrl;
      a.target = '_blank';
      a.rel = 'noopener';
      a.style.display = 'none';
      document.body.appendChild(a);
      a.click();
      setTimeout(() => a.remove(), 100);
      anchorTried = true;
    } catch (_) {}

    // Path 3: Cordova-style _system (only works if InAppBrowser-like shim exists)
    try { window.open(fullUrl, '_system'); } catch (_) {}

    // Path 4: location.href (web fallback)
    try { window.location.href = fullUrl; } catch (_) {}

    // Path 5: if none of the above produced a visible result within 800ms,
    // surface the URL with a Copy button so the user can paste in Chrome.
    setTimeout(() => {
      _showApkUpdateFallback(fullUrl);
    }, 800);
  };
  document.getElementById('apk-update-later').onclick = () => {
    try { sessionStorage.setItem('apk_update_dismissed', String(meta.versionCode)); } catch (_) {}
    try { backdrop.remove(); } catch (_) {}
  };
}


function _showApkUpdateFallback(url) {
  if (document.getElementById('apk-update-fallback')) return;
  const back = document.createElement('div');
  back.id = 'apk-update-fallback';
  back.style.cssText = 'position:fixed;inset:0;z-index:100000;background:rgba(15,23,42,.75);display:flex;align-items:center;justify-content:center;padding:20px;font:600 14px/1.4 system-ui,-apple-system,sans-serif;';
  back.innerHTML =
    '<div style="background:#fff;border-radius:18px;max-width:380px;width:100%;padding:24px 22px;box-shadow:0 24px 64px rgba(0,0,0,.4);text-align:left;">' +
      '<div style="font-size:36px;text-align:center;margin-bottom:6px">📲</div>' +
      '<h2 style="margin:0 0 12px;text-align:center;font-size:20px;font-weight:800;color:#0f172a">One-time install</h2>' +
      '<p style="margin:0 0 14px;color:#475569;font-size:13px;font-weight:500">Open <b>Chrome</b> on your phone, paste this link, and tap install. After this one update, future updates will install with one tap.</p>' +
      '<div style="background:#f1f5f9;border:1px solid #cbd5e1;border-radius:10px;padding:10px 12px;margin-bottom:14px;font-size:12px;color:#0f172a;font-family:monospace;word-break:break-all" id="apk-fb-url">' + url + '</div>' +
      '<button id="apk-fb-copy" style="background:#4f46e5;color:#fff;border:none;border-radius:10px;padding:12px 16px;font-weight:700;font-size:15px;cursor:pointer;width:100%">📋 Copy link</button>' +
      '<button id="apk-fb-close" style="background:transparent;border:none;color:#64748b;font-size:13px;font-weight:600;cursor:pointer;padding:10px;margin-top:6px;width:100%">Close</button>' +
    '</div>';
  document.body.appendChild(back);
  document.getElementById('apk-fb-copy').onclick = async () => {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(url);
      } else {
        // Fallback select+copy
        const span = document.getElementById('apk-fb-url');
        const range = document.createRange();
        range.selectNode(span);
        getSelection().removeAllRanges();
        getSelection().addRange(range);
        document.execCommand('copy');
        getSelection().removeAllRanges();
      }
      const btn = document.getElementById('apk-fb-copy');
      btn.textContent = '✅ Copied — paste in Chrome';
      btn.style.background = '#10b981';
    } catch (e) {
      alert('Copy failed. Long-press the link to copy it manually.');
    }
  };
  document.getElementById('apk-fb-close').onclick = () => {
    try { back.remove(); } catch (_) {}
  };
}

// APK_AUTO_UPDATE_v2: re-run the check when the app returns from background.
(function _wireApkUpdateRecheck() {
  try {
    if (!_IS_APK) return;
    const App = (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App) || null;
    if (!App || !App.addListener) return;
    App.addListener('appStateChange', ev => {
      if (ev && ev.isActive) {
        setTimeout(() => { try { window._apkUpdateCheck && window._apkUpdateCheck(); } catch (_) {} }, 800);
      }
    });
  } catch (_) {}
})();

// Endpoints that accept a {mobile:true} flag for trimmed responses.
const _MOBILE_FLAG_FNS = new Set([
  'api_leads_list', 'api_wb_chat_threads',
  'api_announcements_active', 'api_notifications_mine'
]);

async function api(fn, ...args) {
  const _perfStart = performance.now();
  const silent = _SILENT_FNS.has(fn);
  // MOBILE_PERF_v1: auto-inject mobile flag into the FIRST arg for the
  // four heavy endpoints. We treat the existing first arg as an opts
  // object — if it's missing or not an object we create one. Desktop
  // sends nothing extra. Backends gracefully ignore unknown keys.
  if (_IS_APK && _MOBILE_FLAG_FNS.has(fn)) {
    if (args.length === 0) args = [{ mobile: true }];
    else if (args[0] && typeof args[0] === 'object' && !Array.isArray(args[0])) {
      args[0] = { ...args[0], mobile: true };
    }
  }
  // Skip pre-auth firing for background polls. Real user actions still
  // try the call (and will surface a normal error if the token expired).
  if (!CRM.token && _POLL_OR_OPTIONAL_FNS.has(fn)) {
    return Array.isArray(args) && args.length === 0 ? [] : null;
  }
  if (!silent) _bumpApiLoader(+1);
  try {
    const res = await fetch('/api', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ fn, args: [CRM.token, ...args] })
    });
    // QUOTE_MANY_ITEMS_v1: 413 Payload Too Large comes back as HTML
    // from Express's default error handler, not JSON. Catch it here
    // so users see a useful message instead of "Unexpected token <".
    if (res.status === 413) {
      throw new Error('Payload too large — your quote / data has too much embedded content (often big product images). Try smaller product images, or save in smaller batches.');
    }
    const j = await res.json();
    if (!res.ok || j.error) {
      // Strict allow-list. Old regex matched any error containing the
      // word 'token' which logged users out on transient/background
      // failures (e.g. 'No token' when the client raced ahead of the
      // login bootstrap, or SQL errors mentioning 'token' columns).
      // Now we only logout on a real auth-expiry signal AND only when
      // we actually sent a token — if CRM.token was empty when we
      // fired, the failure was our own bug, not the server kicking us.
      const msg = String(j.error || '');
      const reallyExpired = /Invalid token|Bad token|Token expired|User inactive|Session expired|jwt expired|jwt malformed/i.test(msg);
      if (reallyExpired && CRM.token) logout();
      try { window.crmPerf && window.crmPerf.recordApi(fn, performance.now() - _perfStart, false, j.error || 'API error'); } catch (_) {}
      throw new Error(j.error || 'API error');
    }
    try { window.crmPerf && window.crmPerf.recordApi(fn, performance.now() - _perfStart, true); } catch (_) {}
    return j.result;
  } finally {
    if (!silent) _bumpApiLoader(-1);
  }
}

// ----- Sample-template URL helpers ---------------------------------
// In single-tenant deploys (lead-crm-node) this is just '/api/sample.xls'.
// In smartcrm-saas the page lives at /t/<slug>/ and the fetch monkey-
// patch in index.html only intercepts xhr `fetch()` calls — it does
// NOT rewrite plain <a href> clicks. Without prefixing manually the
// download falls through to the JSON-404 catch-all and the user gets
// `sample.json` containing `{"error":"Not found: GET /api/sample.csv"}`
// instead of the spreadsheet.
function _sampleUrl(ext /* 'csv' | 'xls' */) {
  const base = '/api/sample.' + (ext === 'xls' ? 'xls' : 'csv');
  if (typeof window !== 'undefined' && window.TENANT_SLUG) {
    return '/t/' + window.TENANT_SLUG + base;
  }
  return base;
}

// ----- Tenant-aware /api/wa/media URL ------------------------------
// <img src> / <a href> bypass the fetch monkey-patch, so they need
// the /t/<slug>/ prefix baked in manually. Inbound chat images were
// rendering broken because we built '/api/wa/media/<id>' which 404s.
function _waMediaUrl(msgId, token) {
  if (!msgId) return '';
  const base = '/api/wa/media/' + msgId + (token ? '?token=' + encodeURIComponent(token) : '');
  if (typeof window !== 'undefined' && window.TENANT_SLUG) {
    return '/t/' + window.TENANT_SLUG + base;
  }
  return base;
}

function _attachSampleLink(el, ext) {
  if (!el) return;
  el.href = _sampleUrl(ext);
  // Click handler is defensive — even if href somehow resets, we
  // navigate to the resolved tenant URL. preventDefault to avoid
  // double-navigation when both fire.
  el.addEventListener('click', (ev) => {
    ev.preventDefault();
    window.location.href = _sampleUrl(ext);
  });
}

async function apiRaw(fn, ...args) {
  const res = await fetch('/api', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ fn, args })
  });
  const j = await res.json();
  if (!res.ok || j.error) throw new Error(j.error || 'API error');
  return j.result;
}

/* ---------------- Boot ---------------- */
(async () => {
  try {
    const r = await fetch('/config.json');
    if (r.ok) CRM.config = Object.assign(CRM.config, await r.json());
    // QNOTE_v1 — lazy-fetch tenant gate for the AI Quick Note row icon.
    try {
      const qn = await api('api_leads_quickNote_status').catch(() => null);
      if (false) CRM.config.QNOTE_ENABLED = 1; /* AI Quick Note removed for NextEra clone */
    } catch (_) {}
    /* OPPORTUNITIES_v1 — lazy fetch tenant flag so the Lead-modal Opportunities tab
     * only renders for tenants where Settings → OPPORTUNITIES_ENABLED = 1. */
    try {
      const op = await api('api_opportunities_status').catch(() => null);
      if (op && op.enabled) CRM.config.OPPORTUNITIES_ENABLED = '1';
    } catch (_) {}
  } catch (_) {}
  // Apply tenant theme as EARLY as possible — before login screen renders
  // and before warmCache. Public api_admin_brand returns brand colours
  // without auth so even unauthenticated users on the login page see the
  // tenant's brand. Best-effort; quietly no-ops if endpoint isn't ready.
  try {
    const brand = await api('api_admin_brand').catch(() => null);
    if (brand && typeof applyTenantTheme === 'function') applyTenantTheme(brand);
  } catch (_) {}
  // Layout config: sidebar group order + hidden ids — admin-tunable.
  // Falls back to defaults if the api isn't loaded yet.
  try {
    const layout = await api('api_layout_get').catch(() => null);
    if (layout) {
      CRM.layout = {
        sidebar_nav_group_order: Array.isArray(layout.sidebar_nav_group_order) ? layout.sidebar_nav_group_order : [],
        hidden_nav_ids:          Array.isArray(layout.hidden_nav_ids)          ? layout.hidden_nav_ids          : []
      };
      // Hidden ids surface to the existing CRM.config.hidden_nav_ids reader
      if (CRM.layout.hidden_nav_ids.length) CRM.config.hidden_nav_ids = CRM.layout.hidden_nav_ids.join(',');
    }
  } catch (_) {}
  document.title = CRM.config.company_name || 'Lead CRM';

  if (CRM.token) {
    try {
      CRM.user = await api('api_me');
      // Load industry pack BEFORE renderShell so the sidebar's requiresPack
      // filter sees the active pack at render time. Without this, the nav
      // gets built with installedPacks=undefined, every Edu/RE item gets
      // filtered out, and even though warmCache later populates the Set,
      // the sidebar has already been rendered without those items.
      try {
        const brand = await api('api_admin_brand').catch(() => ({}));
        const set = (CRM.installedPacks instanceof Set) ? CRM.installedPacks : new Set();
        if (brand && brand.INDUSTRY_PACK) set.add(String(brand.INDUSTRY_PACK));
        CRM.installedPacks = set;
        // Stash brand on CRM so warmCache and other consumers can read it.
        CRM._earlyBrand = brand || {};
      } catch (_) {
        if (!(CRM.installedPacks instanceof Set)) CRM.installedPacks = new Set();
      }
      renderShell();
      await warmCache();
      try { await warmCacheNotifPref(); } catch (_) {}
      // Resolve chat access for the current user — admin can disable chat
      // for specific roles. Stored in CRM.access.can_chat so renderShell's
      // nav rendering and gates check it consistently.
      try {
        const acc = await api('api_chat_myAccess');
        CRM.access = Object.assign(CRM.access || {}, {
          can_chat: !!acc.can_chat, chat_allowed_roles: acc.allowed_roles || []
        });
      } catch (_) {
        CRM.access = Object.assign(CRM.access || {}, { can_chat: true });
      }
      navigateTo(parseHashView() || 'dashboard');
      startFollowupPolling();
      startRecordingAutoSync();
      refreshNotifs();
      // Load + render any active announcement banners. Polls every 60s so a
      // freshly-posted admin announcement appears for already-logged-in users
      // without them needing to refresh.
      refreshAnnouncements();
      // MOBILE_PERF_v1: 60s on desktop, 10min on APK
      setInterval(() => refreshAnnouncements().catch(() => {}), _IS_APK ? 600_000 : 60_000);
      // In-app chat notification popup — polls every 10s while the user is
      // anywhere in the CRM. Always starts (the backend endpoint silently
      // refuses for users with chat disabled). Skips popping when the chat
      // tab is open with that exact room visible.
      startChatNotificationPolling();
      // Register Web Push so the user's phone gets SMS-style banners even
      // when the CRM tab / installed PWA is closed. Runs after a short delay
      // so it doesn't block initial render. Silently skips on browsers that
      // don't support push or where the user declines permission.
      setTimeout(() => registerWebPush().catch(() => {}), 2000);
      // Native push (Capacitor APK only) — talks to Firebase Cloud Messaging.
      // No-ops in regular browsers / installed PWAs (those use Web Push above).
      setTimeout(() => registerCapacitorPush().catch(() => {}), 2500);
      setTimeout(() => _startFcmAutoHeal(), 10000);  // FCM_AUTOHEAL_v1
      // If a notification tap launched the app cold and we stashed the
      // target URL before the router was ready, apply it now that we're in.
      try {
        const pending = sessionStorage.getItem('pendingPushUrl');
        if (pending) {
          sessionStorage.removeItem('pendingPushUrl');
          setTimeout(() => applyPushUrl(pending), 1000);
        }
      } catch (_) {}
      // Resume any pending call (WebView may have been killed during the call).
      // Runs after warmCache so the lead's status options etc are loaded.
      setTimeout(() => _resumePendingCall('boot'), 1500);
      // First-run onboarding (APK only) — if user has never picked a
      // call-recordings folder, prompt them with a clear modal so they
      // don't have to discover it via the Dialer tab.
      setTimeout(() => firstRunRecordingPrompt().catch(() => {}), 2500);
      // First-run product tour — only shown the very first time a user
      // signs in (flagged in localStorage). Walks them through the
      // sidebar so they know where Leads / WhatsBot / Reports / etc.
      // live before they go hunting. See maybeShowFirstRunTour() near
      // the bottom of this file.
      setTimeout(() => maybeShowFirstRunTour().catch(() => {}), 1800);
      // If user is already checked in today (came back to app later in
      // the day), resume the 30-min location-ping loop so the trail
      // continues from where the previous session left off.
      setTimeout(() => _resumeLocationPingsIfCheckedIn().catch(() => {}), 3000);
      // REC_AUTOSYNC_KILL_v1 (2026-06-06) — disabled app-launch silent sweep per
      // user request. Yellow "No NEW recordings since X min ago" toast was firing on every
      // open. Manual Sync buttons on Recordings page still work.
      // setTimeout(() => silentBackgroundSync(), 4000);
    } catch (_) { logout(); }
  } else {
    renderLogin();
  }

  // When the service worker fires a notificationclick, it posts a 'navigate'
  // message back to the page — route to the URL the push payload pointed at.
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.addEventListener('message', ev => {
      const m = ev && ev.data;
      if (m && m.type === 'navigate' && m.url) {
        try { location.assign(m.url); } catch (_) { location.href = m.url; }
      }
    });
  }

  window.addEventListener('hashchange', () => {
    if (!CRM.user) return;
    navigateTo(parseHashView() || 'dashboard');
  });
})();

function parseHashView() {
  // STU360_PAGE_v2_HOTFIX: regex must allow digits too — view ids like
  // 'student360' contain numbers; old [a-z_-]+ stopped at the digit.
  const m = String(location.hash).match(/^#\/([a-z0-9_-]+)/i);
  return m ? m[1] : null;
}
// STU360_PAGE_v2: extract trailing numeric id from hash, e.g. '#/student360/42' → 42
function parseHashId() {
  const m = String(location.hash).match(/\/(\d+)(?:\/|$|\?)/);
  return m ? parseInt(m[1], 10) : null;
}

// NOTIF_TOGGLE_v2 (2026-06-02) ------------------------------------------
//   CRM._notifEnabled is a client-side cache of users.notifications_enabled.
//   _notifGuard() is the single chokepoint every in-app popup / chime /
//   browser-notification should hit before firing. When the user has the
//   master switch OFF (toggled in Settings → Security → 🔔 Notifications),
//   every popup the SPA shows is suppressed — matching the server-side
//   gate at sendPushToUser() in routes/push.js so the experience is
//   consistent across web push, FCM, AND in-app pop-ups.
//
//   Default is "on" if we haven't loaded the flag yet — we'd rather show a
//   stray notification than silently swallow it before the cache warms.
//   The cache is refreshed (a) right after login by warmCacheNotifPref()
//   and (b) every time the user flips the toggle in the Security modal.
// ------------------------------------------------------------------------
function _notifGuard() {
  try { return CRM._notifEnabled !== false; } catch (_) { return true; }
}
async function warmCacheNotifPref() {
  try {
    const r = await api('api_user_notifGet');
    CRM._notifEnabled = Number(r && r.enabled) !== 0;
  } catch (_) { CRM._notifEnabled = true; }
}
async function warmCache() {
  const [statuses, sources, products, users, customFields, cfg, mods, brand, packs] = await Promise.all([
    api('api_statuses_list'),
    api('api_sources_list'),
    api('api_products_list'),
    api('api_users_list'),
    api('api_customFields_list').catch(() => []),
    api('api_admin_getConfig').catch(() => ({})),
    api('api_modules_active').catch(() => null),
    // Public brand endpoint — works for non-admins too. We merge it under
    // any admin-config we already have so themes apply for every user role.
    api('api_admin_brand').catch(() => ({})),
    // Industry packs installed for THIS tenant. Drives the requiresPack
    // filter in _navAnchor so Edu/RE tabs only show when their pack is
    // active. Without this load CRM.installedPacks stays undefined and
    // every requiresPack item gets hidden — which is why Education
    // showcase was rendering as Generic.
    api('api_packs_listInstalled').catch(() => [])
  ]);
  CRM.cache = { statuses, sources, products, users, customFields };
  // Build the active-pack Set from TWO sources, either of which resolves:
  //   1. api_packs_listInstalled (canonical, requires valid auth token)
  //   2. brand.INDUSTRY_PACK (public, self-heals — added 2026-05-16 hotfix)
  // The brand fallback is critical: when a tenant token expires,
  // api_packs_listInstalled returns 401 and the pack list stays empty,
  // which used to hide Education/RealEstate sidebar items even on tenants
  // that legitimately had those packs. brand always works.
  try {
    const set = new Set();
    (packs || []).forEach(p => {
      if (p && p.pack_id && Number(p.is_active) === 1) set.add(String(p.pack_id));
    });
    if (brand && brand.INDUSTRY_PACK) set.add(String(brand.INDUSTRY_PACK));
    CRM.installedPacks = set;
  } catch (_) {
    CRM.installedPacks = new Set();
    if (brand && brand.INDUSTRY_PACK) CRM.installedPacks.add(String(brand.INDUSTRY_PACK));
  }
  // Merge: admin cfg wins for keys it has, but for non-admin users (where
  // api_admin_getConfig returned {}) we fall back to brand so colours apply.
  const mergedCfg = Object.assign({}, brand || {}, cfg || {});
  // Re-apply brand keys explicitly so an empty admin value never blanks out a real brand value.
  ['BRAND_PRIMARY_COLOR','BRAND_ACCENT_COLOR','BRAND_SIDEBAR_COLOR','BRAND_TEXT_COLOR','THEME_MODE','COMPANY_NAME','COMPANY_LOGO_URL']
    .forEach(k => { if (!mergedCfg[k] && brand && brand[k]) mergedCfg[k] = brand[k]; });
  CRM.cache.config = mergedCfg;
  // Active modules — set of module keys the super-admin has enabled.
  // null/undefined means every module is enabled (backwards-compatible).
  CRM.cache.modules = (mods && Array.isArray(mods.active)) ? mods.active : null;
  CRM.cache.module_catalog = (mods && Array.isArray(mods.catalog)) ? mods.catalog : null;
  applyTenantTheme(mergedCfg);
}

// Helpers for module-aware filtering. Used by sidebar render + settings rail.
function _isModuleActive(key) {
  if (!CRM.cache.modules) return true;             // pre-load or single-tenant fallback
  return CRM.cache.modules.includes(key);
}
function _moduleForNavId(navId) {
  const cat = CRM.cache.module_catalog;
  if (!cat) return null;
  for (const m of cat) {
    if ((m.nav_ids || []).includes(navId)) return m.key;
  }
  return null;
}
function _moduleForSettingsId(setId) {
  const cat = CRM.cache.module_catalog;
  if (!cat) return null;
  for (const m of cat) {
    if ((m.settings_ids || []).includes(setId)) return m.key;
  }
  return null;
}

/**
 * Inject tenant-configured colours as CSS variables so every
 * existing var(--brand) etc. usage picks them up automatically.
 * Empty / missing keys keep the design-system defaults.
 */
function applyTenantTheme(cfg) {
  try {
    const root = document.documentElement;
    const set = (k, v) => { if (v && /^#[0-9a-fA-F]{3,8}$/.test(String(v).trim())) root.style.setProperty(k, String(v).trim()); };
    set('--brand',         cfg.BRAND_PRIMARY_COLOR);
    set('--brand-dark',    cfg.BRAND_PRIMARY_COLOR);
    set('--brand-accent',  cfg.BRAND_ACCENT_COLOR);
    // Sidebar colour applies to BOTH the existing --sidebar-bg used by
    // .sidebar rules AND a new --brand-sidebar var for any future use.
    set('--sidebar-bg',    cfg.BRAND_SIDEBAR_COLOR);
    set('--brand-sidebar', cfg.BRAND_SIDEBAR_COLOR);
    set('--brand-text',    cfg.BRAND_TEXT_COLOR);
    set('--text',          cfg.BRAND_TEXT_COLOR);
    // Theme mode: 'light' | 'dark' | 'auto'.
    const mode = String(cfg.THEME_MODE || 'auto').toLowerCase();
    document.documentElement.setAttribute('data-theme', ['light','dark','auto'].includes(mode) ? mode : 'auto');
    // GLASS_THEME_v1 — opt-in premium skin. Classic is default.
    const skin = String(cfg.THEME_SKIN || 'classic').toLowerCase();
    if (skin === 'glass') {
      document.documentElement.setAttribute('data-skin', 'glass');
      const pal = String(cfg.THEME_PALETTE || 'cream').toLowerCase();
      const VALID_PAL = ['cream','rose','lavender','mint','ocean','peach','sunset','berry','slate'];
      document.documentElement.setAttribute('data-pal', VALID_PAL.includes(pal) ? pal : 'cream');
    } else {
      document.documentElement.removeAttribute('data-skin');
      document.documentElement.removeAttribute('data-pal');
    }
  } catch (_) {}
}

/**
 * Return the active role list as { value, label } pairs for <select>
 * dropdowns in the admin tabs (Settings → Permissions, the User edit
 * form, role-aware filters). Memoised in CRM.cache._rolesForSelect so
 * we don't refetch on every render. The Roles tab invalidates the
 * cache by setting CRM.cache._rolesForSelect = null after add/edit/
 * delete (lines ~270-305) — see those handlers for the pattern.
 *
 * The previous build referenced this helper from three call sites
 * (showAdminTab('permissions'), the User edit form, and the role-
 * filter UI) but the function definition was missing, causing the
 * Permissions tab to render "_rolesForSelect is not defined" instead
 * of the role grid.
 */
async function _rolesForSelect() {
  if (CRM.cache && CRM.cache._rolesForSelect) return CRM.cache._rolesForSelect;
  let rows;
  try { rows = await api('api_roles_list'); } catch (_) { rows = []; }
  const list = (Array.isArray(rows) ? rows : []).map(r => ({
    value: String(r.key || r.code || r.id || ''),
    label: String(r.label || r.name || r.key || '')
  }));
  if (CRM.cache) CRM.cache._rolesForSelect = list;
  return list;
}


// Lazy-load the connected WhatsApp phones list — used by every "Send
// from" picker in the SPA. Caches on CRM.cache.waPhones so the chat
// composer / initiate-chat modal don't refetch on every render.
async function _loadWaPhones() {
  if (CRM.cache.waPhones) return CRM.cache.waPhones;
  try { CRM.cache.waPhones = await api('api_wa_phones_listAll'); }
  catch (_) { CRM.cache.waPhones = []; }
  return CRM.cache.waPhones || [];
}

// Builds a <select> element listing every active phone, with
// 'Use default' as the first option. Returns the element. The caller
// reads picker.value to get the phone_number_id (or '' for default).
function _phonePickerSelect(opts) {
  opts = opts || {};
  const sel = h('select', { class: 'wa-phone-picker', style: opts.style || { fontSize: '.85rem' } },
    h('option', { value: '' }, opts.defaultLabel || '— Use default phone —'));
  (opts.phones || []).filter(p => Number(p.is_active) === 1).forEach(p => {
    const lbl = (Number(p.is_default) === 1 ? '⭐ ' : '') +
                (p.display_phone_number || p.phone_number_id) +
                (p.label ? ' (' + p.label + ')' : '');
    sel.appendChild(h('option', { value: p.phone_number_id }, lbl));
  });
  return sel;
}
/* ---------------- utility ---------------- */
const $ = (sel, ctx) => (ctx || document).querySelector(sel);
const $$ = (sel, ctx) => [...(ctx || document).querySelectorAll(sel)];
function h(tag, attrs = {}, ...children) {
  const el = document.createElement(tag);
  for (const [k, v] of Object.entries(attrs || {})) {
    if (k === 'style' && typeof v === 'object') Object.assign(el.style, v);
    else if (k === 'class') el.className = v;
    else if (k === 'html') el.innerHTML = v;
    else if (k.startsWith('on') && typeof v === 'function') el.addEventListener(k.slice(2).toLowerCase(), v);
    else if (v === true) el.setAttribute(k, '');
    else if (v === false || v == null) {}
    else el.setAttribute(k, v);
  }
  for (const c of children.flat()) {
    if (c == null || c === false) continue;
    el.append(c instanceof Node ? c : document.createTextNode(String(c)));
  }
  return el;
}
function esc(s) { return String(s ?? '').replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c])); }
function fmtDate(s, opts) {
  if (!s) return '';
  try {
    const d = new Date(s);
    if (opts === 'short') return d.toLocaleDateString();
    if (opts === 'time') return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    if (opts === 'relative') {
      const diff = Date.now() - d.getTime();
      const abs = Math.abs(diff);
      const min = Math.round(abs / 60000);
      const rel = diff >= 0 ? ago => ago + ' ago' : ago => 'in ' + ago;
      if (min < 1) return 'just now';
      if (min < 60) return rel(min + 'm');
      const hr = Math.round(min / 60);
      if (hr < 24) return rel(hr + 'h');
      return rel(Math.round(hr / 24) + 'd');
    }
    return d.toLocaleString();
  } catch (_) { return String(s); }
}

/* ---- adminRoles tab ---- */
async function adminRoles() {
  const roles = await api('api_roles_list');
  const wrap = h('div', {});
  const keyInput   = h('input', { placeholder: 'Key (e.g. senior_sales)', style: { flex: '1' } });
  const labelInput = h('input', { placeholder: 'Display label (e.g. Senior Sales)', style: { flex: '1' } });
  const lvlInput   = h('select', {},
    h('option', { value: '0' }, '0 — admin (sees everyone)'),
    h('option', { value: '1' }, '1 — manager (whole subtree)'),
    h('option', { value: '2' }, '2 — team leader (2 levels)'),
    h('option', { value: '3', selected: 'selected' }, '3 — sales (self only)')
  );
  wrap.appendChild(h('div', { class: 'card' },
    h('h3', {}, 'Add a new role'),
    h('p', { class: 'muted' }, 'New roles inherit no permissions by default. After adding, set them up in the Permissions tab.'),
    h('div', { style: { display: 'flex', gap: '.5rem', alignItems: 'center', marginTop: '.5rem', flexWrap: 'wrap' } },
      keyInput, labelInput, lvlInput,
      h('button', { class: 'btn primary', onclick: async () => {
        try {
          await api('api_roles_save', {
            key: keyInput.value, label: labelInput.value,
            hierarchy_level: parseInt(lvlInput.value, 10) || 3
          });
          CRM.cache._rolesForSelect = null;
          toast('Role added'); showAdminTab('roles');
        } catch (e) { toast(e.message, 'err'); }
      } }, '+ Add role'))
  ));

  const list = h('div', { class: 'card' }, h('h3', {}, 'Existing roles (' + roles.length + ')'));
  list.appendChild(h('div', { class: 'table-wrap' }, h('table', {},
    h('thead', {}, h('tr', {},
      h('th', {}, 'Key'), h('th', {}, 'Label'), h('th', {}, 'Level'),
      h('th', {}, 'System?'),
      h('th', { style: { textAlign: 'right' } }, 'Actions'))),
    h('tbody', {}, ...roles.map(r => {
      const labelEdit = h('input', { value: r.label, style: { width: '160px' } });
      const lvlEdit   = h('input', { type: 'number', min: '0', max: '99', value: String(r.hierarchy_level), style: { width: '60px' } });
      return h('tr', {},
        h('td', {}, h('code', {}, r.key)),
        h('td', {}, labelEdit),
        h('td', {}, lvlEdit),
        h('td', {}, Number(r.is_system) === 1 ? '✓' : ''),
        h('td', { style: { textAlign: 'right' } },
          h('button', { class: 'btn sm', onclick: async () => {
            try {
              await api('api_roles_save', { id: r.id, key: r.key, label: labelEdit.value,
                hierarchy_level: parseInt(lvlEdit.value, 10) || 3 });
              CRM.cache._rolesForSelect = null;
              toast('Saved');
            } catch (e) { toast(e.message, 'err'); }
          } }, '💾 Save'),
          ' ',
          Number(r.is_system) === 1 ? null
            : h('button', { class: 'btn sm danger', onclick: async () => {
                if (!confirm(`Delete role "${r.label}"?`)) return;
                try { await api('api_roles_delete', r.id); CRM.cache._rolesForSelect = null; toast('Deleted'); showAdminTab('roles'); }
                catch (e) { toast(e.message, 'err'); }
              } }, '🗑 Delete')
        ));
    }))
  )));
  wrap.appendChild(list);
  return wrap;
}

/**
 * Convert any datetime stored in the DB (ISO UTC, or naive Postgres timestamp)
 * to a "YYYY-MM-DDTHH:mm" string in the user's LOCAL timezone, suitable for
 * a datetime-local input. Without this, a UTC value like 2026-04-25T15:10:00Z
 * shows in the form as 15:10 instead of the local 20:40.
 */
function isoToLocalDtInput(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  if (isNaN(d)) return String(iso).slice(0, 16);
  const pad = n => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

/**
 * Inverse of isoToLocalDtInput. Converts a "YYYY-MM-DDTHH:mm" datetime-local
 * value (interpreted as the user's local time) into a UTC ISO string the
 * server can store and round-trip safely. JavaScript's Date constructor parses
 * datetime-local strings as local time — toISOString() then emits proper UTC.
 */
function localDtInputToIso(s) {
  const v = String(s || '').trim();
  if (!v) return null;
  const d = new Date(v);
  if (isNaN(d)) return null;
  return d.toISOString();
}
function toast(msg, type = 'ok') {
  const t = h('div', { class: `toast toast-${type}` }, msg);
  document.body.appendChild(t);
  setTimeout(() => t.remove(), 3000);
}
function confirmDialog(msg) {
  return new Promise(resolve => {
    const modal = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) { modal.remove(); resolve(false); } } },
      h('div', { class: 'modal modal-sm' },
        h('p', {}, msg),
        h('div', { class: 'actions' },
          h('button', { class: 'btn', onclick: () => { modal.remove(); resolve(false); } }, 'Cancel'),
          h('button', { class: 'btn primary', onclick: () => { modal.remove(); resolve(true); } }, 'OK')
        )
      )
    );
    document.body.appendChild(modal);
  });
}

function logout() {
  localStorage.removeItem(CRM._slug ? ('crm_token_' + CRM._slug) : 'crm_token'); try { localStorage.removeItem('crm_token'); } catch (_) {}
  CRM.token = null; CRM.user = null;
  location.hash = '';
  location.reload();
}

/* ---------------- Login ---------------- */
function renderLogin() {
  const app = $('#app');
  // Demo tenants get their credentials pre-filled so visitors can just
  // click Sign in. Detected via the slug — the showcase seeder always
  // uses 'showcase'. Add more demo slugs to this list as needed.
  const isDemoTenant = String(window.TENANT_SLUG || '').toLowerCase() === 'showcase';
  const demoEmail    = isDemoTenant ? 'demo@smartcrm.in'   : '';
  const demoPassword = isDemoTenant ? 'Showcase@123'       : '';
  const demoBanner   = isDemoTenant
    ? `<div style="margin:.75rem 0;padding:.6rem .8rem;background:#eef2ff;border:1px solid #c7d2fe;border-radius:8px;font-size:.82rem;color:#3730a3;text-align:left">
         <b>👋 Demo workspace</b> — credentials are pre-filled. Just click <b>Sign in</b>.
       </div>` : '';
  app.innerHTML = `
    <div class="login-screen">
      <div class="login-card">
        <div class="login-brand">
          ${CRM.config.company_logo_url ? `<img src="${esc(CRM.config.company_logo_url)}" class="login-logo" alt="" />` : '<div class="login-logo-dot">🎯</div>'}
          <h1>${esc(CRM.config.company_name || 'Lead CRM')}</h1>
          <p class="muted">Sign in to continue</p>
        </div>
        ${demoBanner}
        <form id="login-form">
          <label>Email</label>
          <input type="email" name="email" autocomplete="username" required ${isDemoTenant ? '' : 'autofocus'} value="${esc(demoEmail)}" />
          <label>Password</label>
          <input type="password" name="password" autocomplete="current-password" required value="${esc(demoPassword)}" />
          <button type="submit" class="btn primary block" ${isDemoTenant ? 'autofocus' : ''}>Sign in</button>
          <p id="login-err" class="error"></p>
        </form>
        <div style="text-align:center;margin-top:.75rem">
          <a href="#" id="btn-forgot-password" style="color:#6366f1;font-size:.85rem;text-decoration:none">Forgot password?</a>
        </div>
        <div style="text-align:center;margin-top:1.5rem;font-size:.78rem;color:#94a3b8">
          Workspace: <b style="color:#64748b">${esc(window.TENANT_SLUG || '')}</b>
          <span style="margin:0 .35rem">·</span>
          <a href="#" id="btn-switch-workspace"
            style="color:#94a3b8;text-decoration:underline;font-size:.78rem">switch</a>
        </div>
      </div>
    </div>`;
  // Switch-workspace link — confirms first because it clears the
  // session token and redirects to the workspace picker. Was getting
  // tapped accidentally on phones because the button was too prominent.
  const forgotBtn = document.getElementById('btn-forgot-password');
  if (forgotBtn) forgotBtn.addEventListener('click', (ev) => {
    ev.preventDefault();
    const email = prompt('Enter the email registered with your workspace:\n\nWe\'ll send you a link to reset your password.');
    if (!email) return;
    apiRaw('api_password_forgot', '', email.trim()).then(() => {
      alert('If an account with that email exists, a password-reset link has been sent.\n\nCheck your inbox (and spam folder) — the link expires in 60 minutes.');
    }).catch(e => alert('Could not send reset email: ' + e.message));
  });
  const switchBtn = document.getElementById('btn-switch-workspace');
  if (switchBtn) switchBtn.addEventListener('click', (ev) => {
    ev.preventDefault();
    if (!confirm('Switch to a different workspace?\n\nThis signs you out of "' + (window.TENANT_SLUG || '') + '" and takes you to the workspace picker.')) return;
    try { localStorage.removeItem('tenant_slug'); } catch (_) {}
    try { localStorage.removeItem(CRM._slug ? ('crm_token_' + CRM._slug) : 'crm_token'); try { localStorage.removeItem('crm_token'); } catch (_) {} } catch (_) {}
    try { localStorage.removeItem('crm_user'); } catch (_) {}
    location.href = '/app?stay=1';
  });
  $('#login-form').addEventListener('submit', async ev => {
    ev.preventDefault();
    const f = ev.target;
    $('#login-err').textContent = '';
    try {
      const r = await apiRaw('api_login', '', f.email.value, f.password.value);
      // 2FA path — server returned a challenge token instead of a session.
      // Swap the form for an OTP entry step. The user's challenge expires
      // in 5 minutes; api_login_otp_verify exchanges it for the real token.
      if (r && r.needs_otp && r.challenge_token) {
        showOtpStep(r.challenge_token, r.user || { email: f.email.value });
        return;
      }
      CRM.token = r.token; CRM.user = r.user;
      localStorage.setItem(CRM._slug ? ('crm_token_' + CRM._slug) : 'crm_token', r.token);
      _syncNativeCallEventCreds();
      location.reload();
    } catch (e) { $('#login-err').textContent = e.message; }
  });
}

/**
 * Security modal — change password + manage 2FA (Google Authenticator).
 *
 * 2FA flow:
 *   1. User clicks "Set up 2FA" → server generates a fresh secret (saved
 *      with totp_enabled=0 so the half-set-up state can't lock anyone out).
 *   2. We render a QR code (qrcode.js loaded from cdnjs) plus the raw
 *      base32 for manual entry.
 *   3. User scans, types one code, clicks Verify → server flips the
 *      totp_enabled flag to 1.
 *   4. From the next login onwards, the OTP step in the login form fires.
 *
 * Disable requires the current password AND a current OTP — defends
 * against both a hijacked session token and a stolen/known password.
 */
async function openSecurityModal() {
  let me;
  try { me = await api('api_me'); }
  catch (e) { return toast(e.message, 'err'); }

  const status = h('div', { class: 'sec-status' });
  const renderStatus = () => {
    status.innerHTML = '';
    const enabled = !!me.totp_enabled;
    status.appendChild(h('div', {
      style: { padding: '10px 12px', borderRadius: '6px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '10px',
               background: enabled ? 'var(--ok-soft)' : 'var(--warn-soft)',
               color: enabled ? 'var(--ok)' : 'var(--warn)', fontWeight: 500 } },
      h('span', {}, enabled ? '✓ Two-factor authentication is enabled' : '⚠ Two-factor authentication is not enabled'),
      enabled
        ? h('button', { class: 'btn sm', onclick: () => disable2FA() }, 'Disable')
        : h('button', { class: 'btn sm primary', onclick: () => setup2FA() }, 'Set up 2FA')
    ));
  };

  const setup2FA = async () => {
    let r;
    try { r = await api('api_2fa_setup_start'); }
    catch (e) { return toast(e.message, 'err'); }

    const qrHolder = h('div', { id: 'sec-qr', style: { width: '180px', height: '180px', background: '#fff', border: '1px solid var(--border)', padding: '8px', borderRadius: '6px' } });
    const otpInput = h('input', { name: 'otp', maxlength: '6', inputmode: 'numeric', placeholder: '000000',
      style: { fontSize: '1.2rem', letterSpacing: '.3em', textAlign: 'center', fontFamily: 'monospace' } });

    const setupModal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal' },
      h('div', { class: 'modal-head' },
        h('h3', {}, '🔒 Set up two-factor authentication'),
        h('button', { class: 'btn icon', onclick: () => setupModal.remove() }, '✕')
      ),
      h('ol', { style: { paddingLeft: '1.2rem', fontSize: '.88rem', lineHeight: '1.55' } },
        h('li', {}, 'Install Google Authenticator (or Microsoft Authenticator / Authy / 1Password) on your phone.'),
        h('li', {}, 'Open the app and tap +, choose ', h('b', {}, 'Scan QR code'), '.'),
        h('li', {}, 'Scan this code:')
      ),
      h('div', { style: { display: 'flex', gap: '14px', alignItems: 'center', justifyContent: 'center', margin: '10px 0', flexWrap: 'wrap' } },
        qrHolder,
        h('div', { style: { fontSize: '.8rem' } },
          h('div', { class: 'muted' }, 'Or type this secret manually:'),
          h('code', { style: { display: 'inline-block', padding: '4px 8px', marginTop: '4px', background: 'var(--bg-alt)', borderRadius: '4px', fontSize: '.85rem', wordBreak: 'break-all' } }, r.secret),
          h('div', { class: 'muted', style: { marginTop: '6px' } }, 'Issuer: ' + (r.issuer || 'CRM')),
          h('div', { class: 'muted' }, 'Account: ' + (r.account || me.email))
        )
      ),
      h('label', {}, '4. Enter the 6-digit code shown in your authenticator:'),
      otpInput,
      h('div', { class: 'actions' },
        h('button', { class: 'btn', onclick: () => setupModal.remove() }, 'Cancel'),
        h('button', { class: 'btn primary', onclick: async () => {
          try {
            await api('api_2fa_setup_verify', otpInput.value.trim());
            toast('2FA enabled — you\'ll need your authenticator app to sign in next time');
            me.totp_enabled = true;
            setupModal.remove();
            renderStatus();
          } catch (e) { toast(e.message, 'err'); }
        } }, 'Verify and enable')
      )
    ));
    document.body.appendChild(setupModal);

    // Render QR code. Library is ~16KB from cdnjs, loaded once and cached.
    const drawQr = () => {
      if (!window.QRCode) return setTimeout(drawQr, 200);
      qrHolder.innerHTML = '';
      new window.QRCode(qrHolder, { text: r.otpauth_url, width: 168, height: 168, correctLevel: window.QRCode.CorrectLevel.M });
    };
    if (!window.QRCode) {
      const s = document.createElement('script');
      s.src = 'https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js';
      s.onload = drawQr;
      document.head.appendChild(s);
    } else { drawQr(); }
  };

  const disable2FA = async () => {
    const pwInput = h('input', { type: 'password', autocomplete: 'current-password' });
    const otpInput = h('input', { name: 'otp', maxlength: '6', inputmode: 'numeric', placeholder: '000000',
      style: { letterSpacing: '.2em', textAlign: 'center', fontFamily: 'monospace' } });
    const disableModal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal modal-sm' },
      h('div', { class: 'modal-head' },
        h('h3', {}, 'Disable 2FA'),
        h('button', { class: 'btn icon', onclick: () => disableModal.remove() }, '✕')
      ),
      h('p', { class: 'muted', style: { fontSize: '.85rem' } }, 'Confirm your password and a current 6-digit code to disable two-factor authentication.'),
      h('label', {}, 'Password'),
      pwInput,
      h('label', { style: { marginTop: '8px' } }, 'Current 6-digit code'),
      otpInput,
      h('div', { class: 'actions' },
        h('button', { class: 'btn', onclick: () => disableModal.remove() }, 'Cancel'),
        h('button', { class: 'btn danger', onclick: async () => {
          try {
            await api('api_2fa_disable', pwInput.value, otpInput.value.trim());
            toast('2FA disabled');
            me.totp_enabled = false;
            disableModal.remove();
            renderStatus();
          } catch (e) { toast(e.message, 'err'); }
        } }, 'Disable')
      )
    ));
    document.body.appendChild(disableModal);
  };

  // Change password section
  const cpOld = h('input', { type: 'password', autocomplete: 'current-password' });
  const cpNew = h('input', { type: 'password', autocomplete: 'new-password', minlength: '6' });

  const modal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, '🔒 Security'),
      h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
    ),

    h('h4', { style: { margin: '4px 0 8px' } }, 'Two-factor authentication'),
    status,
    h('p', { class: 'muted', style: { fontSize: '.78rem', marginTop: '6px' } },
      'Adds a 6-digit code from your phone on top of your password. Strongly recommended for admins and managers.'),

    h('hr', { style: { margin: '18px 0', border: '0', borderTop: '1px solid var(--border-light)' } }),

    h('h4', { style: { margin: '4px 0 8px' } }, 'Change password'),
    h('label', {}, 'Current password'), cpOld,
    h('label', { style: { marginTop: '8px' } }, 'New password'), cpNew,
    h('div', { class: 'actions' },
      h('button', { class: 'btn', onclick: () => modal.remove() }, 'Close'),
      h('button', { class: 'btn primary', onclick: async () => {
        if (!cpOld.value || !cpNew.value) return toast('Both fields required', 'err');
        if (cpNew.value.length < 6) return toast('New password must be at least 6 characters', 'err');
        try {
          await api('api_changePassword', cpOld.value, cpNew.value);
          toast('Password changed');
          cpOld.value = ''; cpNew.value = '';
        } catch (e) { toast(e.message, 'err'); }
      } }, 'Update password')
    ),

    h('hr', { style: { margin: '18px 0', border: '0', borderTop: '1px solid var(--border-light)' } }),

    /* NOTIF_TOGGLE_v1 — admin (and every user) can silence all push notifications. */
    (function () {
      const wrap = h('div', {});
      wrap.appendChild(h('h4', { style: { margin: '4px 0 8px' } }, '🔔 Notifications'));
      const state = h('div', {
        style: {
          padding: '10px 12px', borderRadius: '6px', display: 'flex',
          justifyContent: 'space-between', alignItems: 'center', gap: '10px',
          background: 'var(--bg-alt)', fontWeight: 500
        }
      });
      const label = h('span', {}, 'Loading…');
      const btn = h('button', { class: 'btn sm primary' }, '…');
      state.appendChild(label);
      state.appendChild(btn);
      wrap.appendChild(state);
      wrap.appendChild(h('p', { class: 'muted', style: { fontSize: '.78rem', marginTop: '6px' } },
        'Silences every push (new lead, follow-up due, heat alert, WhatsApp inbound, click-to-mobile, etc.) for just you. Other users are unaffected.'));
      function paint(enabled) {
        state.style.background = enabled ? 'var(--ok-soft)' : 'var(--warn-soft)';
        state.style.color = enabled ? 'var(--ok)' : 'var(--warn)';
        label.textContent = enabled ? '✓ Notifications are ON' : '🔕 Notifications are OFF';
        btn.textContent = enabled ? 'Turn OFF' : 'Turn ON';
        btn.dataset.next = enabled ? '0' : '1';
      }
      api('api_user_notifGet')
        .then(r => { CRM._notifEnabled = Number(r.enabled) !== 0; paint(CRM._notifEnabled); })
        .catch(e => { label.textContent = 'Error: ' + e.message; });
      btn.onclick = async () => {
        btn.disabled = true;
        try {
          const next = Number(btn.dataset.next);
          const r = await api('api_user_notifSet', next);
          CRM._notifEnabled = Number(r.enabled) !== 0;   /* NOTIF_TOGGLE_v2 */
          paint(Number(r.enabled) !== 0);
          toast(Number(r.enabled) ? 'Notifications turned ON' : 'Notifications turned OFF', 'ok');
        } catch (e) { toast(e.message, 'err'); }
        finally { btn.disabled = false; }
      };
      return wrap;
    })()
  ));
  document.body.appendChild(modal);
  renderStatus();
}

function showOtpStep(challengeToken, who) {
  const card = document.querySelector('.login-card');
  if (!card) return;
  card.innerHTML = `
    <div class="login-brand">
      ${CRM.config && CRM.config.company_logo_url ? `<img src="${esc(CRM.config.company_logo_url)}" class="login-logo" alt="" />` : '<div class="login-logo-dot">🔒</div>'}
      <h1>Two-step verification</h1>
      <p class="muted">Enter the 6-digit code from your authenticator app for ${esc(who.email || '')}.</p>
    </div>
    <form id="login-otp-form">
      <label>6-digit code</label>
      <input type="text" name="otp" inputmode="numeric" autocomplete="one-time-code"
             maxlength="6" pattern="[0-9]{6}" required autofocus
             style="font-size:1.4rem;letter-spacing:.4em;text-align:center;font-family:var(--font-mono,monospace);" />
      <button type="submit" class="btn primary block">Verify and sign in</button>
      <p id="login-err" class="error"></p>
      <button type="button" class="btn ghost block" id="login-otp-back" style="margin-top:.5rem;">← Use a different account</button>
    </form>`;
  document.getElementById('login-otp-back').addEventListener('click', () => location.reload());
  document.getElementById('login-otp-form').addEventListener('submit', async ev => {
    ev.preventDefault();
    const otp = ev.target.otp.value.trim();
    document.getElementById('login-err').textContent = '';
    try {
      const r = await apiRaw('api_login_otp_verify', challengeToken, otp);
      CRM.token = r.token; CRM.user = r.user;
      localStorage.setItem(CRM._slug ? ('crm_token_' + CRM._slug) : 'crm_token', r.token);
      _syncNativeCallEventCreds();
      location.reload();
    } catch (e) { document.getElementById('login-err').textContent = e.message; }
  });
}

