// QUOTE_WA_DESKTOP_v1 — helper that produces a WhatsApp share URL respecting
// the user's preference. localStorage.crm_wa_open_mode = 'app' returns the
// whatsapp:// protocol URL (which the OS routes to the WhatsApp Desktop app
// if installed). Otherwise returns wa.me/... which opens web.whatsapp.com.
window._waShareUrl = function(phone, text) {
  const dig = String(phone || '').replace(/\D/g, '');
  if (!dig) return '';
  const mode = (localStorage.getItem('crm_wa_open_mode') || 'web');
  if (mode === 'app') {
    return 'whatsapp://send?phone=' + dig + (text ? '&text=' + encodeURIComponent(text) : '');
  }
  // FIX1 (2026-06-06) — switched from wa.me to api.whatsapp.com because the
  // api.whatsapp.com host is more likely to surface the Android app chooser
  // when both Personal + Business WhatsApp are installed. wa.me historically
  // gets bound to whichever app the user first picked "Always" with.
  return 'https://api.whatsapp.com/send/?phone=' + dig + (text ? '&text=' + encodeURIComponent(text) : '');
};

// FIX1 — Android intent URL pinned to a specific WhatsApp package.
// kind = 'personal' | 'business' | 'chooser'
/* WA_PKG_FIX_v3 — return MULTIPLE intent URL candidates per target, since
   different Android versions / OEM WebView builds resolve intent filters
   differently. _waOpenPinned will try them in order. */
window._waPinnedIntentCandidates = function(phone, text, kind) {
  const dig = String(phone || '').replace(/\D/g, '');
  if (!dig) return [];
  const txt = text ? ('&text=' + encodeURIComponent(text)) : '';
  if (kind === 'chooser') {
    return ['https://api.whatsapp.com/send/?phone=' + dig + txt];
  }
  const pkg = (kind === 'business') ? 'com.whatsapp.w4b' : 'com.whatsapp';
  return [
    // Candidate 1: whatsapp:// scheme — most direct, both apps register it
    'intent://send?phone=' + dig + txt + '#Intent;scheme=whatsapp;package=' + pkg + ';action=android.intent.action.VIEW;end',
    // Candidate 2: api.whatsapp.com host (HTTPS) — Meta canonical deep link
    'intent://api.whatsapp.com/send?phone=' + dig + txt + '#Intent;scheme=https;package=' + pkg + ';action=android.intent.action.VIEW;end',
    // Candidate 3: wa.me — universal short link, both apps register
    'intent://wa.me/' + dig + (text ? '?text=' + encodeURIComponent(text) : '') + '#Intent;scheme=https;package=' + pkg + ';action=android.intent.action.VIEW;end'
  ];
};
// Backwards-compat wrapper for any code that still calls _waPinnedIntent.
window._waPinnedIntent = function(phone, text, kind) {
  const arr = window._waPinnedIntentCandidates(phone, text, kind);
  return arr[0] || '';
};
window._waOpenPinned = function(phone, text, kind) {
  /* WA_PKG_FIX_v4 — use Capacitor App.openUrl when available (bypasses WebView
     intent interception), then fall back to window.open(_system), then
     location.href. If everything fails, fire chooser URL + clipboard + toast.
     Tries each candidate URL in succession. If the WhatsApp app launches,
     document goes hidden (visibilitychange fires) and we stop. If nothing
     launches within ~2s the page is still visible, so we copy the phone+text
     to the clipboard, fire the chooser URL as guaranteed last-resort, and
     toast the user explaining how to set the Android default. */
  // WA_APP_TARGET_v1 (2026-06-09) — when running inside the Android APK,
  // hand off to the native LeadCRMNative.openWhatsApp bridge, which sets the
  // intent package explicitly (com.whatsapp.w4b for Business, com.whatsapp for
  // Personal). The JS-only intent:// candidates below CANNOT enforce the
  // package — Capacitor App.openUrl parses with Uri.parse (not Intent.parseUri),
  // so ";package=" was dropped and Android opened the default (Personal) app.
  // The bridge reliably opens the chosen app; only browsers fall through to the
  // legacy intent:// path.
  try {
    if ((kind === 'business' || kind === 'personal')
        && window.LeadCRMNative && typeof window.LeadCRMNative.openWhatsApp === 'function') {
      window.__waPinnedCb = function(ok, detail) {
        if (ok) return;
        // Targeted app not installed (or no activity). Tell the user plainly
        // instead of silently opening the wrong app.
        var label = kind === 'business' ? 'WhatsApp Business' : 'WhatsApp';
        if (detail === 'not_installed' && typeof toast === 'function') {
          toast(label + ' is not installed on this phone. Install it (or pick the other option) to chat from that number.', 'err');
        } else if (typeof toast === 'function') {
          toast('Could not open ' + label + ' (' + (detail || 'error') + ').', 'err');
        }
      };
      window.LeadCRMNative.openWhatsApp(String(phone || ''), String(text || ''), kind, '__waPinnedCb');
      return;
    }
  } catch (_) { /* fall through to the browser intent:// path */ }

  const candidates = (window._waPinnedIntentCandidates
    ? window._waPinnedIntentCandidates(phone, text, kind)
    : [window._waPinnedIntent(phone, text, kind)]).filter(Boolean);
  if (!candidates.length) return;

  let opened = false;
  const onHidden = () => {
    if (document.visibilityState === 'hidden') opened = true;
  };
  document.addEventListener('visibilitychange', onHidden);

  // Helper: try to fire ONE URL through the most reliable channel available.
  // Capacitor App.openUrl explicitly delegates to Android's intent system
  // (Intent.parseUri + startActivity) without involving the WebView's
  // shouldOverrideUrlLoading, which on some OEM builds swallows intent://.
  function fireOne(url) {
    const App = (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App) || null;
    if (App && App.openUrl) {
      try {
        App.openUrl({ url }).catch(() => { /* probably no matching activity */ });
        return;
      } catch (_) { /* fall through */ }
    }
    // window.open(_system) tells Capacitor to use the OS handler, not the WebView
    try {
      const w = window.open(url, '_system');
      if (w) return;
    } catch (_) { /* fall through */ }
    // Final fallback: top-level navigation
    try { window.location.href = url; } catch (_) {}
  }

  // Try candidate[0] immediately; advance to subsequent candidates if still visible.
  fireOne(candidates[0]);
  let idx = 1;
  function tryNext() {
    if (opened || idx >= candidates.length) return finish();
    fireOne(candidates[idx]);
    idx += 1;
    setTimeout(tryNext, 600);
  }
  setTimeout(tryNext, 1200);

  function finish() {
    document.removeEventListener('visibilitychange', onHidden);
    if (opened) return;
    // Nothing opened. Last resort — open the chooser URL via _system so the user
    // at least lands SOMEWHERE in WhatsApp (with the default app), and copy the
    // message to clipboard for safety.
    const label = kind === 'business' ? 'WhatsApp Business'
                : kind === 'personal' ? 'WhatsApp' : 'WhatsApp';
    const dig = String(phone || '').replace(/\D/g, '');
    const clip = '+' + dig + (text ? '\n' + text : '');
    try { navigator.clipboard.writeText(clip); } catch (_) {}
    // Try one last URL — the unconstrained chooser link. Capacitor will hand
    // this off cleanly to whichever WhatsApp is the Android default.
    try {
      const App = (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App) || null;
      const chooserUrl = 'https://api.whatsapp.com/send/?phone=' + dig + (text ? '&text=' + encodeURIComponent(text) : '');
      if (App && App.openUrl) { App.openUrl({ url: chooserUrl }).catch(() => {}); }
      else { window.open(chooserUrl, '_system'); }
    } catch (_) {}
    if (typeof toast === 'function') {
      toast(label + ' couldn\'t be pinned. Opened default WhatsApp instead — message copied to clipboard if you need to paste. To always use ' + label + ', set it as the default in Android Settings → Apps → Default apps.', 'err');
    }
  }
  // Hard cap — if neither visibility change nor candidate exhaustion fires.
  setTimeout(finish, 3500);
};
window._waOpenLink = function(phone, text) {
  // Helper that opens the link in the right way for the picked mode.
  // For 'app' mode we use location.href so the OS protocol handler is
  // invoked (window.open with a custom protocol is blocked by some browsers).
  const url = window._waShareUrl(phone, text);
  if (!url) return;
  const mode = (localStorage.getItem('crm_wa_open_mode') || 'web');
  if (mode === 'app') {
    // Use an invisible anchor click — works across Chrome/Edge/Firefox/Safari
    const a = document.createElement('a');
    a.href = url; a.style.display = 'none'; document.body.appendChild(a);
    a.click(); setTimeout(() => a.remove(), 100);
  } else {
    window.open(url, '_blank');
  }
};

