/**
 * Bulk WhatsApp send — fire an approved template to every selected lead.
 *
 * Reuses the existing campaign infra (api_wb_campaigns_create + send_now)
 * so messages queue, retry on failure, log to whatsapp_messages, and show
 * up in the per-lead chat thread automatically.
 *
 * Variables support per-lead merge tokens via @{name}, @{firstname},
 * @{phone}, @{email}, @{source} — same renderer the rest of WhatsBot uses.
 */

async function bulkNurturePrompt() {
  const ids = [...(CRM._selected || [])].filter(Boolean);
  if (!ids.length) return toast('Select leads first', 'err');
  const seqs = await api('api_nurture_list').catch(() => []);
  const active = seqs.filter(s => Number(s.is_active));
  if (!active.length) return toast('No active sequences. Create one in Settings → 🌱 Nurture Sequences first.', 'err');
  const sel = h('select', {}, ...active.map(s => h('option', { value: s.id }, s.name + ' (' + s.step_count + ' steps)')));
  const modal = h('div', { class: 'modal-backdrop' },
    h('div', { class: 'modal' },
      h('div', { class: 'modal-head' },
        h('h3', {}, '🌱 Enroll ' + ids.length + ' lead' + (ids.length === 1 ? '' : 's') + ' in sequence'),
        h('button', { class: 'btn ghost', onclick: () => modal.remove() }, '×')
      ),
      h('div', { class: 'modal-body-wrap', style: { padding: '.25rem 0' } },
        h('p', { class: 'muted', style: { fontSize: '.85rem' } }, 'Pick a nurture sequence. Each selected lead will be enrolled (leads already enrolled in this sequence are skipped).'),
        h('div', { class: 'field' }, h('label', {}, 'Sequence'), sel)
      ),
      h('div', { class: 'actions' },
        h('button', { class: 'btn primary', onclick: async () => {
          try {
            const r = await api('api_nurture_enroll', { sequence_id: Number(sel.value), lead_ids: ids });
            toast('Enrolled ' + r.enrolled + ' lead' + (r.enrolled === 1 ? '' : 's') + (r.skipped ? ' · skipped ' + r.skipped + ' already enrolled' : ''), 'ok');
            modal.remove();
            clearSelection();
          } catch (e) { toast(e.message, 'err'); }
        } }, 'Enroll')
      )
    )
  );
  document.body.appendChild(modal);
}

async function bulkWhatsAppPrompt() {
  const ids = selectedIds(); if (!ids.length) return;
  const templates = await api('api_wb_templates_list').catch(() => []);
  if (!templates.length) {
    return toast('No approved WhatsApp templates yet — sync from Meta in WhatsBot tab', 'err');
  }

  const tplSel = h('select', { id: 'bw-tpl' },
    ...templates.map(t => h('option', { value: t.name + '|' + (t.language || 'en_US') }, `${t.name} · ${t.language || 'en_US'}`))
  );
  const varsBox = h('div', { id: 'bw-vars', style: { display: 'flex', flexDirection: 'column', gap: '6px', marginTop: '6px' } });
  const previewBox = h('div', { class: 'muted', id: 'bw-preview',
    style: { background: 'var(--bg-alt)', padding: '8px 10px', borderRadius: '6px', fontSize: '.82rem', whiteSpace: 'pre-wrap', marginTop: '8px', minHeight: '40px' } });

  const renderVars = () => {
    const sel = tplSel.value || '';
    const [name, lang] = sel.split('|');
    const tpl = templates.find(t => t.name === name && (t.language || 'en_US') === lang);
    const bodyText = String(tpl?.body_text || '');
    const params = (tpl?.body_params || tpl?.params || []);
    const count = Array.isArray(params) ? params.length : (Number(tpl?.body_params_count) || (bodyText.match(/\{\{\d+\}\}/g) || []).length);
    varsBox.innerHTML = '';
    if (!count) {
      varsBox.appendChild(h('div', { class: 'muted', style: { fontSize: '.78rem' } }, 'This template has no variables.'));
    } else {
      for (let i = 0; i < count; i++) {
        const inp = h('input', { class: 'bw-var', placeholder: 'e.g. @{firstname} or "20%"', 'data-idx': String(i) });
        const row = h('div', { style: { display: 'flex', gap: '6px', alignItems: 'center' } },
          h('span', { class: 'muted', style: { minWidth: '70px', fontSize: '.78rem' } }, '{{' + (i + 1) + '}}'),
          inp,
          h('button', { type: 'button', class: 'btn sm ghost', title: 'Insert lead first name', onclick: () => { inp.value = '@{firstname}'; updatePreview(); } }, '@name')
        );
        inp.addEventListener('input', updatePreview);
        varsBox.appendChild(row);
      }
    }
    updatePreview();
  };

  const updatePreview = () => {
    const sel = tplSel.value || '';
    const [name, lang] = sel.split('|');
    const tpl = templates.find(t => t.name === name && (t.language || 'en_US') === lang);
    let body = String(tpl?.body_text || '');
    const inputs = Array.from(varsBox.querySelectorAll('.bw-var'));
    inputs.forEach((inp, i) => {
      const v = inp.value || ('{{' + (i + 1) + '}}');
      body = body.replace(new RegExp('\\{\\{' + (i + 1) + '\\}\\}', 'g'), v);
    });
    previewBox.textContent = body || '(empty template)';
  };

  tplSel.addEventListener('change', renderVars);

  const modal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, `💬 Send WhatsApp to ${ids.length} lead${ids.length === 1 ? '' : 's'}`),
      h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
    ),
    h('p', { class: 'muted', style: { marginTop: 0, fontSize: '.82rem' } },
      'Pick an approved template and fill its variables. Use @{firstname}, @{name}, @{phone}, @{email}, @{source} for per-lead substitution. The send queues through the campaign worker — failures are retried automatically.'),
    h('label', {}, 'Template'),
    tplSel,
    h('label', { style: { marginTop: '10px' } }, 'Variables'),
    varsBox,
    h('label', { style: { marginTop: '10px' } }, 'Preview (first lead)'),
    previewBox,
    h('div', { class: 'actions' },
      h('button', { class: 'btn', onclick: () => modal.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        const sel = tplSel.value || '';
        const [name, lang] = sel.split('|');
        const inputs = Array.from(varsBox.querySelectorAll('.bw-var'));
        const variables = inputs.map(inp => ({ value: inp.value || '' }));
        try {
          const r = await api('api_wb_campaigns_create', {
            name: 'Bulk send · ' + new Date().toLocaleString(),
            template_name: name,
            template_language: lang,
            variables_json: JSON.stringify(variables),
            filter: { lead_ids: ids },
            send_now: 1
          });
          if (r && r.id) {
            await api('api_wb_campaigns_send_now', r.id);
          }
          toast(`Queued WhatsApp send to ${ids.length} leads`);
          modal.remove();
          clearSelection();
        } catch (e) { toast(e.message, 'err'); }
      } }, `Send to ${ids.length}`)
    )
  ));
  document.body.appendChild(modal);
  renderVars();
}

async function bulkAddTagPrompt() {
  const ids = selectedIds(); if (!ids.length) return;
  const tag = prompt('Tag to add to ' + ids.length + ' leads:');
  if (!tag) return;
  const leads = (CRM.cache.lastLeads || []).filter(l => ids.includes(Number(l.id)));
  for (const l of leads) {
    const existing = String(l.tags || '').split(',').map(s => s.trim()).filter(Boolean);
    if (!existing.includes(tag)) existing.push(tag);
    try { await api('api_leads_update', l.id, { tags: existing.join(', ') }); } catch (_) {}
  }
  toast('Tag added'); clearSelection(); loadLeads();
}

/**
 * Bulk-set a custom field's value on every selected lead.
 * - Dropdown of active custom fields (key + label from CRM.cache.customFields)
 * - Value input adapts to the field's `type`:
 *     select  → <select> with the configured options
 *     date    → <input type="date">
 *     number  → <input type="number">
 *     boolean → checkbox (Yes / No)
 *     other   → free-form text
 * - Empty value clears the field for every selected lead (sets extra_json[key] = '').
 * Backend merges into each lead's existing extra_json so other CF values are preserved.
 */

/* LEAD_MERGE_v1 — bulk merge selected leads into one target */
async function bulkMergePrompt() {
  const ids = selectedIds(); if (ids.length < 2) { toast('Select at least 2 leads to merge'); return; }
  if (ids.length > 50) { toast('Pick 50 leads or fewer'); return; }
  // Pull the lead rows for each selected id so the modal can show them.
  const leadsCache = (CRM.cache.leads || []);
  const rows = ids.map(id => leadsCache.find(l => Number(l.id) === Number(id)) || { id, name: '#' + id });

  const modal = h('div', { class: 'modal-backdrop' });  /* LEAD_MERGE_MODAL_FIX_v1 */
  const targetId = { v: rows[0].id };
  const list = h('div', { style: { maxHeight: '300px', overflow: 'auto', border: '1px solid var(--border, #e2e8f0)', borderRadius: '8px', padding: '.5rem' } });
  rows.forEach(r => {
    const radio = h('input', { type: 'radio', name: 'merge-target', value: r.id });
    if (Number(r.id) === Number(targetId.v)) radio.checked = true;
    radio.onchange = () => { targetId.v = Number(r.id); };
    list.appendChild(h('label', { style: { display: 'flex', gap: '.5rem', alignItems: 'center', padding: '.4rem .2rem', cursor: 'pointer', borderBottom: '1px dashed #eee' } },
      radio,
      h('div', { style: { flex: '1' } },
        h('b', {}, r.name || r.phone || ('Lead #' + r.id)),
        h('span', { class: 'muted', style: { marginLeft: '.5rem', fontSize: '.8rem' } },
          [r.phone, r.email, r.company].filter(Boolean).join(' · ') || ' '
        )
      )
    ));
  });

  modal.innerHTML = '';
  modal.appendChild(h('div', { class: 'modal' },  /* LEAD_MERGE_MODAL_FIX_v1: inner card uses .modal */
    h('h3', {}, '🔀 Merge ' + ids.length + ' leads into one'),
    h('p', { class: 'muted', style: { fontSize: '.85rem' } },
      'Pick the lead to KEEP. The other ' + (ids.length - 1) + ' will be merged into it ' +
      '(remarks, call recordings, WhatsApp chats, follow-ups, quotations all move over). ' +
      'Blank fields on the target get filled in from the duplicates. This cannot be undone.'),
    list,
    h('div', { class: 'modal-actions', style: { display: 'flex', gap: '.5rem', marginTop: '.8rem', justifyContent: 'flex-end' } },
      h('button', { class: 'btn ghost', onclick: () => modal.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        const target_id = Number(targetId.v);
        const source_ids = ids.map(Number).filter(n => n !== target_id);
        try {
          const r = await api('api_leads_merge', { target_id, source_ids });
          toast('✅ Merged ' + r.merged_count + ' lead(s) into #' + target_id);
          modal.remove();
          clearSelection();
          loadLeads();
        } catch (e) { toast('⚠ ' + e.message, 'err'); }
      } }, '🔀 Merge into selected target')
    )
  ));
  document.body.appendChild(modal);
}

async function bulkCustomFieldPrompt() {
  const ids = selectedIds(); if (!ids.length) return;
  const cfList = (CRM.cache.customFields || []).filter(c => Number(c.is_active) !== 0 && c.key);
  if (!cfList.length) {
    return toast('No custom fields defined yet. Add one in Settings → Custom fields.', 'warn');
  }

  const fieldSel = h('select', { id: 'bulk-cf-field', style: { minWidth: '200px' } },
    ...cfList.map(c => h('option', { value: c.key }, c.label || c.key))
  );
  const valueWrap = h('div', { id: 'bulk-cf-value-wrap', style: { marginTop: '.4rem' } });

  function renderValueInput() {
    const cf = cfList.find(c => c.key === fieldSel.value);
    valueWrap.innerHTML = '';
    if (!cf) return;
    const t = String(cf.type || 'text').toLowerCase();
    let el;
    if (t === 'select' || t === 'dropdown') {
      const opts = String(cf.options || '').split(/[,;|\n]/).map(s => s.trim()).filter(Boolean);
      el = h('select', { id: 'bulk-cf-value', style: { minWidth: '220px' } },
        h('option', { value: '' }, '— Clear / no value —'),
        ...opts.map(o => h('option', { value: o }, o))
      );
    } else if (t === 'date') {
      el = h('input', { id: 'bulk-cf-value', type: 'date', style: { minWidth: '180px' } });
    } else if (t === 'number') {
      el = h('input', { id: 'bulk-cf-value', type: 'number', style: { minWidth: '180px' } });
    } else if (t === 'boolean' || t === 'checkbox' || t === 'bool') {
      el = h('select', { id: 'bulk-cf-value', style: { minWidth: '180px' } },
        h('option', { value: '' }, '— No change / clear —'),
        h('option', { value: '1' }, 'Yes'),
        h('option', { value: '0' }, 'No')
      );
    } else {
      el = h('input', { id: 'bulk-cf-value', type: 'text', placeholder: 'New value (leave blank to clear)', style: { minWidth: '260px' } });
    }
    valueWrap.appendChild(h('label', { style: { display: 'block', marginTop: '.5rem' } }, 'Value'));
    valueWrap.appendChild(el);
    valueWrap.appendChild(h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } },
      'Leaving the value blank clears the field on every selected lead. Other custom-field values are preserved.'));
  }
  fieldSel.onchange = renderValueInput;

  const modal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal' },
    h('h3', {}, '🧩 Set custom field on ' + ids.length + ' leads'),
    h('label', { style: { display: 'block' } }, 'Field'),
    fieldSel,
    valueWrap,
    h('div', { class: 'actions', style: { marginTop: '.85rem' } },
      h('button', { class: 'btn', onclick: () => modal.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async (ev) => {
        const btn = ev.currentTarget; btn.disabled = true;
        try {
          const key = fieldSel.value;
          const valEl = document.getElementById('bulk-cf-value');
          const val = valEl ? valEl.value : '';
          await api('api_leads_bulkUpdate', ids, { extra: { [key]: val } });
          toast('✅ Updated ' + ids.length + ' leads');
          modal.remove(); clearSelection(); loadLeads();
        } catch (e) {
          btn.disabled = false;
          toast(e.message, 'err');
        }
      } }, 'Apply')
    )
  ));
  document.body.appendChild(modal);
  renderValueInput();
}
async function bulkDelete() {
  const ids = selectedIds(); if (!ids.length) return;
  if (!await confirmDialog(`Delete ${ids.length} leads? This cannot be undone.`)) return;
  try { await api('api_leads_bulkDelete', ids); toast('Deleted'); clearSelection(); loadLeads(); }
  catch (e) { toast(e.message, 'err'); }
}

/**
 * Delete every lead currently flagged is_duplicate=1, server-side.
 * Admin/manager only. Confirmation prompt with the count first.
 */
async function deleteAllDuplicates() {
  // Surface the duplicates view first so the admin can see what's about
  // to be removed, with the accurate total.
  const sel = document.getElementById('f-duplicate');
  if (sel) sel.value = 'only';
  await loadLeads({ page: 1 });
  const fullCount = Number(CRM.cache.lastTotal) || (CRM.cache.lastLeads || []).length;
  if (!fullCount) {
    toast('No duplicates found. ✨');
    if (sel) sel.value = '';
    await loadLeads({ page: 1 });
    return;
  }
  const msg = `Delete ALL ${fullCount} duplicate lead${fullCount === 1 ? '' : 's'}?\n\n` +
              `This will permanently remove them from the database. ` +
              `Their remarks and follow-ups will also be deleted.\n\n` +
              `This cannot be undone.`;
  if (!await confirmDialog(msg)) return;
  try {
    const r = await api('api_leads_deleteAllDuplicates');
    toast(`✅ Removed ${r.count} duplicate lead${r.count === 1 ? '' : 's'}`);
    if (sel) sel.value = '';
    await loadLeads({ page: 1 });
  } catch (e) { toast(e.message, 'err'); }
}

/* --- CSV export / upload --- */
function exportCSV() {
  const rows = CRM.cache.lastLeads || [];
  if (!rows.length) return toast('No leads to export', 'warn');
  const headers = ['id', 'name', 'phone', 'email', 'whatsapp', 'source', 'product_name', 'status_name', 'assigned_name', 'tags', 'city', 'next_followup_at', 'last_status_change_at', 'notes', 'created_at'];
  const csv = [headers.join(',')].concat(rows.map(r => headers.map(k => {
    const v = r[k] == null ? '' : String(r[k]).replace(/"/g, '""');
    return /[",\n]/.test(v) ? `"${v}"` : v;
  }).join(','))).join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `leads-${new Date().toISOString().slice(0, 10)}.csv`;
  a.click();
  URL.revokeObjectURL(a.href);
}

// ─────────────────────────────────────────────────────────────────────
// Bulk-upload field mapping — added 2026-05-14
// Each uploaded column gets a target lead-field selector + an
// "unmapped behavior" dropdown decides what happens to columns the
// user leaves unmapped (skip / custom field / append to notes).
// ─────────────────────────────────────────────────────────────────────
const BULK_MAP_TARGETS = [
  { v: '__skip',           l: '— Skip this column —' },
  { v: '__custom',         l: '★ Save as custom field (column name = key)' },
  { v: 'name',             l: 'Name' },
  { v: 'phone',            l: 'Phone' },
  { v: 'alt_phone',        l: 'Alt phone' },
  { v: 'whatsapp',         l: 'WhatsApp' },
  { v: 'email',            l: 'Email' },
  { v: 'source',           l: 'Source' },
  { v: 'source_ref',       l: 'Source reference' },
  { v: 'company',          l: 'Company' },
  { v: 'address',          l: 'Address' },
  { v: 'city',             l: 'City' },
  { v: 'state',            l: 'State' },
  { v: 'pincode',          l: 'Pincode' },
  { v: 'country',          l: 'Country' },
  { v: 'value',            l: 'Value (₹)' },
  { v: 'currency',         l: 'Currency' },
  { v: 'qualified',        l: 'Qualified flag' },
  { v: 'status',           l: 'Status (by name)' },
  { v: 'product',          l: 'Product (by name)' },
  { v: 'assigned_to',      l: 'Assigned-to (user email/name)' },
  { v: 'tags',             l: 'Tags' },
  { v: 'notes',            l: 'Notes' },
  { v: 'next_followup_at', l: 'Next follow-up date' },
  { v: 'created_at',       l: 'Created date' },
  { v: 'gclid',            l: 'GCLID' },
  { v: 'gad_campaignid',   l: 'Google Ads campaign ID' },
  { v: 'utm_source',       l: 'UTM source' },
  { v: 'utm_medium',       l: 'UTM medium' },
  { v: 'utm_campaign',     l: 'UTM campaign' },
  { v: 'utm_term',         l: 'UTM term' },
  { v: 'utm_content',      l: 'UTM content' }
];

/* CSV_MAP_CF_v1 — append active custom fields to the bulk-mapping target list */
function _bulkMapTargets() {
  const base = BULK_MAP_TARGETS.slice();
  const cfList = (CRM && CRM.cache && CRM.cache.customFields) || [];
  // Filter to active CFs with a usable key.
  const active = cfList.filter(c => Number(c.is_active) !== 0 && c.key);
  if (!active.length) return base;
  // Push a separator pseudo-option then one option per CF.
  base.push({ v: '__cf_sep', l: '── Custom fields ──', disabled: true });
  for (const cf of active) {
    base.push({
      v: 'cf_' + cf.key,
      l: '🧩 ' + (cf.label || cf.key) + (cf.label && cf.label !== cf.key ? ' (' + cf.key + ')' : '')
    });
  }
  return base;
}


// Auto-suggest a target for a source column based on common header aliases.
function _bulkSuggestTarget(col) {
  const c = String(col || '').toLowerCase().replace(/[\s\-_]+/g, '');
  const exact = {
    name:'name', fullname:'name', leadname:'name', customername:'name', contactname:'name', clientname:'name',
    phone:'phone', mobile:'phone', phoneno:'phone', mobileno:'phone', contactnumber:'phone', mobilenumber:'phone', phonenumber:'phone',
    altphone:'alt_phone', alternatephone:'alt_phone', secondaryphone:'alt_phone', altmobile:'alt_phone', altcontact:'alt_phone',
    whatsapp:'whatsapp', whatsappnumber:'whatsapp', wa:'whatsapp',
    email:'email', emailaddress:'email', emailid:'email',
    source:'source', leadsource:'source',
    sourceref:'source_ref', referrer:'source_ref',
    company:'company', organization:'company', org:'company', firm:'company', companyname:'company',
    address:'address', addr:'address', fulladdress:'address',
    city:'city', town:'city',
    state:'state', province:'state',
    pincode:'pincode', pin:'pincode', zipcode:'pincode', zip:'pincode', postalcode:'pincode',
    country:'country',
    value:'value', amount:'value', dealvalue:'value', budget:'value', dealamount:'value',
    currency:'currency',
    qualified:'qualified', isqualified:'qualified',
    status:'status', leadstatus:'status',
    product:'product', interest:'product', productinterest:'product',
    assignedto:'assigned_to', assigneduser:'assigned_to', owner:'assigned_to', salesrep:'assigned_to', salesperson:'assigned_to', rep:'assigned_to', agent:'assigned_to', user:'assigned_to',
    tags:'tags', labels:'tags',
    notes:'notes', remarks:'notes', comments:'notes', description:'notes',
    nextfollowup:'next_followup_at', nextfollowupat:'next_followup_at', followupdate:'next_followup_at', followup:'next_followup_at',
    createdat:'created_at', created:'created_at', createdon:'created_at',
    gclid:'gclid',
    gadcampaignid:'gad_campaignid',
    utmsource:'utm_source', utmmedium:'utm_medium', utmcampaign:'utm_campaign', utmterm:'utm_term', utmcontent:'utm_content'
  };
  if (exact[c]) return exact[c];
  // If the column already matches a lead column name verbatim, use it
  if (BULK_MAP_TARGETS.some(t => t.v === c)) return c;
  /* CSV_MAP_CF_v1 — try to match a registered custom field */
  try {
    const cfList = (CRM && CRM.cache && CRM.cache.customFields) || [];
    const want = c;
    for (const cf of cfList) {
      if (Number(cf.is_active) === 0 || !cf.key) continue;
      const k = String(cf.key).toLowerCase().replace(/[\s\-_]+/g, '');
      const lbl = String(cf.label || '').toLowerCase().replace(/[\s\-_]+/g, '');
      if (k === want || lbl === want) return 'cf_' + cf.key;
    }
  } catch (_) {}
  return '__skip';
}

// Apply the mapping to transform parsed rows into rows shaped for bulkCreate.
// `mapping` = { sourceCol: targetField }, `unmappedBehavior` = 'skip' | 'custom' | 'notes'
function _bulkApplyMapping(rows, mapping, unmappedBehavior, headers) {
  const out = [];
  for (const r of rows) {
    const newRow = {};
    const cfBag = {};
    const notesBits = [];
    for (const col of headers) {
      const target = mapping[col] || '__skip';
      const v = r[col];
      if (target === '__skip') continue;
      if (target === '__custom') {
        // Use the source column (normalised) as custom-field key
        const key = String(col || '').toLowerCase().replace(/[\s\-]+/g, '_').replace(/[^a-z0-9_]/g, '');
        if (key && v != null && String(v).trim() !== '') cfBag[key] = String(v);
        continue;
      }
      // Mapped to a real lead field
      newRow[target] = v;
    }
    // Handle unmapped behavior for any column whose mapping is __skip but
    // user picked something other than skip globally.
    if (unmappedBehavior !== 'skip') {
      for (const col of headers) {
        if (mapping[col] && mapping[col] !== '__skip') continue;
        const v = r[col];
        if (v == null || String(v).trim() === '') continue;
        if (unmappedBehavior === 'custom') {
          const key = String(col || '').toLowerCase().replace(/[\s\-]+/g, '_').replace(/[^a-z0-9_]/g, '');
          if (key) cfBag[key] = String(v);
        } else if (unmappedBehavior === 'notes') {
          notesBits.push(String(col) + ': ' + String(v));
        }
      }
    }
    if (Object.keys(cfBag).length) newRow.extra = Object.assign({}, newRow.extra || {}, cfBag);
    if (notesBits.length) {
      const prefix = newRow.notes ? String(newRow.notes) + '\n\n' : '';
      newRow.notes = prefix + notesBits.join(' | ');
    }
    out.push(newRow);
  }
  return out;
}


function openBulkUpload() {
  // Include admin too, since admin may want to assign to themselves
  const users = (CRM.cache.users || []).filter(u => Number(u.is_active ?? 1) === 1);
  const noUsers = users.length === 0;

  let parsedRows = [];
  let assignMode = 'csv';
  // Field-mapping state — populated after file parse
  let columnMapping = {};            // { sourceCol -> targetField }
  let unmappedBehavior = 'skip';     // 'skip' | 'custom' | 'notes'
  let sourceHeaders = [];
  const mappingBox = h('div', { class: 'card', id: 'bulk-mapping', hidden: true, style: { marginTop: '1rem', padding: '.75rem', background: '#f8fafc', borderRadius: '8px' } });
  const unmappedBox = h('div', { class: 'card', id: 'bulk-unmapped', hidden: true, style: { marginTop: '.5rem', padding: '.75rem', background: '#fefce8', borderRadius: '8px', borderLeft: '3px solid #f59e0b' } });

  function renderMappingUI() {
    mappingBox.innerHTML = ''; unmappedBox.innerHTML = '';
    if (!sourceHeaders.length) { mappingBox.hidden = true; unmappedBox.hidden = true; return; }
    mappingBox.hidden = false; unmappedBox.hidden = false;
    mappingBox.appendChild(h('h4', { style: { margin: '0 0 .5rem', fontSize: '.95rem' } }, '🔗 Step 2: map your columns to lead fields'));
    mappingBox.appendChild(h('p', { class: 'muted', style: { fontSize: '.78rem', marginTop: 0 } }, 'Pick what each uploaded column should become on each lead. We auto-suggested based on column names — review and override below.'));
    const tbl = h('table', { class: 'mini-table', style: { width: '100%', fontSize: '.82rem' } });
    const thead = h('thead', {}, h('tr', {},
      h('th', { style: { textAlign: 'left' } }, 'Source column'),
      h('th', { style: { textAlign: 'left' } }, 'Sample value'),
      h('th', { style: { textAlign: 'left' } }, 'Maps to')
    ));
    const tbody = h('tbody', {});
    sourceHeaders.forEach(col => {
      const sample = (parsedRows[0] && parsedRows[0][col]) || (parsedRows[1] && parsedRows[1][col]) || '';
      const sel = h('select', { style: { width: '100%', padding: '.25rem' } },
        ...(_bulkMapTargets()).map(t => h('option', Object.assign({ value: t.v, selected: (columnMapping[col] || '__skip') === t.v ? 'selected' : null }, t.disabled ? { disabled: 'disabled' } : {}), t.l))
      );
      sel.addEventListener('change', () => { columnMapping[col] = sel.value; });
      tbody.appendChild(h('tr', {},
        h('td', {}, h('b', {}, col)),
        h('td', { style: { color: '#64748b', maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' } }, String(sample).slice(0, 60)),
        h('td', {}, sel)
      ));
    });
    tbl.append(thead, tbody);
    mappingBox.appendChild(tbl);

    unmappedBox.appendChild(h('h4', { style: { margin: '0 0 .35rem', fontSize: '.9rem' } }, '⚙ What to do with columns left as "Skip"?'));
    const skipR = h('input', { type: 'radio', name: 'unmappedBehavior', value: 'skip',   checked: unmappedBehavior === 'skip'   ? 'checked' : null });
    const cfR   = h('input', { type: 'radio', name: 'unmappedBehavior', value: 'custom', checked: unmappedBehavior === 'custom' ? 'checked' : null });
    const ntR   = h('input', { type: 'radio', name: 'unmappedBehavior', value: 'notes',  checked: unmappedBehavior === 'notes'  ? 'checked' : null });
    [skipR, cfR, ntR].forEach(r => r.addEventListener('change', () => { unmappedBehavior = document.querySelector('input[name=unmappedBehavior]:checked').value; }));
    unmappedBox.appendChild(h('label', { style: { display: 'block', padding: '.2rem 0', fontSize: '.85rem' } }, skipR, h('span', { style: { marginLeft: '.4rem' } }, ' Skip them — discard data in unmapped columns (default)')));
    unmappedBox.appendChild(h('label', { style: { display: 'block', padding: '.2rem 0', fontSize: '.85rem' } }, cfR,   h('span', { style: { marginLeft: '.4rem' } }, ' Save as custom fields — every unmapped column becomes a cf_<col> field on the lead')));
    unmappedBox.appendChild(h('label', { style: { display: 'block', padding: '.2rem 0', fontSize: '.85rem' } }, ntR,   h('span', { style: { marginLeft: '.4rem' } }, ' Combine into Notes — concatenate "col: value" pairs into the lead notes field')));
  }


  // -------- Modal layout --------
  const fileInput = h('input', {
    type: 'file',
    accept: '.csv,.xlsx,.xls,.xlsm,text/csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    id: 'csv-file',
    style: { width: '100%' }
  });
  const fileInfo = h('div', { class: 'muted', id: 'csv-file-info', style: { fontSize: '.85rem', marginTop: '.4rem' } }, 'No file selected. Accepts .csv, .xlsx and .xls.');
  const filePreview = h('div', { class: 'csv-preview', id: 'csv-preview', hidden: true });

  // Mode picker as 4 button cards — no radios, no labels, no flex weirdness.
  const modeCard = (id, icon, title, desc) => h('button', {
    type: 'button',
    class: 'assign-mode-card',
    'data-mode': id,
    onclick: () => { assignMode = id; updateMode(); }
  },
    h('span', { class: 'amc-icon' }, icon),
    h('span', { class: 'amc-content' },
      h('span', { class: 'amc-title' }, title),
      h('span', { class: 'amc-desc' }, desc)
    )
  );
  const modePicker = h('div', { class: 'assign-mode-grid' },
    modeCard('single',      '👤', 'One employee',         'Assign every lead to one person.'),
    modeCard('round_robin', '🔁', 'Round-robin',           'Divide equally between selected employees.'),
    modeCard('percent',     '📊', 'Percentage split',      'Custom share — e.g. 60% / 30% / 10%.'),
    modeCard('csv',         '📄', 'Use CSV value',         'Per-row assigned_to or your assignment rules.')
  );

  // Mode-specific bodies
  const singleSel = h('select', { id: 'assign-single-user', class: 'assign-single-input' },
    h('option', { value: '' }, '— pick employee —'),
    ...users.map(u => h('option', { value: u.id }, `${u.name} (${u.role})`))
  );
  const singleBody = h('div', { class: 'assign-mode-body', 'data-for': 'single', hidden: true, style: { display: 'none' } },
    h('label', {}, 'Assign all leads to:'), singleSel
  );

  const rrChecks = users.map(u => h('label', { class: 'assign-rr-check' },
    h('input', { type: 'checkbox', name: 'rr-user', value: u.id }),
    h('span', {}, ` ${u.name}`),
    h('span', { class: 'muted', style: { fontSize: '.78rem', marginLeft: '.35rem' } }, u.role)
  ));
  const rrBody = h('div', { class: 'assign-mode-body', 'data-for': 'round_robin', hidden: true, style: { display: 'none' } },
    h('label', {}, 'Pick the employees to share these leads:'),
    h('div', { class: 'assign-rr-grid' }, ...rrChecks),
    h('div', { class: 'actions', style: { marginTop: '.5rem' } },
      h('button', { class: 'btn sm ghost', type: 'button', onclick: () => { rrChecks.forEach(c => c.querySelector('input').checked = true); previewAssignment(); } }, 'Select all'),
      h('button', { class: 'btn sm ghost', type: 'button', onclick: () => { rrChecks.forEach(c => c.querySelector('input').checked = false); previewAssignment(); } }, 'Clear')
    )
  );
  rrBody.querySelectorAll('input').forEach(i => i.addEventListener('change', previewAssignment));

  const percentRows = users.map(u => h('div', { class: 'assign-pct-row' },
    h('label', { class: 'assign-pct-name' }, u.name + ' '),
    h('input', { type: 'number', min: 0, max: 100, step: 1, value: 0, 'data-uid': u.id, class: 'assign-pct-input', oninput: previewAssignment }),
    h('span', { class: 'muted' }, '%')
  ));
  const pctTotalEl = h('div', { class: 'assign-pct-total muted', id: 'pct-total' }, 'Total: 0%');
  const percentBody = h('div', { class: 'assign-mode-body', 'data-for': 'percent', hidden: true, style: { display: 'none' } },
    h('label', {}, 'Assign by percentage (must add up to 100%):'),
    h('div', { class: 'assign-pct-grid' }, ...percentRows),
    pctTotalEl
  );

  const csvBody = h('div', { class: 'assign-mode-body', 'data-for': 'csv' },
    h('p', { class: 'muted', style: { fontSize: '.85rem' } },
      'Each row keeps its own ',
      h('code', {}, 'assigned_to'),
      ' value (or stays empty for your assignment rules / round-robin defaults to apply).'
    )
  );

  const previewEl = h('div', { class: 'assign-preview' });
  const importBtn = h('button', { class: 'btn primary', disabled: 'disabled', onclick: doImport }, 'Import');

  function updateMode() {
    [...modePicker.children].forEach(c => c.classList.toggle('active', c.dataset.mode === assignMode));
    modePicker.querySelectorAll('input[type=radio]').forEach(r => r.checked = r.value === assignMode);
    [singleBody, rrBody, percentBody, csvBody].forEach(b => {
      const visible = b.dataset.for === assignMode;
      b.hidden = !visible;
      b.style.display = visible ? '' : 'none';
    });
    previewAssignment();
  }
  singleSel.addEventListener('change', previewAssignment);

  function readPercentSplit() {
    const split = {};
    let total = 0;
    percentRows.forEach(r => {
      const inp = r.querySelector('input');
      const v = Number(inp.value) || 0;
      const uid = Number(inp.dataset.uid);
      if (v > 0 && uid) { split[uid] = v; total += v; }
    });
    return { split, total };
  }

  function previewAssignment() {
    previewEl.innerHTML = '';
    if (!parsedRows.length) {
      importBtn.disabled = 'disabled';
      return;
    }
    const userById = Object.fromEntries(users.map(u => [Number(u.id), u]));
    let plan = [];
    let valid = false;

    if (assignMode === 'csv') {
      valid = true;
      previewEl.appendChild(h('div', { class: 'muted' }, `${parsedRows.length} rows — assignment per row's CSV value or your rules.`));

    } else if (assignMode === 'single') {
      const uid = Number(singleSel.value);
      if (!uid) {
        previewEl.appendChild(h('div', { class: 'muted warn' }, 'Pick an employee to continue.'));
      } else {
        valid = true;
        const u = userById[uid];
        previewEl.appendChild(h('div', {}, `All ${parsedRows.length} leads → `, h('b', {}, u.name)));
      }

    } else if (assignMode === 'round_robin') {
      const ids = [...rrBody.querySelectorAll('input[name=rr-user]:checked')].map(i => Number(i.value));
      if (!ids.length) {
        previewEl.appendChild(h('div', { class: 'muted warn' }, 'Pick at least one employee.'));
      } else {
        valid = true;
        const counts = {};
        for (let i = 0; i < parsedRows.length; i++) {
          const uid = ids[i % ids.length];
          counts[uid] = (counts[uid] || 0) + 1;
        }
        const lines = Object.entries(counts).map(([uid, n]) =>
          h('div', {}, `${userById[Number(uid)]?.name || ('User ' + uid)}: `, h('b', {}, n + ' leads'))
        );
        previewEl.appendChild(h('div', { class: 'preview-grid' }, ...lines));
      }

    } else if (assignMode === 'percent') {
      const { split, total } = readPercentSplit();
      pctTotalEl.textContent = 'Total: ' + total + '%';
      pctTotalEl.classList.toggle('warn', total !== 100);
      pctTotalEl.classList.toggle('ok', total === 100);
      if (total === 100) {
        valid = true;
        const lines = Object.entries(split).map(([uid, pct]) => {
          const n = Math.round((pct / 100) * parsedRows.length);
          return h('div', {}, `${userById[Number(uid)]?.name || ('User ' + uid)}: `, h('b', {}, `${n} leads (${pct}%)`));
        });
        previewEl.appendChild(h('div', { class: 'preview-grid' }, ...lines));
      } else {
        previewEl.appendChild(h('div', { class: 'muted warn' }, 'Percentages must add up to exactly 100%.'));
      }
    }
    importBtn.disabled = (parsedRows.length && valid) ? null : 'disabled';
  }

  fileInput.addEventListener('change', async (e) => {
    parsedRows = [];
    filePreview.hidden = true;
    filePreview.innerHTML = '';
    sourceHeaders = []; columnMapping = {}; renderMappingUI();
    const f = e.target.files[0];
    if (!f) { fileInfo.textContent = 'No file selected.'; previewAssignment(); return; }
    fileInfo.textContent = '⏳ Parsing ' + f.name + '…';
    try {
      parsedRows = await parseSpreadsheet(f);
      const cols = parsedRows.length ? Object.keys(parsedRows[0]) : [];
      const sample = parsedRows.slice(0, 3);
      fileInfo.textContent = `✅ ${f.name} — ${parsedRows.length} rows · ${cols.length} columns`;

      // Build mapping UI
      sourceHeaders = cols;
      columnMapping = {};
      cols.forEach(c => { columnMapping[c] = _bulkSuggestTarget(c); });
      renderMappingUI();

      // -------- Sanity warnings --------
      const warnings = [];
      // 1. Phone fields that came in as scientific notation -> Excel data loss
      const phoneFields = cols.filter(c => /^(phone|mobile|whatsapp|alt_phone|alternate)$/i.test(c));
      let sciPhoneCount = 0;
      const allPhonesSeen = [];
      parsedRows.forEach(r => {
        phoneFields.forEach(f => {
          const v = String(r[f] || '');
          allPhonesSeen.push(v);
          // Detect a phone that ends with a long run of zeros (Excel signature
          // of a sci-notation conversion that lost trailing digits)
          if (/^\d{10,}0{4,}$/.test(v) || /[eE]/.test(v)) sciPhoneCount++;
        });
      });
      if (sciPhoneCount > 0) {
        warnings.push({
          icon: '⚠️',
          msg: `${sciPhoneCount} phone number${sciPhoneCount === 1 ? ' is' : 's are'} in scientific notation — Excel has truncated trailing digits and these numbers are now corrupted. To fix: open your spreadsheet, right-click the Phone column → Format cells → Text, re-enter the numbers, then re-export.`
        });
      }
      // 2. Detect employee column under common alias names
      const userCols = cols.filter(c => /^(user|owner|assignee|sales_rep|salesperson|agent|assigned_user|rep|assigned_to)$/i.test(c));
      if (userCols.length) {
        warnings.push({
          icon: '👤',
          msg: `Detected employee column "${userCols[0]}" — leads will be auto-mapped to employees by name/email match.`,
          ok: true
        });
      }
      // 3. Notice if 'tags' column has status-like values (Duplicate, Lost, etc)
      if (cols.includes('tags')) {
        const dupCount = parsedRows.filter(r => /\b(duplicate|dup)\b/i.test(String(r.tags || ''))).length;
        if (dupCount > 0) {
          warnings.push({
            icon: 'ℹ️',
            msg: `${dupCount} row${dupCount === 1 ? '' : 's'} tagged as "Duplicate" will be flagged is_duplicate=1 (visible under Leads → ⚠️ Duplicates only filter).`,
            ok: true
          });
        }
      }
      if (warnings.length) {
        const wrap = h('div', { class: 'csv-warn-list' }, ...warnings.map(w =>
          h('div', { class: 'csv-warn ' + (w.ok ? 'ok' : 'warn') },
            h('span', { class: 'csv-warn-ico' }, w.icon),
            h('span', {}, w.msg)
          )
        ));
        filePreview.appendChild(wrap);
      }

      if (sample.length) {
        const tbl = h('table', { class: 'mini-table csv-preview-table' });
        const thead = h('thead', {}, h('tr', {}, ...cols.map(c => h('th', {}, c))));
        const tbody = h('tbody', {}, ...sample.map(r => h('tr', {}, ...cols.map(c => h('td', {}, String(r[c] || ''))))));
        tbl.append(thead, tbody);
        filePreview.appendChild(h('div', { class: 'muted', style: { fontSize: '.78rem', margin: '.5rem 0 .35rem' } }, 'Preview — first 3 rows:'));
        filePreview.appendChild(tbl);
        filePreview.hidden = false;
      }
      previewAssignment();
    } catch (err) {
      fileInfo.textContent = '⚠️ Could not parse file: ' + err.message;
    }
  });

  async function doImport() {
    if (!parsedRows.length) return toast('Choose a file first', 'warn');
    let assign;
    if (assignMode === 'csv') {
      assign = { mode: 'csv' };
    } else if (assignMode === 'single') {
      const uid = Number(singleSel.value);
      if (!uid) return toast('Pick an employee', 'warn');
      assign = { mode: 'single', user_id: uid };
    } else if (assignMode === 'round_robin') {
      const ids = [...rrBody.querySelectorAll('input[name=rr-user]:checked')].map(i => Number(i.value));
      if (!ids.length) return toast('Pick at least one employee', 'warn');
      assign = { mode: 'round_robin', user_ids: ids };
    } else if (assignMode === 'percent') {
      const { split, total } = readPercentSplit();
      if (total !== 100) return toast('Percentages must sum to 100%', 'warn');
      assign = { mode: 'percent', split };
    }
    importBtn.disabled = 'disabled';
    importBtn.textContent = 'Importing…';
    try {
      // Transform rows according to the column-mapping picked above
      const mapped = _bulkApplyMapping(parsedRows, columnMapping, unmappedBehavior, sourceHeaders);
      const r = await api('api_leads_bulkCreate', mapped, assign);
      const lines = [`✅ Imported ${r.created} of ${parsedRows.length}`];
      if (r.duplicate) lines.push(`${r.duplicate} duplicates`);
      if (r.skipped) lines.push(`${r.skipped} skipped`);
      toast(lines.join(' · '));
      modal.remove();
      loadLeads();
    } catch (e) {
      toast(e.message, 'err');
      importBtn.disabled = null;
      importBtn.textContent = 'Import';
    }
  }

  const modal = h('div', { class: 'modal-backdrop' },
    h('div', { class: 'modal modal-lg' },
      h('div', { class: 'modal-head' }, h('h3', {}, '⬆️ Bulk upload leads'), h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')),
      h('p', { class: 'muted' }, 'Step 1: pick a CSV or Excel (.xlsx) file. Columns: name, phone, email, whatsapp, source, product, status, notes, city, tags, next_followup_at, assigned_to, plus any custom field keys. The status and product columns accept names — unknown values are auto-created.'),
      h('p', { class: 'muted', style: { fontSize: '.82rem' } },
        h('b', {}, 'Tip: '), 'You can pre-assign leads to specific employees by adding an ',
        h('code', {}, 'assigned_to'),
        ' column with the rep\'s email or full name. Or use Step 2 below to assign in bulk.'
      ),
      fileInput,
      fileInfo,
      filePreview,
      mappingBox,
      unmappedBox,
      h('p', { style: { marginTop: '1rem' } },
        // Two download options — Excel-friendly XLS first, plain CSV second.
        // _attachSampleLink rewrites href + click to the tenant-scoped URL.
        (() => { const a = h('a', { href: '#', download: '' }, '⬇️ Download sample (Excel)'); _attachSampleLink(a, 'xls'); return a; })(),
        ' · ',
        (() => { const a = h('a', { href: '#', download: '' }, 'CSV'); _attachSampleLink(a, 'csv'); return a; })()
      ),
      h('h4', { style: { marginTop: '1.5rem' } }, 'Step 2: how should these leads be assigned?'),
      modePicker,
      singleBody, rrBody, percentBody, csvBody,
      h('div', { class: 'assign-preview-wrap' },
        h('h5', { style: { margin: '1rem 0 .5rem' } }, 'Preview'),
        previewEl
      ),
      h('div', { class: 'actions' },
        h('button', { class: 'btn', onclick: () => modal.remove() }, 'Cancel'),
        importBtn
      )
    )
  );
  document.body.appendChild(modal);
  updateMode();
}
/* ---------------- Spreadsheet parsing (CSV + XLSX) ---------------- */

/** Lazy-load SheetJS only when the user actually opens an Excel file. */
let _xlsxLib = null;
async function ensureXLSX() {
  if (window.XLSX) return window.XLSX;
  if (_xlsxLib) return _xlsxLib;
  await new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
    s.onload = resolve; s.onerror = reject;
    document.head.appendChild(s);
  });
  _xlsxLib = window.XLSX;
  return _xlsxLib;
}

/** Normalize a column header into a snake_case key (lowercase, spaces+dashes → _). */
function normalizeKey(k) {
  return String(k || '').replace(/^﻿/, '').trim().toLowerCase().replace(/[\s\-]+/g, '_');
}

/**
 * Clean up a single cell value:
 *  - convert numbers to strings (Excel returns numbers for digit cells)
 *  - strip leading apostrophe (Excel uses ' to force text)
 *  - strip BOM, trim whitespace
 *  - convert scientific-notation phone numbers back to plain digits
 *  - lowercase + trim emails
 */
function cleanCell(key, val) {
  if (val == null) return '';
  if (val instanceof Date && !isNaN(val)) return val.toISOString();
  if (typeof val === 'number') val = String(val);
  let s = String(val).replace(/^﻿/, '').trim();
  s = s.replace(/^'/, '');
  // Scientific notation? Reconstruct (e.g. "9.876543E+9" → "9876543000")
  if (/^\d+(\.\d+)?[eE][+-]?\d+$/.test(s)) {
    const n = Number(s);
    if (!isNaN(n) && isFinite(n)) s = String(n.toFixed(0));
  }
  if (key === 'email') s = s.toLowerCase();
  return s;
}

/**
 * Parse a CSV or XLSX file → array of normalized row objects.
 * Handles BOM, multi-line cells, Excel quirks, scientific-notation phones.
 */
async function parseSpreadsheet(file) {
  const name = (file.name || '').toLowerCase();
  // ---- XLSX / XLS path ----
  if (name.endsWith('.xlsx') || name.endsWith('.xls') || name.endsWith('.xlsm')) {
    const XLSX = await ensureXLSX();
    const buf = await file.arrayBuffer();
    const wb = XLSX.read(buf, { type: 'array', cellDates: true, raw: false });
    const ws = wb.Sheets[wb.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(ws, { defval: '', raw: false, blankrows: false });
    return rows.map(r => {
      const out = {};
      for (const [k, v] of Object.entries(r)) {
        const key = normalizeKey(k);
        out[key] = cleanCell(key, v);
      }
      return out;
    }).filter(r => Object.values(r).some(v => v !== ''));
  }
  // ---- CSV path ----
  let text = await file.text();
  text = text.replace(/^﻿/, ''); // strip UTF-8 BOM (Excel always adds one)
  const rows = parseCSVText(text);
  if (rows.length === 0) return [];
  const headers = rows[0].map(normalizeKey);
  return rows.slice(1).map(line => {
    if (line.every(c => c === '' || c == null)) return null;
    const o = {};
    headers.forEach((h, i) => { o[h] = cleanCell(h, line[i]); });
    return o;
  }).filter(Boolean);
}

/**
 * Full CSV parser — handles quoted multi-line fields, escaped quotes,
 * CRLF or LF line endings. Returns an array of arrays.
 */
function parseCSVText(text) {
  const out = [];
  let row = []; let cur = ''; let inQ = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQ) {
      if (c === '"' && text[i + 1] === '"') { cur += '"'; i++; }
      else if (c === '"') inQ = false;
      else cur += c;
    } else {
      if (c === '"') inQ = true;
      else if (c === ',') { row.push(cur); cur = ''; }
      else if (c === '\n' || c === '\r') {
        if (c === '\r' && text[i + 1] === '\n') i++; // swallow LF after CR
        row.push(cur); cur = '';
        out.push(row); row = [];
      } else cur += c;
    }
  }
  if (cur !== '' || row.length) { row.push(cur); out.push(row); }
  return out.filter(r => r.length > 1 || (r[0] && r[0].trim()));
}

// Backwards-compat shim — older code calls parseCSV(text) on already-loaded text
function parseCSV(text) {
  const stripped = String(text || '').replace(/^﻿/, '');
  const rows = parseCSVText(stripped);
  if (rows.length === 0) return [];
  const headers = rows[0].map(normalizeKey);
  return rows.slice(1).map(line => {
    if (line.every(c => c === '' || c == null)) return null;
    const o = {};
    headers.forEach((h, i) => { o[h] = cleanCell(h, line[i]); });
    return o;
  }).filter(Boolean);
}

