function _reStageDataFieldsFor(statusName) {
  if (!statusName) return null;
  // Case-insensitive match
  for (const k of Object.keys(_RE_STAGE_FIELDS)) {
    if (k.toLowerCase() === String(statusName).toLowerCase()) return _RE_STAGE_FIELDS[k];
  }
  return null;
}
function _reBuildStagePanel(lead, statuses, container) {
  if (!_reIsActive || !_reIsActive()) return;
  const statusSel = container.parentElement && container.parentElement.querySelector('[name="status_id"]');
  const renderFor = () => {
    container.innerHTML = '';
    const sid = statusSel ? Number(statusSel.value) : Number(lead.status_id);
    const status = (statuses || []).find(s => Number(s.id) === sid);
    if (!status) return;
    const fields = _reStageDataFieldsFor(status.name);
    if (!fields || !fields.length) return;
    const ex = (lead && lead.extra) || {};
    const card = document.createElement('div');
    card.style.cssText = 'grid-column:1/-1;border:2px solid ' + (status.color || '#6366f1') + '55;border-radius:10px;padding:.7rem .9rem;background:linear-gradient(180deg,' + (status.color || '#6366f1') + '0a,transparent);margin-top:.3rem';
    const head = document.createElement('div');
    head.style.cssText = 'display:flex;align-items:center;gap:.4rem;margin-bottom:.5rem;';
    head.innerHTML = '<span style="background:' + (status.color || '#6366f1') + ';color:#fff;padding:.15rem .45rem;border-radius:6px;font-weight:700;font-size:.7rem">' + status.name.toUpperCase() + '</span><span style="font-size:.8rem;color:#475569">Stage-specific data</span>';
    card.appendChild(head);
    const grid = document.createElement('div');
    grid.style.cssText = 'display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:.5rem .6rem;';
    fields.forEach(f => {
      const wrap = document.createElement('label');
      wrap.style.cssText = 'display:flex;flex-direction:column;font-size:.75rem;';
      wrap.appendChild(Object.assign(document.createElement('span'), { textContent: f.label, style: 'color:#475569;margin-bottom:.15rem;font-weight:600;' }));
      let inp;
      if (f.type === 'textarea') {
        inp = document.createElement('textarea');
        inp.rows = 2;
      } else if (f.type === 'select') {
        inp = document.createElement('select');
        (f.options || []).forEach(o => {
          const opt = document.createElement('option');
          opt.value = o;
          opt.textContent = o || '— select —';
          inp.appendChild(opt);
        });
      } else {
        inp = document.createElement('input');
        inp.type = f.type || 'text';
        if (f.step) inp.step = f.step;
      }
      inp.name = f.key;
      inp.className = 're-stage-field input';
      if (f.placeholder) inp.placeholder = f.placeholder;
      inp.style.cssText = 'padding:.4rem .5rem;border:1px solid #cbd5e1;border-radius:6px;font-size:.85rem;background:#fff;';
      // Pre-fill from existing extra
      const prefill = ex[f.key];
      if (prefill != null) inp.value = String(prefill);
      wrap.appendChild(inp);
      grid.appendChild(wrap);
    });
    card.appendChild(grid);
    container.appendChild(card);
  };
  renderFor();
  // Re-render when the user changes status via the dropdown OR via the strip
  if (statusSel) {
    statusSel.addEventListener('change', renderFor);
  }
}


// WA_WHITELIST_v1 — shared helper used by the lead modal Quick Actions,
// the lead list row actions, the mobile card actions, and the WA chat
// header. Whitelists a phone so future WA inbound doesn't auto-create a
// lead; optionally deletes the current lead too.
async function whitelistLeadPhone(lead, opts) {
  if (!lead || !lead.phone) { toast('No phone number on this lead', 'err'); return false; }
  const note = prompt('Add a note (optional, e.g. "Personal contact", "Junk lead"):', lead.name || '');
  if (note === null) return false;
  const deleteAlso = !opts || opts.deleteLead !== false;
  const msg = 'Whitelist ' + lead.phone + '?\n\n'
    + '\u2022 Future inbound WhatsApp messages from this number will NOT create a lead.\n'
    + (deleteAlso && lead.id ? '\u2022 This lead (#' + lead.id + ') will also be deleted.\n' : '')
    + '\nContinue?';
  if (!confirm(msg)) return false;
  try {
    const r = await api('api_wb_whitelist_add', { phone: lead.phone, note });
    if (deleteAlso && lead.id) {
      try { await api('api_leads_bulkDelete', [lead.id]); } catch (_) {}
    }
    toast('\u2713 Whitelisted ' + lead.phone + (r.leads_removed ? ' (' + r.leads_removed + ' lead(s) removed)' : ''));
    return true;
  } catch (e) { toast(e.message, 'err'); return false; }
}

async function openLeadModal(id) {
  const { statuses, sources, products, users, customFields } = CRM.cache;
  // Lazy-load the admin-managed tag library; cached for the session.
  if (!CRM.cache.tagLibrary) {
    try { CRM.cache.tagLibrary = await api('api_tags_list'); } catch (_) { CRM.cache.tagLibrary = []; }
  }
  const tagLibrary = CRM.cache.tagLibrary || [];
  if (!CRM.cache.campaigns) {
    try { CRM.cache.campaigns = await api('api_campaigns_list'); } catch (_) { CRM.cache.campaigns = []; }
  }
  const campaigns = (CRM.cache.campaigns || []).filter(c => Number(c.is_active) === 1);
  const isAdmin = CRM.user.role === 'admin';
  let lead = { name: '', phone: '', email: '', whatsapp: '', source: '', status_id: statuses[0]?.id, assigned_to: CRM.user.id, notes: '', tags: '', next_followup_at: '', qualified: 0 };
  let remarks = [];
  if (id) {
    const r = await api('api_leads_get', id);
    lead = Object.assign(lead, r.lead || r);
    remarks = r.remarks || [];
  }
  const modal = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) modal.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  modal.appendChild(body);
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, id ? 'Edit Lead' : 'New Lead'),
    lead.is_duplicate ? h('span', { class: 'dup-pill', onclick: () => openDuplicateHistory(id) }, 'DUPLICATE of #' + (lead.duplicate_of || '?')) : null,
    Number(lead.qualified) === 1 ? h('span', { class: 'qual-pill ok' }, '✓ Qualified') : null,
    // SHARE_LEAD_v1: 🤝 Share button + co-owner chips. Visible on existing leads only.
    id ? h('span', { class: 'share-row', id: 'share-row-' + id }, '') : null,
    h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
  ));


  // SHARE_LEAD_v1: hydrate the share row with co-owner chips and a + Share button.
  if (id) {
    (async () => {
      const sr = body.querySelector('#share-row-' + id);
      if (!sr) return;
      try {
        const co = await api('api_leads_listCoOwners', id);
        sr.innerHTML = '';
        (co || []).forEach(c => {
          const chip = h('span', { class: 'co-chip' },
            '🤝 ' + (c.name || ('User #' + c.user_id)),
            h('button', { class: 'co-chip-x', title: 'Remove', onclick: async (ev) => {
              ev.stopPropagation();
              if (!confirm('Remove ' + (c.name || 'this user') + ' from this lead?')) return;
              try { await api('api_leads_unshare', id, c.user_id); chip.remove(); toast('Removed'); }
              catch (e) { toast(e.message || 'err', 'err'); }
            } }, '×')
          );
          sr.appendChild(chip);
        });
        const addBtn = h('button', { class: 'share-add-btn', title: 'Share with another user', onclick: () => {
          const usersAll = (CRM.cache.users || []).filter(u => u.id !== Number(lead.assigned_to) && Number(u.is_active) === 1);
          const taken = new Set((co || []).map(x => Number(x.user_id)));
          const remaining = usersAll.filter(u => !taken.has(Number(u.id)));
          if (!remaining.length) { toast('No more users to share with'); return; }
          const pickerWrap = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) pickerWrap.remove(); } });
          const picker = h('div', { class: 'modal modal-sm' });
          pickerWrap.appendChild(picker);
          picker.appendChild(h('div', { class: 'modal-head' },
            h('h3', {}, '🤝 Share lead with…'),
            h('button', { class: 'btn icon', onclick: () => pickerWrap.remove() }, '✕')
          ));
          const sel = h('select', { style: { width: '100%', padding: '.5rem' } },
            ...remaining.map(u => h('option', { value: u.id }, u.name || u.email || ('User #' + u.id))));
          const pbody = h('div', { class: 'modal-body' }, sel,
            h('p', { class: 'muted', style: { marginTop: '.5rem' } }, 'Both you and the picked user will see this lead under My Leads with a 🤝 badge. Both can fully work it.'));
          picker.appendChild(pbody);
          picker.appendChild(h('div', { class: 'modal-foot' },
            h('button', { class: 'btn', onclick: () => pickerWrap.remove() }, 'Cancel'),
            h('button', { class: 'btn primary', onclick: async () => {
              const uid = Number(sel.value);
              try { await api('api_leads_shareWith', id, uid); pickerWrap.remove(); toast('Shared');
                const co2 = await api('api_leads_listCoOwners', id);
                sr.innerHTML = '';
                (co2 || []).forEach(c => sr.appendChild(h('span', { class: 'co-chip' }, '🤝 ' + (c.name || ('User #' + c.user_id)))));
                sr.appendChild(addBtn);
              } catch (e) { toast(e.message || 'err', 'err'); }
            } }, 'Share')
          ));
          document.body.appendChild(pickerWrap);
        } }, '🤝 + Share');
        sr.appendChild(addBtn);
      } catch (e) { /* table not migrated yet — silent */ }
    })();
  }

  // Quick actions row — front-and-centre Call / personal WA / Cloud-API
  // template / Calendly buttons so reps don't have to hunt for them in
  // the leads table. Only shows on existing leads with a phone number.
  if (id && lead.phone) {
    const _digits = String(lead.phone || '').replace(/\D/g, '');
    const _intl = _digits.length === 10 && /^[6-9]/.test(_digits) ? '91' + _digits : _digits;
    body.appendChild(h('div', { class: 'card', style: { padding: '.6rem .8rem', margin: '0 0 .75rem', display: 'flex', flexWrap: 'wrap', gap: '.5rem', alignItems: 'center' } },
      h('span', { class: 'muted', style: { fontSize: '.78rem', marginRight: '.25rem' } }, 'Quick actions:'),
      _digits ? h('button', { type: 'button', class: 'btn sm btn-call', onclick: () => callLead(lead) }, '📞 Call') : null,
      _digits ? h('button', {
        type: 'button', class: 'btn sm',
        onclick: () => openPersonalWaPicker(lead),
        title: 'Pick a template — opens WhatsApp from MY number with text pre-filled'
      }, '💬 My WhatsApp') : null,
      _digits ? h('button', { type: 'button', class: 'btn sm wa-cloud-btn', onclick: () => openInitiateChatModal(lead) }, '🟢 WA Template') : null,
      _digits ? h('button', { type: 'button', class: 'btn sm', onclick: () => sendCalendlyLink(lead) }, '📅 Send Calendly') : null,
      lead.email ? h('a', { class: 'btn sm', href: 'mailto:' + lead.email }, '✉ Email') : null,
      h('button', {
        type: 'button', class: 'btn sm',
        title: 'Create a quotation pre-filled with this lead\'s details',
        style: { background: '#fef3c7', color: '#92400e', borderColor: '#fde68a' },
        onclick: () => { modal.remove(); openQuotationModal(null, lead); }
      }, '\ud83d\udcc4 Quote'),
      // WA_WHITELIST_v1 — whitelist this number so future inbound WA never
      // creates a lead; also deletes THIS lead.
      _digits ? h('button', {
        type: 'button', class: 'btn sm',
        title: 'Whitelist this number — future WhatsApp inbound from it will NOT create a lead. Also deletes this lead.',
        style: { background: '#fee2e2', color: '#b91c1c', borderColor: '#fecaca' },
        onclick: async () => {
          const ok = await whitelistLeadPhone(Object.assign({}, lead, { id }));
          if (ok) { modal.remove(); try { navigateTo('leads'); } catch (_) {} }
        }
      }, '\ud83d\udeab Whitelist') : null
    ));
  }

  // Multi-phone widget — backed by lead.extra.extra_phones JSON array.
  // Renders rows of { phone, label } with + Add and 🗑 buttons. Saved
  // along with the lead via the top-level extra_phones key (server folds
  // into extra_json). _findLeadByPhone() reads this back for matching.
  const _existingExtraPhones = ((lead.extra && Array.isArray(lead.extra.extra_phones)) ? lead.extra.extra_phones
                              : (Array.isArray(lead.extra_phones) ? lead.extra_phones : []));
  const extraPhonesWrap = h('div', { class: 'field-full', 'data-extra-phones': '1', style: { gridColumn: '1 / -1' } });
  function renderExtraPhones() {
    extraPhonesWrap.replaceChildren();
    extraPhonesWrap.appendChild(h('label', { style: { fontWeight: 600, marginBottom: '.25rem', display: 'block' } }, '📞 Additional phone numbers'));
    const rows = h('div', { class: 'extra-phones-rows', style: { display: 'flex', flexDirection: 'column', gap: '.35rem' } });
    function addRow(rec) {
      const rec0 = rec || { phone: '', label: '' };
      const phI = h('input', { type: 'tel', placeholder: '+91 9876543210', value: rec0.phone || '', style: { flex: '2', minWidth: '12em' } });
      const lblI = h('input', { type: 'text', placeholder: 'Label (e.g. Husband, Office)', value: rec0.label || '', style: { flex: '1', minWidth: '8em' } });
      const del = h('button', { type: 'button', class: 'btn sm danger', title: 'Remove', onclick: () => { row.remove(); } }, '🗑');
      const row = h('div', { class: 'extra-phone-row', 'data-extra-phone-row': '1', style: { display: 'flex', gap: '.4rem', alignItems: 'center' } }, phI, lblI, del);
      rows.appendChild(row);
    }
    (_existingExtraPhones || []).forEach(r => addRow(r));
    extraPhonesWrap.appendChild(rows);
    extraPhonesWrap.appendChild(h('button', {
      type: 'button', class: 'btn sm', style: { marginTop: '.4rem' },
      onclick: () => addRow({})
    }, '+ Add another number'));
    extraPhonesWrap.appendChild(h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.2rem' } },
      'Calls and WhatsApp from any of these numbers will match this lead.'));
  }
  renderExtraPhones();

  const form = h('form', { id: 'lead-form', class: 'form-grid' });
  form.append(
    field('name', 'Name *', lead.name, { required: true }),
    field('phone', 'Phone *', lead.phone, { required: true }),
    field('whatsapp', 'WhatsApp', lead.whatsapp || lead.phone),
    field('email', 'Email', lead.email, { type: 'email' }),
    selectField('source', 'Source', lead.source, sources.map(s => s.name)),
    selectField('product_id', 'Product', lead.product_id, [{ value: '', label: '—' }, ...products.map(p => ({ value: p.id, label: p.name }))]),
    selectField('status_id', 'Status', lead.status_id, statuses.map(s => ({ value: s.id, label: s.name })), { id: 'lead-status' }),
    selectField('assigned_to', 'Assigned To', lead.assigned_to, users.map(u => ({ value: u.id, label: u.name }))),
    selectField('campaign_id', '🎯 Campaign', lead.campaign_id || '',
      [{ value: '', label: '— None —' }].concat(campaigns.map(c => ({ value: c.id, label: c.name })))),
    tagsInput(lead.tags, tagLibrary, isAdmin),
    field('next_followup_at', 'Next follow-up', isoToLocalDtInput(lead.next_followup_at), { type: 'datetime-local', id: 'lead-fu' }),
    field('city', 'City', lead.city),
    qualifiedToggle(lead),
    // Inventory matching inputs — used by api_inventory_match. Reps fill
    // these on the lead form so the "Matching inventory" panel below can
    // suggest items the prospect's actually likely to buy.
    field('budget_max', 'Budget (max ₹)', lead.budget_max, { type: 'number', min: 0, step: 1 }),
    field('requirement_type', 'Requirement type (e.g. 2BHK, Plot, Premium plan)', lead.requirement_type),
    field('requirement_notes', 'Requirement notes', lead.requirement_notes, { type: 'textarea', full: true }),
    field('notes', 'Notes', lead.notes, { type: 'textarea', full: true })
  );

  // RE_STAGE_DATA_v1 — stage-specific data capture panel inside the form.
  // Re-renders when status changes. Inputs use name="re_*" so the
  // submit handler picks them up into extra.re_*.
  const _reStageDataWrap = document.createElement('div');
  _reStageDataWrap.className = 're-stage-data-wrap';
  _reStageDataWrap.style.cssText = 'grid-column:1/-1;';
  form.appendChild(_reStageDataWrap);
  try { _reBuildStagePanel(lead, statuses, _reStageDataWrap); } catch (e) { console.warn('[RE stage panel]', e && e.message); }

  // RE_CP_PIPELINE_v1 (2026-05-21) — render 12-stage horizontal strip above the form
  // when Real Estate pack is installed. Clicking a stage updates the status_id
  // select in-place (no save until the user clicks Save).
  let _reLocalLead = lead;
  function _reRenderStrip() {
    const old = body.querySelector('.re-stage-strip-wrap');
    const fresh = _reStageStrip(_reLocalLead, statuses, {
      onPick: (stage) => {
        _reLocalLead = Object.assign({}, _reLocalLead, { status_id: stage.id });
        const sel = form.querySelector('[name="status_id"]');
        if (sel) {
          sel.value = String(stage.id);
          sel.dispatchEvent(new Event('change', { bubbles: true }));
        }
        _reRenderStrip();
      }
    });
    if (fresh) {
      fresh.classList.add('re-stage-strip-wrap');
      if (old) old.replaceWith(fresh);
      else body.appendChild(fresh);
    }
  }
  _reRenderStrip();

  // Hide any custom field that collides with a hardcoded built-in field key —
  // otherwise the user sees Budget / Requirement type / Requirement notes
  // twice (once as the inventory-matching inputs above, once as the custom
  // field they originally created in Admin). The hardcoded version wins
  // because it's what api_inventory_match reads from.
  const RESERVED_FIELD_KEYS = new Set([
    'budget_max', 'requirement_type', 'requirement_notes',
    'name', 'phone', 'email', 'city', 'notes', 'tags',
    'status_id', 'assigned_to', 'next_followup_at', 'qualified',
    'source_id', 'product_id'
  ]);
  (customFields || []).forEach(cf => {
    if (RESERVED_FIELD_KEYS.has(String(cf.key || '').toLowerCase())) return;
    const extra = lead.extra || {};
    form.appendChild(customFieldInput(cf, extra[cf.key]));
  });

  // ORPHAN_CF_v1 — render fallback inputs for any extra_json key that
  // (a) isn't a built-in reserved field, (b) isn't already covered by a
  // registered active custom_fields row, and (c) doesn't start with '_'
  // (internal flags). This covers two real-world cases:
  //   1. The CF row got deactivated (is_active=0), so api_customFields_list
  //      drops it, but leads still carry the value in extra_json. Without
  //      this fallback the value silently lives forever, invisible.
  //   2. The key arrived via /hook/website, /hook/leadsource, or a CSV
  //      import that mapped an unknown column straight to extra_json.
  //      Examples we've seen in the wild: company_name on shipuncle,
  //      designation on adbullet, hsn_code on stockbox.
  // The fallback input is a plain text box labelled from the key
  // (kebab/snake → Title Case) with a 🪜 hint so admins know they can
  // turn it into a proper field in Admin → Custom Fields.
  try {
    const _renderedCfKeys = new Set();
    (customFields || []).forEach(cf => {
      if (cf && cf.key) _renderedCfKeys.add(String(cf.key));
    });
    const _orphanIgnore = new Set([
      'extra_phones', 'is_duplicate', 'duplicate_of'
    ]);
    const _extraObj = (lead && lead.extra) || {};
    function _humanize(k) {
      return String(k || '')
        .replace(/[_\-]+/g, ' ')
        .replace(/\s+/g, ' ')
        .trim()
        .replace(/\b\w/g, c => c.toUpperCase());
    }
    Object.keys(_extraObj).forEach(rawKey => {
      const key = String(rawKey || '');
      if (!key) return;
      if (key[0] === '_') return;
      if (_orphanIgnore.has(key)) return;
      if (RESERVED_FIELD_KEYS.has(key.toLowerCase())) return;
      if (_renderedCfKeys.has(key)) return;
      const val = _extraObj[key];
      // Skip non-primitive values (arrays/objects) — they likely belong
      // to a structured widget (extra_phones etc.) and shouldn't be
      // surfaced as a single text input.
      if (val !== null && typeof val === 'object') return;
      const wrap = h('label', { class: 'field orphan-cf', 'data-orphan-cf-key': key, style: { display: 'flex', flexDirection: 'column', gap: '.15rem' } });
      wrap.appendChild(h('span', { style: { fontWeight: 600, fontSize: '.85rem', display: 'inline-flex', alignItems: 'center', gap: '.25rem' } },
        _humanize(key),
        h('span', { title: 'This field came from an import or webhook and isn\u2019t in your Custom Fields list yet. Saving the lead keeps the value; admins can register it in Settings \u2192 Custom Fields to add type/options.', style: { color: '#f59e0b', cursor: 'help', fontSize: '.78rem' } }, '\ud83e\ude9c')
      ));
      wrap.appendChild(h('input', {
        type: 'text',
        name: 'cf_' + key,
        value: val == null ? '' : String(val),
        class: 'input'
      }));
      form.appendChild(wrap);
    });
  } catch (e) { console.warn('[orphan-cf render]', e && e.message); }

  // THREE_FEATURES_v1 — F2: collapsible "All fields" so power-users can
  // see every column the leads row carries even if it isn't in the
  // hardcoded form above. Read-only for system fields (created_at,
  // heat_score, etc.). Editable for the rest. Custom fields are
  // already rendered above so they're skipped here.
  try {
    const _allFieldsRendered = new Set([
      'id', 'name', 'phone', 'whatsapp', 'email', 'source', 'product_id',
      'status_id', 'assigned_to', 'campaign_id', 'tags', 'next_followup_at',
      'city', 'qualified', 'budget_max', 'requirement_type', 'requirement_notes',
      'notes', 'extra_json', 'extra', 'extra_phones', 'remarks',
      'is_duplicate', 'duplicate_of'
    ]);
    const _readOnlyKeys = new Set([
      'created_at', 'updated_at', 'last_status_change_at',
      'created_by', 'heat_score', 'heat_score_at',
      'ai_processed_at', 'ai_score'
    ]);
    const moreKeys = [];
    Object.keys(lead || {}).forEach(k => {
      if (_allFieldsRendered.has(k)) return;
      const v = lead[k];
      if (v !== null && typeof v === 'object') return; // skip arrays/objects
      moreKeys.push(k);
    });
    if (moreKeys.length) {
      const det = h('details', { class: 'all-fields', style: { gridColumn: '1 / -1', marginTop: '.4rem', background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: '6px', padding: '.4rem .6rem' } });
      det.appendChild(h('summary', { style: { cursor: 'pointer', fontWeight: 600, padding: '.25rem 0', color: '#0f172a' } }, '\ud83d\udccb All other fields (' + moreKeys.length + ')'));
      const grid = h('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(220px,1fr))', gap: '.5rem', padding: '.4rem 0' } });
      function _humanize(k) {
        return String(k || '').replace(/[_\-]+/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
      }
      moreKeys.forEach(k => {
        const ro = _readOnlyKeys.has(k);
        const v = lead[k];
        const isDate = /at$|_date$/.test(k) && v && /\d{4}-\d{2}/.test(String(v));
        const wrap = h('label', { class: 'field all-field' + (ro ? ' readonly' : ''), 'data-all-field-key': k, style: { display: 'flex', flexDirection: 'column', gap: '.15rem' } });
        wrap.appendChild(h('span', { style: { fontWeight: 600, fontSize: '.82rem' } },
          _humanize(k),
          ro ? h('span', { style: { color: '#94a3b8', fontSize: '.7rem', marginLeft: '.3rem' } }, '(read-only)') : null
        ));
        wrap.appendChild(h('input', {
          type: 'text',
          name: 'allf_' + k,
          value: v == null ? '' : (isDate ? String(v).slice(0, 16).replace('T', ' ') : String(v)),
          class: 'input',
          readonly: ro ? 'readonly' : null,
          style: ro ? { background: '#f3f4f6', color: '#475569' } : {}
        }));
        grid.appendChild(wrap);
      });
      det.appendChild(grid);
      form.appendChild(det);
    }
  } catch (e) { console.warn('[F2 all-fields]', e && e.message); }


    // Append extra-phones widget AT THE END of the form so it spans width and
  // doesn't crowd the address fields.
  try { form.appendChild(extraPhonesWrap); } catch (_) {}
  body.appendChild(form);

  // ---- Quotations panel for this lead ----
  if (id) {
    const quotesCard = h('div', { class: 'card', style: { marginTop: '.75rem' } });
    quotesCard.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '.4rem' } },
      h('h4', { style: { margin: 0 } }, '\ud83d\udcc4 Quotations'),
      h('button', { class: 'btn sm primary', type: 'button', onclick: () => { modal.remove(); openQuotationModal(null, lead); } }, '+ New')
    ));
    const quotesList = h('div', { class: 'muted', style: { fontSize: '.85rem' } }, 'Loading\u2026');
    quotesCard.appendChild(quotesList);
    body.appendChild(quotesCard);
    api('api_quotations_list', { lead_id: id }).then(d => {
      quotesList.innerHTML = '';
      const rows = (d && d.rows) || [];
      if (!rows.length) {
        quotesList.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem' } }, 'No quotations sent yet for this lead.'));
        return;
      }
      const tbl = h('table', { style: { width: '100%', fontSize: '.85rem' } },
        h('thead', {}, h('tr', {},
          h('th', { style: { textAlign: 'left' } }, 'Number'),
          h('th', { style: { textAlign: 'left' } }, 'Status'),
          h('th', { style: { textAlign: 'right' } }, 'Total'),
          h('th', { style: { textAlign: 'left' } }, 'Sent'),
          h('th', {}, '')
        )),
        h('tbody', {}, ...rows.map(r => {
          const stColor = { draft: '#94a3b8', sent: '#3b82f6', accepted: '#10b981', rejected: '#ef4444', expired: '#f59e0b' }[r.status] || '#64748b';
          return h('tr', {},
            h('td', {}, h('code', {}, r.number)),
            h('td', {}, h('span', { style: { background: stColor, color: '#fff', padding: '.1rem .4rem', borderRadius: '4px', fontSize: '.76rem' } }, r.status)),
            h('td', { style: { textAlign: 'right' } }, '\u20b9' + Number(r.total || 0).toLocaleString('en-IN')),
            h('td', { class: 'muted', style: { fontSize: '.78rem' } }, r.sent_at ? fmtDate(r.sent_at, 'relative') : '\u2014'),
            h('td', { style: { textAlign: 'right' } },
              h('button', { class: 'btn xs', type: 'button', onclick: () => { modal.remove(); openQuotationModal(r.id); } }, 'Open')
            )
          );
        }))
      );
      quotesList.appendChild(tbl);
    }).catch(e => {
      quotesList.innerHTML = '';
      quotesList.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem' } }, 'Could not load quotations: ' + e.message));
    });
  }

  // ---- Education pack: Fees panel for this lead ----
  // Only renders when the Education pack is installed. Backend throws
  // 'pack not active' if not — we catch and silently skip.
  if (id) {
    const eduFeesCard = h('div', { class: 'card', style: { marginTop: '.75rem' } });
    const eduHeader = h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '.4rem' } },
      h('h4', { style: { margin: 0 } }, '🎓 Fees & Installments'),
      h('button', { class: 'btn sm primary', type: 'button', onclick: () => openCreateEnrollmentModal(lead, () => openLeadModal(id)) }, '+ Enroll')
    );
    const eduList = h('div', { class: 'muted', style: { fontSize: '.85rem' } }, 'Loading…');
    eduFeesCard.appendChild(eduHeader);
    eduFeesCard.appendChild(eduList);
    api('api_edu_enrollment_byLead', id).then(enrolls => {
      eduList.innerHTML = '';
      if (!enrolls || !enrolls.length) {
        eduList.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem' } }, 'No fee plan attached. Tap “+ Enroll” to set up an installment schedule.'));
        body.appendChild(eduFeesCard);
        return;
      }
      enrolls.forEach(e => {
        const totalDue = (e.installments || []).reduce((sum, i) => sum + Math.max(0, Number(i.amount) + Number(i.late_fee) - Number(i.paid_amount)), 0);
        const totalPaid = (e.installments || []).reduce((sum, i) => sum + Number(i.paid_amount), 0);
        const head = h('div', { style: { display: 'flex', alignItems: 'baseline', gap: '.5rem', marginTop: '.3rem' } },
          h('strong', {}, e.course_name || 'Enrollment #' + e.id),
          e.batch_name ? h('span', { class: 'muted', style: { fontSize: '.78rem' } }, '· ' + e.batch_name) : null,
          h('span', { style: { marginLeft: 'auto', color: '#16a34a', fontWeight: 600 } }, '₹' + totalPaid.toLocaleString('en-IN') + ' paid'),
          h('span', { style: { color: '#dc2626', fontWeight: 600 } }, '· ₹' + totalDue.toLocaleString('en-IN') + ' due')
        );
        eduFeesCard.appendChild(head);
        const tbl = h('table', { style: { width: '100%', fontSize: '.85rem', marginTop: '.3rem' } },
          h('thead', {}, h('tr', {},
            h('th', { style: { textAlign: 'left' } }, '#'),
            h('th', { style: { textAlign: 'left' } }, 'Due'),
            h('th', { style: { textAlign: 'right' } }, 'Amount'),
            h('th', { style: { textAlign: 'right' } }, 'Paid'),
            h('th', { style: { textAlign: 'left' } }, 'Status'),
            h('th', {}, '')
          )),
          h('tbody', {}, ...(e.installments || []).map(i => {
            const statusColor = { paid: '#16a34a', partial: '#f59e0b', due: '#64748b', overdue: '#dc2626' }[i.status] || '#64748b';
            const isOverdue = i.status !== 'paid' && new Date(i.due_date) < new Date();
            return h('tr', {},
              h('td', {}, '#' + i.seq),
              h('td', { style: { color: isOverdue ? '#dc2626' : 'inherit', fontWeight: isOverdue ? 600 : 400 } },
                String(i.due_date).slice(0, 10)),
              h('td', { style: { textAlign: 'right' } }, '₹' + Number(i.amount).toLocaleString('en-IN')),
              h('td', { style: { textAlign: 'right', color: '#16a34a' } }, Number(i.paid_amount) ? '₹' + Number(i.paid_amount).toLocaleString('en-IN') : '—'),
              h('td', {},
                h('span', { style: { background: statusColor, color: '#fff', padding: '.1rem .4rem', borderRadius: '4px', fontSize: '.74rem' } },
                  isOverdue && i.status !== 'paid' ? 'overdue' : i.status)),
              h('td', { style: { textAlign: 'right' } },
                i.status === 'paid' ? null :
                  h('button', { class: 'btn xs', type: 'button', onclick: () => openMarkPaidModal(i, () => openLeadModal(id)) }, '₹ Mark paid')
              )
            );
          }))
        );
        eduFeesCard.appendChild(tbl);
      });
      body.appendChild(eduFeesCard);
    }).catch(err => {
      // Pack not installed = silently skip
      if (/not active/i.test(String(err.message || ''))) return;
      eduList.innerHTML = '';
      eduList.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem' } }, 'Fees panel unavailable: ' + err.message));
      body.appendChild(eduFeesCard);
    });
  }

  // Customer / campaign-supplied fields are read-only for non-admins on
  // existing leads. Reps can update status/notes/follow-up/etc. but cannot
  // overwrite what the customer typed in the form, the source, the GCLID,
  // or the UTMs. Admin can still change these for legitimate corrections.
  if (id && !isAdmin) {
    const LOCKED = ['name', 'phone', 'whatsapp', 'email', 'source'];
    LOCKED.forEach(name => {
      const el = form.querySelector(`[name="${name}"]`);
      if (!el) return;
      el.readOnly = true;
      el.disabled = (el.tagName === 'SELECT'); // <select> needs disabled, not readonly
      el.title = 'Locked — set by the campaign / customer. Only admin can edit.';
      el.classList.add('lead-locked');
      // Append a lock badge to the field's label so users see immediately
      // why they can't type.
      const label = el.closest('.f-row')?.querySelector('label')
                 || el.parentElement?.querySelector('label');
      if (label && !label.querySelector('.locked-badge')) {
        const badge = h('span', { class: 'locked-badge', title: 'Set by campaign — only admin can edit' }, ' 🔒');
        label.appendChild(badge);
      }
    });
  }

  if (id) body.appendChild(projectStageBlock(id, lead));
  if (id) body.appendChild(matchingInventoryBlock(id));
  if (id) body.appendChild(actionTimelineBlock(id));
  if (id) body.appendChild(remarksBlock(remarks, id));
  if (id) body.appendChild(recordingsBlock(id));
  // Action row — Cancel / Save / [Duplicate & reassign for managers+]
  const actionsRow = h('div', { class: 'actions' });
  actionsRow.appendChild(h('button', { type: 'button', class: 'btn', onclick: () => modal.remove() }, 'Cancel'));
  if (id && ['admin', 'manager', 'team_leader'].includes(CRM.user.role)) {
    actionsRow.appendChild(h('button', { type: 'button', class: 'btn', onclick: () => openDuplicateAndReassignModal(id, lead, () => { modal.remove(); loadLeads && loadLeads(); }) }, '📋 Duplicate & reassign'));
  }
  actionsRow.appendChild(h('button', { type: 'submit', form: 'lead-form', class: 'btn primary' }, id ? 'Save changes' : 'Create lead'));
  body.appendChild(actionsRow);
  document.body.appendChild(modal);

  // Status → Follow-up enforcement: when the user picks a status whose
  // name is "Follow Up", they MUST also pick a date+time. The submit
  // handler validates this and blocks save with a clear message.
  function selectedStatusName() {
    const sel = form.querySelector('[name="status_id"]');
    if (!sel) return '';
    const opt = sel.options[sel.selectedIndex];
    return (opt ? opt.textContent : '').trim().toLowerCase();
  }

  // When the rep flips status to a "dead-end" one (Not Pick, Not Interested,
  // Junk, Does Not Exist, Broker) we strip the HTML5 `required` attribute
  // from custom fields so they can save the lead without filling capital
  // range / risk tolerance / etc. JS validation below honours the same rule.
  function syncRequiredFromStatus() {
    const skip = _statusSkipsRequired(selectedStatusName());
    form.querySelectorAll('[data-cf-required="1"]').forEach(el => {
      if (skip) el.removeAttribute('required');
      else      el.setAttribute('required', '');
    });
  }
  const _statusSel = form.querySelector('[name="status_id"]');
  if (_statusSel) _statusSel.addEventListener('change', syncRequiredFromStatus);
  syncRequiredFromStatus();

  form.addEventListener('submit', async ev => {
    ev.preventDefault();

    // Status = "Follow Up" requires next_followup_at — both date AND time.
    const statusName = selectedStatusName();
    const fuVal = form.querySelector('[name="next_followup_at"]')?.value || '';
    if (/follow\s*up/i.test(statusName) && !fuVal) {
      toast('Status "Follow Up" requires a next follow-up date and time', 'err');
      form.querySelector('[name="next_followup_at"]')?.focus();
      return;
    }

    // Required custom fields — enforce here in addition to HTML5 `required`.
    // Admin is exempt: they often need to update a lead in flight (e.g.
    // change status, add a note) without re-typing every required field
    // that the rep should have filled. Other roles still get the validation.
    // Also exempt: when the chosen status marks the lead as a dead-end
    // (Not Pick, Not Interested, Junk, Does Not Exist, Broker) — pointless
    // to demand custom-field detail for leads that aren't progressing.
    const _skipRequired = _statusSkipsRequired(statusName);
    if (CRM.user.role !== 'admin' && !_skipRequired) {
      for (const cf of (customFields || [])) {
        if (!cf.is_required) continue;
        const key = 'cf_' + cf.key;
        let val;
        if (cf.field_type === 'multiselect') val = (new FormData(form)).getAll(key).join(',');
        else val = form.querySelector(`[name="${key}"]`)?.value || '';
        if (!String(val).trim()) {
          toast(`"${cf.label}" is required`, 'err');
          const el = form.querySelector(`[name="${key}"]`);
          if (el && el.focus) el.focus();
          return;
        }
      }
    }

    const fd = new FormData(form);
    const extra = {};
    (customFields || []).forEach(cf => {
      const key = 'cf_' + cf.key;
      if (cf.field_type === 'multiselect') extra[cf.key] = fd.getAll(key).join(',');
      else extra[cf.key] = fd.get(key) || '';
    });
    // RE_STAGE_DATA_v1 — scoop re_* stage-specific inputs into extra
    try {
      form.querySelectorAll('.re-stage-field').forEach(inp => {
        const k = inp.name;
        if (!k || !k.startsWith('re_')) return;
        extra[k] = inp.value || '';
      });
    } catch (e) { console.warn('[re-stage submit]', e && e.message); }
    // ORPHAN_CF_v1 — collect orphan extra-json fields rendered above
    // (e.g. company_name from a webhook import). The input names use
    // the same 'cf_<key>' convention so server merge logic stays the
    // same. We also preserve any non-string values the original lead
    // already carried (arrays/objects we skipped in the render pass).
    try {
      const _origExtra = (lead && lead.extra) || {};
      form.querySelectorAll('.orphan-cf').forEach(wrap => {
        const k = wrap.getAttribute('data-orphan-cf-key');
        if (!k) return;
        const inp = wrap.querySelector('input,textarea,select');
        if (!inp) return;
        // Don't overwrite if the registered-CF loop already wrote
        // something for this key (would mean a name collision; the
        // registered field wins).
        if (Object.prototype.hasOwnProperty.call(extra, k)) return;
        extra[k] = inp.value || '';
      });
      // Preserve non-primitive values that the render pass intentionally
      // skipped (e.g. arrays we wouldn't render as text inputs).
      Object.keys(_origExtra).forEach(k => {
        if (Object.prototype.hasOwnProperty.call(extra, k)) return;
        const v = _origExtra[k];
        if (v !== null && typeof v === 'object') extra[k] = v;
      });
    } catch (e) { console.warn('[orphan-cf submit]', e && e.message); }

    // THREE_FEATURES_v1 — F2 submit: collect editable "All fields" back
    // into payload. These map directly onto leads-table columns (not
    // into extra_json) since they came from there. Read-only inputs
    // are skipped (browser doesn't include readonly values? — it does,
    // but we filter them client-side anyway because server might reject).
    try {
      form.querySelectorAll('.all-field').forEach(wrap => {
        if (wrap.classList.contains('readonly')) return;
        const k = wrap.getAttribute('data-all-field-key');
        if (!k) return;
        const inp = wrap.querySelector('input,textarea,select');
        if (!inp) return;
        payload[k] = inp.value;
      });
    } catch (e) { console.warn('[F2 all-fields submit]', e && e.message); }
    // Tags: if non-admin, the tags field is a multi-select — collect with getAll.
    const tagsValue = isAdmin
      ? (fd.get('tags') || '')
      : fd.getAll('tags[]').join(',');
    const payload = {
      name: fd.get('name'), phone: fd.get('phone'), email: fd.get('email'),
      whatsapp: fd.get('whatsapp'), source: fd.get('source'),
      product_id: Number(fd.get('product_id')) || null,
      status_id: Number(fd.get('status_id')) || null,
      assigned_to: Number(fd.get('assigned_to')) || null,
      tags: tagsValue,
      next_followup_at: localDtInputToIso(fd.get('next_followup_at')),
      city: fd.get('city'), notes: fd.get('notes'),
      qualified: form.querySelector('[name="qualified"]')?.checked ? 1 : 0,
      // Inventory matching inputs
      budget_max:        Number(fd.get('budget_max')) || null,
      requirement_type:  fd.get('requirement_type') || '',
      requirement_notes: fd.get('requirement_notes') || '',
      // Multi-phone widget — collect rows added via "+ Add another number"
      extra_phones: (() => {
        try {
          const rows = extraPhonesWrap.querySelectorAll('.extra-phone-row');
          const list = [];
          rows.forEach(r => {
            const inps = r.querySelectorAll('input');
            const ph = (inps[0] && inps[0].value || '').trim();
            const lb = (inps[1] && inps[1].value || '').trim();
            if (ph) list.push({ phone: ph, label: lb });
          });
          return list;
        } catch (_) { return []; }
      })(),
      extra
    };
    try {
      if (id) await api('api_leads_update', id, payload);
      else    await api('api_leads_create', payload);
      toast(id ? 'Saved' : 'Created');
      // Lead edit submit → kick a silent recording sweep. Reps usually
      // open the lead to log an update right after a call, so this is
      // the natural moment to pull any pending recording without
      // forcing them to tap Sync now.
      try { _kickRecordingSyncSoon(6000); setTimeout(() => _kickRecordingSyncSoon(0), 20000); } catch (_) {}
      modal.remove();
      loadLeads();
    } catch (e) { toast(e.message, 'err'); }
  });
}

/**
 * Build the Tags form row.
 * - Admin → freeform comma-separated input AND can add new tags from this UI
 *   (still suggested values dropdown via datalist).
 * - Non-admin → multi-select of existing tags only. Cannot type new ones.
 */
function tagsInput(currentTags, tagLibrary, isAdmin) {
  const current = String(currentTags || '').split(',').map(s => s.trim()).filter(Boolean);
  if (isAdmin) {
    // Free-form input plus a datalist of known tags for autocomplete.
    const dlId = 'tag-suggest-' + Math.random().toString(36).slice(2, 8);
    const inp = h('input', { name: 'tags', value: current.join(', '), list: dlId, placeholder: 'comma separated' });
    const dl  = h('datalist', { id: dlId }, ...tagLibrary.map(t => h('option', { value: t.name })));
    return h('div', { class: 'f-row' }, h('label', {}, 'Tags'), h('div', {}, inp, dl,
      h('div', { class: 'muted', style: { fontSize: '.75rem', marginTop: '.25rem' } },
        'Manage the master tag list under Admin → Tags.'))
    );
  }
  // Non-admin: multi-select. Cannot type new tags.
  if (tagLibrary.length === 0) {
    return h('div', { class: 'f-row' }, h('label', {}, 'Tags'),
      h('div', { class: 'muted' }, 'No tags available. Ask an admin to add them under Admin → Tags.'));
  }
  const grid = h('div', { class: 'cf-multi-grid' },
    ...tagLibrary.map(t => h('label', {},
      h('input', { type: 'checkbox', name: 'tags[]', value: t.name, checked: current.includes(t.name) ? 'checked' : null }),
      ' ', h('span', { class: 'tag', style: { background: t.color, color: '#fff' } }, t.name)
    ))
  );
  return h('div', { class: 'f-row full' }, h('label', {}, 'Tags'), grid);
}

function qualifiedToggle(lead) {
  const wrap = h('div', { class: 'f-row' },
    h('label', {}, 'Qualified lead?'),
    h('label', { class: 'qual-toggle' },
      h('input', { type: 'checkbox', name: 'qualified', checked: Number(lead.qualified) === 1 ? 'checked' : null }),
      h('span', {}, ' Mark as qualified (passes minimum criteria, separate from status)')
    )
  );
  return wrap;
}

/**
 * Pop up a small modal with a user picker and a confirm button. On confirm,
 * call api_leads_duplicateAndReassign. Used from the lead modal.
 */
/**
 * "Next Follow Up" modal — replaces the old "Mark done" button.
 *
 * Forces the user to commit to a NEXT step instead of just dismissing the
 * reminder. They pick a new date+time and write a quick remark; we then:
 *  1. Insert a remark on the lead (so it's visible in history)
 *  2. Update the lead's next_followup_at (which auto-syncs the followup row)
 *  3. Close this modal & refresh
 *
 * If the user enters a remark but leaves date blank, we treat it as a Done +
 * remark (close current followup, no next one).
 */
function openNextFollowupModal(row, onSuccess) {
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  // Default next due = tomorrow at 10am local
  const tomorrow = new Date(Date.now() + 24 * 60 * 60 * 1000);
  tomorrow.setHours(10, 0, 0, 0);
  const defaultDt = isoToLocalDtInput(tomorrow.toISOString());

  // Status picker — lets the rep change the lead's status while resolving the
  // follow-up. For "dead-end" statuses (Not Picked, Not Interested, Junk,
  // Does Not Exist, Broker) we drop the next-follow-up requirement because
  // the lead isn't progressing, so a fresh follow-up date is pointless.
  const statuses = (CRM.cache.statuses || []);
  const statusSel = h('select', { class: 'status-picker' },
    h('option', { value: '' }, '— Keep current status —'),
    ...statuses.map(s => h('option', { value: s.id }, s.name))
  );

  const dtInput  = h('input', { type: 'datetime-local', value: defaultDt });
  const dtLabel  = h('label', {}, 'Next follow-up date & time *');
  const dtHint   = h('p', { class: 'muted', style: { fontSize: '.78rem', margin: '.25rem 0 0' } },
    'When should you contact this lead next?');

  const remarkInput = h('textarea', { rows: 3, placeholder: 'What happened on this call / contact attempt?' });

  // Toggle the required indicator + hint based on the selected status.
  function syncFollowupRequired() {
    const opt = statusSel.options[statusSel.selectedIndex];
    const name = (opt ? opt.textContent : '').trim();
    const skip = _statusSkipsRequired(name);
    dtLabel.textContent = skip ? 'Next follow-up date & time (optional)' : 'Next follow-up date & time *';
    dtHint.textContent  = skip
      ? 'Optional — this status closes the lead, no further follow-up needed.'
      : 'When should you contact this lead next?';
  }
  statusSel.addEventListener('change', syncFollowupRequired);
  syncFollowupRequired();

  m.appendChild(h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, '⏰ Next follow-up'),
      h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
    ),
    h('p', { class: 'muted', style: { marginTop: 0 } },
      `For lead: ${row.lead_name || '—'}${row.lead_phone ? ' · ' + row.lead_phone : ''}`),
    h('div', { class: 'f-row full' }, h('label', {}, 'Update status'), statusSel),
    h('div', { class: 'f-row full' }, h('label', {}, 'Remark *'), remarkInput),
    h('div', { class: 'f-row full' }, dtLabel, dtInput, dtHint),
    h('div', { class: 'actions', style: { marginTop: '1rem' } },
      h('button', { class: 'btn', onclick: () => m.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        const remark = String(remarkInput.value || '').trim();
        if (!remark) { toast('Remark is required', 'err'); remarkInput.focus(); return; }

        const newStatusId = statusSel.value ? Number(statusSel.value) : null;
        const newStatusOpt = newStatusId ? statusSel.options[statusSel.selectedIndex] : null;
        const newStatusName = newStatusOpt ? newStatusOpt.textContent.trim() : '';
        const skipFollowup = newStatusName ? _statusSkipsRequired(newStatusName) : false;
        const nextIso = localDtInputToIso(dtInput.value);

        // Validate: for non-dead-end statuses, require a next-follow-up date.
        // Dead-end statuses (Not Picked, Not Interested, Junk, Does Not Exist,
        // Broker) skip this gate so the rep can close the lead in one click.
        if (!skipFollowup && !nextIso) {
          toast('Pick a next follow-up date & time, or set a closing status (Junk / Not Interested / etc.)', 'err');
          dtInput.focus();
          return;
        }

        try {
          // 1. Update the lead's status if a new one was picked
          if (newStatusId) {
            try {
              await api('api_leads_update', row.lead_id, { status_id: newStatusId });
              try { _kickRecordingSyncSoon(6000); } catch (_) {}
            } catch (e) {
              toast('Status update failed: ' + e.message, 'err');
              return;
            }
          }
          // 2. Add the remark and (optionally) set the next followup
          await api('api_leads_addRemark', row.lead_id, {
            remark,
            next_followup_at: nextIso || null
          });
          // 3. Close the current open followup so it leaves Overdue / Due today
          if (row.id) {
            try { await api('api_followup_done', row.id); } catch (_) {}
          }
          toast(skipFollowup
            ? 'Lead updated · status closed'
            : (nextIso ? 'Saved & next follow-up scheduled' : 'Saved'));
          m.remove();
          if (typeof onSuccess === 'function') onSuccess();
        } catch (e) { toast(e.message, 'err'); }
      } }, 'Save')
    )
  ));
  document.body.appendChild(m);
}

function openDuplicateAndReassignModal(leadId, lead, onSuccess) {
  const { users } = CRM.cache;
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const sel = h('select', {},
    h('option', { value: '' }, '— pick a sales user —'),
    ...users.filter(u => Number(u.id) !== Number(lead.assigned_to)).map(u =>
      h('option', { value: u.id }, `${u.name} (${u.role})`))
  );
  m.appendChild(h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, '📋 Duplicate & reassign'),
      h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
    ),
    h('p', { class: 'muted' },
      `A copy of "${lead.name || ('Lead #' + leadId)}" will be created with status "New" and assigned to the user you pick. The original lead stays as-is.`),
    h('label', {}, 'New assignee'),
    sel,
    h('div', { class: 'actions', style: { marginTop: '1rem' } },
      h('button', { class: 'btn', onclick: () => m.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        const newId = sel.value;
        if (!newId) { toast('Pick a user first', 'err'); return; }
        try {
          const r = await api('api_leads_duplicateAndReassign', leadId, Number(newId));
          toast('Duplicated as lead #' + r.id, 'ok');
          m.remove();
          if (typeof onSuccess === 'function') onSuccess();
        } catch (e) { toast(e.message, 'err'); }
      } }, 'Duplicate & reassign')
    )
  ));
  document.body.appendChild(m);
}

function field(name, label, value, opts = {}) {
  const tag = opts.type === 'textarea' ? 'textarea' : 'input';
  const attrs = Object.assign({ name, value: value ?? '' },
    opts.type && opts.type !== 'textarea' ? { type: opts.type } : {},
    opts.required ? { required: true } : {},
    opts.id ? { id: opts.id } : {});
  const el = h(tag, attrs);
  if (opts.type === 'textarea') el.textContent = value ?? '';
  return h('div', { class: opts.full ? 'f-row full' : 'f-row' }, h('label', {}, label), el);
}
function selectField(name, label, value, options, opts = {}) {
  const selAttrs = { name };
  if (opts.id) selAttrs.id = opts.id;
  const sel = h('select', selAttrs,
    ...options.map(o => {
      const v = typeof o === 'object' ? o.value : o;
      const t = typeof o === 'object' ? o.label : o;
      return h('option', { value: v, selected: String(value) === String(v) ? 'selected' : null }, t);
    })
  );
  return h('div', { class: opts.full ? 'f-row full' : 'f-row' }, h('label', {}, label), sel);
}
function selectOpts(id, items, value) {
  return h('select', { id },
    ...items.map(i => h('option', { value: i.id, selected: String(value) === String(i.id) ? 'selected' : null }, i.name))
  );
}

/**
 * Multi-select dropdown with Select All / Deselect All / search.
 * Drop-in friendly: returns a wrapper element that renders a button +
 * popup with checkbox list. Empty selection = "All / no filter".
 *
 *   multiSelectDropdown({
 *     id: 'f-status', label: 'Lead Status',
 *     options: [{ id, name }, ...],
 *     values: ['1', '3'],            // array of ids; empty/undefined = All
 *     onApply: (newValues) => {...}  // fires when user clicks Apply
 *   })
 */
function multiSelectDropdown({ id, label, options, values, onApply, allLabel }) {
  values = (values || []).map(String);
  options = options || [];
  const wrap = document.createElement('div');
  wrap.className = 'ms-dropdown';
  wrap.style.cssText = 'position: relative; display: inline-block;';
  if (id) wrap.id = id;

  const btn = document.createElement('button');
  btn.type = 'button';
  btn.className = 'btn ghost ms-dropdown-button';
  btn.style.cssText = 'min-width: 9rem; max-width: 16rem; text-align: left; display: inline-flex; align-items: center; gap: .35rem; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;';
  function renderBtn() {
    btn.innerHTML = '';
    const active = values.length > 0;
    // FILTER_HIGHLIGHT_A_v1 — blue tint when a non-default value is selected
    btn.style.background   = active ? '#E6F1FB' : '';
    btn.style.borderColor  = active ? '#378ADD' : '';
    btn.style.borderWidth  = active ? '1.5px'   : '';
    btn.style.color        = active ? '#0C447C' : '';
    btn.style.fontWeight   = active ? '600'     : '';
    const lbl = document.createElement('span');
    lbl.style.cssText = 'flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;';
    if (!values.length) {
      lbl.textContent = (label ? label + ': ' : '') + (allLabel || 'All');
    } else if (values.length === 1) {
      const m = options.find(o => String(o.id) === values[0]);
      lbl.textContent = (label ? label + ': ' : '') + (m ? m.name : values[0]);
    } else {
      lbl.textContent = (label ? label + ': ' : '');
      const cnt = document.createElement('span');
      cnt.className = 'ms-count';
      cnt.style.cssText = 'background:#185FA5;color:#fff;border-radius:999px;padding:.05rem .4rem;font-size:.72rem;font-weight:700;margin-left:.2rem;';
      cnt.textContent = values.length;
      btn.appendChild(lbl);
      btn.appendChild(cnt);
      const tail = document.createElement('span'); tail.textContent = ' selected'; tail.style.opacity = '.85'; tail.style.fontSize = '.78rem'; tail.style.marginLeft = '.25rem';
      btn.appendChild(tail);
      btn.appendChild(document.createTextNode(' \u25BE'));
      return;
    }
    btn.appendChild(lbl);
    btn.appendChild(document.createTextNode(' \u25BE'));
  }
  renderBtn();
  wrap.appendChild(btn);

  let panel = null;
  function openPanel() {
    if (panel) return;
    panel = document.createElement('div');
    panel.className = 'ms-dropdown-panel';
    panel.style.cssText = 'position: absolute; top: 100%; left: 0; min-width: 260px; max-width: 340px; max-height: 380px; overflow-y: auto; background: #fff; border: 1px solid var(--border, #e5e7eb); border-radius: 10px; box-shadow: 0 8px 24px rgba(15,23,42,.14); padding: .55rem; margin-top: .3rem; z-index: 1000;';

    // Search box
    const search = document.createElement('input');
    search.type = 'search';
    search.className = 'ms-search';
    search.placeholder = 'Search\u2026';
    panel.appendChild(search);

    // Action row
    const actionRow = document.createElement('div');
    actionRow.className = 'ms-actions';
    const allBtn = document.createElement('button');
    allBtn.type = 'button'; allBtn.textContent = 'Select All'; allBtn.className = 'btn small primary';
    const noneBtn = document.createElement('button');
    noneBtn.type = 'button'; noneBtn.textContent = 'Deselect All'; noneBtn.className = 'btn small ghost';
    actionRow.appendChild(allBtn); actionRow.appendChild(noneBtn);
    panel.appendChild(actionRow);

    const list = document.createElement('div');
    panel.appendChild(list);
    function renderList() {
      list.innerHTML = '';
      const q = search.value.trim().toLowerCase();
      let shown = 0;
      options.forEach(o => {
        if (q && !String(o.name).toLowerCase().includes(q)) return;
        shown++;
        const row = document.createElement('label');
        row.className = 'ms-row' + (values.includes(String(o.id)) ? ' is-checked' : '');
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.checked = values.includes(String(o.id));
        cb.onchange = () => {
          const v = String(o.id);
          if (cb.checked) {
            if (!values.includes(v)) values.push(v);
            row.classList.add('is-checked');
          } else {
            const i = values.indexOf(v); if (i >= 0) values.splice(i, 1);
            row.classList.remove('is-checked');
          }
        };
        row.appendChild(cb);
        const tx = document.createElement('span');
        tx.textContent = o.name;
        row.appendChild(tx);
        list.appendChild(row);
      });
      if (!shown) {
        const empty = document.createElement('div');
        empty.className = 'muted'; empty.style.padding = '.5rem'; empty.style.textAlign = 'center';
        empty.textContent = 'No matches';
        list.appendChild(empty);
      }
    }
    renderList();
    search.addEventListener('input', renderList);
    allBtn.onclick = (e) => { e.preventDefault(); values = options.map(o => String(o.id)); renderList(); };
    noneBtn.onclick = (e) => { e.preventDefault(); values = []; renderList(); };

    // Footer
    const footer = document.createElement('div');
    footer.style.cssText = 'display: flex; gap: .35rem; margin-top: .4rem; padding-top: .4rem; border-top: 1px solid var(--border, #e5e7eb);';
    const cancelBtn = document.createElement('button');
    cancelBtn.type = 'button'; cancelBtn.textContent = 'Cancel'; cancelBtn.className = 'btn ghost small';
    cancelBtn.style.cssText = 'flex: 1;';
    const applyBtn = document.createElement('button');
    applyBtn.type = 'button'; applyBtn.textContent = 'Apply'; applyBtn.className = 'btn primary small';
    applyBtn.style.cssText = 'flex: 1;';
    footer.appendChild(cancelBtn); footer.appendChild(applyBtn);
    panel.appendChild(footer);
    cancelBtn.onclick = (e) => { e.preventDefault(); closePanel(); };
    applyBtn.onclick = (e) => { e.preventDefault(); closePanel(); renderBtn(); if (typeof onApply === 'function') onApply(values.slice()); };

    wrap.appendChild(panel);
    setTimeout(() => document.addEventListener('mousedown', outsideClick), 0);
  }
  function closePanel() {
    if (panel && panel.parentNode) panel.parentNode.removeChild(panel);
    panel = null;
    document.removeEventListener('mousedown', outsideClick);
  }
  function outsideClick(e) {
    if (!wrap.contains(e.target)) closePanel();
  }
  btn.addEventListener('click', (e) => { e.preventDefault(); panel ? closePanel() : openPanel(); });

  // Programmatic API
  wrap.getValues = () => values.slice();
  wrap.setValues = (v) => { values = (v || []).map(String); renderBtn(); };
  return wrap;
}
/**
 * Rule-builder modal — generic Field/Operator/Value triplet editor.
 *
 * Use this when the simple Status/Source dropdown isn't expressive enough.
 * Operators supported: = != contains not_contains starts_with ends_with
 * is_empty is_not_empty in not_in.
 *
 * @param {Object} opts
 * @param {Array} opts.fields  Array of { id, label, type: 'text'|'enum'|'number'|'date', options? }
 * @param {Array} opts.rules   Existing rules (array of { field, op, value })
 * @param {Function} opts.onApply  Callback with (newRules)
 */
function ruleBuilderModal({ fields, rules, onApply, title }) {
  fields = fields || [];
  rules = (rules || []).slice();
  const OPS_TEXT = [
    { id: 'eq',          label: 'is equal to' },
    { id: 'neq',         label: 'is not equal to' },
    { id: 'contains',    label: 'contains' },
    { id: 'not_contains',label: 'does not contain' },
    { id: 'starts_with', label: 'starts with' },
    { id: 'ends_with',   label: 'ends with' },
    { id: 'is_empty',    label: 'is empty (unknown)' },
    { id: 'is_not_empty',label: 'has any value' }
  ];
  const OPS_ENUM = [
    { id: 'eq',          label: 'is' },
    { id: 'neq',         label: 'is not' },
    { id: 'in',          label: 'is one of' },
    { id: 'not_in',      label: 'is none of' },
    { id: 'is_empty',    label: 'is empty (unknown)' },
    { id: 'is_not_empty',label: 'has any value' }
  ];
  const OPS_NUM = [
    { id: 'eq',  label: '=' }, { id: 'neq', label: '\u2260' },
    { id: 'gt',  label: '>' }, { id: 'gte', label: '\u2265' },
    { id: 'lt',  label: '<' }, { id: 'lte', label: '\u2264' },
    { id: 'is_empty', label: 'is empty' }, { id: 'is_not_empty', label: 'has any value' }
  ];
  const OPS_DATE = [
    { id: 'eq', label: 'is on' },
    { id: 'gte', label: 'on or after' },
    { id: 'lte', label: 'on or before' },
    { id: 'between', label: 'between' },
    { id: 'is_empty', label: 'is empty' }, { id: 'is_not_empty', label: 'has any value' }
  ];

  const modal = document.createElement('div');
  modal.className = 'modal-backdrop';
  const dlg = document.createElement('div');
  dlg.className = 'modal';
  dlg.style.cssText = 'max-width: 720px; min-width: 520px;';
  dlg.innerHTML = '<h3 style="margin-top:0">\u2699\ufe0f ' + (title || 'Filter rules') + '</h3>' +
    '<p class="muted" style="font-size:.85rem">Build advanced rules: equal to, not equal to, contains, is empty, etc. Multiple rules combine with AND.</p>';

  const list = document.createElement('div');
  list.style.cssText = 'display:flex; flex-direction:column; gap:.4rem; margin-top:.5rem;';
  dlg.appendChild(list);

  function opsFor(field) {
    if (!field) return OPS_TEXT;
    if (field.type === 'enum') return OPS_ENUM;
    if (field.type === 'number') return OPS_NUM;
    if (field.type === 'date') return OPS_DATE;
    return OPS_TEXT;
  }

  function addRowFromRule(rule) {
    const row = document.createElement('div');
    row.style.cssText = 'display:grid; grid-template-columns: 1.1fr 1.1fr 2fr auto; gap:.4rem; align-items:center;';
    const fSel = document.createElement('select'); fSel.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px;';
    fields.forEach(f => { const o = document.createElement('option'); o.value = f.id; o.textContent = f.label; fSel.appendChild(o); });
    if (rule && rule.field) fSel.value = rule.field;
    const oSel = document.createElement('select'); oSel.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px;';
    const vBox = document.createElement('div'); vBox.style.cssText = 'min-width:0;';
    function rebuildOps() {
      const f = fields.find(x => x.id === fSel.value);
      oSel.innerHTML = '';
      opsFor(f).forEach(op => { const o = document.createElement('option'); o.value = op.id; o.textContent = op.label; oSel.appendChild(o); });
      if (rule && rule.op) oSel.value = rule.op;
      rebuildValue();
    }
    function rebuildValue() {
      const f = fields.find(x => x.id === fSel.value);
      vBox.innerHTML = '';
      const op = oSel.value;
      if (op === 'is_empty' || op === 'is_not_empty') {
        const span = document.createElement('span'); span.className = 'muted'; span.style.fontSize = '.82rem';
        span.textContent = '(no value needed)';
        vBox.appendChild(span);
        vBox._read = () => null;
        return;
      }
      if (f && f.type === 'enum' && (op === 'in' || op === 'not_in') && f.options) {
        const ms = multiSelectDropdown({
          label: '', options: f.options, values: (rule && Array.isArray(rule.value)) ? rule.value : []
        });
        vBox.appendChild(ms);
        vBox._read = () => ms.getValues();
        return;
      }
      if (f && f.type === 'enum' && f.options) {
        const sel = document.createElement('select'); sel.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px; width:100%;';
        f.options.forEach(o => { const opt = document.createElement('option'); opt.value = o.id; opt.textContent = o.name; sel.appendChild(opt); });
        if (rule && rule.value != null) sel.value = String(rule.value);
        vBox.appendChild(sel);
        vBox._read = () => sel.value;
        return;
      }
      if (f && f.type === 'date') {
        if (op === 'between') {
          const a = document.createElement('input'); a.type = 'date'; a.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px;';
          const b = document.createElement('input'); b.type = 'date'; b.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px;';
          if (rule && Array.isArray(rule.value)) { a.value = rule.value[0] || ''; b.value = rule.value[1] || ''; }
          vBox.style.display = 'flex'; vBox.style.gap = '.3rem';
          vBox.appendChild(a); vBox.appendChild(b);
          vBox._read = () => [a.value, b.value];
          return;
        }
        const inp = document.createElement('input'); inp.type = 'date'; inp.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px; width:100%;';
        if (rule && rule.value != null) inp.value = String(rule.value);
        vBox.appendChild(inp); vBox._read = () => inp.value;
        return;
      }
      if (f && f.type === 'number') {
        const inp = document.createElement('input'); inp.type = 'number'; inp.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px; width:100%;';
        if (rule && rule.value != null) inp.value = String(rule.value);
        vBox.appendChild(inp); vBox._read = () => inp.value;
        return;
      }
      const inp = document.createElement('input'); inp.type = 'text'; inp.placeholder = 'value\u2026'; inp.style.cssText = 'padding:.4rem .55rem; border:1px solid var(--border, #e5e7eb); border-radius:6px; width:100%;';
      if (rule && rule.value != null) inp.value = String(rule.value);
      vBox.appendChild(inp); vBox._read = () => inp.value;
    }
    rebuildOps();
    fSel.onchange = rebuildOps;
    oSel.onchange = rebuildValue;
    const delBtn = document.createElement('button');
    delBtn.type = 'button'; delBtn.className = 'btn sm danger ghost'; delBtn.textContent = '\u2715';
    delBtn.onclick = () => row.remove();
    row.appendChild(fSel); row.appendChild(oSel); row.appendChild(vBox); row.appendChild(delBtn);
    row._read = () => ({
      field: fSel.value, op: oSel.value,
      value: (vBox._read ? vBox._read() : null)
    });
    list.appendChild(row);
    return row;
  }

  if (rules.length === 0) addRowFromRule({});
  else rules.forEach(r => addRowFromRule(r));

  const addBtn = document.createElement('button');
  addBtn.type = 'button'; addBtn.className = 'btn ghost'; addBtn.textContent = '+ Add another rule';
  addBtn.style.marginTop = '.4rem';
  addBtn.onclick = () => addRowFromRule({});
  dlg.appendChild(addBtn);

  const footer = document.createElement('div');
  footer.style.cssText = 'display:flex; gap:.4rem; justify-content:flex-end; margin-top:.85rem;';
  const cancelBtn = document.createElement('button');
  cancelBtn.type = 'button'; cancelBtn.className = 'btn ghost'; cancelBtn.textContent = 'Cancel';
  cancelBtn.onclick = () => modal.remove();
  const clearBtn = document.createElement('button');
  clearBtn.type = 'button'; clearBtn.className = 'btn ghost'; clearBtn.textContent = 'Clear all';
  clearBtn.onclick = () => { list.innerHTML = ''; addRowFromRule({}); };
  const applyBtn = document.createElement('button');
  applyBtn.type = 'button'; applyBtn.className = 'btn primary'; applyBtn.textContent = 'Apply rules';
  applyBtn.onclick = () => {
    const out = [];
    list.childNodes.forEach(row => {
      if (row._read) {
        const r = row._read();
        if (!r.field) return;
        const noValueOp = (r.op === 'is_empty' || r.op === 'is_not_empty');
        if (!noValueOp && (r.value == null || r.value === '' || (Array.isArray(r.value) && r.value.length === 0))) return;
        out.push(r);
      }
    });
    modal.remove();
    if (typeof onApply === 'function') onApply(out);
  };
  footer.appendChild(clearBtn); footer.appendChild(cancelBtn); footer.appendChild(applyBtn);
  dlg.appendChild(footer);

  modal.appendChild(dlg);
  document.body.appendChild(modal);
}

/**
 * Wraps ruleBuilderModal as an inline button suitable for filter toolbars.
 * @returns A <button> element + .getRules() / .setRules(rules)
 */
function ruleBuilderButton({ fields, label, storageKey, onChange }) {
  let rules = [];
  if (storageKey) {
    try { const s = localStorage.getItem(storageKey); if (s) rules = JSON.parse(s) || []; } catch (_) {}
  }
  const btn = document.createElement('button');
  btn.type = 'button';
  btn.className = 'btn ghost';
  function refresh() {
    btn.textContent = (rules.length ? '\ud83d\udd0d ' + rules.length + ' rule' + (rules.length === 1 ? '' : 's') : (label || '+ Filter rule'));
  }
  refresh();
  btn.onclick = () => {
    ruleBuilderModal({
      fields: fields,
      rules: rules,
      title: label || 'Filter rules',
      onApply: (newRules) => {
        rules = newRules;
        if (storageKey) try { localStorage.setItem(storageKey, JSON.stringify(rules)); } catch (_) {}
        refresh();
        if (typeof onChange === 'function') onChange(rules);
      }
    });
  };
  btn.getRules = () => rules.slice();
  btn.setRules = (r) => { rules = r || []; refresh(); };
  return btn;
}

/**
 * Apply a list of rules to a row object — returns true if the row passes.
 * Used as a CLIENT-side post-filter so backend doesn't need to understand
 * every operator.
 */
// LEADS_RULE_CF_NCONTAINS_v1 — read custom-field values from extra_json
// (where lead forms / CSV upload / website API write them) AND meta_json
// (where FB Lead Ads / Pabbly / Make.com sometimes land them) when the rule
// field is a custom field with the 'cf_' prefix. Without this fallback the
// rule sees undefined on every row, so 'does not contain X' matched
// every row (including the ones that DO contain X) — the bug user hit
// when filtering Page Name does not contain New Shop on the test tenant.
function _ruleRowValue(row, field) {
  // Top-level column wins (e.g. name, phone, status_name, source).
  if (row && Object.prototype.hasOwnProperty.call(row, field) && row[field] != null) {
    return row[field];
  }
  // Custom fields are stored under the un-prefixed key inside extra_json /
  // meta_json. The rule builder emits ids like 'cf_page_name'.
  if (field && field.indexOf('cf_') === 0) {
    const key = field.slice(3);
    const _read = (raw) => {
      if (!raw) return undefined;
      try {
        const obj = (typeof raw === 'string') ? JSON.parse(raw) : raw;
        if (obj && Object.prototype.hasOwnProperty.call(obj, key) && obj[key] != null) return obj[key];
      } catch (_) {}
      return undefined;
    };
    let v = _read(row.extra_json);
    if (v == null) v = _read(row.meta_json);
    if (v == null && row.extra && Object.prototype.hasOwnProperty.call(row.extra, key)) v = row.extra[key];
    if (v != null) return v;
  }
  return undefined;
}

function _applyClientRules(row, rules) {
  if (!Array.isArray(rules) || rules.length === 0) return true;
  for (const r of rules) {
    const v = _ruleRowValue(row, r.field);
    const sv = (v == null) ? '' : String(v).toLowerCase();
    const cmp = (r.value == null) ? '' : (Array.isArray(r.value) ? r.value.map(x => String(x).toLowerCase()) : String(r.value).toLowerCase());
    let pass = true;
    switch (r.op) {
      case 'eq':         pass = sv === cmp; break;
      case 'neq':        pass = sv !== cmp; break;
      case 'contains':   pass = sv.includes(cmp); break;
      case 'not_contains': pass = !sv.includes(cmp); break;
      case 'starts_with':pass = sv.startsWith(cmp); break;
      case 'ends_with':  pass = sv.endsWith(cmp); break;
      case 'is_empty':   pass = !sv; break;
      case 'is_not_empty': pass = !!sv; break;
      case 'in':         pass = Array.isArray(cmp) ? cmp.includes(sv) : sv === cmp; break;
      case 'not_in':     pass = Array.isArray(cmp) ? !cmp.includes(sv) : sv !== cmp; break;
      case 'gt':         pass = Number(v) > Number(r.value); break;
      case 'gte':        pass = Number(v) >= Number(r.value); break;
      case 'lt':         pass = Number(v) < Number(r.value); break;
      case 'lte':        pass = Number(v) <= Number(r.value); break;
      case 'between':    pass = (sv >= cmp[0]) && (sv <= cmp[1]); break;
      default:           pass = true;
    }
    if (!pass) return false;
  }
  return true;
}

function parseFieldOptions(raw) {
  // Lenient parser: accept pipe-, comma-, or newline-separated lists.
  // Backwards compatible with existing pipe-separated data.
  return String(raw || '').split(/[|,\n]/).map(s => s.trim()).filter(Boolean);
}
// Statuses that mark a lead as "dead-end" and DON'T need the rep to fill
// the full mandatory custom-field set (no point asking for capital range,
// risk tolerance, etc. when the lead never picked up or said no).
// Matched case-insensitively against status name.
const SKIP_REQUIRED_STATUSES = [
  'not pick', 'not picked', 'not picking',
  'not interested',
  'junk', 'spam',
  'does not exist', 'doesnt exist', "doesn't exist", 'invalid',
  'broker'
];
function _statusSkipsRequired(statusName) {
  const n = String(statusName || '').toLowerCase().trim();
  return SKIP_REQUIRED_STATUSES.some(s => n.includes(s));
}

function customFieldInput(cf, val) {
  const name = 'cf_' + cf.key;
  const opts = parseFieldOptions(cf.options);
  // Required attribute on the underlying input — backed up by JS validation
  // in the lead-modal submit handler so multi-select / checkbox cases also
  // work. Admins are exempt from required-field enforcement (they often
  // need to update status / notes without re-typing every required field
  // the rep should have filled). Skip the HTML5 `required` attribute for
  // admins so the browser-level "Please select an item in the list"
  // popup doesn't fire either.
  // Required fields are also tagged with data-cf-required="1" so the lead
  // form can dynamically toggle the `required` attribute when the user
  // picks a "dead-end" status (Not Pick / Not Interested / Junk / etc.).
  const reqAttr = (cf.is_required && CRM.user?.role !== 'admin') ? { required: true } : {};
  if (cf.is_required && CRM.user?.role !== 'admin') reqAttr['data-cf-required'] = '1';
  let input;
  if (cf.field_type === 'textarea') input = h('textarea', Object.assign({ name }, reqAttr), val || '');
  else if (cf.field_type === 'select') input = h('select', Object.assign({ name }, reqAttr),
    h('option', { value: '' }, '—'),
    ...opts.map(o => h('option', { value: o, selected: val === o ? 'selected' : null }, o)));
  else if (cf.field_type === 'multiselect') {
    // Render as a checkbox grid instead of a native <select multiple>.
    // Native multi-select requires Ctrl/Cmd+click and is unusable on touch.
    // FormData.getAll('cf_<key>') still returns the same array of checked values,
    // so the existing save logic at line ~1549 works unchanged.
    const selectedSet = new Set(String(val || '').split(',').map(s => s.trim()).filter(Boolean));
    if (opts.length === 0) {
      input = h('div', { class: 'cf-opts-help' },
        '⚠️ No options defined yet — add some in Admin → Custom fields.');
    } else {
      input = h('div', { class: 'cf-multi-grid' },
        ...opts.map(o => h('label', {},
          h('input', { type: 'checkbox', name, value: o, checked: selectedSet.has(o) ? 'checked' : null }),
          ' ', o
        ))
      );
    }
  }
  else if (cf.field_type === 'checkbox') input = h('input', { type: 'checkbox', name, checked: val ? 'checked' : null, value: '1' });
  else input = h('input', Object.assign({ name, value: val || '', type: cf.field_type === 'number' ? 'number' : cf.field_type === 'date' ? 'date' : 'text' }, reqAttr));
  // Long-form fields span both columns in the grid for breathing room.
  const rowClass = (cf.field_type === 'multiselect' || cf.field_type === 'textarea') ? 'f-row full' : 'f-row';
  return h('div', { class: rowClass }, h('label', {}, cf.label + (cf.is_required ? ' *' : '')), input);
}

/**
 * Action timeline block — fetches lead_actions for this lead and shows
 * a vertical timeline: Created → 1st action → 2nd action → … with the
 * minutes elapsed since lead-create next to each step.
 *
 * Always renders a placeholder while loading; on failure, hides itself
 * silently so the modal remains usable on older deploys.
 */
/**
 * Post-sale project stage tracker block. Shown on every lead detail —
 * if no stages defined yet, shows a hint pointing admin to Settings.
 * If stages exist and the lead has no current stage, shows a "Start
 * delivery tracker" button that sets the first stage. If the lead is
 * mid-flow, shows a horizontal progress strip with the current step
 * highlighted, and an "Advance to next" button.
 */
function projectStageBlock(leadId, lead) {
  const wrap = h('div', { class: 'card', style: { marginTop: '1rem', padding: '1rem' } },
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', marginBottom: '.5rem' } },
      h('h4', { style: { margin: 0, flex: 1 } }, '🚚 Sale Final Closure'),
      h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'Stage tracker for what happens after the sale')
    ),
    h('div', { class: 'muted' }, 'Loading…')
  );
  (async () => {
    try {
      const stages = await api('api_projectStages_list');
      const body = wrap.lastChild;
      if (!stages.length) {
        body.replaceWith(h('p', { class: 'muted', style: { margin: 0 } },
          'No stages defined yet. Admin can set them up under Settings → 🚚 Sale Final Closure Stages.'));
        return;
      }
      const currentId = Number(lead.project_stage_id) || 0;
      const idx = stages.findIndex(s => Number(s.id) === currentId);
      const isLast = idx === stages.length - 1;
      // Progress strip
      const strip = h('div', {
        style: { display: 'flex', flexWrap: 'wrap', gap: '.35rem', marginBottom: '.75rem' }
      });
      stages.forEach((s, i) => {
        const isPast = idx > i;
        const isCurrent = idx === i;
        strip.appendChild(h('span', {
          style: {
            padding: '.3rem .6rem', borderRadius: '999px', fontSize: '.75rem', fontWeight: 600,
            background: isCurrent ? '#3b82f6' : (isPast ? '#10b981' : '#e5e7eb'),
            color: isCurrent || isPast ? '#fff' : '#6b7280'
          },
          title: s.description || ''
        }, (isPast ? '✓ ' : (isCurrent ? '▶ ' : '')) + s.name));
      });
      const advanceBtn = (idx < stages.length - 1) ? h('button', {
        class: 'btn primary', onclick: async () => {
          const notes = prompt('Optional notes for this transition (e.g. cheque #, doc reference):', '') || '';
          try {
            const r = await api('api_projectStages_advanceLead', leadId, notes);
            toast('Advanced to: ' + r.stage_name);
            // Re-render the modal so the new stage shows. Easiest path: close and reopen.
            const modal = document.querySelector('.modal-backdrop');
            if (modal) modal.remove();
            openLeadModal(leadId);
          } catch (e) { toast(e.message, 'err'); }
        }
      }, idx < 0 ? '▶ Start delivery tracker' : '➡ Advance to next stage') : null;
      const setBtn = h('button', {
        class: 'btn', onclick: () => {
          const choices = stages.map(s => '#' + s.sort_order + ' — ' + s.name).join('\n');
          const ans = prompt('Jump to stage by typing its number (#):\n\n' + choices, '');
          if (!ans) return;
          const num = Number(ans.replace(/[^\d]/g, ''));
          const target = stages.find(s => Number(s.sort_order) === num);
          if (!target) return toast('Unknown stage number', 'err');
          const notes = prompt('Optional notes:', '') || '';
          api('api_projectStages_setForLead', leadId, target.id, notes)
            .then(r => {
              toast('Set to: ' + r.stage_name);
              const modal = document.querySelector('.modal-backdrop');
              if (modal) modal.remove();
              openLeadModal(leadId);
            })
            .catch(e => toast(e.message, 'err'));
        }
      }, '↪ Jump to specific stage');
      const summary = h('div', { class: 'muted', style: { fontSize: '.85rem', marginBottom: '.6rem' } },
        idx < 0 ? 'Tracker not started yet — click below to enter the first stage.'
        : isLast ? '✅ On the final stage (' + stages[idx].name + ').'
        : '▶ Currently at: ' + stages[idx].name +
          (lead.project_stage_started_at ? ' · since ' + fmtDate(lead.project_stage_started_at, 'relative') : '')
      );
      const actionsRow = h('div', { class: 'actions', style: { gap: '.5rem' } });
      if (advanceBtn) actionsRow.appendChild(advanceBtn);
      actionsRow.appendChild(setBtn);
      const newBody = h('div', {}, strip, summary, actionsRow);
      body.replaceWith(newBody);
    } catch (e) {
      wrap.lastChild.replaceWith(h('div', { class: 'error-box' }, e.message));
    }
  })();
  return wrap;
}

/**
 * Inventory matches block — fetches api_inventory_match(leadId) and renders
 * up to 8 ranked suggestions inline on the lead detail. Each card shows
 * the item, price, type and a "Recommend" button that adds a remark
 * "📦 Recommended <name>" so the team sees what was suggested.
 *
 * The match algorithm filters by status=available, lead.budget_max
 * (with 10% headroom) and lead.requirement_type. Blank inputs = no
 * filter on that axis.
 */
function matchingInventoryBlock(leadId) {
  const wrap = h('div', { class: 'card', style: { marginTop: '1rem', padding: '1rem' } },
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', marginBottom: '.5rem' } },
      h('h4', { style: { margin: 0, flex: 1 } }, '📦 Matching inventory'),
      h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'Auto-suggested based on budget + requirement type')
    ),
    h('div', { class: 'muted' }, 'Loading…')
  );
  (async () => {
    try {
      const matches = await api('api_inventory_match', leadId);
      const body = wrap.lastChild;
      if (!matches.length) {
        body.replaceWith(h('p', { class: 'muted', style: { margin: 0 } },
          'No matching inventory yet. Add items under 📦 Inventory or set a budget / requirement type on this lead.'));
        return;
      }
      const grid = h('div', { class: 'cards', style: { gap: '.5rem', marginTop: '.25rem' } });
      matches.forEach(m => {
        grid.appendChild(h('div', {
          class: 'card', style: { padding: '.75rem', border: '1px solid #e5e7eb', display: 'flex', flexDirection: 'column', gap: '.35rem' }
        },
          h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', justifyContent: 'space-between' } },
            h('strong', {}, m.name),
            h('span', { class: 'tag', style: { background: '#dcfce7', color: '#166534' } }, '★ ' + m.score)
          ),
          h('div', { style: { fontSize: '.95rem' } }, '₹ ' + Number(m.price).toLocaleString('en-IN')),
          m.item_type ? h('div', { class: 'muted', style: { fontSize: '.8rem' } }, '📁 ' + m.item_type) : null,
          m.location ? h('div', { class: 'muted', style: { fontSize: '.8rem' } }, '📍 ' + m.location) : null,
          h('button', { class: 'btn sm primary', onclick: async () => {
            try {
              await api('api_leads_addRemark', leadId, {
                remark: '📦 Recommended ' + m.name +
                        ' · ₹' + Number(m.price).toLocaleString('en-IN') +
                        (m.item_type ? ' · ' + m.item_type : '') +
                        (m.location ? ' · ' + m.location : '')
              });
              toast('Recommendation logged on lead');
            } catch (e) { toast(e.message, 'err'); }
          } }, '+ Recommend')
        ));
      });
      body.replaceWith(grid);
    } catch (e) {
      wrap.lastChild.replaceWith(h('div', { class: 'error-box' }, e.message));
    }
  })();
  return wrap;
}

function actionTimelineBlock(leadId) {
  const wrap = h('div', { class: 'timeline-block' },
    h('div', { class: 'timeline-head' },
      h('h4', {}, '📋 Activity timeline'),
      h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'Every action on this lead — newest first')
    ),
    h('div', { class: 'muted' }, 'Loading…')
  );
  api('api_lead_actions', leadId).then(rows => {
    wrap.innerHTML = '';
    wrap.appendChild(h('div', { class: 'timeline-head' },
      h('h4', {}, '📋 Activity timeline'),
      h('span', { class: 'muted', style: { fontSize: '.78rem' } }, (rows?.length || 0) + ' events · newest first')
    ));
    if (!rows || rows.length === 0) {
      wrap.appendChild(h('p', { class: 'muted' }, 'No activity logged yet for this lead.'));
      return;
    }
    const created = rows[0]?.created_at;
    const fmtAge = (when) => {
      if (!created || !when) return '';
      const diffMs = new Date(when).getTime() - new Date(created).getTime();
      if (diffMs < 60_000) return Math.round(diffMs / 1000) + ' sec';
      if (diffMs < 3_600_000) return Math.round(diffMs / 60_000) + ' min';
      if (diffMs < 86_400_000) return (diffMs / 3_600_000).toFixed(1) + ' hr';
      return (diffMs / 86_400_000).toFixed(1) + ' days';
    };
    // Visual config per action type — icon + label + chip color so the
    // timeline reads at a glance.
    const cfg = {
      created:        { icon: '🎯', label: 'Lead received',        color: '#3b82f6' },
      status_change:  { icon: '🔄', label: 'Status changed',       color: '#8b5cf6' },
      remark:         { icon: '💬', label: 'Remark added',         color: '#06b6d4' },
      note_updated:   { icon: '📝', label: 'Notes updated',        color: '#06b6d4' },
      tags_updated:   { icon: '🏷️', label: 'Tags updated',         color: '#06b6d4' },
      followup_set:   { icon: '⏰', label: 'Follow-up scheduled',  color: '#f59e0b' },
      assigned:       { icon: '👤', label: 'Reassigned',           color: '#64748b' },
      call:           { icon: '📞', label: 'Call',                 color: '#ec4899' },
      whatsapp_out:   { icon: '📤', label: 'WhatsApp sent',        color: '#25d366' },
      whatsapp_in:    { icon: '📥', label: 'WhatsApp received',    color: '#10b981' },
      qualified:      { icon: '⭐', label: 'Marked qualified',     color: '#10b981' },
      unqualified:    { icon: '✕',  label: 'Unmarked qualified',   color: '#ef4444' },
      duplicated:     { icon: '📋', label: 'Duplicated',           color: '#64748b' },
      email_out:      { icon: '📧', label: 'Email sent',           color: '#3b82f6' },
      merged_from_duplicate: { icon: '🔀', label: 'Merged from duplicate', color: '#7c3aed' }  /* LEAD_MERGE_AUDIT_v1 */
    };

    // Render in REVERSE chronological order (newest first) — easier to skim
    // when checking "what was the last thing that happened?"
    const sorted = [...rows].reverse();
    const ul = h('ul', { class: 'timeline timeline-rich' });
    sorted.forEach(r => {
      const c = cfg[r.action_type] || { icon: '•', label: r.action_type, color: '#94a3b8' };
      const m = r.meta || {};
      // Compose a sub-line based on action type
      let sub = null;
      if (r.action_type === 'status_change') {
        sub = m.to_status_id || m.from_status_id ? ('Status #' + (m.from_status_id || '?') + ' → #' + (m.to_status_id || '?')) : null;
      } else if (r.action_type === 'remark') {
        sub = m.remark || null;
      } else if (r.action_type === 'followup_set') {
        sub = m.due_at ? ('Due ' + fmtDate(m.due_at)) : null;
      } else if (r.action_type === 'assigned') {
        // REASSIGN_LOG_v1 — prefer human names if backend wrote them.
        // Falls back to "User #N" for old rows that only have ids.
        const fromTxt = m.from_user_name || (m.from_user_id || m.from ? ('User #' + (m.from_user_id || m.from)) : '—');
        const toTxt   = m.to_user_name   || (m.to_user_id   || m.to   ? ('User #' + (m.to_user_id   || m.to))   : '—');
        sub = fromTxt + ' → ' + toTxt + (m.bulk ? ' (bulk)' : '');
      } else if (r.action_type === 'whatsapp_out') {
        sub = (m.template ? '[Template: ' + m.template + '] ' : '') + (m.preview || '');
        if (m.error) sub += ' ⚠ ' + m.error;
      } else if (r.action_type === 'whatsapp_in') {
        sub = m.preview || ('[' + (m.type || 'message') + ']');
      } else if (r.action_type === 'note_updated') {
        sub = m.preview || null;
      } else if (r.action_type === 'tags_updated') {
        sub = m.tags || null;
      } else if (r.action_type === 'merged_from_duplicate') {  /* LEAD_MERGE_AUDIT_v1 */
        const who = m.source_name || m.source_phone || m.source_email || ('lead #' + (m.source_id || '?'));
        const when = m.source_created_at ? (' · originally arrived ' + fmtDate(m.source_created_at, 'relative')) : '';
        const id = m.source_id ? (' (#' + m.source_id + ')') : '';
        sub = 'Absorbed: ' + who + id + when;
      }
      ul.appendChild(h('li', {},
        h('span', { class: 'tl-dot tl-dot-rich', style: { background: c.color } }, c.icon),
        h('div', { class: 'tl-body' },
          h('div', { class: 'tl-title' },
            h('b', {}, c.label),
            r.user_name ? h('span', { class: 'muted', style: { marginLeft: '.5rem', fontSize: '.78rem' } }, ' by ' + r.user_name) : null
          ),
          sub ? h('div', { class: 'tl-sub muted', style: { fontSize: '.85rem', marginTop: '.15rem' } }, String(sub).slice(0, 240) + (String(sub).length > 240 ? '…' : '')) : null,
          h('div', { class: 'tl-meta muted' },
            fmtDate(r.created_at, 'relative'),
            r.action_type !== 'created' ? ' · +' + fmtAge(r.created_at) + ' since received' : ''
          )
        )
      ));
    });
    wrap.appendChild(ul);
  }).catch(() => { wrap.style.display = 'none'; });
  return wrap;
}

function recordingsBlock(leadId) {
  const wrap = h('div', { class: 'recordings-block' }, h('h4', {}, '📼 Call recordings & AI Summary'));
  const list = h('ul', { class: 'rec-list' }, h('li', { class: 'muted' }, 'Loading…'));
  wrap.appendChild(list);
  api('api_leads_recordings', leadId).then(rows => {
    list.innerHTML = '';
    if (!rows || rows.length === 0) {
      list.appendChild(aiSummaryPlaceholder());
      return;
    }
    rows.forEach(r => list.appendChild(renderRecordingItem(r)));
  }).catch(e => {
    list.innerHTML = '';
    list.appendChild(h('li', { class: 'muted' }, 'Could not load: ' + e.message));
  });
  return wrap;
}

// Placeholder shown when a lead has no recordings yet — gives users a
// preview of what the AI Summary section will look like once a call is logged.
function aiSummaryPlaceholder() {
  return h('li', { class: 'rec-item rec-placeholder' },
    h('div', { class: 'placeholder-banner' },
      h('div', { class: 'placeholder-title' }, '🤖 AI Call Summary will appear here'),
      h('div', { class: 'placeholder-sub' },
        'Once a call is recorded for this lead, our AI automatically transcribes the conversation and shows the summary, sentiment, action items, suggested next status & a quality rating — all in this space.'
      )
    ),
    h('div', { class: 'ai-summary-card sample' },
      h('div', { class: 'ai-header' },
        h('span', { class: 'ai-badge' }, '🤖 AI Summary'),
        h('span', { class: 'ai-sentiment', style: 'color:#10b981' }, '😊 Positive'),
        h('span', { class: 'sample-tag' }, 'Sample preview')
      ),
      h('div', { class: 'ai-summary-text' },
        'Customer is interested in a 2BHK unit, budget around ₹85L. Discussed floor plans, payment schedule and possession timeline. Asked about home-loan tie-ups with HDFC.'
      ),
      h('div', { class: 'ai-insight' }, '💡 High-intent buyer — wants a site visit this weekend.'),
      h('div', { class: 'ai-actions' },
        h('div', { class: 'ai-actions-title' }, '✓ Action items'),
        h('div', { class: 'ai-action-item' }, '• Share 2BHK floor plan PDF on WhatsApp'),
        h('div', { class: 'ai-action-item' }, '• Confirm Saturday 11 AM site visit'),
        h('div', { class: 'ai-action-item' }, '• Send HDFC pre-approval form')
      ),
      h('div', { class: 'ai-apply-row' },
        h('span', { class: 'muted' }, '⭐ Suggested rating: 5/5  ·  ⏰ Follow up in 2 days  ·  🎯 Suggested status: Hot lead')
      )
    ),
    h('div', { class: 'placeholder-foot muted' },
      '↑ This is what you will see here after the first call is recorded. Upload a recording or call from the dialler to generate a real AI summary.'
    )
  );
}

function renderRecordingItem(r) {
  const dur = Number(r.duration_s) || 0;
  const mm = Math.floor(dur / 60), ss = (dur % 60).toString().padStart(2, '0');
  const dirIcon = r.direction === 'in' ? '📲' : r.direction === 'missed' ? '⚠️' : '📞';
  // Prefix /t/<slug>/ so attachTenant middleware runs FIRST and locks
  // the request to the tenant the user is currently viewing. The
  // token-only fallback in the audio handler can pick the wrong tenant
  // when the same user_id exists in multiple tenants' users tables,
  // which would 404 the recording lookup. Belt + suspenders.
  const _tslug = (typeof window !== 'undefined' && window.TENANT_SLUG) ? window.TENANT_SLUG : '';
  const _audioUrl = (_tslug ? '/t/' + _tslug : '') + '/api/recordings/' + r.id + '/audio?token=' + encodeURIComponent(CRM.token || '');
  const audio = h('audio', {
    controls: true,
    preload: 'none',
    src: _audioUrl
  });
  // Download fallback — always available, just below the player. Critical
  // for recordings the browser can't decode (AMR-in-3GP from Samsung
  // dialer especially) — the user can save the file and play it locally
  // in any media player that handles AMR.
  const _dlLink = h('a', {
    href: _audioUrl,
    download: 'recording-' + r.id + '.mp3',
    style: { fontSize: '.75rem', color: '#64748b', marginLeft: '.5rem', textDecoration: 'underline' },
    title: 'Download the original recording file'
  }, '⬇ Download');
  // 🤖 AI Audit this call — manual on-demand processing. Always visible
  // so admins can force a fresh Gemini call even when ai_processed_at
  // is already set. Useful when the user wants the AI to re-listen
  // after the rep added context, or to bypass the per-user toggle.
  const _auditBtn = h('button', {
    class: 'btn sm',
    style: { marginLeft: '.5rem', background: '#eef2ff', color: '#4338ca', borderColor: '#a5b4fc', fontSize: '.75rem', padding: '2px 8px' },
    title: 'Force Gemini to (re-)transcribe + summarise this call now',
    onclick: async () => {
      _auditBtn.disabled = true;
      _auditBtn.textContent = '🤖 Auditing…';
      try {
        await api('api_recording_aiReprocess', r.id);
        toast('AI audit started — refreshing in a few seconds', 'ok');
        // Re-load the AI block so the polling loop picks up the new state
        if (aiBlock) {
          aiBlock.innerHTML = '<div class="ai-pending">🤖 Re-auditing…</div>';
          setTimeout(() => loadRecordingAI(r.id, aiBlock, 0), 4000);
        }
      } catch (e) { toast('Audit failed: ' + e.message, 'err'); }
      _auditBtn.disabled = false;
      _auditBtn.textContent = '🤖 AI Audit';
    }
  }, '🤖 AI Audit');
  // When this audio starts playing, pause every OTHER recording on the
  // page. Without this, two recordings can play simultaneously and the
  // admin can't tell which is which.
  audio.addEventListener('play', () => {
    document.querySelectorAll('audio').forEach(other => {
      if (other !== audio && !other.paused) {
        try { other.pause(); } catch (_) {}
      }
    });
  });
  audio.addEventListener('error', async () => {
    // Slim error feedback — full diagnostics removed now that playback
    // works. If something does fail, show a short toast and turn the
    // download link red so the user knows to try downloading instead.
    try {
      const r2 = await fetch(_audioUrl);
      let msg;
      if (r2.status === 410)      msg = '🎧 Recording has no audio bytes — re-sync from phone.';
      else if (r2.status === 404) msg = '🎧 Recording not found.';
      else if (r2.status === 401) msg = '🎧 Session expired — log out and back in.';
      else                        msg = '🎧 Playback failed (HTTP ' + r2.status + ') — try ⬇ Download.';
      if (typeof toast === 'function') toast(msg, 'err');
      _dlLink.style.color = '#dc2626';
      _dlLink.style.fontWeight = '600';
    } catch (e) {
      if (typeof toast === 'function') toast('🎧 Playback failed — try ⬇ Download', 'err');
    }
  });
  const aiBlock = h('div', { class: 'rec-ai-block' });
  // Lazy-load the AI summary on first paint. Polls every 10s while pending.
  loadRecordingAI(r.id, aiBlock);
  return h('li', { class: 'rec-item' },
    h('div', { class: 'rec-meta' },
      h('span', { class: 'rec-dir' }, dirIcon),
      h('b', {}, r.lead_name || r.phone || '—'),
      h('span', { class: 'muted' }, ' · ' + (r.rep_name ? r.rep_name + ' · ' : '') + fmtDate(r.created_at, 'relative') + ' · ' + mm + ':' + ss),
      _dlLink,
      _auditBtn
    ),
    audio,
    aiBlock
  );
}

/**
 * Fetch the AI summary for a recording and render it. If still pending,
 * poll every 10s. Renders summary + action items + sentiment chip +
 * "Apply suggested status" + "Schedule follow-up" buttons.
 */
/**
 * Build a 5-star rating widget. Filled to currentRating, hover changes
 * preview. Click to set. Shows AI-suggested rating as a faint hint star.
 */
function ratingStars(recId, currentRating, aiRating, onChange) {
  const wrap = h('div', { class: 'rating-stars' });
  const stars = [];
  for (let i = 1; i <= 5; i++) {
    const s = h('span', { class: 'rating-star', 'data-val': i, role: 'button', tabindex: 0,
      title: 'Rate ' + i + (i === 1 ? ' star' : ' stars') }, '★');
    s.onclick = async () => {
      try {
        await api('api_recording_rate', recId, i, '');
        currentRating = i;
        paint();
        if (typeof onChange === 'function') onChange(i);
        toast('Rated ' + i + '/5');
      } catch (e) { toast(e.message, 'err'); }
    };
    s.onmouseenter = () => paintHover(i);
    s.onmouseleave = () => paint();
    stars.push(s);
    wrap.appendChild(s);
  }
  function paint() {
    stars.forEach((s, idx) => {
      const v = idx + 1;
      s.classList.toggle('filled', currentRating != null && v <= currentRating);
      s.classList.toggle('ai-hint', currentRating == null && aiRating != null && v <= aiRating);
    });
  }
  function paintHover(n) {
    stars.forEach((s, idx) => s.classList.toggle('filled', idx < n));
  }
  paint();
  if (currentRating != null) {
    const clear = h('button', { class: 'btn xs ghost rating-clear', title: 'Clear rating', onclick: async () => {
      try {
        await api('api_recording_rate', recId, null, '');
        currentRating = null;
        paint();
        toast('Rating cleared');
      } catch (e) { toast(e.message, 'err'); }
    } }, '✕');
    wrap.appendChild(clear);
  }
  if (aiRating != null) {
    const aiHint = h('span', { class: 'rating-ai-hint', title: 'AI suggested rating' },
      currentRating == null ? '🤖 ' + aiRating + '/5' : ''
    );
    if (currentRating == null) wrap.appendChild(aiHint);
  }
  return wrap;
}

// AI_SUMMARY_DESKTOP_ONLY_v1 (2026-05-29) — APK detection.
// On the Android app, mobile reps are MAKING calls, not reviewing them
// in CRM. The AI Summary panel was polling api_recording_aiSummary every
// 10s up to 18 times PER recording rendered, which (a) hammered the
// postgres pool and (b) blew through Gemini quota for an audience that
// doesn't read these summaries anyway. Reviews happen at desk on web.
// On APK: skip the polling entirely, still render the Rate-this-call
// row (so the rep can rate from phone), and show a tiny "View on desktop"
// hint. Server-side worker still processes the recording in background,
// so when the user opens it on web later the summary is ready instantly.
function _isApkForAiSummary() {
  try {
    if (window.Capacitor && window.Capacitor.isNativePlatform && window.Capacitor.isNativePlatform()) return true;
  } catch (_) {}
  try {
    if (window.Capacitor) return true;
    if (/Capacitor|wv\)/i.test(navigator.userAgent || '')) return true;
  } catch (_) {}
  return false;
}

async function loadRecordingAI(recId, container, retries) {
  retries = retries || 0;
  // AI_SUMMARY_DESKTOP_ONLY_v1 — bail early on the mobile app. Render the
  // rate-this-call stars (no API call needed — recId is enough) plus a
  // discreet hint pointing the rep to the desktop.
  if (_isApkForAiSummary()) {
    try {
      container.innerHTML = '';
      container.appendChild(h('div', { class: 'rating-row' },
        h('span', { class: 'rating-label' }, 'Rate this call:'),
        ratingStars(recId, null, null)
      ));
      container.appendChild(h('div', { class: 'ai-pending muted', style: 'font-size:.72rem;margin-top:.4rem;color:#64748b' },
        '🖥 AI summary is available on desktop only'));
    } catch (_) {}
    return;
  }
  try {
    const r = await api('api_recording_aiSummary', recId);
    if (!r || r.status === 'pending') {
      if (retries === 0) {
        container.innerHTML = '';
        container.appendChild(h('div', { class: 'rating-row' },
          h('span', { class: 'rating-label' }, 'Rate this call:'),
          ratingStars(recId, null, null)
        ));
        const pending = h('div', { class: 'ai-pending' }, '🤖 AI is analysing this call…');
        container.appendChild(pending);
      }
      if (retries < 18) {
        setTimeout(() => loadRecordingAI(recId, container, retries + 1), 10000);
      } else {
        container.innerHTML = '';
        container.appendChild(h('div', { class: 'rating-row' },
          h('span', { class: 'rating-label' }, 'Rate this call:'),
          ratingStars(recId, null, null)
        ));
        container.appendChild(h('div', { class: 'ai-pending muted' }, '⏳ Still processing — refresh in a minute'));
      }
      return;
    }
    if (r.status === 'failed') {
      container.innerHTML = '';
      // Manual rating still works even when AI failed
      container.appendChild(h('div', { class: 'rating-row' },
        h('span', { class: 'rating-label' }, 'Rate this call:'),
        ratingStars(recId, r.rating, r.ai_suggested_rating)
      ));
      const isDisabled = /disabled by admin/i.test(r.error || '');
      if (!isDisabled) {
        container.appendChild(h('div', { class: 'ai-error' },
          '⚠️ AI summary failed: ' + (r.error || 'unknown') + ' ',
          h('button', { class: 'btn xs', onclick: () => window.retryAi(recId, null) }, 'Retry')
        ));
      }
      return;
    }
    // r.status === 'done'
    const sentColor = { positive: '#10b981', neutral: '#64748b', negative: '#ef4444' }[r.sentiment] || '#64748b';
    const sentLabel = { positive: '😊 Positive', neutral: '😐 Neutral', negative: '😟 Negative' }[r.sentiment] || r.sentiment || '—';
    container.innerHTML = '';
    // Manual call rating row — always shown, regardless of AI status
    container.appendChild(h('div', { class: 'rating-row' },
      h('span', { class: 'rating-label' }, 'Rate this call:'),
      ratingStars(recId, r.rating, r.ai_suggested_rating)
    ));
    container.appendChild(h('div', { class: 'ai-summary-card' },
      h('div', { class: 'ai-header' },
        h('span', { class: 'ai-badge' }, '🤖 AI Summary'),
        h('span', { class: 'ai-sentiment', style: 'color:' + sentColor }, sentLabel),
        h('button', { class: 'btn xs ghost', title: 'Re-analyse this call', onclick: () => {
          api('api_recording_aiReprocess', recId).then(() => loadRecordingAI(recId, container, 0));
        } }, '↻')
      ),
      h('div', { class: 'ai-summary-text' }, r.summary || '—'),
      r.key_insight ? h('div', { class: 'ai-insight' }, '💡 ' + r.key_insight) : null,
      r.action_items && r.action_items.length > 0
        ? h('div', { class: 'ai-actions' },
            h('div', { class: 'ai-actions-title' }, '✓ Action items'),
            ...r.action_items.map(a => h('div', { class: 'ai-action-item' }, '• ' + a))
          )
        : null,
      (r.suggested_status_id || r.next_followup_days != null)
        ? h('div', { class: 'ai-apply-row' },
            h('button', { class: 'btn sm primary', onclick: async () => {
              try {
                await api('api_recording_applySuggestion', recId, { applyStatus: true, applyFollowup: true });
                toast('✓ Status updated + follow-up scheduled');
                if (typeof loadLeads === 'function') loadLeads();
              } catch (e) { toast(e.message, 'err'); }
            } }, '✓ Apply suggestion'),
            r.next_followup_days != null
              ? h('span', { class: 'muted' }, '· schedule callback in ' + r.next_followup_days + ' day(s)')
              : null
          )
        : null,
      h('details', { class: 'ai-transcript' },
        h('summary', {}, '📝 Transcript'),
        h('pre', {}, r.transcript || 'No transcript')
      )
    ));
  } catch (e) {
    container.innerHTML = '<div class="ai-error muted">AI summary unavailable: ' + esc(e.message) + '</div>';
  }
}

window.retryAi = function(id, btn) {
  if (btn) btn.disabled = true;
  api('api_recording_aiReprocess', id).then(() => {
    const block = btn && btn.closest('.rec-ai-block');
    if (block) loadRecordingAI(id, block, 0);
  }).catch(e => toast(e.message, 'err'));
};

function remarksBlock(rs, leadId) {
  const list = h('ul', { class: 'remarks-list' });
  (rs || []).forEach(r => list.appendChild(h('li', {},
    h('b', {}, r.user_name || '—'), ' · ', fmtDate(r.created_at, 'relative'),
    h('br'), r.remark || ''
  )));
  const textarea = h('textarea', { placeholder: 'Add a remark…', rows: 2 });
  const btn = h('button', { type: 'button', class: 'btn sm', onclick: async () => {
    if (!textarea.value.trim()) return;
    try {
      await api('api_leads_addRemark', leadId, { remark: textarea.value });
      const r = await api('api_leads_get', leadId);
      list.innerHTML = '';
      (r.remarks || []).forEach(x => list.appendChild(h('li', {},
        h('b', {}, x.user_name || '—'), ' · ', fmtDate(x.created_at, 'relative'), h('br'), x.remark || ''
      )));
      textarea.value = '';
      toast('Remark added');
    } catch (e) { toast(e.message, 'err'); }
  } }, 'Add remark');
  return h('div', { class: 'remarks-block' },
    h('h4', {}, 'Remarks'), list, textarea, btn
  );
}

// QNOTE_v1 — AI Quick Note inline modal.
//   Opens a small input on each lead row. User types like a chat:
//     "/Follow up call 3pm tomorrow he is interested"
//   Slash-command shows status autocomplete from tenant statuses.
//   AI parses time + remark via api_leads_quickNote.
//   Reuses the same modal-backdrop styling as openRemarkInline so it
//   feels native.
async function openQuickNoteInline(lead) {
  // QNOTE_v2_FIX — fetch fresh if cache is empty (cache wasn't warming
  // before the row buttons were rendered on first paint).
  let statuses = (CRM.cache && CRM.cache.statuses) || [];
  if (!statuses.length) {
    try {
      const fresh = await api('api_statuses_list');
      if (Array.isArray(fresh) && fresh.length) {
        statuses = fresh;
        if (CRM.cache) CRM.cache.statuses = fresh;
      }
    } catch (e) { console.warn('[qnote] status fetch:', e.message); }
  }
  let pickedStatus = null;        // {id, name, color}
  let menuOpen = false;
  let menuActiveIdx = 0;

  // ---- DOM scaffold ----
  const chipWrap = h('div', { class: 'qn-chip-wrap', style: {
    display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: '6px',
    background: '#fff', border: '1.5px solid #c7d2fe', borderRadius: '8px',
    padding: '8px 10px', minHeight: '44px', position: 'relative'
  }});
  const input = h('input', { type: 'text', id: 'qn-input',
    placeholder: 'Type / for status, then say what happened. e.g. follow up call 3pm tomorrow',
    style: { flex: '1', minWidth: '160px', border: 'none', outline: 'none',
             fontSize: '14px', padding: '4px 0', fontFamily: 'inherit', background: 'transparent' },
    autocomplete: 'off'
  });
  const slashMenu = h('div', { class: 'qn-slash-menu', style: {
    position: 'absolute', top: '100%', left: '0', right: '0',
    maxWidth: '320px', background: '#fff', border: '1px solid #e2e8f0',
    borderRadius: '8px', boxShadow: '0 8px 24px rgba(15,23,42,.15)',
    marginTop: '4px', zIndex: '10', maxHeight: '220px', overflowY: 'auto',
    display: 'none'
  }});
  chipWrap.appendChild(input);
  chipWrap.appendChild(slashMenu);

  const hint = h('div', { style: { fontSize: '11px', color: '#64748b', marginTop: '8px' } },
    '⌨ Press ', h('kbd', { style: { background: '#f1f5f9', border: '1px solid #e2e8f0', borderRadius: '4px', padding: '1px 6px', fontFamily: 'monospace', fontSize: '11px' } }, '/'),
    ' for status · mention a time, or we\'ll use ', h('b', {}, '10:00 AM'), ' as default.'
  );

  const saveBtn = h('button', { class: 'btn primary', disabled: 'disabled' }, '✨ Save');
  const cancelBtn = h('button', { class: 'btn' }, 'Cancel');
  const statusLine = h('div', { class: 'muted', style: { fontSize: '11px', marginTop: '6px' } }, '');

  const modal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal', style: { maxWidth: '520px' } },
    h('h3', { style: { display: 'flex', alignItems: 'center', gap: '8px' } },
      h('span', { class: 'qn-spark' }, '✨'),
      ' AI Quick Note — ',
      h('span', { class: 'muted', style: { fontSize: '13px', fontWeight: 'normal' } }, lead.name || ('Lead #' + lead.id))
    ),
    chipWrap,
    hint,
    statusLine,
    h('div', { class: 'actions', style: { marginTop: '12px' } }, cancelBtn, saveBtn)
  ));

  cancelBtn.onclick = () => modal.remove();

  function updateSaveEnabled() {
    const hasText = input.value.trim().length > 0;
    saveBtn.disabled = !(pickedStatus || hasText) ? 'disabled' : null;
  }

  function renderChip() {
    // Remove any existing chip and the input's left padding
    const existing = chipWrap.querySelector('.qn-chip');
    if (existing) existing.remove();
    if (!pickedStatus) return;
    const chip = h('span', { class: 'qn-chip', style: {
      display: 'inline-flex', alignItems: 'center', gap: '5px',
      background: pickedStatus.color || '#6366f1', color: '#fff',
      padding: '3px 10px', borderRadius: '999px', fontSize: '12px', fontWeight: '600'
    }},
      pickedStatus.name,
      h('span', { style: { cursor: 'pointer', opacity: '.85' },
        onclick: ev => { ev.stopPropagation(); pickedStatus = null; renderChip(); updateSaveEnabled(); }
      }, '×')
    );
    chipWrap.insertBefore(chip, input);
  }

  function showSlashMenu(filter) {
    const matches = statuses.filter(s => !filter || String(s.name).toLowerCase().includes(filter));
    if (!matches.length) { slashMenu.style.display = 'none'; menuOpen = false; return; }
    slashMenu.innerHTML = '';
    slashMenu.appendChild(h('div', { style: { fontSize: '10.5px', color: '#64748b', padding: '6px 12px', textTransform: 'uppercase', letterSpacing: '.04em', background: '#f8fafc' } },
      '↑↓ navigate · Enter to pick · ' + matches.length + ' status' + (matches.length > 1 ? 'es' : '')));
    matches.forEach((s, i) => {
      const item = h('div', {
        class: 'qn-slash-item' + (i === 0 ? ' active' : ''),
        style: { padding: '8px 12px', cursor: 'pointer', display: 'flex',
                 alignItems: 'center', gap: '8px', fontSize: '13px',
                 borderBottom: i === matches.length - 1 ? 'none' : '1px solid #f1f5f9',
                 background: i === 0 ? '#eef2ff' : '#fff' },
        onclick: () => { pickedStatus = { id: s.id, name: s.name, color: s.color || '#6366f1' };
                         // QNOTE_v3_FIX — remove only the '/foo' fragment, keep the rest of the note intact.
                         try {
                           const cur = input.value || '';
                           const lastSlash = cur.lastIndexOf('/');
                           if (lastSlash >= 0) {
                             const before = cur.slice(0, lastSlash).replace(/\s+$/, '');
                             // Drop everything from '/' to next whitespace (or end of string)
                             const afterSegment = cur.slice(lastSlash + 1);
                             const tail = afterSegment.replace(/^[^\s]*/, '');
                             input.value = (before + ' ' + tail).replace(/\s+/g, ' ').trim();
                           } else {
                             input.value = '';
                           }
                         } catch (_) { input.value = ''; }
                         slashMenu.style.display = 'none'; menuOpen = false;
                         renderChip(); updateSaveEnabled(); input.focus(); }
      },
        h('span', { style: { width: '10px', height: '10px', borderRadius: '50%', background: s.color || '#94a3b8' } }),
        h('span', {}, s.name)
      );
      slashMenu.appendChild(item);
    });
    slashMenu.style.display = 'block';
    menuOpen = true;
    menuActiveIdx = 0;
  }

  function moveMenuActive(dir) {
    const items = slashMenu.querySelectorAll('.qn-slash-item');
    if (!items.length) return;
    items[menuActiveIdx].classList.remove('active');
    items[menuActiveIdx].style.background = '#fff';
    menuActiveIdx = (menuActiveIdx + dir + items.length) % items.length;
    items[menuActiveIdx].classList.add('active');
    items[menuActiveIdx].style.background = '#eef2ff';
    items[menuActiveIdx].scrollIntoView({ block: 'nearest' });
  }

  input.addEventListener('input', () => {
    const v = input.value;
    // QNOTE_v3_FIX (2026-06-16) — allow '/' ANYWHERE in the input, not just
    // at the start. User wanted to type the note first then hit '/' at the
    // end to pick a status. Find the LAST '/' that's at start or preceded
    // by whitespace (so URLs like http:// don't trigger).
    const lastSlash = v.lastIndexOf('/');
    let opened = false;
    if (lastSlash >= 0) {
      const prefixOK = lastSlash === 0 || /\s/.test(v.charAt(lastSlash - 1));
      // Anything after the slash up to next whitespace is the filter
      const tail = v.slice(lastSlash + 1);
      const filter = tail.split(/\s/)[0].toLowerCase().trim();
      // Only show menu if filter has 0-25 chars and no space immediately after '/'
      // (so '/foo bar' filters by 'foo', '/ ' closes menu)
      if (prefixOK && tail.length < 30 && !/^\s/.test(tail)) {
        showSlashMenu(filter);
        opened = true;
      }
    }
    if (!opened && menuOpen) {
      slashMenu.style.display = 'none'; menuOpen = false;
    }
    updateSaveEnabled();
  });

  input.addEventListener('keydown', (e) => {
    if (menuOpen) {
      if (e.key === 'ArrowDown') { e.preventDefault(); moveMenuActive(1); return; }
      if (e.key === 'ArrowUp')   { e.preventDefault(); moveMenuActive(-1); return; }
      if (e.key === 'Enter')     { e.preventDefault(); slashMenu.querySelectorAll('.qn-slash-item')[menuActiveIdx].click(); return; }
      if (e.key === 'Escape')    { slashMenu.style.display = 'none'; menuOpen = false; return; }
    } else if (e.key === 'Enter') {
      e.preventDefault();
      if (!saveBtn.disabled) saveBtn.click();
    } else if (e.key === 'Backspace' && input.value === '' && pickedStatus) {
      e.preventDefault();
      pickedStatus = null; renderChip(); updateSaveEnabled();
    }
  });

  saveBtn.onclick = async () => {
    saveBtn.disabled = 'disabled';
    statusLine.textContent = '🤖 Saving…';
    try {
      const r = await api('api_leads_quickNote', {
        lead_id: lead.id,
        text: input.value.trim(),
        picked_status_id: pickedStatus ? pickedStatus.id : null
      });
      toast(r.message || '✓ Saved', 'ok');
      modal.remove();
      if (typeof loadLeads === 'function') loadLeads();
    } catch (e) {
      statusLine.textContent = '';
      saveBtn.disabled = null;
      toast(e.message || 'Failed', 'err');
    }
  };

  document.body.appendChild(modal);
  setTimeout(() => input.focus(), 50);
}

async function openRemarkInline(leadId) {
  const modal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal' },
    h('h3', {}, 'Add remark'),
    h('textarea', { id: 'inline-rmk', rows: 3, placeholder: 'Write remark…' }),
    h('div', { class: 'actions' },
      h('button', { class: 'btn', onclick: () => modal.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        const text = $('#inline-rmk').value.trim();
        if (!text) return;
        try { await api('api_leads_addRemark', leadId, { remark: text }); toast('Added'); modal.remove(); loadLeads(); }
        catch (e) { toast(e.message, 'err'); }
      } }, 'Save')
    )
  ));
  document.body.appendChild(modal);
  setTimeout(() => $('#inline-rmk').focus(), 50);
}

async function openDuplicateHistory(leadId) {
  try {
    const history = await api('api_leads_duplicateHistory', leadId);
    const modal = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) modal.remove(); } },
      h('div', { class: 'modal modal-lg' },
        h('div', { class: 'modal-head' }, h('h3', {}, 'Duplicate history'), h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')),
        (!history || history.length === 0)
          ? h('p', { class: 'muted' }, 'No matching past leads found.')
          : h('div', {},
              ...history.map(l => h('div', { class: 'dup-item' },
                h('div', {}, h('b', {}, l.name || '—'), ' · ', l.phone || l.email || '', ' · ', fmtDate(l.created_at, 'relative')),
                h('div', { class: 'muted' }, 'Status: ' + (l.status_name || '—') + ' · Assigned: ' + (l.assigned_name || '—')),
                ...(l.remarks || []).map(r => h('div', { class: 'dup-remark' }, '💬 ', r.remark, ' — ', fmtDate(r.created_at, 'short')))
              ))
            )
      )
    );
    document.body.appendChild(modal);
  } catch (e) { toast(e.message, 'err'); }
}

/* ---------------- Dialer (TeleCRM-style) ---------------- */
let _dialerState = null;

VIEWS.dialer = async (view) => {
  // Tab state: 'pad' (dialpad) | 'history' (call log) | 'recordings' (audio list)
  _dialerState = { tab: 'pad', digits: '', view };

  view.innerHTML = '';

  // Always-visible banner when running on the APK and no folder is connected
  // yet. Impossible to miss, taps directly into the picker. Hidden as soon
  // as the user picks a folder (next render won't include it).
  const isApkRuntime = !!(window.LeadCRMNative && typeof LeadCRMNative.getRecordingFolder === 'function');
  let connectedFolder = '';
  try { connectedFolder = isApkRuntime ? (LeadCRMNative.getRecordingFolder() || '') : ''; } catch (_) {}
  if (isApkRuntime && !connectedFolder) {
    view.appendChild(h('div', {
      style: { background: '#fef3c7', color: '#92400e', borderLeft: '4px solid #f59e0b', padding: '.7rem 1rem', borderRadius: '8px', marginBottom: '.75rem', cursor: 'pointer' },
      onclick: () => setupRecordingFolder()
    },
      h('b', {}, '📁 Connect call recordings folder '),
      h('span', { class: 'muted' }, '— tap here to pick the folder where your phone saves call recordings. Without this, calls won\'t auto-attach to leads.')
    ));
  }

  const tabs = h('div', { class: 'dialer-tabs' },
    tabBtn('pad', '📟 Dialpad'),
    tabBtn('history', '🕒 History'),
    tabBtn('recordings', '📼 Recordings'),
    tabBtn('settings', '⚙️')
  );
  const body = h('div', { class: 'dialer-body' });
  view.appendChild(h('div', { class: 'dialer-shell' }, tabs, body));

  function tabBtn(id, label) {
    return h('button', {
      class: 'dialer-tab' + (_dialerState.tab === id ? ' active' : ''),
      onclick: () => { _dialerState.tab = id; renderDialerTab(); }
    }, label);
  }

  function renderDialerTab() {
    [...tabs.children].forEach((c, i) => {
      const ids = ['pad', 'history', 'recordings', 'settings'];
      c.classList.toggle('active', _dialerState.tab === ids[i]);
    });
    body.innerHTML = '';
    if (_dialerState.tab === 'pad') body.appendChild(renderDialpad());
    else if (_dialerState.tab === 'history') body.appendChild(renderHistory());
    else if (_dialerState.tab === 'recordings') body.appendChild(renderRecordingsList());
    else body.appendChild(renderDialerSettings());
  }

  renderDialerTab();

  // Dialer-tab nudge: if the user lands on the Dialer page and still hasn't
  // picked a folder (e.g. they dismissed the boot-time onboarding modal),
  // open the picker once per session. The boot onboarding (firstRunRecordingPrompt)
  // is the primary path; this is a backup so users who hit Dialer before
  // dismissing/seeing onboarding still get prompted.
  if (window.LeadCRMNative && typeof LeadCRMNative.getRecordingFolder === 'function') {
    try {
      const fld = LeadCRMNative.getRecordingFolder();
      if (!fld
          && !sessionStorage.getItem('rec_setup_dismissed')
          && localStorage.getItem('rec_onboarding_seen_v2') !== '1') {
        setTimeout(() => {
          if (location.hash === '#/dialer') setupRecordingFolder();
          sessionStorage.setItem('rec_setup_dismissed', '1');
        }, 800);
      }
    } catch (_) {}
  }
};

function renderDialerSettings() {
  // Auto-kick a silent recording sync when the user opens this view.
  try { if (typeof _kickRecordingSyncSoon === 'function') _kickRecordingSyncSoon(2000); } catch (_) {}

  const wrap = h('div', { class: 'dialer-settings' });
  const isApp = !!(window.LeadCRMNative && typeof LeadCRMNative.getRecordingFolder === 'function');
  let folder = '';
  try { folder = isApp ? (LeadCRMNative.getRecordingFolder() || '') : ''; } catch (_) {}
  const lastSync = Number(localStorage.getItem('rec_last_sync') || 0);

  if (!isApp) {
    wrap.appendChild(h('div', { class: 'settings-card' },
      h('h4', {}, '📱 Open in the Android app'),
      h('p', { class: 'muted' }, 'Recording sync only works inside the LeadCRM Android app — install it from the Install page.')
    ));
    return wrap;
  }

  // BULK_AUDIT_HISTORY_v1 — Bulk AI Audit card on Recordings settings page.
  { const bar = _buildBulkAuditBar({ onDone: () => {} }); if (bar) wrap.appendChild(bar); }

  // INCOMING_CARD_v1 — Runo-style incoming-call popup toggle (APK only).
  // Default ON. Bridge talks to LeadCRMNative.setIncomingCardEnabled/getIncomingCardEnabled.
  if (typeof window !== 'undefined' && window.LeadCRMNative && typeof LeadCRMNative.setIncomingCardEnabled === 'function') {
    let _incOn = true;
    try { _incOn = LeadCRMNative.getIncomingCardEnabled() !== '0'; } catch(_) {}
    wrap.appendChild(h('div', { class: 'settings-card', style: { borderLeft: '4px solid ' + (_incOn ? '#4f46e5' : '#94a3b8') } },
      h('h4', {}, '📞 Incoming call popup card'),
      h('p', { class: 'muted', style: { marginBottom: '.6rem' } },
        _incOn
          ? 'ON — when a call comes in, a Runo-style card appears over the dialer with the customer name + last remark (or an Add-to-CRM button if the number is new). Tap ✕ to close.'
          : 'OFF — incoming calls only get a notification, no card popup. Turn ON to see the card with customer info.'),
      h('label', { class: 'toggle-row', style: { display: 'flex', alignItems: 'center', gap: '.6rem' } },
        h('input', {
          type: 'checkbox',
          checked: _incOn ? 'checked' : null,
          onchange: ev => {
            const on = !!ev.target.checked;
            try { LeadCRMNative.setIncomingCardEnabled(on); } catch(_) {}
            toast(on ? 'Incoming-call card ON.' : 'Incoming-call card OFF.', 'ok');
            try { if (typeof navigateTo === 'function') navigateTo('recordings'); else location.reload(); } catch(_) { location.reload(); }
          }
        }),
        h('span', { style: { fontWeight: 600 } }, _incOn ? 'Card is ON' : 'Card is OFF')
      )
    ));
  }

  // REC_AUTOSYNC_OFF_BY_DEFAULT_v1 — auto-sync toggle card.
  // Default OFF for everyone. User flips ON per-device if they want background polling.
  // Manual Sync buttons below ALWAYS work regardless of this toggle.
  const _autoOn = (function(){ try { return localStorage.getItem('crm_rec_autosync') === '1'; } catch(_) { return false; } })();
  wrap.appendChild(h('div', { class: 'settings-card', style: { borderLeft: '4px solid ' + (_autoOn ? '#10b981' : '#94a3b8') } },
    h('h4', {}, '🔁 Auto-sync recordings'),
    h('p', { class: 'muted', style: { marginBottom: '.6rem' } },
      _autoOn
        ? 'ON — the app checks for new recordings every few minutes. Switch OFF if the app feels slow.'
        : 'OFF (default) — the app does NOT poll for recordings in the background. Use the manual Sync buttons below in the evening or whenever you want. Call logs (incoming / missed / outgoing) are unaffected — they sync live regardless.'
    ),
    h('label', { class: 'toggle-row', style: { display: 'flex', alignItems: 'center', gap: '.6rem' } },
      h('input', {
        type: 'checkbox',
        checked: _autoOn ? 'checked' : null,
        onchange: ev => {
          const on = !!ev.target.checked;
          try { localStorage.setItem('crm_rec_autosync', on ? '1' : '0'); } catch(_) {}
          toast(on ? 'Auto-sync ON — background checks resumed.' : 'Auto-sync OFF — use the manual Sync buttons below.', 'ok');
          // Re-render the Recordings page so the card updates.
          try { if (typeof navigateTo === 'function') navigateTo('recordings'); else location.reload(); } catch(_) { location.reload(); }
        }
      }),
      h('span', { style: { fontWeight: 600 } }, _autoOn ? 'Auto-sync is ON' : 'Auto-sync is OFF')
    )
  ));

  // Folder card
  wrap.appendChild(h('div', { class: 'settings-card' },
    h('h4', {}, '📁 Call recordings folder'),
    folder
      ? h('div', {},
          h('div', { class: 'rec-folder-current' }, h('code', {}, folder)),
          h('div', { class: 'muted' }, 'The app reads new files from this folder, parses the phone number, and uploads each recording to the matching lead.'),
          h('div', { class: 'actions' },
            h('button', { class: 'btn primary', onclick: () => syncRecordings() }, '🔄 Sync now'),
            /* REC_DATE_SYNC_v1 — safety-net buttons: pick a day and re-sync everything from it. */
            h('button', { class: 'btn', title: 'Re-scan + upload every recording modified TODAY (since midnight, your phone time).', onclick: () => { const d = new Date(); d.setHours(0,0,0,0); const tomorrow = d.getTime() + 24*3600*1000; toast('Scanning today\u2019s recordings\u2026', 'ok'); syncRecordings({ sinceMs: d.getTime(), untilMs: tomorrow }); } }, '📅 Sync today'),
            h('button', { class: 'btn', title: 'Re-scan + upload every recording from YESTERDAY (midnight to midnight, your phone time).', onclick: () => { const d = new Date(); d.setHours(0,0,0,0); const yest = d.getTime() - 24*3600*1000; toast('Scanning yesterday\u2019s recordings\u2026', 'ok'); syncRecordings({ sinceMs: yest, untilMs: d.getTime() }); } }, '📆 Sync yesterday'),
            h('button', { class: 'btn', title: 'Re-scan + upload every recording modified in the last 7 days. Useful for catching up after a long offline period.', onclick: () => { const d = new Date(); d.setHours(0,0,0,0); const wk = d.getTime() - 7*24*3600*1000; toast('Scanning last 7 days of recordings\u2026', 'ok'); syncRecordings({ sinceMs: wk }); } }, '📈 Sync last 7 days'),
            h('button', { class: 'btn', onclick: () => syncRecordings({ full: true }) }, '⚡ Re-sync all'),
            /* REC_RETRY_v1 */ h('button', { class: 'btn primary', title: 'Clears uploaded markers + re-scans every file. Use after a server-side fix.', onclick: async () => { if (!confirm('Reset upload markers and re-scan EVERY file in the folder?')) return; localStorage.removeItem('rec_uploaded'); localStorage.removeItem('rec_last_sync'); toast('Markers cleared — running full sync now\u2026', 'ok'); await syncRecordings({ full: true }); } }, '🩹 Fresh sync (after fix)'),
            h('button', { class: 'btn', onclick: () => openRecordingSyncDebug() }, '🐞 Debug sync'),
            h('button', { class: 'btn', onclick: () => openRecordingSyncDiagnostics() }, '🩺 Sync diagnostics'),
            /* REC_SELFTEST_v1 */ h('button', { class: 'btn primary', title: 'Run an end-to-end self-test of the recording pipeline. Shows pass/fail for each stage.', onclick: () => openRecordingSelftest() }, '🧪 Run self-test'),
            h('button', { class: 'btn ghost', onclick: () => { setupRecordingFolder(); } }, 'Change folder'),
            h('button', { class: 'btn ghost', onclick: () => { if (confirm('Forget folder + clear sync history?')) resetRecordingFolder(); } }, 'Reset')
          ),
          h('div', { class: 'muted', style: { marginTop: '.5rem', fontSize: '.78rem' } },
            h('span', { id: 'sync-progress', style: { fontWeight: 600 } }, ''),
            ' · Last synced: ', lastSync ? fmtDate(new Date(lastSync).toISOString(), 'relative') : 'never'
          )
        )
      : h('div', {},
          h('p', { class: 'muted' }, 'No folder connected yet. Pick the folder where your phone saves call recordings.'),
          h('button', { class: 'btn primary', onclick: () => setupRecordingFolder() }, '📁 Pick recordings folder')
        )
  ));

  // Filter card
  const includeUnmatched = localStorage.getItem('rec_include_unmatched') === '1';
  wrap.appendChild(h('div', { class: 'settings-card' },
    h('h4', {}, '🎯 Sync filter'),
    h('p', { class: 'muted' },
      'By default the app only uploads recordings whose phone number matches a lead in your CRM. ' +
      'Personal calls (family, courier, OTP) are skipped.'),
    h('label', { class: 'toggle-row' },
      h('input', {
        type: 'checkbox',
        checked: includeUnmatched ? 'checked' : null,
        onchange: ev => {
          localStorage.setItem('rec_include_unmatched', ev.target.checked ? '1' : '0');
          toast(ev.target.checked ? 'Will upload all recordings' : 'Lead-only filter active');
        }
      }),
      h('span', {}, 'Include unmatched recordings (upload everything)')
    )
  ));

  // Help card
  wrap.appendChild(h('div', { class: 'settings-card' },
    h('h4', {}, 'ℹ️ How it works'),
    h('ol', { class: 'how-it-works' },
      h('li', {}, 'Enable call recording in your phone\'s dialer (Settings → Phone → Call recording).'),
      h('li', {}, 'Make a call. The phone saves an audio file (e.g. ', h('code', {}, '+91XXXX_2024-04-25.m4a'), ') to its recordings folder.'),
      h('li', {}, 'Open this app and tap ', h('b', {}, 'Sync now'), '. The CRM finds each new file, reads the phone number from the filename, looks up the matching lead, and uploads the recording.'),
      h('li', {}, 'Listen to recordings inside any lead\'s detail page or under ', h('b', {}, 'Recordings'), '.')
    ),
    h('p', { class: 'muted' }, 'Note: the CRM does not record calls itself — that complies with Indian and EU regulations. You (or your phone\'s built-in recorder) control recording.')
  ));

  return wrap;
}

function renderDialpad() {
  const wrap = h('div', { class: 'dialpad-wrap' });

  // Number display + lead-match dropdown
  const display = h('input', {
    type: 'tel',
    class: 'dialpad-display',
    placeholder: 'Enter number or name…',
    value: _dialerState.digits,
    oninput: ev => { _dialerState.digits = ev.target.value; debouncedRenderMatches(); }
  });
  const matches = h('div', { class: 'dialpad-matches' });

  // Debounce so we don't re-filter the lead list on every keystroke
  let _matchTimer = null;
  function debouncedRenderMatches() {
    if (_matchTimer) clearTimeout(_matchTimer);
    _matchTimer = setTimeout(renderMatches, 80);
  }

  function renderMatches() {
    matches.innerHTML = '';
    const q = _dialerState.digits.trim();
    if (!q) return;
    const isDigits = /^[\d+\-\s]+$/.test(q);
    const ql = q.toLowerCase();
    const found = (CRM.cache.lastLeads || []).filter(l => {
      if (isDigits) {
        const d = String(l.phone || '').replace(/\D/g, '');
        return d.includes(q.replace(/\D/g, ''));
      }
      return String(l.name || '').toLowerCase().includes(ql);
    }).slice(0, 6);
    found.forEach(l => matches.appendChild(h('button', {
      class: 'dialpad-match',
      onclick: () => {
        display.value = l.phone || '';
        _dialerState.digits = l.phone || '';
        callLead(l);
      }
    },
      h('div', {}, h('b', {}, l.name || '—')),
      h('div', { class: 'muted' }, l.phone || '')
    )));
    // If no match and digits look like a phone, offer "Save & Call"
    if (found.length === 0 && isDigits && q.replace(/\D/g, '').length >= 6) {
      matches.appendChild(h('button', {
        class: 'dialpad-match new',
        onclick: () => {
          openLeadModal();
          setTimeout(() => {
            const f = $('#lead-form');
            if (f && f.phone) f.phone.value = q;
          }, 150);
        }
      }, '+ Save "' + q + '" as new lead'));
    }
  }

  // Dialpad keys
  const keys = [
    ['1', ''], ['2', 'ABC'], ['3', 'DEF'],
    ['4', 'GHI'], ['5', 'JKL'], ['6', 'MNO'],
    ['7', 'PQRS'], ['8', 'TUV'], ['9', 'WXYZ'],
    ['*', ''], ['0', '+'], ['#', '']
  ];
  const grid = h('div', { class: 'dialpad-grid' },
    ...keys.map(([d, sub]) => h('button', {
      class: 'dialpad-key',
      onclick: () => {
        // Long-press on 0 = "+"
        if (d === '0' && _dialerLongPress0) {
          _dialerState.digits += '+';
        } else {
          _dialerState.digits += d;
        }
        display.value = _dialerState.digits;
        debouncedRenderMatches();
      },
      onmousedown: () => { if (d === '0') _dialerLongPress0Timer = setTimeout(() => { _dialerLongPress0 = true; }, 600); },
      onmouseup: () => { clearTimeout(_dialerLongPress0Timer); setTimeout(() => { _dialerLongPress0 = false; }, 50); },
      ontouchstart: () => { if (d === '0') _dialerLongPress0Timer = setTimeout(() => { _dialerLongPress0 = true; }, 600); },
      ontouchend: () => { clearTimeout(_dialerLongPress0Timer); setTimeout(() => { _dialerLongPress0 = false; }, 50); }
    },
      h('span', { class: 'dialpad-d' }, d),
      sub ? h('span', { class: 'dialpad-sub' }, sub) : null
    ))
  );

  const callBtn = h('button', {
    class: 'dialpad-call',
    onclick: () => {
      const raw = _dialerState.digits.trim();
      if (!raw) return toast('Type a number first', 'warn');
      const digits = raw.replace(/\D/g, '');
      // Look up matching lead
      const lead = (CRM.cache.lastLeads || []).find(l =>
        digits && String(l.phone || '').replace(/\D/g, '').endsWith(digits.slice(-10))
      ) || { id: null, name: '', phone: raw };
      callLead(lead);
    }
  }, '📞');

  const back = h('button', {
    class: 'dialpad-back',
    onclick: () => {
      _dialerState.digits = _dialerState.digits.slice(0, -1);
      display.value = _dialerState.digits;
    }
  }, '⌫');

  wrap.appendChild(display);
  wrap.appendChild(matches);
  wrap.appendChild(grid);
  wrap.appendChild(h('div', { class: 'dialpad-actions' }, back, callBtn));
  return wrap;
}
let _dialerLongPress0 = false;
let _dialerLongPress0Timer = null;

function renderHistory() {
  const wrap = h('div', { class: 'dialer-history' }, h('div', { class: 'muted' }, 'Loading call history…'));
  api('api_call_history', 100).then(rows => {
    wrap.innerHTML = '';
    if (!rows || rows.length === 0) {
      wrap.appendChild(h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, 'No calls yet.'));
      return;
    }
    rows.forEach(r => wrap.appendChild(renderHistoryItem(r)));
  }).catch(e => {
    wrap.innerHTML = '';
    wrap.appendChild(h('div', { class: 'muted' }, 'Could not load: ' + e.message));
  });
  return wrap;
}

function renderHistoryItem(r) {
  const dur = Number(r.duration_s || r.rec_duration) || 0;
  const mm = Math.floor(dur / 60), ss = (dur % 60).toString().padStart(2, '0');
  const dirIcon = r.direction === 'in' ? '📲' :
                  r.event === 'recording_saved' ? '📼' :
                  r.event === 'call_ended' ? '✅' :
                  r.event === 'incoming_ringing' ? '📲' : '📞';
  const item = h('div', { class: 'hist-item' },
    h('div', { class: 'hist-row' },
      h('span', { class: 'hist-icon' }, dirIcon),
      h('div', { class: 'hist-meta' },
        h('div', {}, h('b', {}, r.lead_name || r.phone || 'Unknown')),
        h('div', { class: 'muted' }, (r.lead_name ? r.phone + ' · ' : '') + fmtDate(r.created_at, 'relative') + (dur ? ' · ' + mm + ':' + ss : ''))
      ),
      r.phone ? h('button', {
        class: 'btn icon hist-redial',
        onclick: () => {
          const lead = (CRM.cache.lastLeads || []).find(l =>
            String(l.phone || '').replace(/\D/g, '').endsWith(String(r.phone).replace(/\D/g, '').slice(-10))
          ) || { name: r.lead_name || '', phone: r.phone };
          callLead(lead);
        }
      }, '📞') : null,
      r.lead_id ? h('button', {
        class: 'btn icon',
        title: 'Open lead',
        onclick: () => openLeadModal(r.lead_id)
      }, '📂') : null
    )
  );
  // Inline audio player if there's a recording attached
  if (r.recording_id || r.rec_id) {
    const recId = r.recording_id || r.rec_id;
    item.appendChild(h('audio', {
      controls: true, preload: 'none',
      class: 'hist-audio',
      src: ((typeof window !== 'undefined' && window.TENANT_SLUG) ? '/t/' + window.TENANT_SLUG : '') + '/api/recordings/' + recId + '/audio?token=' + encodeURIComponent(CRM.token || '')
    }));
  }
  return item;
}

function renderRecordingsList() {
  const wrap = h('div', { class: 'dialer-history' });
  // Toolbar at the top: Refresh + Reset all (admin only).
  const toolbar = h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '.5rem', alignItems: 'center', padding: '.5rem .25rem', borderBottom: '1px solid #e5e7eb', marginBottom: '.5rem' } });
  const refreshBtn = h('button', { class: 'btn sm', onclick: () => {
    const body = _dialerState && _dialerState.view && _dialerState.view.querySelector('.dialer-body');
    if (body) { body.innerHTML = ''; body.appendChild(renderRecordingsList()); }
  } }, '⟳ Refresh');
  toolbar.appendChild(refreshBtn);
  // Reset button — admin only. Wipes every recording in the tenant.
  if (CRM.user && CRM.user.role === 'admin') {
    const resetBtn = h('button', {
      class: 'btn sm danger',
      style: { background: '#fef2f2', color: '#991b1b', borderColor: '#fca5a5' },
      title: 'Permanently delete every recording in this tenant',
      onclick: async () => {
        if (!await confirmDialog('🛑 Delete EVERY recording in this tenant?\n\nThis also clears the call-history entries that referenced those recordings. Lead-event log and AI summaries are kept. Cannot be undone.')) return;
        try {
          const r = await api('api_recordings_resetAll');
          const msg = 'Reset complete — ' + r.deleted + ' recording(s) deleted'
                    + (r.call_events_cleared ? ', ' + r.call_events_cleared + ' call-history entries cleared' : '')
                    + (r.diag_cleared ? ', ' + r.diag_cleared + ' diagnostic rows cleared' : '');
          toast(msg, 'ok');
          // Re-render the list — guaranteed to hit the right host since
          // renderRecordingsList() returns the entire wrap (toolbar + list).
          const body = _dialerState && _dialerState.view && _dialerState.view.querySelector('.dialer-body');
          if (body) { body.innerHTML = ''; body.appendChild(renderRecordingsList()); }
          // Also refresh the call-history tab in case it's the active view
          // so it doesn't show stale entries with 404 audio players.
          if (typeof refreshDialerHistory === 'function') refreshDialerHistory();
        } catch (e) { toast('Reset failed: ' + e.message, 'err'); }
      }
    }, '🛑 Reset all');
    toolbar.appendChild(resetBtn);
    // Relink orphans — runs a one-shot pass that re-matches every recording
    // whose lead_id is NULL against leads (by last-10-digit phone match).
    // Useful when an APK uploaded a recording BEFORE the matching lead was
    // created — without this they'd stay orphaned forever.
    const relinkBtn = h('button', {
      class: 'btn sm',
      style: { background: '#dbeafe', color: '#1e40af', borderColor: '#93c5fd' },
      title: 'Find recordings with no lead and try to match them to existing leads by phone',
      onclick: async () => {
        relinkBtn.textContent = 'Relinking…'; relinkBtn.disabled = true;
        try {
          const r = await api('api_recordings_relinkOrphans');
          toast('Relink: ' + r.scanned + ' scanned, ' + r.linked + ' linked to leads', 'ok');
          const body = _dialerState && _dialerState.view && _dialerState.view.querySelector('.dialer-body');
          if (body) { body.innerHTML = ''; body.appendChild(renderRecordingsList()); }
        } catch (e) { toast('Relink failed: ' + e.message, 'err'); }
        relinkBtn.textContent = '🔗 Relink orphans'; relinkBtn.disabled = false;
      }
    }, '🔗 Relink orphans');
    toolbar.appendChild(relinkBtn);
    // Description sits in its OWN full-width row below the buttons so it
    // wraps naturally and doesn't get squeezed into a narrow column on
    // mobile. flex: '1 1 100%' forces a line break in the flex container.
    toolbar.appendChild(h('span', {
      class: 'muted',
      style: { fontSize: '.78rem', flex: '1 1 100%', marginTop: '.15rem', lineHeight: '1.3' }
    }, 'Reset wipes everything · Relink re-matches recordings with empty lead_id to existing leads by phone.'));
  }
  wrap.appendChild(toolbar);

  const listHost = h('div', {}, h('div', { class: 'muted' }, 'Loading recordings…'));
  wrap.appendChild(listHost);

  api('api_my_recordings', 200).then(rows => {
    listHost.innerHTML = '';
    if (!rows || rows.length === 0) {
      listHost.appendChild(h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, 'No recordings yet.'));
      return;
    }
    rows.forEach(r => listHost.appendChild(renderRecordingItem(r)));
  }).catch(e => {
    listHost.innerHTML = '';
    listHost.appendChild(h('div', { class: 'muted' }, 'Could not load: ' + e.message));
  });
  return wrap;
}

function refreshDialerHistory() {
  if (!_dialerState || !_dialerState.view) return;
  if (location.hash !== '#/dialer') return;
  // NEVER re-render the whole dialer — that nukes the dialpad input focus
  // and the digits the user is typing. Only refresh the History/Recordings
  // tabs (those don't have user inputs).
  if (_dialerState.tab === 'history') {
    const body = _dialerState.view.querySelector('.dialer-body');
    if (body && typeof renderHistory === 'function') {
      body.innerHTML = '';
      body.appendChild(renderHistory());
    }
  } else if (_dialerState.tab === 'recordings') {
    const body = _dialerState.view.querySelector('.dialer-body');
    if (body && typeof renderRecordingsList === 'function') {
      body.innerHTML = '';
      body.appendChild(renderRecordingsList());
    }
  }
  // Dialpad / Settings tabs intentionally NOT auto-refreshed.
}

/* ---------------- Pipeline ---------------- */
// RE_CP_PIPELINE_VIEW_v1 (2026-05-21) — replace the Pipeline page with the
// CP CRM Process card-grid layout (3-row infographic style) when the Real
// Estate industry pack is installed. Each card shows the stage number, icon,
// title, action bullets, lead count, and status pill - matching the user's
// canonical CP CRM Process diagram. Click a card to expand inline and show
// the leads currently in that stage.
//
// Falls back to the standard kanban-lane layout for tenants without RE pack.
const _RE_STAGE_META = [
  { n: 1,  match: ['New Lead'],              icon: '📣', color: '#a855f7', bullets: ['Source: CP, Call, Website, WhatsApp, Walk-in', 'Lead details capture'] },
  { n: 2,  match: ['Lead Captured'],         icon: '📝', color: '#3b82f6', bullets: ['Name, Mobile, Email', 'Requirement (Budget, BHK, Location)', 'Source / CP name'] },
  { n: 3,  match: ['Assigned'],              icon: '👤', color: '#06b6d4', bullets: ['Assign to Executive / CP Manager', 'Auto notification to owner'] },
  { n: 4,  match: ['In Follow-up','Follow Up','Follow-up'], icon: '📞', color: '#22c55e', bullets: ['Call within 5–10 min', 'Discuss requirement, budget, timeline', 'Update in CRM'] },
  { n: 5,  match: ['Presentation Done'],     icon: '🏢', color: '#f59e0b', bullets: ['Brochure, Cost sheet', 'Floor plan, Location video', 'Send & Update'] },
  { n: 6,  match: ['Site Visit Fixed','Site Visit Scheduled','Site Visit Planned'], icon: '📅', color: '#ec4899', bullets: ['Date & time fix', 'Send details to client', 'Update in CRM'] },
  { n: 7,  match: ['Site Visit Done'],       icon: '👣', color: '#0ea5e9', bullets: ['Visit completed', 'Client feedback (likes / dislikes)', 'Update in CRM'] },
  { n: 8,  match: ['Offer Given'],           icon: '🤝', color: '#f97316', bullets: ['Price discussion', 'Discount / benefits', 'Payment plan & update'] },
  { n: 9,  match: ['Booked','Token Amount Done','Token Paid'], icon: '✅', color: '#16a34a', bullets: ['Client agrees', 'Token amount received', 'Update in CRM'] },
  { n: 10, match: ['Documents Collected','Agreement Signed'], icon: '📋', color: '#8b5cf6', bullets: ['Booking form', 'KYC docs (PAN, Aadhaar)', 'Cheque / payment details'] },
  { n: 11, match: ['Commission In Progress'],icon: '💰', color: '#0284c7', bullets: ['CP agreement', 'Commission slab', 'Stage-wise tracking, TDS'] },
  { n: 12, match: ['Paid','Possession Given','Registered'], icon: '🏦', color: '#15803d', bullets: ['Commission due', 'Approval', 'Payment released, payout receipt'] }
];
function _reFindStageStatus(allStatuses, names) {
  // Backward-compat: returns the FIRST matching status (used by stage panel).
  for (const nm of names) {
    const hit = (allStatuses || []).find(s => String(s.name || '').toLowerCase() === nm.toLowerCase());
    if (hit) return hit;
  }
  return null;
}
// Returns ALL statuses whose name matches any of the alias names — so the
// Pipeline card aggregates leads from 'Site Visit Planned' + 'Site Visit Fixed'
// into the same stage 6 card.
function _reFindAllStageStatuses(allStatuses, names) {
  const lower = names.map(n => n.toLowerCase());
  return (allStatuses || []).filter(s => lower.includes(String(s.name || '').toLowerCase()));
}
function _rePipelineCardClick(card, stage, leads, allStatuses) {
  // Toggle inline body with the leads in this stage.
  const existing = card.querySelector('.re-pipe-card-body');
  if (existing) { existing.remove(); card.classList.remove('open'); return; }
  const body = document.createElement('div');
  body.className = 're-pipe-card-body';
  body.style.cssText = 'margin-top:.5rem;border-top:1px solid #eee;padding-top:.5rem;';
  if (!leads.length) {
    body.style.cssText = 'font-size:.78rem;color:#888;padding:.4rem 0;';
    body.textContent = 'No leads in this stage yet.';
    card.appendChild(body);
    card.classList.add('open');
    return;
  }
  // Helper: format a stage-specific chip string from the lead's extra_json
  const stageName = (stage && stage.match && stage.match[0]) || '';
  const stageFields = (typeof _RE_STAGE_FIELDS !== 'undefined') ? _RE_STAGE_FIELDS[stageName] : null;
  const fmtChip = (val, key) => {
    if (val == null || val === '') return null;
    if (/_at$/.test(key) || /_date$/.test(key)) {
      try {
        const d = new Date(val);
        if (!isNaN(d)) return d.toLocaleDateString() + (val.length > 10 ? ' ' + d.toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '');
      } catch(_) {}
    }
    if (/_amount$/.test(key) || /_pct$/.test(key)) return '₹ ' + Number(val).toLocaleString('en-IN');
    return String(val);
  };
  leads.slice(0, 50).forEach(l => {
    const row = document.createElement('div');
    row.style.cssText = 'padding:.45rem 0;border-bottom:1px solid #f4f4f5;cursor:pointer;font-size:.8rem;';
    row.onclick = (ev) => { ev.stopPropagation(); openLeadModal(l.id); };

    const topRow = document.createElement('div');
    topRow.style.cssText = 'display:flex;justify-content:space-between;gap:.4rem;align-items:center;';
    const left = document.createElement('div');
    left.style.cssText = 'display:flex;flex-direction:column;';
    const name = document.createElement('div'); name.style.fontWeight = '600'; name.textContent = l.name || '—';
    const meta = document.createElement('div'); meta.style.cssText = 'color:#666;font-size:.72rem;';
    meta.textContent = (l.phone || '') + ' · ' + (l.assigned_name || 'unassigned');
    left.appendChild(name); left.appendChild(meta);
    topRow.appendChild(left);
    if (l.next_followup_at) {
      const fu = document.createElement('div');
      const overdue = new Date(l.next_followup_at) < new Date();
      fu.style.cssText = 'font-size:.7rem;color:' + (overdue ? '#b91c1c' : '#666') + ';';
      try { fu.textContent = fmtDate(l.next_followup_at, 'relative'); } catch(_) { fu.textContent = ''; }
      topRow.appendChild(fu);
    }
    row.appendChild(topRow);

    // RE_STAGE_DATA_v1 — chips for stage-specific fields read from lead.extra
    if (stageFields && stageFields.length) {
      const ex = l.extra || {};
      const chips = [];
      stageFields.forEach(f => {
        const v = ex[f.key];
        if (v != null && v !== '') {
          const formatted = fmtChip(v, f.key);
          if (formatted) chips.push({ label: f.label.replace(/^[^\s]+\s/, ''), val: formatted });
        }
      });
      if (chips.length) {
        const chipRow = document.createElement('div');
        chipRow.style.cssText = 'display:flex;flex-wrap:wrap;gap:.25rem;margin-top:.3rem;';
        chips.forEach(c => {
          const chip = document.createElement('span');
          chip.style.cssText = 'background:#eef2ff;color:#3730a3;padding:.1rem .4rem;border-radius:6px;font-size:.7rem;';
          chip.textContent = c.label + ': ' + c.val;
          chipRow.appendChild(chip);
        });
        row.appendChild(chipRow);
      } else {
        const hint = document.createElement('div');
        hint.style.cssText = 'font-size:.68rem;color:#94a3b8;margin-top:.25rem;font-style:italic;';
        hint.textContent = 'Tap to fill stage data: ' + stageFields.map(f => f.label.replace(/^[^\s]+\s/, '')).slice(0, 3).join(' · ');
        row.appendChild(hint);
      }
    }
    body.appendChild(row);
  });
  if (leads.length > 50) {
    const more = document.createElement('div');
    more.style.cssText = 'font-size:.7rem;color:#888;margin-top:.3rem;';
    more.textContent = '+ ' + (leads.length - 50) + ' more';
    body.appendChild(more);
  }
  card.appendChild(body);
  card.classList.add('open');
}
// GENERIC_PIPE_GRID_v1 (2026-05-21) — card-grid Pipeline for ALL tenants.
// Builds the same layout as _reRenderCPProcessPipeline but using whatever
// statuses the tenant has, sorted by sort_order. Re-uses the RE canonical
// bullets when a status NAME matches a canonical RE stage name; otherwise
// shows a brief placeholder so non-real-estate tenants get a useful card
// without canned content.
function _genericRenderCardGridPipeline(view, pipeline, allStatuses) {
  view.innerHTML = '';
  view.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '.5rem', marginBottom: '.5rem', flexWrap: 'wrap' } },
    h('div', {},
      h('h2', { style: { margin: 0 }}, '\ud83d\udcc8 Lead Pipeline \u2014 New Lead To Sales'),
      h('p', { class: 'muted', style: { fontSize: '.82rem', margin: '.2rem 0 0' } }, 'Click any stage to expand and see the leads currently sitting in that stage. Click a lead row to open the full lead.')
    ),
    h('button', { class: 'btn ghost sm', type: 'button', onclick: () => { window._rePipeForceKanban = false; window._rePipeForceLegacyGrid = false; VIEWS.pipeline(view); } }, '📈 Switch to Funnel view')
  ));

  const sorted = [...(allStatuses || [])].sort((a, b) =>
    (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0)
  );

  const grid = h('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '.7rem', marginTop: '.6rem' } });

  sorted.forEach((status, idx) => {
    const entry = pipeline.find(p => Number(p.id) === Number(status.id));
    const leads = (entry && entry.leads) || [];
    const count = leads.length;
    const color = status.color || '#6366f1';
    // If the status name matches a RE canonical stage, reuse its bullets.
    let icon = '\u26AB';
    let bullets = [];
    if (typeof _RE_STAGE_META !== 'undefined') {
      const meta = _RE_STAGE_META.find(m => m.match.some(n => n.toLowerCase() === String(status.name || '').toLowerCase()));
      if (meta) { icon = meta.icon; bullets = meta.bullets; }
    }
    if (!bullets.length) {
      // Generic placeholder bullets — encourage reps to take an action.
      bullets = [
        'Reach out and qualify',
        'Update lead notes / next follow-up'
      ];
    }

    const card = h('div', { class: 're-pipe-card', style: {
      border: '2px solid ' + color + '55',
      borderRadius: '12px',
      padding: '.75rem .85rem',
      background: '#fff',
      boxShadow: '0 1px 4px rgba(0,0,0,.04)',
      cursor: 'pointer',
      transition: 'transform .15s, box-shadow .15s',
      position: 'relative'
    }});
    card.onmouseenter = () => { card.style.transform = 'translateY(-2px)'; card.style.boxShadow = '0 4px 12px rgba(0,0,0,.08)'; };
    card.onmouseleave = () => { card.style.transform = ''; card.style.boxShadow = '0 1px 4px rgba(0,0,0,.04)'; };
    card.onclick = (ev) => {
      if (ev.target.closest('a, button, .re-pipe-card-body')) return;
      _rePipelineCardClick(card, { match: [status.name] }, leads, allStatuses);
    };

    card.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' }},
      h('div', { style: { minWidth: '30px', height: '30px', borderRadius: '7px', background: color, color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, fontSize: '.9rem' }}, String(idx + 1)),
      h('div', { style: { flex: 1, minWidth: 0 }},
        h('div', { style: { fontWeight: 700, fontSize: '.95rem', color: color, display: 'flex', alignItems: 'center', gap: '.3rem' }},
          h('span', {}, icon),
          h('span', { style: { overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}, status.name)
        )
      ),
      h('div', { style: { background: count > 0 ? color : '#e5e7eb', color: count > 0 ? '#fff' : '#666', padding: '.15rem .5rem', borderRadius: '999px', fontWeight: 700, fontSize: '.85rem', minWidth: '32px', textAlign: 'center' }}, String(count))
    ));

    card.appendChild(h('ul', { style: { margin: '.4rem 0 .35rem 1.05rem', padding: 0, fontSize: '.76rem', color: '#444', lineHeight: '1.35' }},
      ...bullets.map(b => h('li', { style: { marginBottom: '.1rem' }}, b))
    ));

    card.appendChild(h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '.35rem' }},
      h('div', { style: { background: '#f1f5f9', padding: '.15rem .45rem', borderRadius: '999px', fontSize: '.68rem', color: '#334155', fontWeight: 600 }}, 'Status: ' + status.name),
      count > 0
        ? h('div', { style: { fontSize: '.7rem', color: color, fontWeight: 600 }}, count + ' lead' + (count === 1 ? '' : 's') + ' \u2192')
        : h('div', { style: { fontSize: '.7rem', color: '#aaa' }}, 'empty')
    ));

    grid.appendChild(card);
  });

  view.appendChild(grid);

  const totalLeads = pipeline.reduce((a, p) => a + ((p.leads || []).length), 0);
  const active = pipeline.filter(p => (p.leads || []).length > 0).length;
  view.appendChild(h('div', { style: { marginTop: '1rem', padding: '.6rem .8rem', background: '#f8fafc', borderRadius: '10px', fontSize: '.78rem', color: '#475569', display: 'flex', gap: '1rem', flexWrap: 'wrap' }},
    h('span', {}, '\ud83d\udcca Total in pipeline: ', h('b', { style: { color: '#0f172a' }}, totalLeads)),
    h('span', {}, '\ud83d\udfe2 Active stages: ', h('b', { style: { color: '#0f172a' }}, active)),
    h('span', { class: 'muted' }, 'Empty stages stay visible to remind reps to fill the pipeline.')
  ));
}

function _reRenderCPProcessPipeline(view, pipeline, allStatuses) {
  view.innerHTML = '';
  // Header
  view.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '.5rem', marginBottom: '.5rem', flexWrap: 'wrap' } },
    h('div', {},
      h('h2', { style: { margin: 0 }}, '📈 Lead Pipeline — New Lead To Sales'),
      h('p', { class: 'muted', style: { fontSize: '.82rem', margin: '.2rem 0 0' } }, 'Click any stage to expand and see the leads currently sitting in that stage. Click a lead row to open the full lead with the 12-stage strip.')
    ),
    h('button', { class: 'btn ghost sm', type: 'button', onclick: () => { window._rePipeForceKanban = false; window._rePipeForceLegacyGrid = false; VIEWS.pipeline(view); } }, '📈 Switch to Funnel view')
  ));

  // 12-card grid
  const grid = h('div', {
    style: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
      gap: '.7rem',
      marginTop: '.6rem'
    }
  });

  _RE_STAGE_META.forEach(meta => {
    // RE_STAGE_AGGREGATE_v1 — combine leads from EVERY matching status name
    // so the demo's old 'Site Visit Planned' + the seeded 'Site Visit Fixed'
    // BOTH count toward stage 6's card.
    const matchedStatuses = _reFindAllStageStatuses(allStatuses, meta.match);
    const status = matchedStatuses[0] || null;
    let leads = [];
    matchedStatuses.forEach(st => {
      const entry = pipeline.find(p => Number(p.id) === Number(st.id));
      if (entry && Array.isArray(entry.leads)) leads = leads.concat(entry.leads);
    });
    const count = leads.length;
    const usedName = matchedStatuses.length > 1
      ? matchedStatuses.map(s => s.name).join(' / ')
      : (status ? status.name : meta.match[0]);

    const card = h('div', { class: 're-pipe-card', style: {
      border: '2px solid ' + meta.color + '55',
      borderRadius: '12px',
      padding: '.75rem .85rem',
      background: '#fff',
      boxShadow: '0 1px 4px rgba(0,0,0,.04)',
      cursor: 'pointer',
      transition: 'transform .15s, box-shadow .15s',
      position: 'relative'
    }});
    card.onmouseenter = () => { card.style.transform = 'translateY(-2px)'; card.style.boxShadow = '0 4px 12px rgba(0,0,0,.08)'; };
    card.onmouseleave = () => { card.style.transform = ''; card.style.boxShadow = '0 1px 4px rgba(0,0,0,.04)'; };
    card.onclick = (ev) => {
      if (ev.target.closest('a, button, .re-pipe-card-body')) return;
      _rePipelineCardClick(card, meta, leads, allStatuses);
    };

    // Header row: number badge + icon + title + count
    card.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' }},
      h('div', { style: {
        minWidth: '30px', height: '30px', borderRadius: '7px',
        background: meta.color, color: '#fff',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontWeight: 700, fontSize: '.9rem'
      }}, String(meta.n)),
      h('div', { style: { flex: 1, minWidth: 0 }},
        h('div', { style: { fontWeight: 700, fontSize: '.95rem', color: meta.color, display: 'flex', alignItems: 'center', gap: '.3rem' }},
          h('span', {}, meta.icon),
          h('span', { style: { overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}, meta.match[0])
        )
      ),
      h('div', { style: {
        background: count > 0 ? meta.color : '#e5e7eb',
        color: count > 0 ? '#fff' : '#666',
        padding: '.15rem .5rem',
        borderRadius: '999px',
        fontWeight: 700,
        fontSize: '.85rem',
        minWidth: '32px',
        textAlign: 'center'
      }}, String(count))
    ));

    // Bullets
    card.appendChild(h('ul', { style: {
      margin: '.4rem 0 .35rem 1.05rem',
      padding: 0,
      fontSize: '.76rem',
      color: '#444',
      lineHeight: '1.35'
    } },
      ...meta.bullets.map(b => h('li', { style: { marginBottom: '.1rem' } }, b))
    ));

    // Status pill at bottom + click hint
    card.appendChild(h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '.35rem' } },
      h('div', { style: {
        background: '#f1f5f9',
        padding: '.15rem .45rem',
        borderRadius: '999px',
        fontSize: '.68rem',
        color: '#334155',
        fontWeight: 600
      }}, 'Status: ' + usedName),
      count > 0
        ? h('div', { style: { fontSize: '.7rem', color: meta.color, fontWeight: 600 } }, count + ' lead' + (count === 1 ? '' : 's') + ' →')
        : h('div', { style: { fontSize: '.7rem', color: '#aaa' } }, 'empty')
    ));

    grid.appendChild(card);
  });

  view.appendChild(grid);

  // Footer — summary stats
  const totalLeads = pipeline.reduce((a, p) => a + ((p.leads || []).length), 0);
  const active = pipeline.filter(p => (p.leads || []).length > 0).length;
  view.appendChild(h('div', { style: {
    marginTop: '1rem', padding: '.6rem .8rem', background: '#f8fafc',
    borderRadius: '10px', fontSize: '.78rem', color: '#475569',
    display: 'flex', gap: '1rem', flexWrap: 'wrap'
  }},
    h('span', {}, '📊 Total in pipeline: ', h('b', { style: { color: '#0f172a' }}, totalLeads)),
    h('span', {}, '🟢 Active stages: ', h('b', { style: { color: '#0f172a' }}, active)),
    h('span', { class: 'muted' }, 'Empty stages stay visible to remind reps to fill the pipeline.')
  ));
}

// PIPELINE_STAGE_v1_PHASE2 — new funnel pipeline view that aggregates by
// universal stage. Becomes the default. Old kanban still reachable via the
// 'Switch to Kanban' button. Layout follows the reference screenshot:
// title strip + 4 KPI cards + descending trapezoid bands with dashed
// connectors to a right-side count, then Won/Lost cards.

const _FUNNEL_BAND_COLORS = ['#bfdbfe','#93c5fd','#60a5fa','#3b82f6','#1d4ed8'];
const _FUNNEL_BAND_TEXT  = ['#1e3a8a','#1e3a8a','#1e3a8a','#ffffff','#ffffff'];
const _FUNNEL_DOT_COLORS = ['#60a5fa','#3b82f6','#2563eb','#1d4ed8','#1e3a8a'];

function _formatInr(n) {
  n = Number(n) || 0;
  if (n >= 10000000) return '\u20B9' + (n / 10000000).toFixed(1) + 'Cr';
  if (n >= 100000)   return '\u20B9' + (n / 100000).toFixed(1) + 'L';
  if (n >= 1000)     return '\u20B9' + (n / 1000).toFixed(1) + 'K';
  return '\u20B9' + n.toLocaleString('en-IN');
}

async function _renderPipelineFunnel(view) {
  // PIPELINE_FUNNEL_REDESIGN_v2 — compact, viewport-fitting funnel that
  // matches the reference: connected trapezoids whose widths are data-
  // driven (top edge of band i = pct_of_total[i], bottom edge = pct_of_total[i+1]),
  // tight stacking, compact KPI strip, Won/Lost cards visible without scroll.
  view.innerHTML = '';

  // Header
  const tenantName = (CRM.tenant && CRM.tenant.name) || (CRM.brand && CRM.brand.name) || '';
  view.appendChild(h('div', { style: { display:'flex', alignItems:'flex-start', justifyContent:'space-between', flexWrap:'wrap', gap:'.5rem', marginBottom:'.85rem' } },
    h('div', {},
      h('h2', { style: { margin:0, fontSize:'1.3rem', color:'#0f172a', letterSpacing:'-.01em' } }, 'Sales pipeline'),
      h('div', { class: 'muted', style: { fontSize:'.78rem', marginTop:'.15rem', color:'#64748b' } },
        (tenantName ? (tenantName + ' · ') : '') + 'auto-updated')
    ),
    h('div', { style: { display:'flex', gap:'.4rem', alignItems:'center', flexWrap:'wrap' } },
      h('span', { style: { background:'#dbeafe', color:'#1e40af', padding:'.3rem .65rem', borderRadius:'999px', fontSize:'.72rem', fontWeight:600, display:'inline-flex', alignItems:'center', gap:'.3rem' } },
        h('span', { style: { color:'#facc15' } }, '⚡'),
        'leads move automatically'
      ),
      h('button', { class: 'btn ghost sm', style: { fontSize:'.78rem', padding:'.3rem .65rem' }, onclick: () => { window._rePipeForceKanban = true; VIEWS.pipeline(view); } }, '\u{1F4CA} Switch to Kanban')
    )
  ));

  // ───── Filter bar ─────
  // Same pattern as the old VIEWS.pipeline so users have a familiar UX.
  // Persists across funnel re-renders via window._funnelPicked.
  window._funnelPicked = window._funnelPicked || {
    from: '', to: '', sources: [], users: [], products: [], campaigns: [], statuses: []
  };
  const fp = window._funnelPicked;
  // Warm campaigns cache on demand
  if (!CRM.cache.campaigns) {
    try { CRM.cache.campaigns = await api('api_campaigns_list'); } catch (_) { CRM.cache.campaigns = []; }
  }
  const _statuses = CRM.cache.statuses || [];
  const _sources  = CRM.cache.sources  || [];
  const _users    = CRM.cache.users    || [];
  const _products = CRM.cache.products || [];
  const _camps    = CRM.cache.campaigns || [];

  const filterBar = h('div', { style: { display:'flex', alignItems:'center', flexWrap:'wrap', gap:'.4rem', marginBottom:'.85rem', padding:'.55rem .65rem', background:'#fff', border:'1px solid #e2e8f0', borderRadius:'10px' } });
  filterBar.appendChild(h('span', { style: { fontSize:'.78rem', fontWeight:600, color:'#475569', marginRight:'.2rem' } }, '🔎 Filters:'));
  const _dateFrom = h('input', { type:'date', class:'input', value: fp.from || '', style: { width:'140px', fontSize:'.8rem', padding:'.3rem .4rem' } });
  const _dateTo   = h('input', { type:'date', class:'input', value: fp.to   || '', style: { width:'140px', fontSize:'.8rem', padding:'.3rem .4rem' } });
  function _apply() {
    fp.from = _dateFrom.value || '';
    fp.to   = _dateTo.value   || '';
    _renderPipelineFunnel(view);
  }
  _dateFrom.addEventListener('change', _apply);
  _dateTo.addEventListener('change', _apply);
  filterBar.appendChild(h('span', { style: { fontSize:'.72rem', color:'#64748b' } }, 'From'));
  filterBar.appendChild(_dateFrom);
  filterBar.appendChild(h('span', { style: { fontSize:'.72rem', color:'#64748b' } }, 'To'));
  filterBar.appendChild(_dateTo);

  // PIPELINE_FUNNEL_FILTERS_v2 + DASH_DATE_CHIPS_v1 (2026-05-29) — preset
  // chips. Reuses the global window._attachDatePresets helper so behaviour
  // matches every other date-filtered surface (Dashboard, Leads, Call
  // Activity, etc.). MUST be deferred to setTimeout because filterBar is
  // not yet in the DOM at this point — the helper inserts the chip row
  // BEFORE filterBar's parent, which is null synchronously and would
  // silently fail. Every other caller of _attachDatePresets in this file
  // wraps in setTimeout for the same reason.
  setTimeout(() => {
    try { window._attachDatePresets && window._attachDatePresets(_dateFrom, _dateTo, { key: 'pipeline-funnel', apply: _apply }); } catch (_) {}
  }, 0);

  if (typeof multiSelectDropdown === 'function') {
    filterBar.appendChild(multiSelectDropdown({ label:'Status', allLabel:'Any status',
      options: _statuses.map(s => ({ id: String(s.id), name: s.name })),
      values:  fp.statuses || [],
      onApply: (v) => { fp.statuses = v; _renderPipelineFunnel(view); }
    }));
    filterBar.appendChild(multiSelectDropdown({ label:'Source', allLabel:'Any source',
      options: _sources.map(s => ({ id: s.name, name: s.name })),
      values:  fp.sources || [],
      onApply: (v) => { fp.sources = v; _renderPipelineFunnel(view); }
    }));
    filterBar.appendChild(multiSelectDropdown({ label:'Owner', allLabel:'All users',
      options: _users.map(u => ({ id: String(u.id), name: u.name })),
      values:  fp.users || [],
      onApply: (v) => { fp.users = v; _renderPipelineFunnel(view); }
    }));
    filterBar.appendChild(multiSelectDropdown({ label:'Product', allLabel:'Any product',
      options: _products.map(pr => ({ id: String(pr.id), name: pr.name })),
      values:  fp.products || [],
      onApply: (v) => { fp.products = v; _renderPipelineFunnel(view); }
    }));
    filterBar.appendChild(multiSelectDropdown({ label:'Campaign', allLabel:'Any campaign',
      options: _camps.map(c => ({ id: String(c.id), name: c.name })),
      values:  fp.campaigns || [],
      onApply: (v) => { fp.campaigns = v; _renderPipelineFunnel(view); }
    }));
  }

  const hasFilters = fp.from || fp.to || (fp.statuses && fp.statuses.length) || (fp.sources && fp.sources.length) || (fp.users && fp.users.length) || (fp.products && fp.products.length) || (fp.campaigns && fp.campaigns.length);
  if (hasFilters) {
    const clr = h('button', { class:'btn ghost', style: { fontSize:'.74rem', padding:'.3rem .55rem' },
      onclick: () => { window._funnelPicked = { from:'', to:'', sources:[], users:[], products:[], campaigns:[], statuses:[] }; _renderPipelineFunnel(view); }
    }, '✕ Clear all');
    filterBar.appendChild(clr);
  }
  view.appendChild(filterBar);

  // Build payload for backend
  const funnelPayload = {};
  if (fp.from) funnelPayload.from = fp.from;
  if (fp.to)   funnelPayload.to   = fp.to;
  if (fp.sources && fp.sources.length)   funnelPayload.source_ids   = fp.sources;
  if (fp.users && fp.users.length)       funnelPayload.user_ids     = fp.users.map(Number).filter(Boolean);
  if (fp.products && fp.products.length) funnelPayload.product_ids  = fp.products.map(Number).filter(Boolean);
  if (fp.campaigns && fp.campaigns.length) funnelPayload.campaign_ids = fp.campaigns.map(Number).filter(Boolean);
  if (fp.statuses && fp.statuses.length) funnelPayload.status_ids   = fp.statuses.map(Number).filter(Boolean);

  let data;
  try { data = await api('api_pipeline_funnel', funnelPayload); }
  catch (e) {
    view.appendChild(h('div', { class: 'error-box' }, 'Could not load funnel: ' + e.message));
    return;
  }
  const k = data.kpis || {};

  // Compact KPI strip — 4 light-blue rounded cards
  const kpiRow = h('div', { style: { display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(170px, 1fr))', gap:'.6rem', marginBottom:'1.1rem' } });
  function kpi(label, val, sub) {
    return h('div', { style: { background:'#eff6ff', border:'1px solid #dbeafe', borderRadius:'10px', padding:'.6rem .85rem' } },
      h('div', { style: { fontSize:'.68rem', color:'#1e40af', textTransform:'lowercase', letterSpacing:'.02em' } }, label),
      h('div', { style: { fontSize:'1.5rem', fontWeight:700, color:'#0f172a', lineHeight:'1.1', marginTop:'.15rem' } }, val),
      h('div', { style: { fontSize:'.68rem', color:'#64748b', marginTop:'.2rem' } }, sub)
    );
  }
  kpiRow.appendChild(kpi('total leads',  String(k.total_leads || 0), 'in pipeline'));
  kpiRow.appendChild(kpi('open value',   _formatInr(k.open_value || 0), 'weighted ' + _formatInr(k.weighted_value || 0)));
  kpiRow.appendChild(kpi('win rate',     (k.win_rate || 0) + '%', 'won vs closed'));
  kpiRow.appendChild(kpi('avg cycle',    k.avg_cycle_days != null ? (k.avg_cycle_days + 'd') : '—', 'lead to close'));
  view.appendChild(kpiRow);

  // ---- Funnel drawn as a single SVG: connected trapezoids ----
  const bands = (data.bands || []).slice(0, 5);
  if (!bands.length) {
    view.appendChild(h('div', { class:'muted', style:{ padding:'1rem', textAlign:'center' } },
      'No leads in the pipeline yet. As leads come in and get their stage mapped, they\'ll appear here.'));
    return;
  }

  // Derive top/bottom widths from data. For balanced pipelines (e.g.
  // reference 100/76/45/29/17) the funnel reads naturally. For heavily-
  // skewed pipelines (e.g. 100/12/5/2/1) we lift the floor to 38% so the
  // bottom bands stay wide enough to fit their labels ("Proposal sent ·
  // 15 leads · 1% of total" needs ~180px). Top band stays at the real
  // pct_of_total so the funnel still narrows visibly.
  const MIN_BAND_W = 38;   // % — keeps text readable inside the band
  const rawPcts = bands.map(b => Math.max(0, Math.min(100, Number(b.pct_of_total) || 0)));
  // Blend: width = max(MIN_BAND_W, raw_pct). For raw values above MIN it's
  // identical to raw_pct (matches reference). For raw values below MIN it
  // gets lifted to MIN.
  const widths = rawPcts.map(p => Math.max(MIN_BAND_W, Math.min(100, p)));
  // Force monotonic descent — each band must be at least 2pp narrower
  // than the one above so the funnel doesn't go flat. Skip if doing so
  // would push us below MIN_BAND_W (then we just stay equal).
  for (let i = 1; i < widths.length; i++) {
    const cap = widths[i - 1] - 2;
    if (widths[i] > cap) widths[i] = Math.max(MIN_BAND_W, cap);
  }
  // Bottom of each band = next band's top width; last band tapers a bit
  const bottoms = widths.map((w, i) =>
    i < widths.length - 1 ? widths[i + 1] : Math.max(MIN_BAND_W - 4, w - 4));

  const BAND_H = 64;            // px per band
  const FUNNEL_W = 520;         // funnel column width
  const RIGHT_GUTTER = 250;     // space for the right-side label
  const TOTAL_W = FUNNEL_W + 90 + RIGHT_GUTTER; // funnel + connector + label
  const FUNNEL_H = BAND_H * bands.length;

  const wrap = h('div', { style: { display:'flex', justifyContent:'center', margin:'.2rem 0' } });
  const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
  svg.setAttribute('viewBox', '0 0 ' + TOTAL_W + ' ' + FUNNEL_H);
  svg.setAttribute('width', '100%');
  svg.setAttribute('style', 'max-width:' + TOTAL_W + 'px; height:auto; display:block;');

  function pctToX(pct) { return (50 - pct / 2) * (FUNNEL_W / 100); }
  function pctToXR(pct) { return (50 + pct / 2) * (FUNNEL_W / 100); }

  bands.forEach((b, i) => {
    const yTop = i * BAND_H;
    const yBot = (i + 1) * BAND_H;
    const wTop = widths[i];
    const wBot = bottoms[i];
    const tl = pctToX(wTop), tr = pctToXR(wTop);
    const bl = pctToX(wBot), br = pctToXR(wBot);
    const fill = _FUNNEL_BAND_COLORS[i] || _FUNNEL_BAND_COLORS[_FUNNEL_BAND_COLORS.length - 1];
    const txt  = _FUNNEL_BAND_TEXT[i] || '#fff';
    const dot  = _FUNNEL_DOT_COLORS[i] || '#1e3a8a';

    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    path.setAttribute('d', 'M ' + tl + ' ' + yTop + ' L ' + tr + ' ' + yTop + ' L ' + br + ' ' + yBot + ' L ' + bl + ' ' + yBot + ' Z');
    path.setAttribute('fill', fill);
    path.setAttribute('stroke', '#ffffff');
    path.setAttribute('stroke-width', '1');
    path.style.cursor = 'pointer';
    path.addEventListener('mouseenter', () => { path.setAttribute('filter', 'brightness(1.08)'); });
    path.addEventListener('mouseleave', () => { path.removeAttribute('filter'); });
    path.addEventListener('click', () => { location.hash = '#/leads?stage=' + b.id; });
    const t = document.createElementNS('http://www.w3.org/2000/svg', 'title');
    t.textContent = 'Click to see leads in ' + b.label;
    path.appendChild(t);
    svg.appendChild(path);

    // Label text inside band
    const labelGrp = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    labelGrp.setAttribute('pointer-events', 'none');
    const lbl = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    lbl.setAttribute('x', FUNNEL_W / 2);
    lbl.setAttribute('y', yTop + BAND_H / 2 - 4);
    lbl.setAttribute('text-anchor', 'middle');
    lbl.setAttribute('fill', txt);
    lbl.setAttribute('font-weight', '700');
    lbl.setAttribute('font-size', '14');
    lbl.textContent = b.label;
    labelGrp.appendChild(lbl);
    const sub = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    sub.setAttribute('x', FUNNEL_W / 2);
    sub.setAttribute('y', yTop + BAND_H / 2 + 12);
    sub.setAttribute('text-anchor', 'middle');
    sub.setAttribute('fill', txt);
    sub.setAttribute('opacity', '0.95');
    sub.setAttribute('font-size', '11');
    sub.textContent = b.count + ' leads · ' + b.pct_of_total + '% of total';
    labelGrp.appendChild(sub);
    svg.appendChild(labelGrp);

    // Dashed connector + dot at right edge of band middle
    const yMid = yTop + BAND_H / 2;
    const connector = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    connector.setAttribute('x1', FUNNEL_W);
    connector.setAttribute('y1', yMid);
    connector.setAttribute('x2', FUNNEL_W + 80);
    connector.setAttribute('y2', yMid);
    connector.setAttribute('stroke', dot);
    connector.setAttribute('stroke-width', '1.5');
    connector.setAttribute('stroke-dasharray', '4 4');
    connector.setAttribute('opacity', '0.7');
    svg.appendChild(connector);

    const dotEl = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    dotEl.setAttribute('cx', FUNNEL_W + 80);
    dotEl.setAttribute('cy', yMid);
    dotEl.setAttribute('r', '4.5');
    dotEl.setAttribute('fill', dot);
    svg.appendChild(dotEl);

    // Right-side label text
    const rTitle = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    rTitle.setAttribute('x', FUNNEL_W + 95);
    rTitle.setAttribute('y', yMid - 3);
    rTitle.setAttribute('fill', '#0f172a');
    rTitle.setAttribute('font-weight', '700');
    rTitle.setAttribute('font-size', '13');
    rTitle.textContent = b.count + ' leads';
    svg.appendChild(rTitle);

    const advanceText = (b.advance_pct != null && i < bands.length - 1)
      ? (b.advance_pct + '% advance')
      : (i === bands.length - 1 ? 'final stage' : '');
    const rSub = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    rSub.setAttribute('x', FUNNEL_W + 95);
    rSub.setAttribute('y', yMid + 12);
    rSub.setAttribute('fill', '#64748b');
    rSub.setAttribute('font-size', '11');
    rSub.textContent = _formatInr(b.value) + (advanceText ? (' · ' + advanceText) : '');
    svg.appendChild(rSub);
  });
  wrap.appendChild(svg);
  view.appendChild(wrap);

  // ---- Won / Lost cards ----
  const won = data.won || { count:0, value:0 };
  const lost = data.lost || { count:0, value:0 };
  const closed = won.count + lost.count;
  const lostPct = closed ? Math.round((lost.count / closed) * 100) : 0;

  const summary = h('div', { style: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:'.6rem', marginTop:'1rem' } });

  summary.appendChild(h('div', {
    style: { background:'#dcfce7', border:'1px solid #bbf7d0', borderRadius:'10px', padding:'.7rem .9rem', cursor:'pointer', display:'flex', alignItems:'center', gap:'.7rem' },
    onclick: () => { location.hash = '#/leads?stage=won'; }
  },
    h('div', { style: { width:'34px', height:'34px', borderRadius:'8px', background:'#86efac', color:'#14532d', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'1.05rem', fontWeight:700, flexShrink:0 } }, '✓'),
    h('div', { style: { flex:1, minWidth:0 } },
      h('div', { style: { fontWeight:700, color:'#14532d', fontSize:'.92rem' } }, 'Won'),
      h('div', { style: { fontSize:'.7rem', color:'#15803d', marginTop:'.1rem' } }, (data.kpis.win_rate || 0) + '% win rate')
    ),
    h('div', { style: { textAlign:'right' } },
      h('div', { style: { fontWeight:700, fontSize:'1.3rem', color:'#14532d', lineHeight:1 } }, String(won.count)),
      h('div', { style: { fontSize:'.72rem', color:'#16a34a', marginTop:'.2rem' } }, _formatInr(won.value))
    )
  ));

  summary.appendChild(h('div', {
    style: { background:'#fee2e2', border:'1px solid #fecaca', borderRadius:'10px', padding:'.7rem .9rem', cursor:'pointer', display:'flex', alignItems:'center', gap:'.7rem' },
    onclick: () => { location.hash = '#/leads?stage=lost'; }
  },
    h('div', { style: { width:'34px', height:'34px', borderRadius:'8px', background:'#fca5a5', color:'#7f1d1d', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'1.05rem', fontWeight:700, flexShrink:0 } }, '✕'),
    h('div', { style: { flex:1, minWidth:0 } },
      h('div', { style: { fontWeight:700, color:'#7f1d1d', fontSize:'.92rem' } }, 'Lost'),
      h('div', { style: { fontSize:'.7rem', color:'#b91c1c', marginTop:'.1rem' } }, lostPct + '% of closed')
    ),
    h('div', { style: { textAlign:'right' } },
      h('div', { style: { fontWeight:700, fontSize:'1.3rem', color:'#7f1d1d', lineHeight:1 } }, String(lost.count)),
      h('div', { style: { fontSize:'.72rem', color:'#dc2626', marginTop:'.2rem' } }, _formatInr(lost.value))
    )
  ));
  view.appendChild(summary);

  // Unmapped statuses warning
  if (data.unmapped && data.unmapped.count > 0) {
    view.appendChild(h('div', { style: { marginTop:'.8rem', background:'#fef3c7', border:'1px solid #fde68a', borderRadius:'10px', padding:'.55rem .85rem', display:'flex', alignItems:'center', gap:'.6rem', cursor:'pointer' },
      onclick: () => { location.hash = '#/admin'; }
    },
      h('span', { style: { fontSize:'1.1rem' } }, '⚠️'),
      h('div', { style: { flex:1 } },
        h('div', { style: { fontWeight:600, color:'#92400e', fontSize:'.82rem' } }, data.unmapped.count + ' leads on unmapped statuses'),
        h('div', { style: { fontSize:'.72rem', color:'#b45309', marginTop:'.1rem' } }, 'These don\'t appear in the funnel. Click to open Settings → Statuses and map them to a stage.')
      )
    ));
  }
}

VIEWS.pipeline = async (view) => {
  // PIPELINE_STAGE_v1_PHASE2 — new funnel pipeline view is now the default.
  // If user clicked Switch to Kanban, fall through to the old logic below.
  if (!window._rePipeForceKanban && !window._rePipeForceLegacyGrid) {
    try { await _renderPipelineFunnel(view); return; }
    catch (e) { console.warn('[pipeline funnel] fell back to legacy:', e.message); }
  }
  // Legacy generic / RE card-grid pipeline (still available via the toggle).
  if (!window._rePipeForceKanban) {
    try {
      const { statuses = [] } = CRM.cache;
      const pipeline = await api('api_leads_pipeline');
      const useREGrid = (typeof _reIsActive === 'function') && _reIsActive();
      if (useREGrid) _reRenderCPProcessPipeline(view, pipeline, statuses);
      else _genericRenderCardGridPipeline(view, pipeline, statuses);
      return;
    } catch (e) {
      console.warn('[pipeline grid] fallback to kanban:', e.message);
      // fall through to standard view
    }
  }
  // Filter state (stored on window so it survives re-render).
  window._pipePicked = window._pipePicked || { statuses: [], sources: [], users: [] };
  const _pipeFilters = {
    status_ids: window._pipePicked.statuses.length ? window._pipePicked.statuses : undefined,
    sources:    window._pipePicked.sources.length  ? window._pipePicked.sources  : undefined,
    user_ids:   window._pipePicked.users.length    ? window._pipePicked.users    : undefined
  };
  const [funnel, summary, pipeline] = await Promise.all([
    api('api_reports_funnel', _pipeFilters),
    api('api_reports_summary', _pipeFilters),
    api('api_leads_pipeline')
  ]);
  const total = summary.totals.total || 1;
  view.innerHTML = '';
  // PIPELINE_LEGACY_FUNNEL_SWITCH_v1 — this legacy 'Sales funnel' fallback
  // view never had a way to get back to the new pipeline funnel. Add a
  // toolbar at the top with a 📈 Switch to Funnel view button that clears
  // both force flags and re-renders.
  view.appendChild(h('div', { style: { display:'flex', alignItems:'center', justifyContent:'space-between', flexWrap:'wrap', gap:'.5rem', marginBottom:'.55rem' } },
    h('h2', { style: { margin: 0, fontSize: '1.3rem', color: '#0f172a' } }, 'Pipeline'),
    h('button', { class: 'btn ghost sm', type: 'button',
      style: { fontSize:'.78rem', padding:'.3rem .65rem' },
      onclick: () => {
        window._rePipeForceKanban = false;
        window._rePipeForceLegacyGrid = false;
        VIEWS.pipeline(view);
      }
    }, '📈 Switch to Funnel view')
  ));

  // Filter bar — multi-select Status/Source/User + rule-builder.
  (function(){
    const { statuses = [], sources = [], users = [] } = CRM.cache;
    const tb = document.createElement('div');
    tb.className = 'toolbar';
    tb.style.marginBottom = '.5rem';
    tb.appendChild(multiSelectDropdown({ label: 'Status', allLabel: 'Any status',
      options: statuses.map(s => ({ id: String(s.id), name: s.name })),
      values: window._pipePicked.statuses || [],
      onApply: (v) => { window._pipePicked.statuses = v; VIEWS.pipeline(view); }
    }));
    tb.appendChild(multiSelectDropdown({ label: 'Source', allLabel: 'Any source',
      options: sources.map(s => ({ id: s.name, name: s.name })),
      values: window._pipePicked.sources || [],
      onApply: (v) => { window._pipePicked.sources = v; VIEWS.pipeline(view); }
    }));
    tb.appendChild(multiSelectDropdown({ label: 'Owner', allLabel: 'All users',
      options: users.map(u => ({ id: String(u.id), name: u.name })),
      values: window._pipePicked.users || [],
      onApply: (v) => { window._pipePicked.users = v; VIEWS.pipeline(view); }
    }));
    const rb = ruleBuilderButton({ label: '+ Filter rule', storageKey: 'crm.pipeline.rules.v1',
      fields: [ { id: 'name', label: 'Lead name', type: 'text' }, { id: 'phone', label: 'Phone', type: 'text' }, { id: 'company', label: 'Company', type: 'text' }, { id: 'tag', label: 'Tag', type: 'text' }, { id: 'source', label: 'Source', type: 'text' } ],
      onChange: () => VIEWS.pipeline(view)
    });
    window._pipeRuleBtn = rb;
    tb.appendChild(rb);
    if (window._pipePicked.statuses.length || window._pipePicked.sources.length || window._pipePicked.users.length || rb.getRules().length) {
      const clr = document.createElement('button');
      clr.type = 'button'; clr.className = 'btn ghost'; clr.textContent = 'Clear all';
      clr.onclick = () => { window._pipePicked = { statuses: [], sources: [], users: [] }; rb.setRules([]); try { localStorage.removeItem('crm.pipeline.rules.v1'); } catch(_){} VIEWS.pipeline(view); };
      tb.appendChild(clr);
    }
    view.appendChild(tb);
  })();
  // Apply per-stage client-side rule-builder + multi-select status/source/owner filtering on the pipeline data.
  try {
    const _rb = (window._pipeRuleBtn && window._pipeRuleBtn.getRules) ? window._pipeRuleBtn.getRules() : [];
    const _ss = window._pipePicked.statuses.map(String);
    const _src= window._pipePicked.sources.map(String);
    const _us = window._pipePicked.users.map(String);
    pipeline.forEach(p => {
      if (!Array.isArray(p.leads)) return;
      p.leads = p.leads.filter(l => {
        if (_ss.length && !_ss.includes(String(l.status_id))) return false;
        if (_src.length && !_src.includes(String(l.source || ''))) return false;
        if (_us.length && !_us.includes(String(l.assigned_to || ''))) return false;
        if (_rb.length && !_applyClientRules(l, _rb)) return false;
        return true;
      });
    });
  } catch (_) {}

  // Funnel summary card — waterfall view: biggest stage on top,
  // narrower as we go down. Hides empty stages so the visual stays clean.
  // Sort by count DESC and use the top stage as the conversion baseline.
  const funnelSorted = [...funnel]
    .map(s => ({ ...s, _c: Number(s.count) || 0 }))
    .filter(s => s._c > 0)
    .sort((a, b) => b._c - a._c);
  const topCount = funnelSorted[0]?._c || total;
  view.appendChild(h('div', { class: 'card' },
    h('h3', {}, 'Sales funnel'),
    h('div', { class: 'funnel' },
      ...funnelSorted.map((s, i) => {
        const pct = Math.round((s._c / total) * 100);
        const width = topCount > 0 ? Math.max(20, Math.round((s._c / topCount) * 100)) : 20;
        const prev = i > 0 ? funnelSorted[i - 1]._c : topCount;
        const conv = prev > 0 ? Math.round((s._c / prev) * 100) : 0;
        return h('div', { class: 'funnel-row' },
          h('div', { class: 'funnel-label' }, s.name),
          h('div', { class: 'funnel-bar-wrap' },
            h('div', { class: 'funnel-bar', style: { width: width + '%', background: s.color } },
              h('span', { class: 'funnel-count' }, s._c),
              h('span', { class: 'funnel-pct' }, pct + '%')
            )
          ),
          h('div', { class: 'funnel-conv' }, i === 0 ? '—' : conv + '% vs prev')
        );
      })
    )
  ));

  // Leads per stage (expandable sections) — also rendered in waterfall
  // order so the biggest bucket is at the top, matching the funnel above.
  // Includes empty stages too so the user can still see them and add
  // leads if needed.
  view.appendChild(h('h3', { style: { marginTop: '1.25rem' } }, 'Leads by stage'));
  const wrap = h('div', { class: 'pipeline-stages' });
  view.appendChild(wrap);

  const funnelByCount = [...funnel]
    .map(s => ({ ...s, _c: Number(s.count) || 0 }))
    .sort((a, b) => b._c - a._c);
  funnelByCount.forEach(s => {
    const entry = pipeline.find(p => Number(p.id) === Number(s.id));
    const leads = entry?.leads || [];
    const details = h('details', { class: 'pipeline-stage-card', style: { borderTopColor: s.color } },
      h('summary', {},
        h('span', { class: 'ps-dot', style: { background: s.color } }),
        h('span', { class: 'ps-name' }, s.name),
        h('span', { class: 'ps-count' }, leads.length),
        h('span', { class: 'ps-hint muted' }, leads.length > 0 ? 'click to expand' : 'no leads')
      ),
      leads.length > 0
        ? h('div', { class: 'ps-body' },
            h('table', { class: 'mini-table' },
              h('thead', {}, h('tr', {},
                h('th', {}, 'Name'), h('th', {}, 'Phone'),
                h('th', {}, 'Source'), h('th', {}, 'Assignee'),
                h('th', {}, 'Follow-up'), h('th', {})
              )),
              h('tbody', {}, ...leads.map(l => h('tr', {},
                h('td', {}, h('a', { href: '#', onclick: ev => { ev.preventDefault(); openLeadModal(l.id); } }, l.name || '—')),
                h('td', {},
                  l.phone || '',
                  l.phone ? h('button', { class: 'btn icon', title: 'Copy', onclick: () => { navigator.clipboard.writeText(l.phone); toast('Copied'); } }, '📋') : null,
                  l.phone ? h('a', { class: 'btn icon', href: window._waShareUrl(l.phone, ''), target: '_blank', title: 'WhatsApp (toggle Web/App in user menu)' }, '💬') : null
                ),
                h('td', {}, l.source || ''),
                h('td', {}, l.assigned_name || '—'),
                h('td', { class: l.next_followup_at && new Date(l.next_followup_at) < new Date() ? 'overdue' : '' },
                  l.next_followup_at ? fmtDate(l.next_followup_at, 'relative') : '—'),
                h('td', {}, h('button', { class: 'btn sm', onclick: () => openLeadModal(l.id) }, '✎'))
              )))
            )
          )
        : null
    );
    // Auto-expand first non-empty stage
    if (leads.length > 0 && !wrap.querySelector('details[open]')) details.open = true;
    wrap.appendChild(details);
  });
};

/* ---------------- Kanban (drag & drop, stable handlers) ----------------
 * Design notes:
 *  - Cards mirror the leads-list row content (name, phone, value, tags,
 *    qualified ★, assignee, FU chip) so reps don't lose info when they
 *    flip from list to board.
 *  - Same filter set as the leads list (search, assignee, source,
 *    qualified). Persisted to localStorage as `crm_kanban_filters` so
 *    the rep's morning view stays put.
 *  - Click a column header to collapse it to a thin strip — useful for
 *    Lost / Junk which don't need to occupy 250px of board real estate.
 *    Collapsed columns persist via `crm_kanban_collapsed`.
 */

function _kbFollowupChip(iso) {
  if (!iso) return null;
  const due = new Date(iso).getTime();
  if (isNaN(due)) return null;
  const now = Date.now();
  const today = new Date(); today.setHours(23, 59, 59, 999);
  const isOverdue = due < now;
  const isToday   = !isOverdue && due <= today.getTime();
  const cls = isOverdue ? 'kc-fu overdue' : isToday ? 'kc-fu today' : 'kc-fu future';
  return h('span', { class: cls }, '⏰ ' + fmtDate(iso, 'relative'));
}

function _kbInr(value) {
  const n = Number(value);
  if (!isFinite(n) || n <= 0) return '';
  if (n >= 10000000) return '₹' + (n / 10000000).toFixed(n % 10000000 === 0 ? 0 : 2) + ' Cr';
  if (n >= 100000)   return '₹' + (n / 100000).toFixed(n % 100000 === 0 ? 0 : 2) + ' L';
  if (n >= 1000)     return '₹' + (n / 1000).toFixed(n % 1000 === 0 ? 0 : 1) + 'k';
  return '₹' + n.toFixed(0);
}

function _kbInitials(name) {
  return String(name || '?').split(/\s+/).map(s => s[0]).filter(Boolean).slice(0, 2).join('').toUpperCase();
}

function _kbMatchesFilters(l, f) {
  if (f.q) {
    const q = String(f.q).toLowerCase();
    const hit =
      String(l.name || '').toLowerCase().includes(q) ||
      String(l.phone || '').toLowerCase().includes(q) ||
      String(l.email || '').toLowerCase().includes(q) ||
      String(l.whatsapp || '').toLowerCase().includes(q);
    if (!hit) return false;
  }
  if (f.assigned_to && Number(l.assigned_to) !== Number(f.assigned_to)) return false;
  if (f.source && l.source !== f.source) return false;
  if (f.qualified === '1' && Number(l.qualified) !== 1) return false;
  if (f.qualified === '0' && Number(l.qualified) === 1) return false;
  return true;
}

VIEWS.kanban = async (view) => {
  if (!CRM.cache.statuses) await warmCache();
  const statuses = CRM.cache.statuses;
  const sources  = CRM.cache.sources  || [];
  const users    = CRM.cache.users    || [];
  const kanban   = await api('api_leads_pipeline');
  const filters  = JSON.parse(localStorage.getItem('crm_kanban_filters') || '{}');
  const collapsed = JSON.parse(localStorage.getItem('crm_kanban_collapsed') || '[]');
  view.innerHTML = '';

  const persistFilters = () => localStorage.setItem('crm_kanban_filters', JSON.stringify(filters));
  const persistCollapsed = () => localStorage.setItem('crm_kanban_collapsed', JSON.stringify(collapsed));

  // ---- Toolbar (mirrors the leads-list filter set) ---------------------
  const search = h('input', {
    id: 'kb-q', class: 'flex',
    placeholder: 'Search name / phone / email…',
    value: filters.q || ''
  });
  let searchTimer;
  search.addEventListener('input', () => {
    filters.q = search.value;
    clearTimeout(searchTimer);
    searchTimer = setTimeout(() => { persistFilters(); render(); }, 200);
  });

  const assigneeSel = selectOpts('kb-assigned',
    [{ id: '', name: 'Any assignee' }, ...users],
    filters.assigned_to);
  assigneeSel.addEventListener('change', () => { filters.assigned_to = assigneeSel.value || ''; persistFilters(); render(); });

  const sourceSel = selectOpts('kb-source',
    [{ id: '', name: 'Any source' }, ...sources.map(s => ({ id: s.name, name: s.name }))],
    filters.source);
  sourceSel.addEventListener('change', () => { filters.source = sourceSel.value || ''; persistFilters(); render(); });

  const qualifiedSel = selectOpts('kb-qualified',
    [{ id: '', name: 'Any qualified' }, { id: '1', name: '⭐ Qualified only' }, { id: '0', name: 'Not qualified' }],
    filters.qualified);
  qualifiedSel.addEventListener('change', () => { filters.qualified = qualifiedSel.value || ''; persistFilters(); render(); });

  const clearBtn = h('button', {
    class: 'btn ghost', title: 'Reset filters',
    onclick: () => {
      ['q', 'assigned_to', 'source', 'qualified'].forEach(k => delete filters[k]);
      persistFilters();
      navigateTo('kanban');
    }
  }, '✕');

  view.appendChild(h('div', { class: 'toolbar' },
    search, assigneeSel, sourceSel, qualifiedSel, clearBtn,
    h('button', { class: 'btn primary', onclick: () => openLeadModal() }, '+ New Lead')
  ));

  const wrap = h('div', { class: 'kanban' });
  view.appendChild(wrap);

  function render() {
    wrap.innerHTML = '';
    statuses.forEach(s => {
      const col = h('div', { class: 'kanban-col' });
      col.dataset.statusId = s.id;
      const isCollapsed = collapsed.includes(Number(s.id));
      if (isCollapsed) col.classList.add('kanban-col-collapsed');

      // ---- Drag-and-drop handlers (drop changes status) -----------------
      col.addEventListener('dragover', ev => {
        ev.preventDefault();
        ev.dataTransfer.dropEffect = 'move';
        col.classList.add('drop-hover');
      });
      col.addEventListener('dragleave', () => col.classList.remove('drop-hover'));
      col.addEventListener('drop', async ev => {
        ev.preventDefault();
        ev.stopPropagation();
        col.classList.remove('drop-hover');
        const leadId = Number(ev.dataTransfer.getData('text/plain') || ev.dataTransfer.getData('application/lead-id'));
        if (!leadId) return;
        const newStatusId = Number(col.dataset.statusId);
        try {
          await api('api_leads_update', leadId, { status_id: newStatusId });
              try { _kickRecordingSyncSoon(6000); } catch (_) {}
          toast('Status updated');
          render();
        } catch (e) { toast(e.message, 'err'); }
      });

      // Filter the leads for this column.
      const allLeads = kanban.find(k => Number(k.id) === Number(s.id))?.leads || [];
      const visible  = allLeads.filter(l => _kbMatchesFilters(l, filters));
      const valueSum = visible.reduce((sum, l) => sum + (Number(l.value) || 0), 0);

      // ---- Column header — click to collapse/expand --------------------
      const head = h('h4', {
        class: 'kanban-head',
        style: { borderTopColor: s.color },
        onclick: () => {
          const idx = collapsed.indexOf(Number(s.id));
          if (idx >= 0) collapsed.splice(idx, 1); else collapsed.push(Number(s.id));
          persistCollapsed();
          render();
        }
      },
        h('span', { class: 'kanban-name' }, s.name),
        h('span', { class: 'kanban-meta' },
          visible.length + (valueSum > 0 ? ' · ' + _kbInr(valueSum) : '')
        )
      );
      col.appendChild(head);

      if (!isCollapsed) {
        visible.forEach(l => {
          const card = h('div', { class: 'kanban-card', draggable: 'true' });
          card.dataset.leadId = l.id;
          card.addEventListener('dragstart', ev => {
            ev.dataTransfer.setData('text/plain', String(l.id));
            ev.dataTransfer.setData('application/lead-id', String(l.id));
            ev.dataTransfer.effectAllowed = 'move';
            card.classList.add('dragging');
          });
          card.addEventListener('dragend', () => card.classList.remove('dragging'));
          card.addEventListener('click', () => {
            if (!card.classList.contains('was-dragged')) openLeadModal(l.id);
          });

          // Top row: name + qualified ★
          const topRow = h('div', { class: 'kc-top' },
            h('div', { class: 'kc-name' }, l.name || '—'),
            Number(l.qualified) === 1 ? h('span', { class: 'kc-star', title: 'Qualified' }, '★') : null
          );
          card.appendChild(topRow);

          // Phone + source
          const meta = (l.phone || '') + (l.source ? ' · ' + l.source : '');
          if (meta) card.appendChild(h('div', { class: 'kc-meta' }, meta));

          // Value (large, prominent)
          const valStr = _kbInr(l.value);
          if (valStr) card.appendChild(h('div', { class: 'kc-value' }, valStr));

          // Tags (chips, max 3 visible)
          const tags = String(l.tags || '').split(',').map(t => t.trim()).filter(Boolean);
          if (tags.length) {
            const tagWrap = h('div', { class: 'kc-tags' });
            tags.slice(0, 3).forEach(t => tagWrap.appendChild(h('span', { class: 'kc-tag' }, t)));
            if (tags.length > 3) tagWrap.appendChild(h('span', { class: 'kc-tag muted' }, '+' + (tags.length - 3)));
            card.appendChild(tagWrap);
          }

          // Footer: assignee | follow-up chip
          const repName = l.assigned_name || '—';
          const initials = _kbInitials(repName);
          card.appendChild(h('div', { class: 'kc-foot' },
            h('span', { class: 'kc-rep', title: repName },
              h('span', { class: 'kc-avatar' }, initials),
              h('span', { class: 'kc-rep-name' }, repName)
            ),
            _kbFollowupChip(l.next_followup_at)
          ));

          col.appendChild(card);
        });

        if (allLeads.length > visible.length) {
          col.appendChild(h('div', { class: 'kanban-filtered-note' },
            (allLeads.length - visible.length) + ' filtered out'));
        }
      }

      wrap.appendChild(col);
    });
  }

  render();
};

/* ---------------- Follow-ups ---------------- */
// Sidebar shortcut views — each one is a single-section variant of
// the Followups view, so users with overdue/due-today work can land
// directly on the right list from the sidebar.
VIEWS.overdue  = async (view) => renderFollowupSection(view, 'overdue');
VIEWS.duetoday = async (view) => renderFollowupSection(view, 'due_today');
VIEWS.upcoming = async (view) => renderFollowupSection(view, 'upcoming');
VIEWS.newleads = async (view) => renderNewTodayLeads(view);

async function renderFollowupSection(view, key) {
  const data = await api('api_notifications_mine');
  view.innerHTML = '';
  const titleMap = { overdue: '⚠️ Overdue follow-ups', due_today: '📅 Due today', upcoming: '⏰ Upcoming' };
  const klassMap = { overdue: 'err', due_today: 'warn', upcoming: '' };
  const allRows = data[key] || [];
  /* FU_PAGINATION_v1 — 25 per page, persisted across re-renders via
     window scope (key-specific so each section has its own page). */
  const PAGE_SIZE = 25;
  if (!window._fuPage) window._fuPage = {};
  if (!window._fuPage[key]) window._fuPage[key] = 1;
  const totalPages = Math.max(1, Math.ceil(allRows.length / PAGE_SIZE));
  if (window._fuPage[key] > totalPages) window._fuPage[key] = totalPages;
  const pageNum = window._fuPage[key];
  const startIdx = (pageNum - 1) * PAGE_SIZE;
  const rows = allRows.slice(startIdx, startIdx + PAGE_SIZE);

  const wrap = h('div', { class: 'card' },
    h('h3', {}, titleMap[key], ' ', h('span', { class: 'chip-count ' + klassMap[key] }, allRows.length))
  );
  if (!allRows.length) {
    wrap.appendChild(h('p', { class: 'muted' }, 'Nothing here. 🎉'));
    view.appendChild(wrap);
    return;
  }
  wrap.appendChild(h('div', { class: 'table-wrap' }, h('table', {},
    h('thead', {}, h('tr', {},
      h('th', {}, 'Lead'), h('th', {}, 'Phone'),
      h('th', {}, 'Assigned to'),
      h('th', {}, 'Due'),
      h('th', {}, 'Latest remark'), h('th', { style: { textAlign: 'right' } }, 'Actions')
    )),
    h('tbody', {}, ...rows.map(r => {
      const phone = String(r.lead_phone || '').trim();
      const telHref = phone ? 'tel:' + phone.replace(/[^\d+]/g, '') : null;
      const waHref  = phone ? window._waShareUrl(phone, '') : null;
      return h('tr', {},
        h('td', {}, h('a', { href: '#', onclick: ev => { ev.preventDefault(); openLeadModal(r.lead_id); } }, r.lead_name || '—')),
        h('td', {}, phone || ''),
        h('td', { class: r.assigned_name ? '' : 'muted' }, r.assigned_name || 'Unassigned'),
        h('td', { class: key === 'overdue' ? 'overdue' : '' }, fmtDate(r.due_at, 'relative')),
        h('td', { class: 'fu-latest-remark', title: r.latest_remark || '' },
          r.latest_remark ? String(r.latest_remark).slice(0, 80) + (String(r.latest_remark).length > 80 ? '…' : '') : h('span', { class: 'muted' }, '—')),
        h('td', { style: { textAlign: 'right', whiteSpace: 'nowrap' } },
          telHref ? h('a', { class: 'btn sm primary', href: telHref }, '📞') : null,
          waHref  ? h('a', { class: 'btn sm ghost', href: waHref, target: '_blank', rel: 'noopener', style: { marginLeft: '.25rem' } }, '💬') : null,
          r.id ? h('button', { class: 'btn sm primary', style: { marginLeft: '.25rem' },
            onclick: () => openNextFollowupModal(r, () => navigateTo(key === 'overdue' ? 'overdue' : key === 'due_today' ? 'duetoday' : 'upcoming'))
          }, '⏰ Next') : null,
          /* FU_DONE_v1: "Mark Done" closes the followup AND clears the
             lead's next_followup_at so the row disappears from due lists. */
          r.lead_id ? h('button', { class: 'btn sm ok', style: { marginLeft: '.25rem' },
            title: 'Mark follow-up done (lead drops off this list)',
            onclick: async () => {
              if (!confirm('Mark this follow-up as done? The lead will be removed from Due / Overdue lists.')) return;
              try {
                await api('api_leads_followupDone', r.lead_id);
                toast('Follow-up marked done ✓');
                navigateTo(key === 'overdue' ? 'overdue' : key === 'due_today' ? 'duetoday' : 'upcoming');
              } catch (e) { toast(e.message || 'Failed to mark done', 'err'); }
            }
          }, '✓ Done') : null
        )
      );
    }))
  )));

  /* FU_PAGINATION_v1 — Prev/Next page controls + range display. */
  if (totalPages > 1) {
    const showingFrom = startIdx + 1;
    const showingTo   = Math.min(startIdx + PAGE_SIZE, allRows.length);
    wrap.appendChild(h('div', {
      style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center',
               padding: '.7rem .25rem .25rem', gap: '.5rem', flexWrap: 'wrap' } },
      h('span', { class: 'muted', style: { fontSize: '.85rem' } },
        'Showing ' + showingFrom + '–' + showingTo + ' of ' + allRows.length),
      h('div', { style: { display: 'flex', gap: '.4rem', alignItems: 'center' } },
        h('button', { class: 'btn sm' + (pageNum <= 1 ? ' ghost' : ''),
          disabled: pageNum <= 1,
          onclick: () => { window._fuPage[key] = Math.max(1, pageNum - 1); renderFollowupSection(view, key); }
        }, '‹ Prev'),
        h('span', { style: { fontSize: '.85rem', padding: '0 .4rem' } },
          'Page ' + pageNum + ' / ' + totalPages),
        h('button', { class: 'btn sm' + (pageNum >= totalPages ? ' ghost' : ''),
          disabled: pageNum >= totalPages,
          onclick: () => { window._fuPage[key] = Math.min(totalPages, pageNum + 1); renderFollowupSection(view, key); }
        }, 'Next ›')
      )
    ));
  }

  view.appendChild(wrap);
}

/**
 * "New today" sidebar shortcut — shows leads created today (in IST), reusing
 * the leads list with a server-applied date filter so it always matches the
 * dashboard "NEW TODAY" tile count.
 */
async function renderNewTodayLeads(view) {
  view.innerHTML = '';
  // NEW_HEADER_ALL_v1 — surface ALL leads with status='New', any date.
  if (!CRM.cache || !CRM.cache.statuses) {
    try { await warmCache(); } catch (_) {}
  }
  const _stsAll = (CRM.cache && CRM.cache.statuses) || [];
  const _newSt = _stsAll.find(s => String(s.name || '').trim().toLowerCase() === 'new')
              || _stsAll.find(s => String(s.name || '').trim().toLowerCase().startsWith('new '));
  const _newStId = _newSt ? Number(_newSt.id) : null;
  let rows = [];
  try {
    const payload = { page_size: 500 };
    if (_newStId) payload.status_id = _newStId;
    const r = await api('api_leads_list', payload);
    rows = (r && r.leads) || (r && r.rows) || [];
  } catch (e) { /* fall through */ }
  const wrap = h('div', { class: 'card' },
    h('h3', {}, '✨ All new leads ', h('span', { class: 'chip-count accent' }, rows.length))
  );
  if (!_newStId) {
    wrap.appendChild(h('p', { class: 'muted' }, "No status named 'New' is configured."));
    view.appendChild(wrap);
    return;
  }
  if (!rows.length) {
    wrap.appendChild(h('p', { class: 'muted' }, 'No leads in the New status right now.'));
    view.appendChild(wrap);
    return;
  }
  // Surface a small TAT-breach summary at the top so the rep can see
  // at a glance how many of today's leads are already past their stage
  // threshold (rare on day-of, but possible for short thresholds).
  const breachCount = rows.filter(l => l && l.tat_violation).length;
  if (breachCount > 0) {
    wrap.appendChild(h('div', { class: 'tat-banner' },
      '⚠ ', h('b', {}, breachCount), ' of today’s leads ',
      breachCount === 1 ? 'is' : 'are', ' already past TAT — action immediately.'));
  }
  wrap.appendChild(h('div', { class: 'table-wrap' }, h('table', {},
    h('thead', {}, h('tr', {},
      h('th', {}, 'Name'), h('th', {}, 'Phone'), h('th', {}, 'Source'),
      h('th', {}, 'Status'), h('th', {}, 'Assigned to'), h('th', {}, 'Created')
    )),
    h('tbody', {}, ...rows.map(l => h('tr', {
      class: l.tat_violation ? 'row-tat-violation' : '',
      title: l.tat_violation ? tatViolationTitle(l) : null
    },
      h('td', {},
        h('a', { href: '#', onclick: ev => { ev.preventDefault(); openLeadModal(l.id); } }, l.name || '—'),
        l.tat_violation ? h('span', { class: 'tat-pill', title: tatViolationTitle(l) }, '⚠ TAT ', tatOverLabel(l)) : null
      ),
      h('td', {}, l.phone || ''),
      h('td', {}, l.source || ''),
      h('td', {}, l.status_name || ''),
      h('td', {}, l.assigned_name || ''),
      h('td', { class: 'muted' }, fmtDate(l.created_at, 'relative'))
    )))
  )));
  view.appendChild(wrap);
}

VIEWS.followups = async (view) => {
  const data = await api('api_notifications_mine');
  view.innerHTML = '';
  // Filter bar with rule-builder so users can narrow the three sections (Overdue / Due today / Upcoming).
  const _fuRb = ruleBuilderButton({ label: '+ Filter rule', storageKey: 'crm.followups.rules.v1',
    fields: [
      { id: 'lead_name',     label: 'Lead name',     type: 'text' },
      { id: 'lead_phone',    label: 'Phone',         type: 'text' },
      { id: 'assigned_name', label: 'Assigned to',   type: 'text' },
      { id: 'note',          label: 'Note',          type: 'text' },
      { id: 'latest_remark', label: 'Latest remark', type: 'text' }
    ],
    onChange: () => VIEWS.followups(view)
  });
  window._fuRuleBtn = _fuRb;
  view.appendChild(h('div', { class: 'toolbar', style: { marginBottom: '.5rem' } }, _fuRb));
  const _rules = _fuRb.getRules();
  if (_rules && _rules.length) {
    data.overdue   = (data.overdue   || []).filter(r => _applyClientRules(r, _rules));
    data.due_today = (data.due_today || []).filter(r => _applyClientRules(r, _rules));
    data.upcoming  = (data.upcoming  || []).filter(r => _applyClientRules(r, _rules));
  }
  const section = (title, rows, klass, sectionKey) => {
    /* FU_PAGINATION_v1 — cap each section at 10 rows on the combined view.
       If there are more, append a "Show all" CTA that opens the dedicated
       section page with proper pagination. */
    const FU_SECTION_LIMIT = 10;
    const total = rows.length;
    const visibleRows = rows.slice(0, FU_SECTION_LIMIT);
    const wrap = h('div', { class: 'card' },
      h('h3', {}, title, ' ', h('span', { class: 'chip-count ' + (klass || '') }, total))
    );
    if (!rows.length) { wrap.appendChild(h('p', { class: 'muted' }, 'Nothing here.')); view.appendChild(wrap); return; }
    const tbl = h('div', { class: 'table-wrap' }, h('table', {},
      h('thead', {}, h('tr', {},
        h('th', {}, 'Lead'),
        h('th', {}, 'Phone'),
        h('th', {}, 'Assigned to'),
        h('th', {}, 'Due'),
        h('th', {}, 'Latest remark'),
        h('th', {}, 'Note'),
        h('th', { style: { textAlign: 'right' } }, 'Actions')
      )),
      h('tbody', {}, ...visibleRows.map(r => {
        const phone = String(r.lead_phone || '').trim();
        const telHref = phone ? 'tel:' + phone.replace(/[^\d+]/g, '') : null;
        const waHref  = phone ? window._waShareUrl(phone, '') : null;
        return h('tr', {},
          h('td', {},
            h('a', { href: '#', onclick: ev => { ev.preventDefault(); openLeadModal(r.lead_id); } }, r.lead_name || '—')
          ),
          h('td', {}, phone || ''),
          h('td', { class: r.assigned_name ? '' : 'muted' }, r.assigned_name || 'Unassigned'),
          h('td', { class: klass === 'err' ? 'overdue' : '' }, fmtDate(r.due_at)),
          h('td', { class: 'fu-latest-remark', title: r.latest_remark || '' },
            r.latest_remark
              ? h('span', {}, String(r.latest_remark).slice(0, 120) + (String(r.latest_remark).length > 120 ? '…' : ''))
              : h('span', { class: 'muted' }, '—')
          ),
          h('td', { class: 'muted' }, r.note || ''),
          h('td', { style: { textAlign: 'right', whiteSpace: 'nowrap' } },
            telHref ? h('a', { class: 'btn sm primary', href: telHref, title: 'Call ' + phone }, '📞 Call') : null,
            waHref  ? h('a', { class: 'btn sm ghost', href: waHref, target: '_blank', rel: 'noopener',
              style: { marginLeft: '.3rem' }, title: 'WhatsApp' }, '💬') : null,
            h('button', { class: 'btn sm', style: { marginLeft: '.3rem' },
              onclick: () => openLeadModal(r.lead_id), title: 'Open lead' }, '✎'),
            // "Next Follow Up" replaces the old "Done" button — opens a small
            // modal where the user picks a new date+time and writes a remark,
            // which closes the current follow-up AND creates the next one.
            // Forces the user to commit to a next action instead of just
            // dismissing the reminder.
            r.id ? h('button', { class: 'btn sm primary', style: { marginLeft: '.3rem' },
              onclick: () => openNextFollowupModal(r, () => navigateTo('followups'))
            }, '⏰ Next follow-up') : null,
            /* FU_DONE_v1.2 — mark follow-up done on the /followups view too
               (renderFollowupSection had it but VIEWS.followups didn't). */
            r.lead_id ? h('button', { class: 'btn sm ok', style: { marginLeft: '.3rem', background: '#16a34a', color: '#fff' },
              title: 'Mark follow-up done (lead drops off this list)',
              onclick: async () => {
                if (!confirm('Mark this follow-up as done? The lead will be removed from Due / Overdue lists.')) return;
                try {
                  await api('api_leads_followupDone', r.lead_id);
                  toast('Follow-up marked done ✓');
                  VIEWS.followups(view);
                } catch (e) { toast(e.message || 'Failed to mark done', 'err'); }
              }
            }, '✓ Done') : null
          )
        );
      }))
    ));
    wrap.appendChild(tbl);
    /* FU_PAGINATION_v1 — Show all CTA when truncated. */
    if (total > FU_SECTION_LIMIT && sectionKey) {
      const targetRoute = sectionKey === 'overdue' ? 'overdue'
                       : sectionKey === 'due_today' ? 'duetoday'
                       : 'upcoming';
      wrap.appendChild(h('div', { style: { display: 'flex', justifyContent: 'center', padding: '.6rem 0 .2rem' } },
        h('button', { class: 'btn primary', style: { fontWeight: 600 },
          onclick: () => navigateTo(targetRoute) },
          'Show all ' + total + ' →')
      ));
    }
    view.appendChild(wrap);
  };
  section('⚠️ Overdue',  data.overdue,   'err',   'overdue');
  section('📅 Due today', data.due_today, 'warn',  'due_today');
  section('⏰ Upcoming',  data.upcoming,  '',      'upcoming');
};

/* ---------------- Calendar ----------------------------------------
 * Full-month / week / day calendar showing every follow-up due date as
 * an event. Powered by FullCalendar (CDN-loaded on first visit so the
 * library only downloads when needed).
 *
 * Click an event → opens the lead modal so the rep can act immediately.
 * Admin/manager get a "Filter by user" dropdown so they can isolate
 * one rep's day.
 * ------------------------------------------------------------------ */

let _fcLib = null;
async function ensureFullCalendar() {
  if (window.FullCalendar) return window.FullCalendar;
  if (_fcLib) return _fcLib;
  await new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/fullcalendar@6.1.11/index.global.min.js';
    s.onload = resolve; s.onerror = reject;
    document.head.appendChild(s);
  });
  _fcLib = window.FullCalendar;
  return _fcLib;
}

VIEWS.calendar = async (view) => {
  view.innerHTML = '';
  const FC = await ensureFullCalendar();
  const { users = [] } = CRM.cache;
  const isManager = ['admin', 'manager', 'team_leader'].includes(CRM.user.role);

  // Toolbar with user filter (admin/manager only) + a small legend
  const userSelect = h('select', { id: 'cal-user' },
    h('option', { value: '' }, 'All callers'),
    ...users.filter(u => Number(u.is_active) === 1).map(u => h('option', { value: u.id }, u.name))
  );
  const legend = h('div', { class: 'cal-legend muted' },
    h('span', { class: 'cal-dot', style: { background: '#ef4444' } }), ' Overdue ',
    h('span', { class: 'cal-dot', style: { background: '#f59e0b' } }), ' Due today ',
    h('span', { class: 'cal-dot', style: { background: '#3b82f6' } }), ' Upcoming ',
    h('span', { class: 'cal-dot', style: { background: '#10b981' } }), ' Done '
  );

  const toolbar = h('div', { class: 'toolbar', style: { marginBottom: '.75rem', alignItems: 'center' } },
    isManager ? h('span', { class: 'muted' }, 'Show:') : null,
    isManager ? userSelect : null,
    legend
  );
  const calRoot = h('div', { id: 'cal-root', style: { background: '#fff', borderRadius: '12px', padding: '1rem', boxShadow: '0 1px 3px rgba(0,0,0,.05)' } });
  view.append(toolbar, calRoot);

  let calendar;
  function buildCalendar() {
    if (calendar) calendar.destroy();
    calendar = new FC.Calendar(calRoot, {
      initialView: 'timeGridWeek',
      // Match the screenshot's controls: prev/next/today + month/week/day
      headerToolbar: {
        left:   'prev,next today',
        center: 'title',
        right:  'dayGridMonth,timeGridWeek,timeGridDay'
      },
      // Remember the last-chosen view across visits
      initialDate: new Date(),
      height: 'auto',
      slotMinTime: '07:00:00',
      slotMaxTime: '22:00:00',
      nowIndicator: true,
      navLinks: true,           // click a date in month view → jumps to day
      dayMaxEvents: true,       // collapse overflow as "+ more"
      // Pull events on demand whenever the visible range changes
      events: async (info, success, fail) => {
        try {
          const filterUser = $('#cal-user')?.value || undefined;
          const evs = await api('api_calendar_events', {
            from: info.startStr,
            to: info.endStr,
            assigned_to: filterUser || undefined
          });
          success(evs || []);
        } catch (e) {
          toast('Calendar load failed: ' + e.message, 'err');
          fail(e);
        }
      },
      // Click → open the lead modal so the rep can act
      eventClick: (info) => {
        const leadId = info.event.extendedProps.lead_id;
        if (leadId) openLeadModal(leadId);
        info.jsEvent?.preventDefault();
      },
      // Hover tooltip with phone + owner — useful in dense day views
      eventDidMount: (info) => {
        const p = info.event.extendedProps || {};
        const tip = [
          info.event.title,
          p.lead_phone ? '📞 ' + p.lead_phone : null,
          p.owner_name ? '👤 ' + p.owner_name : null,
          p.note ? '📝 ' + p.note : null,
          p.status ? '· ' + p.status : null
        ].filter(Boolean).join('\n');
        info.el.title = tip;
      }
    });
    calendar.render();
  }

  buildCalendar();
  if (userSelect) userSelect.onchange = () => calendar.refetchEvents();
};

/* ---------------- Knowledge Base -----------------------------------
 * Admin-curated reference content for the team — scripts, FAQs, offers,
 * brochures, pricing sheets, video links. Everyone can read; only admin
 * can create / edit / delete.
 *
 * Layout: category sidebar on the left, search box + entry list on the
 * right. Click an entry to open it in a modal with the full body, the
 * external URL (if any), tags, and copy-to-clipboard actions.
 * ------------------------------------------------------------------ */

const KB_CATEGORIES = [
  { id: 'all',      label: 'All',        icon: '📚' },
  { id: 'pinned',   label: 'Pinned',     icon: '📌' },
  { id: 'script',   label: 'Scripts',    icon: '🎯' },
  { id: 'faq',      label: 'FAQs',       icon: '❓' },
  { id: 'offer',    label: 'Offers',     icon: '🎁' },
  { id: 'brochure', label: 'Brochures',  icon: '📄' },
  { id: 'pricing',  label: 'Pricing',    icon: '💰' },
  { id: 'video',    label: 'Videos',     icon: '🎥' },
  { id: 'link',     label: 'Links',      icon: '🔗' },
  { id: 'other',    label: 'Other',      icon: '📌' }
];

VIEWS.knowledge = async (view) => {
  view.innerHTML = '';
  const isAdmin = CRM.user.role === 'admin';
  let activeCat = 'all';
  let query = '';

  // Sidebar — category list (acts as a filter)
  const sidebar = h('div', { class: 'kb-sidebar' });
  function renderSidebar() {
    sidebar.innerHTML = '';
    sidebar.appendChild(h('h4', { style: { margin: '0 0 .5rem' } }, '📚 Knowledge'));
    KB_CATEGORIES.forEach(c => {
      sidebar.appendChild(h('button', {
        class: 'kb-cat' + (c.id === activeCat ? ' active' : ''),
        onclick: () => { activeCat = c.id; renderSidebar(); refresh(); }
      }, c.icon + ' ' + c.label));
    });
  }
  renderSidebar();

  // Right pane — search box + add-button + entry list
  const right = h('div', { class: 'kb-main' });
  const searchInput = h('input', {
    type: 'search', placeholder: '🔍 Search title, body, tags or URL…',
    style: { flex: 1 }
  });
  let _searchTimer;
  searchInput.oninput = () => {
    clearTimeout(_searchTimer);
    _searchTimer = setTimeout(() => { query = searchInput.value || ''; refresh(); }, 250);
  };

  const toolbar = h('div', { class: 'toolbar', style: { marginBottom: '.75rem' } },
    searchInput,
    h('button', {
      class: 'btn ghost',
      title: 'Replay the welcome walkthrough',
      onclick: () => { try { localStorage.removeItem('crm_tour_seen_v1'); } catch (_) {} maybeShowFirstRunTour(true); }
    }, '🎬 Re-watch tour'),
    isAdmin ? h('button', { class: 'btn primary', onclick: () => openKbEditModal(null, refresh) }, '+ Add entry') : null
  );
  right.appendChild(toolbar);

  const listEl = h('div', { id: 'kb-list' });
  right.appendChild(listEl);

  view.appendChild(h('div', { class: 'kb-wrap' }, sidebar, right));

  async function refresh() {
    listEl.innerHTML = '<div class="loading">Loading…</div>';
    let rows;
    try {
      const filters = { q: query };
      if (activeCat !== 'all' && activeCat !== 'pinned') filters.category = activeCat;
      rows = await api('api_kb_list', filters);
    } catch (e) {
      listEl.innerHTML = '';
      listEl.appendChild(h('div', { class: 'error-box' }, e.message));
      return;
    }
    if (activeCat === 'pinned') rows = rows.filter(r => r.is_pinned);
    listEl.innerHTML = '';
    if (!rows.length) {
      listEl.appendChild(h('p', { class: 'muted' }, query
        ? 'No entries matching "' + esc(query) + '"'
        : (isAdmin ? 'No entries yet — click "+ Add entry" to create the first one.' : 'No entries in this category yet.')));
      return;
    }
    rows.forEach(r => listEl.appendChild(kbCard(r, refresh, isAdmin)));
  }

  await refresh();
};

function kbCard(r, refresh, isAdmin) {
  const cat = KB_CATEGORIES.find(c => c.id === r.category) || KB_CATEGORIES.find(c => c.id === 'other');
  const card = h('div', { class: 'kb-card' + (r.is_pinned ? ' pinned' : '') },
    h('div', { class: 'kb-card-head' },
      h('div', {},
        r.is_pinned ? h('span', { class: 'kb-pin' }, '📌 ') : null,
        h('span', { class: 'kb-cat-tag' }, cat.icon + ' ' + cat.label),
        r.product_name ? h('span', { class: 'kb-cat-tag', style: { background: '#ddd6fe', color: '#5b21b6' } }, '📦 ' + r.product_name) : null
      ),
      h('div', { class: 'muted', style: { fontSize: '.75rem' } }, fmtDate(r.updated_at, 'relative'))
    ),
    h('h4', { class: 'kb-title', onclick: () => openKbViewModal(r.id) }, r.title),
    r.body ? h('p', { class: 'kb-body-preview' },
      String(r.body).slice(0, 220) + (String(r.body).length > 220 ? '…' : '')
    ) : null,
    r.tags ? h('div', { class: 'kb-tags' },
      ...String(r.tags).split(',').map(t => t.trim()).filter(Boolean)
        .map(t => h('span', { class: 'kb-tag' }, '#' + t))
    ) : null,
    h('div', { class: 'kb-actions' },
      h('button', { class: 'btn sm', onclick: () => openKbViewModal(r.id) }, '👁 Open'),
      r.url ? h('a', { class: 'btn sm ghost', href: r.url, target: '_blank', rel: 'noopener' }, '🔗 Link') : null,
      // KB_FILE_UPLOAD_v1: show 📎 chip when the entry has an attached file.
      r.has_file ? h('a', { class: 'btn sm ghost', title: r.file_name + (r.file_size_bytes ? ' · ' + _kbFmtSize(r.file_size_bytes) : ''), href: _kbFileUrl(r.id, true), target: '_blank', rel: 'noopener' }, '📎 Download') : null,
      r.body ? h('button', { class: 'btn sm ghost', onclick: () => {
        navigator.clipboard?.writeText(r.body).then(() => toast('Copied'));
      }, title: 'Copy body to clipboard' }, '📋 Copy') : null,
      isAdmin ? h('button', { class: 'btn sm ghost', onclick: () => openKbEditModal(r.id, refresh) }, '✎') : null,
      isAdmin ? h('button', { class: 'btn sm ghost', onclick: async () => {
        if (!confirm('Hide this entry from the team? (Soft-delete; admin can restore later.)')) return;
        try { await api('api_kb_delete', r.id); toast('Hidden'); refresh(); }
        catch (e) { toast(e.message, 'err'); }
      }, title: 'Hide / soft-delete' }, '🗑') : null
    )
  );
  return card;
}


// KB_FILE_UPLOAD_v1 helpers (used by card/view/edit) ----------------
function _kbFmtSize(bytes) {
  bytes = Number(bytes || 0);
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
}
function _kbFileEmoji(mime) {
  const m = String(mime || '').toLowerCase();
  if (m.includes('pdf')) return '📄';
  if (m.includes('powerpoint') || m.includes('presentation')) return '📊';
  if (m.includes('word') || m.includes('document')) return '📝';
  if (m.includes('sheet') || m.includes('excel')) return '📈';
  if (m.includes('image')) return '🖼️';
  if (m.includes('zip') || m.includes('compressed')) return '🗜️';
  return '📎';
}
function _kbFileUrl(id, asDownload) {
  // Tenant-aware URL. The fetch shim rewrites /api/... but <a href> is a
  // direct navigation, so we build the absolute tenant path ourselves.
  // Token in query string so the link opens in a new tab without custom JS.
  const tok = encodeURIComponent(CRM.token || '');
  const dl = asDownload ? '&dl=1' : '';
  const base = window.TENANT_SLUG ? ('/t/' + window.TENANT_SLUG) : '';
  return base + '/api/kb-file/' + id + '?token=' + tok + dl;
}

async function openKbViewModal(id) {
  let entry;
  try { entry = await api('api_kb_get', id); }
  catch (e) { toast(e.message, 'err'); return; }
  const cat = KB_CATEGORIES.find(c => c.id === entry.category) || { icon: '📌', label: entry.category };
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } },
    h('div', { class: 'modal modal-lg' },
      h('div', { class: 'modal-head' },
        h('h3', {}, entry.is_pinned ? '📌 ' : '', entry.title),
        h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
      ),
      h('div', { class: 'modal-body-wrap', style: { padding: '.25rem 0' } },
        h('div', { class: 'kb-meta-row' },
          h('span', { class: 'kb-cat-tag' }, cat.icon + ' ' + cat.label),
          entry.product_name ? h('span', { class: 'kb-cat-tag', style: { background: '#ddd6fe', color: '#5b21b6' } }, '📦 ' + entry.product_name) : null,
          entry.created_by_name ? h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'by ' + entry.created_by_name) : null,
          h('span', { class: 'muted', style: { fontSize: '.78rem' } }, fmtDate(entry.updated_at))
        ),
        entry.url ? h('p', {}, h('a', { class: 'btn primary', href: entry.url, target: '_blank', rel: 'noopener' }, '🔗 Open external link')) : null,
        // KB_FILE_UPLOAD_v1: attached-file panel with view + download.
        entry.has_file ? h('div', { class: 'kb-file-panel', style: { background: '#f1f5f9', border: '1px solid #e2e8f0', borderRadius: '10px', padding: '12px 14px', margin: '0 0 12px' } },
          h('div', { style: { display: 'flex', alignItems: 'center', gap: '12px', flexWrap: 'wrap' } },
            h('span', { style: { fontSize: '28px' } }, _kbFileEmoji(entry.file_mime)),
            h('div', { style: { flex: '1', minWidth: '160px' } },
              h('div', { style: { fontWeight: '600', color: '#0f172a' } }, entry.file_name || 'Attached file'),
              h('div', { class: 'muted', style: { fontSize: '.78rem' } }, (entry.file_mime || '') + (entry.file_size_bytes ? ' · ' + _kbFmtSize(entry.file_size_bytes) : ''))
            ),
            h('a', { class: 'btn ghost', href: _kbFileUrl(entry.id, false), target: '_blank', rel: 'noopener' }, '👁 View'),
            h('a', { class: 'btn primary', href: _kbFileUrl(entry.id, true), target: '_blank', rel: 'noopener', download: entry.file_name || '' }, '⬇️ Download')
          )
        ) : null,
        entry.body ? h('div', { class: 'kb-body-full' }, entry.body) : h('p', { class: 'muted' }, '(No body content — use the link above.)'),
        entry.tags ? h('div', { class: 'kb-tags' },
          ...String(entry.tags).split(',').map(t => t.trim()).filter(Boolean)
            .map(t => h('span', { class: 'kb-tag' }, '#' + t))
        ) : null,
        entry.body ? h('div', { class: 'actions' },
          h('button', { class: 'btn', onclick: () => {
            navigator.clipboard?.writeText(entry.body).then(() => toast('Copied to clipboard'));
          } }, '📋 Copy body')
        ) : null
      )
    )
  );
  document.body.appendChild(m);
}

async function openKbEditModal(id, onSave) {
  const { products = [] } = CRM.cache;
  let entry = { title: '', category: 'script', body: '', url: '', tags: '', product_id: '', is_pinned: 0 };
  if (id) {
    try { entry = await api('api_kb_get', id); }
    catch (e) { toast(e.message, 'err'); return; }
  }
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  m.appendChild(body);
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, id ? 'Edit knowledge entry' : 'New knowledge entry'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));

  const form = h('form', { id: 'kb-form', class: 'form-grid' });
  const catOptions = KB_CATEGORIES
    .filter(c => c.id !== 'all' && c.id !== 'pinned')
    .map(c => ({ value: c.id, label: c.icon + ' ' + c.label }));
  const productOptions = [{ value: '', label: '— None —' }, ...products.map(p => ({ value: p.id, label: p.name }))];
  form.append(
    field('title', 'Title *', entry.title, { required: true, full: true }),
    selectField('category', 'Category *', entry.category, catOptions),
    selectField('product_id', 'Related product (optional)', entry.product_id || '', productOptions),
    field('url', 'External URL (Drive / Box / YouTube — optional)', entry.url, { full: true }),
    // KB_FILE_UPLOAD_v1: native file attach. Up to 25 MB. Uploaded after save.
    (function _kbFileRow() {
      const row = h('div', { class: 'f-row full' },
        h('label', {}, 'Attach a file (brochure / PDF / PPT — max 25 MB)'),
        h('input', { id: 'kb-file-input', class: 'input', type: 'file', accept: '.pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx,.png,.jpg,.jpeg,.gif,.txt' })
      );
      if (entry.has_file) {
        row.appendChild(h('div', { class: 'muted', style: { fontSize: '.82rem', marginTop: '.35rem' } },
          'Currently attached: ', h('b', {}, entry.file_name || 'file'),
          entry.file_size_bytes ? ' · ' + _kbFmtSize(entry.file_size_bytes) : '',
          ' ',
          h('a', { href: _kbFileUrl(entry.id, true), target: '_blank', rel: 'noopener' }, '⬇️ Download'),
          ' · ',
          h('a', { href: '#', onclick: async (ev) => {
            ev.preventDefault();
            if (!confirm('Remove the current file from this entry?')) return;
            try { await api('api_kb_removeFile', entry.id); toast('File removed'); entry.has_file = false; ev.target.parentNode.innerHTML = '(file removed — pick a new one below to replace)'; }
            catch (e) { toast(e.message, 'err'); }
          } }, '🗑 Remove')
        ));
      }
      return row;
    })(),
    field('tags', 'Tags (comma-separated)', entry.tags, { full: true }),
    field('body', 'Body / Content', entry.body, { type: 'textarea', full: true }),
    h('div', { class: 'f-row' },
      h('label', {}, 'Pin to top'),
      h('label', { class: 'qual-toggle' },
        h('input', { type: 'checkbox', name: 'is_pinned', checked: entry.is_pinned ? 'checked' : null }),
        ' Show this entry at the top of every category'
      )
    )
  );
  body.appendChild(form);

  body.appendChild(h('div', { class: 'actions' },
    h('button', { type: 'button', class: 'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { type: 'submit', form: 'kb-form', class: 'btn primary' }, id ? 'Save changes' : 'Create entry')
  ));

  form.addEventListener('submit', async ev => {
    ev.preventDefault();
    const f = form;
    const fd = new FormData(f);
    const payload = {
      id: id || undefined,
      title: f.title.value.trim(),
      category: f.category.value,
      body: f.body.value,
      url: f.url.value.trim(),
      tags: f.tags.value.trim(),
      product_id: f.product_id.value || null,
      is_pinned: fd.get('is_pinned') ? 1 : 0
    };
    if (!payload.title) { toast('Title is required', 'err'); return; }
    try {
      const saved = await api('api_kb_save', payload);
      const entryId = (saved && saved.id) || id;
      // KB_FILE_UPLOAD_v1: if a new file was picked, upload it now.
      const fi = document.getElementById('kb-file-input');
      const file = fi && fi.files && fi.files[0];
      if (file && entryId) {
        if (file.size > 25 * 1024 * 1024) { toast('File too large (max 25 MB)', 'err'); return; }
        toast('Uploading ' + file.name + '…', 'info');
        const fd = new FormData(); fd.append('file', file);
        const tok = CRM.token;
        const r = await fetch('/api/kb-file/' + entryId, {
          method: 'POST',
          headers: { 'x-auth-token': tok },
          body: fd
        });
        if (!r.ok) { const j = await r.json().catch(() => ({})); throw new Error(j.error || 'Upload failed (HTTP ' + r.status + ')'); }
      }
      toast(id ? 'Saved' : 'Created');
      m.remove();
      if (typeof onSave === 'function') onSave();
    } catch (e) { toast(e.message, 'err'); }
  });

  document.body.appendChild(m);
}

/* ---------------- Team Chat (internal) -----------------------------
 * Single team channel + 1-on-1 DMs to any user. Polling-based: thread
 * list refreshes every 10s, active conversation every 4s while open.
 * Reuses the WhatsBot chat polling pattern so the network footprint is
 * predictable. Stops polling when the user navigates to a different tab.
 * ------------------------------------------------------------------ */

/**
 * Pull a query-string-style param out of the location hash.
 * `#/teamchat?room=42&foo=bar` → parseHashParams().room === '42'
 */
function parseHashParams() {
  const hash = String(location.hash || '');
  const i = hash.indexOf('?');
  if (i < 0) return {};
  return Object.fromEntries(new URLSearchParams(hash.slice(i + 1)));
}

VIEWS.teamchat = async (view) => {
  // Kill any previous timers if the tab is reopened
  if (window._tcTimers) {
    clearInterval(window._tcTimers.list);
    clearInterval(window._tcTimers.thread);
  }
  window._tcTimers = { list: null, thread: null };

  // Top-level guard — surface any unexpected failure as a readable card
  // instead of a raw stack trace. Common cause: the boot didn't finish
  // resolving CRM.user / CRM.access before a deep-link tried to open chat.
  if (!CRM.user || !CRM.user.id) {
    view.innerHTML = '<div class="error-box">Session not ready — please refresh and try again.</div>';
    return;
  }

  view.innerHTML = '';
  const wrap = h('div', { class: 'wb-chat' });
  const left = h('div', { class: 'wb-chat-list' });
  const right = h('div', { class: 'wb-chat-thread' },
    h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, '← Pick a channel or DM'));
  wrap.appendChild(left); wrap.appendChild(right);
  view.appendChild(wrap);

  // Pre-load every user the caller is allowed to chat with — this is
  // independent of CRM.cache.users (which is filtered by lead-management
  // hierarchy and would hide the rest of the team from a sales rep).
  let chatUsers = [];
  try { chatUsers = await api('api_chat_visibleUsers'); }
  catch (e) {
    if (String(e.message || '').includes('not enabled')) {
      view.innerHTML = `<div class="card" style="padding: 2rem; text-align: center;">
        <h3>💬 Team chat</h3>
        <p class="muted">Team chat isn't enabled for your role. Ask your admin to enable it in Settings → Chat permissions.</p>
      </div>`;
      return;
    }
    chatUsers = [];
  }

  let openRoomId = null;
  let openMsgFingerprint = '';
  let lastListFingerprint = '';

  function listFp(rooms) {
    return rooms.map(r => `${r.id}|${r.last_at}|${r.unread}`).join(';');
  }
  function msgFp(msgs) {
    return msgs.map(m => m.id).join(';');
  }

  async function renderThreadList() {
    let rooms;
    try { rooms = await api('api_chat_rooms_list'); }
    catch (_) { rooms = []; }

    // Also include every other active user as a potential DM target —
    // even if no DM thread exists yet — so the user can start one.
    // Uses the pre-loaded chatUsers (from api_chat_visibleUsers) which is
    // NOT filtered by lead-management hierarchy. CRM.cache.users would
    // hide the rest of the team from sales/employee role.
    const usersInList = new Set(rooms.filter(r => r.type === 'dm').map(r => r.counterpart_id));
    const otherUsers = chatUsers
      .filter(u => Number(u.id) !== Number(CRM.user.id))
      .filter(u => !usersInList.has(Number(u.id)));

    const fp = listFp(rooms) + '|users:' + otherUsers.length;
    if (fp === lastListFingerprint) return;
    lastListFingerprint = fp;

    left.innerHTML = '';
    const isAdmin = CRM.user.role === 'admin';
    left.appendChild(h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '.5rem' } },
      h('h4', { style: { margin: 0 } }, '👥 Team chat'),
      h('div', {},
        isAdmin ? h('button', { class: 'btn sm ghost', title: 'Create a new group',
          onclick: () => openCreateGroupModal(chatUsers, () => { lastListFingerprint = ''; renderThreadList(); })
        }, '+ Group') : null,
        h('button', { class: 'btn sm ghost', style: { marginLeft: '.25rem' }, title: 'Refresh now',
          onclick: () => { lastListFingerprint = ''; renderThreadList(); if (openRoomId) renderActiveThread(true); }
        }, '↻')
      )
    ));

    // Org-wide team channel first
    rooms.filter(r => r.type === 'channel' && r.label === 'team').forEach(r => left.appendChild(renderRoomRow(r)));
    // Custom groups next, with their own section header
    const groupRooms = rooms.filter(r => r.type === 'channel' && r.label !== 'team');
    if (groupRooms.length) {
      left.appendChild(h('div', { class: 'muted', style: { fontSize: '.7rem', textTransform: 'uppercase', letterSpacing: '.05em', margin: '.75rem 0 .25rem .25rem' } }, 'Groups'));
      groupRooms.forEach(r => left.appendChild(renderRoomRow(r)));
    }
    // DM rooms with existing messages
    const dmRooms = rooms.filter(r => r.type === 'dm');
    if (dmRooms.length) {
      left.appendChild(h('div', { class: 'muted', style: { fontSize: '.7rem', textTransform: 'uppercase', letterSpacing: '.05em', margin: '.75rem 0 .25rem .25rem' } }, 'Direct messages'));
      dmRooms.forEach(r => left.appendChild(renderRoomRow(r)));
    }
    // Users who don't yet have a DM thread — so you can start one
    if (otherUsers.length) {
      left.appendChild(h('div', { class: 'muted', style: { fontSize: '.7rem', textTransform: 'uppercase', letterSpacing: '.05em', margin: '.75rem 0 .25rem .25rem' } }, 'Start a DM'));
      otherUsers.forEach(u => {
        left.appendChild(h('div', { class: 'wb-chat-row', onclick: () => startDmWith(u.id) },
          h('div', {}, h('b', {}, u.name)),
          h('div', { class: 'muted', style: { fontSize: '.78rem' } }, u.role || '')
        ));
      });
    }
  }

  function renderRoomRow(r) {
    return h('div', { class: 'wb-chat-row' + (r.id === openRoomId ? ' active' : ''),
      onclick: () => openRoom(r.id, r.label, r.type)
    },
      h('div', {},
        r.type === 'channel' ? h('span', {}, '# ') : null,
        h('b', {}, r.label || ('Room #' + r.id)),
        r.unread ? h('span', { class: 'wb-unread' }, r.unread) : null
      ),
      h('div', { class: 'muted', style: { fontSize: '.78rem', maxWidth: '220px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' } },
        r.last_message_user ? r.last_message_user + ': ' : '',
        r.last_message || ''),
      h('div', { class: 'muted', style: { fontSize: '.7rem' } }, fmtDate(r.last_at, 'relative'))
    );
  }

  async function startDmWith(userId) {
    // Resolve the target user from the chat-visibleUsers list (NOT
    // CRM.cache.users which is hierarchy-filtered).
    const u = chatUsers.find(x => Number(x.id) === Number(userId));
    openRoomId = 'pending:' + userId;
    wrap.classList.add('thread-open');
    [...left.querySelectorAll('.wb-chat-row')].forEach(r => r.classList.remove('active'));
    right.innerHTML = '';
    right.appendChild(h('div', { class: 'wb-chat-head', style: { display: 'flex', alignItems: 'center' } },
      h('button', { class: 'wb-chat-back', title: 'Back to list', onclick: backToList }, '← Back'),
      h('b', {}, u?.name || 'New DM')));
    const log = h('div', { class: 'wb-chat-log' });
    log.appendChild(h('p', { class: 'muted', style: { padding: '1.5rem', textAlign: 'center' } },
      'Type a message to start a DM with ' + (u?.name || 'this user')));
    right.appendChild(log);
    const input = makeChatInput(async (text) => {
      try {
        const r = await api('api_chat_send', { user_id: userId, body: text });
        openRoomId = r.room_id;
        lastListFingerprint = ''; await renderThreadList();
        // Switch to the now-real room
        await openRoom(r.room_id, u?.name || 'DM', 'dm');
      } catch (e) { toast(e.message, 'err'); }
    });
    right.appendChild(input);
  }

  async function renderActiveThread(force) {
    if (!openRoomId || String(openRoomId).startsWith('pending:')) return;
    let msgs;
    try { msgs = await api('api_chat_messages_list', openRoomId); }
    catch (_) { msgs = []; }
    const fp = msgFp(msgs);
    if (!force && fp === openMsgFingerprint) return;
    openMsgFingerprint = fp;
    const log = right.querySelector('.wb-chat-log');
    if (!log) return;
    const wasNearBottom = (log.scrollHeight - log.scrollTop - log.clientHeight) < 80;
    log.innerHTML = '';
    msgs.forEach(m => {
      log.appendChild(h('div', { class: 'wb-msg ' + (m.is_mine ? 'out' : 'in') },
        h('div', { class: 'wb-msg-meta muted' }, m.user_name + ' · ' + fmtDate(m.created_at, 'relative')),
        h('div', { class: 'wb-msg-body' }, m.body || '')
      ));
    });
    if (wasNearBottom) setTimeout(() => { log.scrollTop = log.scrollHeight; }, 50);
  }

  function makeChatInput(onSend) {
    const input = h('textarea', { rows: 2, placeholder: 'Type a message and press Enter to send…' });
    input.addEventListener('keydown', async ev => {
      if (ev.key === 'Enter' && !ev.shiftKey) {
        ev.preventDefault();
        const text = input.value.trim(); if (!text) return;
        input.disabled = true;
        try { await onSend(text); input.value = ''; }
        finally { input.disabled = false; input.focus(); }
      }
    });
    return h('div', { class: 'wb-chat-compose' }, input);
  }

  function backToList() {
    openRoomId = null;
    window._tcOpenRoomId = null;
    openMsgFingerprint = '';
    wrap.classList.remove('thread-open');
    [...left.querySelectorAll('.wb-chat-row')].forEach(r => r.classList.remove('active'));
    right.innerHTML = h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, '← Pick a channel or DM').outerHTML;
  }

  async function openRoom(roomId, label, type) {
    openRoomId = roomId;
    window._tcOpenRoomId = roomId;       // exposed so the in-app chat toast
                                          // can suppress popups for the room
                                          // the user is actively reading
    openMsgFingerprint = '';
    wrap.classList.add('thread-open');  // mobile: hide list, show thread
    [...left.querySelectorAll('.wb-chat-row')].forEach(r => r.classList.remove('active'));

    const isAdmin = CRM.user.role === 'admin';
    // Manage button only for admin AND only on custom groups (not the
    // org-wide 'team' channel and not DMs).
    const canManage = isAdmin && type === 'channel' && label !== 'team';

    right.innerHTML = '';
    right.appendChild(h('div', { class: 'wb-chat-head', style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between' } },
      h('div', { style: { display: 'flex', alignItems: 'center' } },
        h('button', { class: 'wb-chat-back', title: 'Back to list', onclick: backToList }, '← Back'),
        h('b', {}, type === 'channel' ? '# ' + label : label)
      ),
      h('div', {},
        canManage ? h('button', { class: 'btn sm ghost', title: 'Manage members / rename / delete',
          onclick: () => openManageGroupModal(roomId, label, chatUsers, () => { lastListFingerprint = ''; renderThreadList(); })
        }, '⚙') : null,
        h('button', { class: 'btn sm ghost', style: { marginLeft: '.25rem' }, title: 'Refresh',
          onclick: () => renderActiveThread(true) }, '↻')
      )
    ));
    const log = h('div', { class: 'wb-chat-log' });
    log.innerHTML = '<div class="loading">Loading…</div>';
    right.appendChild(log);

    const input = makeChatInput(async (text) => {
      try {
        await api('api_chat_send', { room_id: roomId, body: text });
        renderActiveThread(true);
        lastListFingerprint = ''; renderThreadList();
      } catch (e) { toast(e.message, 'err'); }
    });
    right.appendChild(input);

    await renderActiveThread(true);
    lastListFingerprint = ''; await renderThreadList();
    // Reading a room marks it read server-side — refresh the sidebar
    // badge immediately so the count drops without waiting 10s.
    if (typeof _updateChatBadge === 'function') _updateChatBadge();
  }

  await renderThreadList();

  // Deep-link from a notification — if the URL hash includes ?room=N,
  // auto-open that conversation so the user lands inside the DM with one
  // tap, not on the room list.
  try {
    const params = parseHashParams();
    if (params.room) {
      const targetId = Number(params.room);
      // Look up label + type from the rooms list we just rendered
      const allRooms = await api('api_chat_rooms_list').catch(() => []);
      const room = allRooms.find(r => Number(r.id) === targetId);
      if (room) {
        await openRoom(room.id, room.label, room.type);
      } else {
        // Room exists but not in our list (e.g. brand-new DM the server
        // hasn't surfaced yet) — fetch messages directly to bootstrap it
        await openRoom(targetId, 'Conversation', 'dm');
      }
    }
  } catch (e) {
    console.warn('[teamchat] deep-link failed:', e.message);
  }

  window._tcTimers.list = setInterval(() => {
    if (document.visibilityState === 'hidden') return;
    renderThreadList().catch(() => {});
  }, 10_000);
  window._tcTimers.thread = setInterval(() => {
    if (document.visibilityState === 'hidden') return;
    if (openRoomId && !String(openRoomId).startsWith('pending:')) {
      renderActiveThread(false).catch(() => {});
    }
  }, 4_000);
};

/**
 * Modal: admin creates a new chat group with a name + member checkboxes.
 * The creator is auto-included server-side.
 */
function openCreateGroupModal(allUsers, onSaved) {
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  m.appendChild(body);
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, '➕ New chat group'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));
  const form = h('form', { id: 'gc-form' });
  form.appendChild(h('p', { class: 'muted', style: { marginTop: 0 } },
    'Pick a name and the members. Only the people you tick can see the group and post in it.'));
  form.appendChild(h('input', { name: 'name', placeholder: 'Group name (e.g. Sales — North zone)',
    style: { width: '100%', padding: '.6rem .75rem', borderRadius: '8px', border: '1px solid #cbd5e1', marginBottom: '.75rem' },
    required: true, maxlength: 80
  }));
  const memberBox = h('div', { class: 'card', style: { padding: '.75rem', maxHeight: '320px', overflowY: 'auto' } });
  (allUsers || []).filter(u => Number(u.id) !== Number(CRM.user.id)).forEach(u => {
    memberBox.appendChild(h('label', {
      style: { display: 'flex', alignItems: 'center', padding: '.3rem 0', cursor: 'pointer' }
    },
      h('input', { type: 'checkbox', name: 'mem_' + u.id, style: { marginRight: '.5rem' } }),
      h('span', { style: { fontWeight: 500 } }, u.name),
      h('span', { class: 'muted', style: { marginLeft: '.5rem', fontSize: '.78rem' } }, ' · ' + (u.role || ''))
    ));
  });
  form.appendChild(memberBox);
  body.appendChild(form);
  body.appendChild(h('div', { class: 'actions' },
    h('button', { type: 'button', class: 'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { type: 'submit', form: 'gc-form', class: 'btn primary' }, 'Create group')
  ));
  form.addEventListener('submit', async ev => {
    ev.preventDefault();
    const name = form.name.value.trim();
    if (!name) { toast('Group name required', 'err'); return; }
    const memberIds = [...form.querySelectorAll('input[type="checkbox"]:checked')]
      .map(c => Number(c.name.replace(/^mem_/, '')));
    try {
      await api('api_chat_groups_create', { name, member_ids: memberIds });
      toast('Group created');
      m.remove();
      if (typeof onSaved === 'function') onSaved();
    } catch (e) { toast(e.message, 'err'); }
  });
  document.body.appendChild(m);
}

/**
 * Modal: admin renames / re-sets members / deletes an existing group.
 * Pre-fills with current members.
 */
async function openManageGroupModal(roomId, currentName, allUsers, onSaved) {
  let currentMembers = [];
  try { currentMembers = await api('api_chat_groups_members', roomId); }
  catch (e) { toast(e.message, 'err'); return; }
  const memberIds = new Set(currentMembers.map(m => Number(m.user_id)));

  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  m.appendChild(body);
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, '⚙ Manage group'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));

  const form = h('form', { id: 'gm-form' });
  form.appendChild(h('label', { class: 'muted', style: { fontSize: '.8rem' } }, 'Group name'));
  form.appendChild(h('input', { name: 'name', value: currentName,
    style: { width: '100%', padding: '.6rem .75rem', borderRadius: '8px', border: '1px solid #cbd5e1', marginBottom: '.75rem' },
    required: true, maxlength: 80
  }));
  form.appendChild(h('label', { class: 'muted', style: { fontSize: '.8rem' } },
    'Members — tick to include. Removing yourself is blocked (server force-includes admin).'));
  const memberBox = h('div', { class: 'card', style: { padding: '.75rem', maxHeight: '320px', overflowY: 'auto' } });
  (allUsers || []).forEach(u => {
    memberBox.appendChild(h('label', {
      style: { display: 'flex', alignItems: 'center', padding: '.3rem 0', cursor: 'pointer' }
    },
      h('input', {
        type: 'checkbox', name: 'mem_' + u.id,
        checked: memberIds.has(Number(u.id)) ? 'checked' : null,
        style: { marginRight: '.5rem' }
      }),
      h('span', { style: { fontWeight: 500 } }, u.name),
      h('span', { class: 'muted', style: { marginLeft: '.5rem', fontSize: '.78rem' } }, ' · ' + (u.role || ''))
    ));
  });
  form.appendChild(memberBox);
  body.appendChild(form);

  body.appendChild(h('div', { class: 'actions' },
    h('button', { type: 'button', class: 'btn', style: { background: '#ef4444', color: '#fff' },
      onclick: async () => {
        if (!confirm('Permanently delete this group and all its messages?')) return;
        try {
          await api('api_chat_groups_delete', roomId);
          toast('Deleted');
          m.remove();
          if (typeof onSaved === 'function') onSaved();
        } catch (e) { toast(e.message, 'err'); }
      }
    }, '🗑 Delete'),
    h('button', { type: 'button', class: 'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { type: 'submit', form: 'gm-form', class: 'btn primary' }, 'Save changes')
  ));

  form.addEventListener('submit', async ev => {
    ev.preventDefault();
    const newName = form.name.value.trim();
    if (!newName) { toast('Group name required', 'err'); return; }
    const newIds = [...form.querySelectorAll('input[type="checkbox"]:checked')]
      .map(c => Number(c.name.replace(/^mem_/, '')));
    try {
      await api('api_chat_groups_update', {
        id: roomId, name: newName, member_ids: newIds
      });
      toast('Saved');
      m.remove();
      if (typeof onSaved === 'function') onSaved();
    } catch (e) { toast(e.message, 'err'); }
  });
  document.body.appendChild(m);
}

/* ---------------- Reports with charts ---------------- */
async function ensureChartJs() {
  if (!window.Chart) {
    await new Promise((resolve, reject) => {
      const s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js';
      s.onload = resolve; s.onerror = reject;
      document.head.appendChild(s);
    });
  }
  // Also load chartjs-plugin-datalabels so we can render the actual numeric
  // value on top of every bar / segment (the user wants numbers visible, not
  // just bars). Register globally so every chart picks it up.
  if (window.Chart && !window.ChartDataLabels) {
    try {
      await new Promise((resolve, reject) => {
        const s = document.createElement('script');
        s.src = 'https://cdn.jsdelivr.net/npm/chartjs-plugin-datalabels@2.2.0/dist/chartjs-plugin-datalabels.min.js';
        s.onload = resolve; s.onerror = reject;
        document.head.appendChild(s);
      });
      if (window.ChartDataLabels && Chart && Chart.register) Chart.register(window.ChartDataLabels);
    } catch (_) { /* non-fatal: charts still render, just without labels */ }
  }
}
/* ============================================================
   WhatsBot module — Connect / Templates / Bots / Campaigns / Chat / Logs
   ============================================================ */
/**
 * Dial route — opened on the user's phone when they tap a "Call from mobile"
 * push. Hash query params: ?phone=+91...&lead=N
 *
 * Auto-fires tel: which the OS dialer opens. Shows a fallback button in
 * case auto-launch is suppressed (some browsers block `tel:` redirects from
 * non-user-initiated navigation).
 */
VIEWS.dial = async (view) => {
  view.innerHTML = '';
  const hash = location.hash || '';
  const queryStr = hash.split('?')[1] || '';
  const params = new URLSearchParams(queryStr);
  const phone = (params.get('phone') || '').trim();
  if (!phone) {
    view.appendChild(h('div', { class: 'error-box' }, 'No phone number in the URL.'));
    return;
  }
  const tel = 'tel:' + phone.replace(/\s+/g, '');
  const status = h('div', { class: 'muted', style: { fontSize: '.8rem', marginTop: '.5rem' } });

  async function autoDial() {
    const cap = window.Capacitor;
    const tries = [];
    // Strategy 1 — Capacitor App.openUrl (Android: launches ACTION_DIAL)
    try {
      if (cap && cap.Plugins && cap.Plugins.App && typeof cap.Plugins.App.openUrl === 'function') {
        const r = await cap.Plugins.App.openUrl({ url: tel });
        tries.push('App.openUrl→' + JSON.stringify(r));
        if (r && r.completed !== false) { status.textContent = '✓ Launched via App.openUrl'; return 'capacitor'; }
      } else { tries.push('no App.openUrl'); }
    } catch (e) { tries.push('App.openUrl threw: ' + e.message); }
    // Strategy 2 — window.open with _system
    try {
      const w = window.open(tel, '_system');
      tries.push('window.open(_system)→' + (w ? 'win' : 'null'));
      if (w) { status.textContent = '✓ Launched via window.open'; return 'window'; }
    } catch (e) { tries.push('window.open threw: ' + e.message); }
    // Strategy 3 — invisible iframe (works in some WebViews where href doesn't)
    try {
      const f = document.createElement('iframe');
      f.style.display = 'none';
      f.src = tel;
      document.body.appendChild(f);
      tries.push('iframe→appended');
      setTimeout(() => f.remove(), 1000);
      status.textContent = '✓ Launched via iframe';
      return 'iframe';
    } catch (e) { tries.push('iframe threw: ' + e.message); }
    // Strategy 4 — programmatic anchor click (very reliable in WebViews)
    try {
      const a = document.createElement('a');
      a.href = tel; a.style.display = 'none';
      document.body.appendChild(a);
      a.click();
      tries.push('anchor.click()→fired');
      setTimeout(() => a.remove(), 100);
      status.textContent = '✓ Launched via anchor.click()';
      return 'anchor';
    } catch (e) { tries.push('anchor.click threw: ' + e.message); }
    // Strategy 5 — plain href
    try { location.href = tel; tries.push('location.href set'); status.textContent = '✓ Launched via location.href'; return 'href'; } catch (e) { tries.push('location.href threw: ' + e.message); }
    status.innerHTML = '<span style="color:#ef4444">All strategies failed: ' + tries.join(' · ') + '</span>';
    return 'failed';
  }

  setTimeout(() => { autoDial().catch(() => {}); }, 150);

  view.appendChild(h('div', { style: { maxWidth: '420px', margin: '1rem auto', textAlign: 'center', padding: '1rem' } },
    h('div', { style: { fontSize: '4rem', marginTop: '1rem' } }, '📞'),
    h('h1', { style: { margin: '.5rem 0', fontSize: '1.5rem' } }, 'Calling…'),
    h('p', { style: { fontSize: '1.4rem', fontWeight: '700', fontFamily: 'monospace', margin: '.5rem 0 1.5rem' } }, phone),
    // Hard anchor tap — most reliable path inside Capacitor WebView. Tapping
    // an <a href="tel:..."> is treated as a real Intent launch by Android.
    h('a', { class: 'btn primary', style: { display: 'block', fontSize: '1.4rem', padding: '1.25rem', background: '#10b981', color: '#fff', border: 'none', borderRadius: '12px', textDecoration: 'none', fontWeight: '600' }, href: tel },
      '📞 CALL NOW'
    ),
    status,
    h('a', { class: 'btn ghost', style: { marginTop: '1.25rem', display: 'inline-block' }, href: '#/leads' }, '← Back to leads')
  ));
};

// ============================================================
// 📄 Quotations — author + send quotes via email + WhatsApp
// ============================================================
VIEWS.quotations = async (view) => {
  view.innerHTML = '';
  view.appendChild(h('div', { class: 'view-head' },
    h('h2', { style: { margin: 0 } }, '📄 Quotations'),
    h('p', { class: 'muted', style: { margin: '.25rem 0 0', fontSize: '.9rem' } },
      'Author professional quotations, send to customers via email or WhatsApp, and share a public link.')
  ));

  const toolbar = h('div', { class: 'toolbar', style: { display: 'flex', gap: '.5rem', marginBottom: '.75rem' } });
  const newBtn = h('button', { class: 'btn primary', onclick: () => openQuotationModal() }, '+ New quotation');
  const stSel = h('select', {},
    h('option', { value: '' }, 'All statuses'),
    h('option', { value: 'draft' }, 'Draft'),
    h('option', { value: 'sent' }, 'Sent'),
    h('option', { value: 'accepted' }, 'Accepted'),
    h('option', { value: 'rejected' }, 'Rejected'),
    h('option', { value: 'expired' }, 'Expired'));
  const qInp = h('input', { type: 'search', placeholder: '🔍 Search number, customer…', style: { padding: '.4rem .6rem' } });
  toolbar.appendChild(newBtn);
  toolbar.appendChild(stSel);
  toolbar.appendChild(qInp);
  view.appendChild(toolbar);

  const listCard = h('div', { class: 'card' });
  view.appendChild(listCard);

  async function reload() {
    listCard.innerHTML = '<div class="muted">Loading…</div>';
    let data;
    try { data = await api('api_quotations_list', { status: stSel.value || null, q: qInp.value || null }); }
    catch (e) { listCard.innerHTML = ''; listCard.appendChild(h('div', { class: 'error-box' }, e.message)); return; }
    listCard.innerHTML = '';
    if (!data.rows.length) {
      listCard.appendChild(h('p', { class: 'muted' }, 'No quotations yet. Click + New quotation.'));
      return;
    }
    const tbl = h('table', { class: 'data-table', style: { width: '100%' } },
      h('thead', {}, h('tr', {},
        h('th', {}, 'Number'), h('th', {}, 'Customer'), h('th', {}, 'Status'),
        h('th', {}, 'Total'), h('th', {}, 'Issued'), h('th', {}, 'Sent'), h('th', {}, '')
      )),
      h('tbody', {}, ...data.rows.map(r => {
        const stColor = { draft: '#94a3b8', sent: '#3b82f6', accepted: '#10b981', rejected: '#ef4444', expired: '#f59e0b' }[r.status] || '#64748b';
        return h('tr', {},
          h('td', {}, h('code', {}, r.number)),
          h('td', {}, r.customer_name + (r.customer_email ? ' · ' + r.customer_email : '')),
          h('td', {}, h('span', { style: { background: stColor, color: '#fff', padding: '.15rem .5rem', borderRadius: '4px', fontSize: '.78rem' } }, r.status)),
          h('td', {}, '₹' + Number(r.total || 0).toLocaleString('en-IN')),
          h('td', { class: 'muted' }, r.issue_date ? new Date(r.issue_date).toLocaleDateString('en-IN') : '—'),
          h('td', { class: 'muted' }, r.sent_at ? fmtDate(r.sent_at, 'relative') : '—'),
          h('td', {},
            h('button', { class: 'btn xs', title: 'Edit', onclick: () => openQuotationModal(r.id) }, '✎'),
            h('button', { class: 'btn xs ghost', title: 'Download as PDF', onclick: async () => {
              try {
                const u = await api('api_quotations_public_url', r.id);
                const sep = u.url.indexOf('?') === -1 ? '?' : '&';
                window.open(u.url + sep + 'autoprint=1', '_blank');
              } catch (e) { toast(e.message, 'err'); }
            } }, '📄'),
            h('button', { class: 'btn xs ghost', title: 'View public link', onclick: async () => {
              try { const u = await api('api_quotations_public_url', r.id); window.open(u.url, '_blank'); }
              catch (e) { toast(e.message, 'err'); }
            } }, '🔗'),
            h('button', { class: 'btn xs ghost danger', title: 'Delete', onclick: async () => {
              if (!confirm('Delete quotation ' + r.number + '?')) return;
              try { await api('api_quotations_delete', r.id); toast('Deleted'); reload(); }
              catch (e) { toast(e.message, 'err'); }
            } }, '🗑')
          )
        );
      }))
    );
    listCard.appendChild(tbl);
  }
  let _qt = null;
  qInp.addEventListener('input', () => { clearTimeout(_qt); _qt = setTimeout(reload, 300); });
  stSel.addEventListener('change', reload);
  reload();
};

async function openQuotationModal(qid, prefillLead) {
  const m = h('div', { class: 'modal-backdrop q-modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const card = h('div', { class: 'modal q-modal', style: { width: '95vw', maxWidth: '1280px', maxHeight: '95vh', overflow: 'auto', padding: '1.25rem 1.5rem' } });
  m.appendChild(card);
  document.body.appendChild(m);

  let existing = null;
  if (qid) {
    // QUOTE_IMG_FIX_v1 — pre-warm the products cache so _imgUrlForRow's
    // fallback works even if the user never opened the Products page.
    if (!CRM.cache) CRM.cache = {};
    if (!Array.isArray(CRM.cache.products) || !CRM.cache.products.length) {
      try { CRM.cache.products = await api('api_products_list') || []; } catch (_) { CRM.cache.products = []; }
    }
    try { const r = await api('api_quotations_get', qid); existing = { ...(r.quotation || {}), items: r.items || [] }; }
    catch (e) { card.appendChild(h('div', { class: 'error-box' }, e.message)); return; }
  }
  // If invoked from a lead detail, pre-fill customer fields + lead_id.
  const seed = prefillLead ? {
    items: [], currency: 'INR', tax_pct: 18, discount_pct: 0,
    issue_date: new Date().toISOString().slice(0, 10),
    lead_id: prefillLead.id,
    customer_name:    prefillLead.name || '',
    customer_email:   prefillLead.email || '',
    customer_phone:   prefillLead.phone || prefillLead.whatsapp || '',
    customer_address: prefillLead.address || prefillLead.location || ''
  } : { items: [], currency: 'INR', tax_pct: 18, discount_pct: 0, issue_date: new Date().toISOString().slice(0, 10) };
  const q = existing || seed;

  // QUOTE_DEFAULT_TC_v2 — for brand new quotes, pre-fill T&C + Notes
  // from the tenant-level defaults configured in Settings → Quotation
  // Defaults. Falls back silently if the config endpoint isn't reachable.
  if (!qid) {
    try {
      if (!q.terms) {
        const t = await api('api_admin_getConfig', 'QUOTATION_DEFAULT_TERMS');
        if (t && t.value) q.terms = t.value;
      }
      if (!q.notes) {
        const n = await api('api_admin_getConfig', 'QUOTATION_DEFAULT_NOTES');
        if (n && n.value) q.notes = n.value;
      }
    } catch (_) { /* defaults not set yet — that's fine */ }
  }

  card.appendChild(h('h3', { style: { marginTop: 0 } }, qid ? '✎ Edit quotation ' + (q.number || '') : '+ New quotation'));

  const nameInp  = h('input', { type: 'text', value: q.customer_name || '', placeholder: 'Customer name *', style: { width: '100%' } });
  const emailInp = h('input', { type: 'email', value: q.customer_email || '', placeholder: 'customer@example.com', style: { width: '100%' } });
  const phoneInp = h('input', { type: 'tel', value: q.customer_phone || '', placeholder: '+91 98765 43210', style: { width: '100%' } });
  const addrInp  = h('textarea', { rows: 2, placeholder: 'Customer billing address (optional)', style: { width: '100%' } }, q.customer_address || '');

  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Customer name *'), nameInp));
  card.appendChild(h('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '.5rem' } },
    h('div', { class: 'field' }, h('label', {}, 'Email'), emailInp),
    h('div', { class: 'field' }, h('label', {}, 'Phone (WhatsApp)'), phoneInp)
  ));
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Billing address'), addrInp));

  const issueInp = h('input', { type: 'date', value: q.issue_date || '' });
  const validInp = h('input', { type: 'date', value: q.valid_until || '' });
  card.appendChild(h('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '.5rem' } },
    h('div', { class: 'field' }, h('label', {}, 'Issue date'), issueInp),
    h('div', { class: 'field' }, h('label', {}, 'Valid until'), validInp)
  ));

  // ---- Items ----
  card.appendChild(h('h4', { style: { marginBottom: '.25rem' } }, 'Line items'));
  const itemsWrap = h('div', { class: 'q-items', style: { border: '1px solid #e2e8f0', borderRadius: '6px', padding: '.5rem' } });
  const totalsLine = h('div', { style: { textAlign: 'right', marginTop: '.5rem', fontWeight: '700' } });
  const discInp = h('input', { type: 'number', value: q.discount_pct || 0, step: '0.01', min: 0, max: 100, style: { width: '5rem' } });
  const taxInp  = h('input', { type: 'number', value: q.tax_pct      || 18, step: '0.01', min: 0, max: 100, style: { width: '5rem' } });

  function recompute() {
    let subtotal = 0;
    [...itemsWrap.querySelectorAll('.q-item')].forEach(row => {
      const qty = Number(row.querySelector('[data-k=qty]').value || 0);
      const price = Number(row.querySelector('[data-k=price]').value || 0);
      const dp = Number(row.querySelector('[data-k=disc]').value || 0);
      const gross = qty * price;
      const line = gross - (gross * dp / 100);
      row.querySelector('[data-k=amt]').textContent = '₹' + line.toFixed(2);
      subtotal += line;
    });
    const dPct = Number(discInp.value || 0);
    const tPct = Number(taxInp.value || 0);
    const dAmt = subtotal * dPct / 100;
    const taxable = subtotal - dAmt;
    const tAmt = taxable * tPct / 100;
    const total = taxable + tAmt;
    totalsLine.innerHTML =
      '<div>Subtotal: ₹' + subtotal.toFixed(2) + '</div>' +
      (dPct > 0 ? '<div>Discount: -₹' + dAmt.toFixed(2) + '</div>' : '') +
      (tPct > 0 ? '<div>Tax: ₹' + tAmt.toFixed(2) + '</div>' : '') +
      '<div style="font-size:1.1rem;color:#6366f1">Total: ₹' + total.toFixed(2) + '</div>';
  }

  // Build a product dropdown — typing or picking auto-fills description
  // + unit_price + product_id. Free-text description still works too.
  function _productSelect(seed) {
    const products = (CRM.cache && CRM.cache.products) || [];
    const sel = h('select', { style: { width: '100%' } },
      h('option', { value: '' }, '\u2014 Pick a product (optional) \u2014'),
      ...products.map(p => h('option', {
        value: String(p.id),
        'data-price': String(p.price || p.unit_price || 0),
        'data-name':  String(p.name || ''),
        'data-description': String(p.description || ''),
        selected: seed && Number(seed.product_id) === Number(p.id) ? 'selected' : null
      }, (p.name || ('Product #' + p.id)) + (p.price ? '  \u2014 \u20b9' + Number(p.price).toLocaleString('en-IN') : '')))
    );
    return sel;
  }
  // QUOTE_UI_v2 (2026-05-21) — Widen Qty/Price columns, add product image
  //   thumbnail in each row, hydrate from item.product_image_url (saved on
  //   the quotation_items row) OR from the product master record.
  function _imgUrlForRow(it, prodIdSelected) {
    // Priority: line-saved image > product master image (lookup by id)
    if (it && it.product_image_url) return it.product_image_url;
    const pid = Number(prodIdSelected || (it && it.product_id) || 0);
    if (pid) {
      const products = (CRM.cache && CRM.cache.products) || [];
      const hit = products.find(p => Number(p.id) === pid);
      if (hit && hit.image_url) return hit.image_url;
    }
    return '';
  }
  function addItem(seed) {
    const it = seed || { description: '', quantity: 1, unit_price: 0, discount_pct: 0 };
    const row = h('div', { class: 'q-item', style: { display: 'grid', gridTemplateColumns: '48px 1fr 1.5fr 1.2fr 1.1fr .9fr 1.1fr 28px', gap: '.4rem', alignItems: 'center', marginBottom: '.3rem' } });
    const prodSel = _productSelect(it);
    // Image thumbnail (48x48) — shows product master / line-saved image
    const initialImg = _imgUrlForRow(it, prodSel.value);
    const imgWrap = h('div', { style: { width: '48px', height: '48px', borderRadius: '6px', border: '1px solid #e2e8f0', overflow: 'hidden', background: '#f8fafc', display: 'flex', alignItems: 'center', justifyContent: 'center' }});
    const imgEl = h('img', {
      src: initialImg || '',
      style: { width: '100%', height: '100%', objectFit: 'cover', display: initialImg ? 'block' : 'none' },
      onerror: (ev) => { ev.target.style.display = 'none'; imgPh.style.display = 'flex'; }
    });
    const imgPh = h('div', { style: { fontSize: '.65rem', color: '#94a3b8', display: initialImg ? 'none' : 'flex', alignItems: 'center', justifyContent: 'center', width: '100%', height: '100%' }}, '📦');
    imgWrap.appendChild(imgEl); imgWrap.appendChild(imgPh);
    const desc = h('input', { type: 'text', placeholder: 'Description', value: it.description || '', style: { width: '100%' } });
    // QUOTE_PRODUCT_DESC_SYNC_v1 — on product CHANGE, refresh desc/price from
    // the new product, unless the user manually edited those fields. We
    // track the last auto-filled values on the row; if the current value
    // still matches the last auto-fill, it's safe to overwrite.
    prodSel.onchange = () => {
      const opt = prodSel.options[prodSel.selectedIndex];
      // Update image thumbnail on product change (always)
      const url = _imgUrlForRow(it, prodSel.value);
      if (url) { imgEl.src = url; imgEl.style.display = 'block'; imgPh.style.display = 'none'; }
      else     { imgEl.style.display = 'none';  imgPh.style.display = 'flex'; }
      row._imageUrl = url;
      if (!opt || !opt.value) {
        // User cleared the product — leave manual values alone.
        return;
      }
      const name      = opt.getAttribute('data-name')        || '';
      const prodDesc  = opt.getAttribute('data-description') || '';
      const price     = Number(opt.getAttribute('data-price') || 0);
      // Prefer the product's stored description; fall back to the name.
      const newDesc = prodDesc.trim() ? prodDesc : name;
      const curDesc = (desc.value || '').trim();
      const lastDesc = (row._lastAutoDesc || '').trim();
      // Update description if: empty, OR matches the previous auto-fill
      // (user hasn't manually edited it). This stops the old product's
      // description from sticking when the user picks a different product.
      if (newDesc && (!curDesc || curDesc === lastDesc)) {
        desc.value = newDesc;
        row._lastAutoDesc = newDesc;
      }
      const curPrice  = Number(pr.value || 0);
      const lastPrice = Number(row._lastAutoPrice || 0);
      if (price && (curPrice === 0 || curPrice === lastPrice)) {
        pr.value = String(price);
        row._lastAutoPrice = price;
      }
      recompute();
    };
    const qty  = h('input', { 'data-k': 'qty',   type: 'number', value: it.quantity || 1, step: '0.001', min: 0, style: { width: '100%', minWidth: '70px', padding: '4px 6px', textAlign: 'right' } });
    const pr   = h('input', { 'data-k': 'price', type: 'number', value: it.unit_price || 0, step: '0.01', min: 0, style: { width: '100%' } });
    const dp   = h('input', { 'data-k': 'disc',  type: 'number', value: it.discount_pct || 0, step: '0.01', min: 0, max: 100, style: { width: '100%' } });
    const amt  = h('div', { 'data-k': 'amt', style: { textAlign: 'right', fontFamily: 'monospace' } }, '₹0.00');
    const del  = h('button', { class: 'btn xs ghost danger', type: 'button', onclick: () => { row.remove(); recompute(); } }, '✕');
    [qty, pr, dp].forEach(el => el.addEventListener('input', recompute));
    row._desc = desc; row._qty = qty; row._pr = pr; row._dp = dp;
    row._prodSel = prodSel;
    row._imageUrl = initialImg || null;
    // QUOTE_PRODUCT_DESC_SYNC_v1 — initialise last-auto-fill markers.
    // Empty by default so an existing seed value (loaded from a saved
    // quote) is treated as user-edited and won't be clobbered.
    row._lastAutoDesc  = '';
    row._lastAutoPrice = 0;
    row.appendChild(imgWrap); row.appendChild(prodSel); row.appendChild(desc); row.appendChild(qty); row.appendChild(pr); row.appendChild(dp); row.appendChild(amt); row.appendChild(del);
    // QUOTE_FULLPAGE_v1: insertBefore the add-button so new rows land
    // ABOVE it and the button stays anchored at the bottom of the list.
    if (addBtn && addBtn.parentNode === itemsWrap) itemsWrap.insertBefore(row, addBtn);
    else itemsWrap.appendChild(row);
    recompute();
    return row;
  }
  // Header row
  itemsWrap.appendChild(h('div', { style: { display: 'grid', gridTemplateColumns: '48px 1fr 1.5fr 1.2fr 1.1fr .9fr 1.1fr 28px', gap: '.4rem', fontSize: '.78rem', color: '#64748b', marginBottom: '.3rem', fontWeight: 600 } },
    h('div', {}, 'Image'), h('div', {}, 'Product'), h('div', {}, 'Description'), h('div', {}, 'Qty'), h('div', {}, 'Unit price'), h('div', {}, 'Disc %'),
    h('div', { style: { textAlign: 'right' } }, 'Amount'), h('div', {})
  ));
  // QUOTE_FULLPAGE_v1: create addBtn FIRST so addItem can insertBefore it.
  // Big primary-styled button so it's obvious you can keep adding items.
  const addBtn = h('button', {
    class: 'btn primary',
    type: 'button',
    style: { marginTop: '.75rem', width: '100%', padding: '.5rem', fontWeight: '600' },
    onclick: () => addItem()
  }, '\u2795 Add another product / line item');
  (q.items || []).forEach(it => addItem(it));
  if (!q.items || !q.items.length) addItem();
  itemsWrap.appendChild(addBtn);
  card.appendChild(itemsWrap);

  card.appendChild(h('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '.5rem', marginTop: '.5rem' } },
    h('div', { class: 'field' }, h('label', {}, 'Discount %'), discInp),
    h('div', { class: 'field' }, h('label', {}, 'Tax %'), taxInp)
  ));
  [discInp, taxInp].forEach(el => el.addEventListener('input', recompute));
  card.appendChild(totalsLine);

  const notesInp = h('textarea', { rows: 2, placeholder: 'Internal notes (visible to customer)', style: { width: '100%' } }, q.notes || '');
  const termsInp = h('textarea', { rows: 3, placeholder: 'Terms & conditions (e.g. 50% advance, balance on delivery)', style: { width: '100%' } }, q.terms || '');
  card.appendChild(h('div', { class: 'field q-field-notes' }, h('label', {}, 'Notes'), notesInp));
  // QUOTE_DEFAULT_TC_v2 — T&C defaults live in Settings → Quotation Defaults
  // (admin-only). The textarea below is for THIS quote only; tenant-wide
  // template editing happens there.
  card.appendChild(h('div', { class: 'field q-field-terms' },
    h('label', {},
      'Terms & conditions',
      h('a', {
        href: '#/admin',
        style: { fontSize: '.75rem', color: '#6366f1', textDecoration: 'underline', marginLeft: '.5rem' },
        title: 'Edit the default T&C template that auto-fills every new quotation',
        onclick: (ev) => { ev.preventDefault(); m.remove(); location.hash = '#/admin'; setTimeout(() => showAdminTab && showAdminTab('quotation'), 150); }
      }, '⚙ Edit default template')
    ),
    termsInp
  ));

  // ---- Save / Send ----
  const saveBtn = h('button', { class: 'btn primary' }, '💾 Save');
  const emailBtn = h('button', { class: 'btn', disabled: qid ? null : 'disabled' }, '📧 Send by email');
  // QUOTE_WA_TEMPLATE_v1 — template picker for API send. When set,
  // the API path uses the approved Meta template instead of free-form
  // text (the only way to deliver outside the 24h customer-service window).
  const waTplSel = h('select', { style: { padding: '.3rem .4rem', borderRadius: '4px', border: '1px solid #cbd5e1', minWidth: '180px', fontSize: '.82rem', maxWidth: '260px' }, title: 'Pick an approved Meta template to send outside the 24-hour window. Leave blank for free-form (only works if customer messaged you in last 24h).' },
    h('option', { value: '' }, '— No template (free-form, 24h rule) —')
  );
  (async () => {
    try {
      const tpls = await api('api_wb_templates_list');
      (tpls || []).filter(t => String(t.status || '').toUpperCase() === 'APPROVED').forEach(t => {
        const opt = h('option', { value: t.name, 'data-lang': t.language || 'en_US', 'data-params': String(t.body_params || 0) }, t.name + ' (' + (t.language || 'en') + ', ' + (t.body_params || 0) + ' vars)');
        waTplSel.appendChild(opt);
      });
      if (waTplSel.options.length === 1) {
        waTplSel.appendChild(h('option', { value: '', disabled: 'disabled' }, 'No approved templates — create one in Settings → WhatsApp → Templates'));
      }
    } catch (_) {}
  })();
  const waBtn = h('button', { class: 'btn', disabled: qid ? null : 'disabled', title: 'Sends via Meta WhatsApp Cloud API. Pick an approved template on the left to send outside the 24h window.' }, '💬 Send by WhatsApp');
  // QUOTE_WA_PERSONAL_v1 — second WA button that opens YOUR personal WhatsApp
  // (Web or Desktop per Settings) with the customer chat + pre-filled
  // quote message. Use whenever Meta API path can't deliver (template
  // not approved, customer outside 24h window, etc).
  const waPersonalBtn = h('button', { class: 'btn', style: { background: '#dcfce7', color: '#166534', borderColor: '#86efac' }, disabled: qid ? null : 'disabled', title: 'Opens YOUR own WhatsApp (Web or Desktop app per Settings) with the customer chat + message pre-filled. You tap Send manually — message goes from your number, not the API. Works even when Meta API path fails.' }, '📱 Send via My WhatsApp');
  const linkBtn = h('button', { class: 'btn ghost', disabled: qid ? null : 'disabled' }, '🔗 Public link');

  let currentId = qid || null;
  async function save() {
    saveBtn.disabled = true;
    // QUOTE_MANY_ITEMS_v1 (2026-05-25) — strip product_image_url when it
    // equals the product master's image. Reason: products store image_url
    // as data:image/...;base64,... (can be 200-500 KB per product). When
    // 15-20 line items each re-send the same data URI, the JSON body
    // exceeded Express's 4 MB limit and returned 413 PayloadTooLarge —
    // which the SPA surfaced to the user as "too many items".
    // The server already hydrates product_image_url back from the master
    // record on read + save when this field is empty, so dropping it
    // here is safe and shaves megabytes off the payload.
    const _prodImgIndex = (CRM.cache && CRM.cache.products) || [];
    const _masterImgFor = (pid) => {
      if (!pid) return '';
      const hit = _prodImgIndex.find(p => Number(p.id) === Number(pid));
      return (hit && hit.image_url) || '';
    };
    const items = [...itemsWrap.querySelectorAll('.q-item')].map(row => {
      const pid = row._prodSel && row._prodSel.value ? Number(row._prodSel.value) : null;
      const img = row._imageUrl || '';
      const masterImg = _masterImgFor(pid);
      // Only send line-image when it DIFFERS from the master (a custom
      // override). When they match, server re-hydrates from products.
      const sendImg = (img && img !== masterImg) ? img : '';
      return {
        description: row._desc.value,
        quantity: Number(row._qty.value || 0),
        unit_price: Number(row._pr.value || 0),
        discount_pct: Number(row._dp.value || 0),
        product_id: pid,
        product_image_url: sendImg
      };
    }).filter(it => it.description);
    try {
      const r = await api('api_quotations_save', {
        id: currentId,
        lead_id: q.lead_id || null,
        customer_name: nameInp.value,
        customer_email: emailInp.value,
        customer_phone: phoneInp.value,
        customer_address: addrInp.value,
        issue_date: issueInp.value || null,
        valid_until: validInp.value || null,
        discount_pct: Number(discInp.value || 0),
        tax_pct: Number(taxInp.value || 0),
        notes: notesInp.value,
        terms: termsInp.value,
        items
      });
      currentId = r.quotation.id;
      [emailBtn, waBtn, linkBtn].forEach(b => b.disabled = false);
      toast('Saved');
      return r.quotation;
    } catch (e) { toast(e.message, 'err'); throw e; }
    finally { saveBtn.disabled = false; }
  }
  saveBtn.onclick = () => save().catch(() => {});
  emailBtn.onclick = async () => {
    if (!emailInp.value) return toast('Add customer email first', 'err');
    if (!currentId) await save();
    try {
      await save();  // QUOTE_WA_PHONE_FIX_v2: persist latest changes before sending email
      const r = await api('api_quotations_send_email', currentId);
      toast('📧 Sent to ' + r.sent_to, 'ok');
    } catch (e) { toast(e.message, 'err'); }
  };
  waBtn.onclick = async () => {
    if (!phoneInp.value) return toast('Add customer phone first', 'err');
    waBtn.disabled = true;
    const _origLabel = waBtn.textContent;
    waBtn.textContent = '⏳ Sending…';
    try {
      // QUOTE_WA_PHONE_FIX_v2: ALWAYS save before sending, even if the
      // quote already has an id. Previously we only saved if !currentId,
      // which meant any change to the phone field AFTER the first save
      // never reached the server — Send-WA used the old empty phone and
      // threw "Customer phone missing". Now we save first so the latest
      // input value is persisted before the send call.
      await save();
      // QUOTE_WA_PHONE_FIX_v3: pass the phone from the input directly so even
      // if save() somehow didn't persist (race, network blip), the send still
      // uses the user-typed number rather than whatever's stale in the DB.
      const _selectedTpl = waTplSel && waTplSel.value ? waTplSel.value : '';
      const _selectedLang = waTplSel && waTplSel.selectedOptions[0] ? (waTplSel.selectedOptions[0].getAttribute('data-lang') || 'en_US') : 'en_US';
      const _sendOpts = { phone: phoneInp.value };
      if (_selectedTpl) { _sendOpts.template_name = _selectedTpl; _sendOpts.template_language = _selectedLang; }
      const r = await api('api_quotations_send_whatsapp', currentId, _sendOpts);
      toast('💬 Accepted by Meta for ' + r.sent_to + ' — should arrive on the customer\'s WhatsApp in a few seconds. If they don\'t see it: they must have messaged us within the last 24 hours (WhatsApp\'s free-form rule).', 'ok');
    } catch (e) {
      // QUOTE_WA_ERROR_v1 — give actionable guidance for the most common
      // WhatsApp send failures so the user knows what to fix.
      const msg = String(e.message || '');
      let hint = '';
      if (/WhatsApp not connected/i.test(msg)) hint = ' Open Settings → WhatsApp and connect a Cloud-API number first.';
      else if (/WhatsApp module not available/i.test(msg)) hint = ' Server-side WhatsApp module not loaded — contact support.';
      else if (/24-hour|outside.*window|re-?engagement/i.test(msg)) hint = ' Customer must message you first (24-hr WhatsApp policy) or use a pre-approved template.';
      else if (/invalid|wa_id|phone/i.test(msg)) hint = ' Check the customer phone number (must include country code, e.g. +91...).';
      else if (/token|expired|OAuth/i.test(msg)) hint = ' WhatsApp token expired — reconnect under Settings → WhatsApp.';
      toast('❌ ' + msg + hint, 'err');
    } finally {
      waBtn.disabled = false;
      waBtn.textContent = _origLabel;
    }
  };
  // QUOTE_WA_PERSONAL_v1 — open rep's own WhatsApp with pre-filled quote msg
  waPersonalBtn.onclick = async () => {
    if (!phoneInp.value) return toast('Add customer phone first', 'err');
    waPersonalBtn.disabled = true;
    const _origLbl = waPersonalBtn.textContent;
    waPersonalBtn.textContent = '⏳ Preparing…';
    try {
      await save();
      let publicUrl = '';
      try {
        const u = await api('api_quotations_public_url', currentId);
        publicUrl = u && u.url ? u.url : '';
      } catch (_) {}
      const cust = (nameInp.value || '').trim() || 'there';
      const quoteN = (q.number || '').toString().trim();
      const totalT = (totalsLine && totalsLine.textContent) || '';
      const totalMatch = totalT.match(/Total[^₹]*₹\s*([\d.,]+)/);
      const total = totalMatch ? totalMatch[1] : '';
      const lines = [];
      lines.push('Hi ' + cust + ',');
      lines.push('');
      lines.push('Please find your quotation' + (quoteN ? ' ' + quoteN : '') + (total ? ' — Total ₹' + total : '') + '.');
      if (publicUrl) {
        lines.push('');
        lines.push('📄 View / Download PDF:');
        lines.push(publicUrl);
      }
      lines.push('');
      lines.push('Let me know if you have any questions.');
      const text = lines.join('\n');
      const dial = String(phoneInp.value).replace(/\D/g, '');
      if (!dial) { toast('Customer phone is not a valid number', 'err'); return; }
      window._waOpenLink(dial, text);
      try {
        if (q.lead_id) {
          api('api_leads_addRemark', q.lead_id, { remark: '📱 Quote ' + (quoteN || '') + ' sent via personal WhatsApp to ' + dial }).catch(() => {});
        }
      } catch (_) {}
      toast('📱 Your WhatsApp opened with the quote pre-filled — tap Send to deliver it from your number.', 'ok');
    } catch (e) {
      toast('❌ ' + e.message, 'err');
    } finally {
      waPersonalBtn.disabled = false;
      waPersonalBtn.textContent = _origLbl;
    }
  };

  linkBtn.onclick = async () => {
    if (!currentId) await save();
    try { const u = await api('api_quotations_public_url', currentId); window.open(u.url, '_blank'); }
    catch (e) { toast(e.message, 'err'); }
  };

  // QUOTE_PDF_v1 — download-as-PDF button. Opens the public viewer with
  // ?autoprint=1 which auto-triggers the browser's Save-as-PDF dialog.
  const pdfBtn = h('button', { class: 'btn', style: { background: '#fef3c7', color: '#92400e', borderColor: '#fde68a' }, title: 'Download as PDF — opens the printable view and triggers Save-as-PDF' }, '\ud83d\udcc4 Download PDF');
  pdfBtn.onclick = async () => {
    if (!currentId) await save();
    try {
      const u = await api('api_quotations_public_url', currentId);
      const sep = u.url.indexOf('?') === -1 ? '?' : '&';
      window.open(u.url + sep + 'autoprint=1', '_blank');
    } catch (e) { toast(e.message, 'err'); }
  };

  card.appendChild(h('div', { class: 'q-actions', style: { display: 'flex', gap: '.5rem', marginTop: '1rem', justifyContent: 'space-between', flexWrap: 'wrap' } },
    h('div', { class: 'q-actions-left', style: { display: 'flex', gap: '.4rem', flexWrap: 'wrap', alignItems: 'center' } }, saveBtn, pdfBtn, emailBtn, h('span', { style: { fontSize: '.78rem', color: '#64748b' } }, 'WA Template:'), waTplSel, waBtn, waPersonalBtn, linkBtn),
    h('button', { class: 'btn ghost', onclick: () => m.remove() }, 'Close')
  ));
  recompute();
}

// ============================================================
// 🤖 AI Bot — per-tenant WhatsApp AI assistant powered by Gemini.
// Phase A1 ships the navigation + sub-tab shells. The actual bot
// reply path, KB ingestion (PDF/DOCX/URL), trigger modes, and
// per-tenant usage view are wired in Phase A2 onwards.
// ============================================================
VIEWS.aibot = async (view) => {
  view.innerHTML = '';
  const tabs = [
    { id: 'bots',     label: '🤖 Bots' },
    { id: 'settings', label: '⚙️ Bot Settings' },
    { id: 'kb',       label: '📚 Knowledge Base' },
    { id: 'activity', label: '📑 Bot Activity' },
    { id: 'usage',    label: '💸 Usage & Cost' }
  ];
  const tabBar = h('div', { class: 'wb-tab-bar', role: 'tablist' });
  const body   = h('div', { class: 'wb-tab-body' });
  // Default landing tab: the Bots overview. Caller can pre-select a different
  // tab + a per-phone bot for editing via window._aibotInitialTab / _aibotActivePhId.
  let active = window._aibotInitialTab || 'bots';
  window._aibotInitialTab = null;

  async function paint() {
    tabBar.innerHTML = '';
    tabs.forEach(t => {
      tabBar.appendChild(h('button', {
        class: 'wb-tab' + (t.id === active ? ' active' : ''),
        onclick: () => { active = t.id; paint(); }
      }, t.label));
    });
    body.innerHTML = '<div class="muted" style="padding:1rem">Loading…</div>';
    try {
      let node;
      if      (active === 'bots')     node = await _aibotBotsListView();
      else if (active === 'settings') node = await _aibotSettingsView(window._aibotActivePhId || null);
      else if (active === 'kb')       node = await _aibotKbView();
      else if (active === 'activity') node = await _aibotActivityView();
      else if (active === 'usage')    node = await _aibotUsageView();
      body.innerHTML = '';
      body.appendChild(node);
    } catch (e) {
      body.innerHTML = '';
      body.appendChild(h('div', { class: 'card', style: { color: '#dc2626' } }, '❌ ' + e.message));
    }
  }

  view.appendChild(h('div', { class: 'view-head' },
    h('h2', { style: { margin: 0 } }, '🤖 AI WhatsApp Bot'),
    h('p', { class: 'muted', style: { margin: '.25rem 0 0', fontSize: '.9rem' } },
      'Set up one or more bots — each with its own numbers + knowledge base + tone. Start on the Bots tab to see them all at a glance.')
  ));
  view.appendChild(tabBar);
  view.appendChild(body);
  paint();
};

// ============================================================
// AI Bot — Bots list (the new default landing tab)
// ============================================================
// Each bot is one row in ai_bot_settings: the legacy id=1 row
// (phone_number_id IS NULL) is the "Default fallback" bot, plus one
// row per phone the tenant gave its own training. This view renders
// each as a card showing: name + status toggle, numbers it serves,
// knowledge base docs assigned, and shortcuts to edit the full
// settings or delete.
// ============================================================
async function _aibotBotsListView() {
  const wrap = h('div', {});

  // ---- Top action bar ----
  const head = h('div', {
    class: 'card',
    style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '.5rem', background: 'linear-gradient(135deg, #eef2ff 0%, #fdf4ff 100%)', border: '1px solid #c7d2fe' }
  });
  head.appendChild(h('div', {},
    h('div', { style: { fontWeight: 700, fontSize: '1rem' } }, 'Your bots'),
    h('div', { class: 'muted', style: { fontSize: '.82rem' } },
      'Each bot has its own training (prompt, KB, languages) and is assigned to one or more WhatsApp numbers. Customers messaging a number get the bot configured for that number.')
  ));
  const newBtn = h('button', { class: 'btn primary' }, '➕ New Bot');
  head.appendChild(newBtn);
  wrap.appendChild(head);

  // ---- Load: bots, phones, KB docs ----
  let bots = [], phones = [], kbDocs = [];
  try { bots = ((await api('api_aibot_settings_listAll')).configs) || []; } catch (e) { bots = []; }
  try { phones = await api('api_wa_phones_listAll'); } catch (_) { phones = []; }
  try { kbDocs = ((await api('api_aibot_kb_list')).docs) || []; } catch (_) { kbDocs = []; }
  const phById = new Map();
  phones.forEach(p => phById.set(String(p.phone_number_id || ''), p));

  // Helper: given a bot row, return list of phone display strings it serves.
  function botServesPhones(bot) {
    const out = [];
    if (bot.phone_number_id) {
      const p = phById.get(String(bot.phone_number_id));
      out.push({ id: String(bot.phone_number_id), label: p ? (p.display_phone_number || bot.phone_number_id) : bot.phone_number_id, ph: p });
    }
    (bot.additional_phone_ids || []).forEach(id => {
      const p = phById.get(String(id));
      out.push({ id: String(id), label: p ? (p.display_phone_number || id) : id, ph: p });
    });
    return out;
  }

  // Helper: which phones are not yet assigned to ANY bot (for + New Bot picker).
  function unassignedPhones() {
    const taken = new Set();
    bots.forEach(b => {
      if (b.phone_number_id) taken.add(String(b.phone_number_id));
      (b.additional_phone_ids || []).forEach(x => taken.add(String(x)));
    });
    return phones.filter(p => !taken.has(String(p.phone_number_id || '')));
  }

  // Helper: filter KB docs scoped to this bot (or global if it's the default bot).
  function botKbDocs(bot) {
    if (!bot.phone_number_id) {
      // Default-fallback bot owns all GLOBAL docs (NULL phone)
      return kbDocs.filter(d => !d.phone_number_id);
    }
    // Per-phone bot owns docs scoped to its primary OR any of its additional phones
    const myIds = new Set([String(bot.phone_number_id), ...(bot.additional_phone_ids || []).map(String)]);
    return kbDocs.filter(d => d.phone_number_id && myIds.has(String(d.phone_number_id)));
  }

  // ---- Render each bot card ----
  if (!bots.length) {
    wrap.appendChild(h('div', { class: 'card', style: { background: '#fef3c7', border: '1px solid #f59e0b', textAlign: 'center', padding: '1.25rem' } },
      h('div', { style: { fontSize: '1.1rem', fontWeight: 700 } }, 'No bots yet'),
      h('div', { class: 'muted', style: { fontSize: '.9rem', marginTop: '.4rem' } },
        'Click "New Bot" above to create your first WhatsApp AI bot. It will start with sensible defaults — you can fine-tune its prompt, knowledge base, and which numbers it replies on.')
    ));
  }

  bots.forEach(bot => renderBotCard(bot));

  function renderBotCard(bot) {
    const isDefault = !bot.phone_number_id;
    const card = h('div', { class: 'card', style: { borderLeft: '4px solid ' + (isDefault ? '#6366f1' : '#10b981') } });

    // ---- Header: name + status ----
    const header = h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '.5rem' } });
    const nameLine = h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
      h('span', { style: { fontSize: '1.5rem' } }, isDefault ? '🏠' : '📱'),
      h('div', {},
        h('div', { style: { fontWeight: 700, fontSize: '1.05rem' } },
          bot.bot_label || (isDefault ? 'Default bot (fallback)' : (bot.bot_name || 'Bot')),
          isDefault ? h('span', { style: { marginLeft: '.5rem', fontSize: '.7rem', background: '#e0e7ff', color: '#4338ca', padding: '2px 6px', borderRadius: '999px', fontWeight: 600 } }, 'DEFAULT') : null
        ),
        h('div', { class: 'muted', style: { fontSize: '.82rem' } },
          isDefault
            ? 'Replies on every number not assigned to another bot.'
            : 'Replies only on the numbers below.')
      )
    );
    const enabledChk = h('input', { type: 'checkbox', checked: Number(bot.is_enabled) === 1 ? 'checked' : null });
    enabledChk.onchange = async () => {
      try {
        await api('api_aibot_settings_save', { phone_number_id: bot.phone_number_id || null, is_enabled: enabledChk.checked });
        toast(enabledChk.checked ? 'Bot enabled' : 'Bot disabled', 'ok');
      } catch (e) { toast(e.message, 'err'); enabledChk.checked = !enabledChk.checked; }
    };
    const statusLbl = h('label', { style: { display: 'flex', alignItems: 'center', gap: '.4rem', fontSize: '.85rem' } },
      enabledChk, h('span', {}, 'Enabled')
    );
    header.appendChild(nameLine);
    header.appendChild(statusLbl);
    card.appendChild(header);

    // ---- Step 1: Numbers this bot replies on ----
    const numbersBlock = h('div', { style: { marginTop: '.85rem', padding: '.6rem .75rem', background: '#f8fafc', borderRadius: '8px', border: '1px solid #e2e8f0' } });
    numbersBlock.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '.4rem' } },
      h('div', { style: { fontWeight: 600, fontSize: '.9rem' } }, '📱 Numbers'),
      isDefault
        ? h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'Auto: every number not assigned elsewhere')
        : h('button', { class: 'btn xs ghost', onclick: () => openNumbersPicker(bot) }, 'Manage numbers')
    ));
    const served = botServesPhones(bot);
    const chips = h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '.35rem' } });
    if (isDefault) {
      // Show the phones NOT assigned to any other bot — those are what this bot will reply on.
      const taken = new Set();
      bots.forEach(b => {
        if (b !== bot && b.phone_number_id) taken.add(String(b.phone_number_id));
        if (b !== bot) (b.additional_phone_ids || []).forEach(x => taken.add(String(x)));
      });
      const fallbackPhones = phones.filter(p => !taken.has(String(p.phone_number_id || '')));
      if (!fallbackPhones.length) {
        chips.appendChild(h('span', { class: 'muted', style: { fontSize: '.82rem' } }, 'No numbers fall through to this bot — every connected number is assigned.'));
      } else {
        fallbackPhones.forEach(p => chips.appendChild(numberChip(p, false)));
      }
    } else if (!served.length) {
      chips.appendChild(h('span', { class: 'muted', style: { fontSize: '.82rem' } }, 'No numbers assigned yet — click "Manage numbers".'));
    } else {
      served.forEach((s, idx) => chips.appendChild(numberChip(s.ph || { phone_number_id: s.id, display_phone_number: s.label }, idx === 0)));
    }
    numbersBlock.appendChild(chips);
    card.appendChild(numbersBlock);

    function numberChip(p, isPrimary) {
      return h('span', {
        style: { display: 'inline-flex', alignItems: 'center', gap: '.3rem', padding: '.25rem .55rem', background: '#fff', border: '1px solid #cbd5e1', borderRadius: '999px', fontSize: '.82rem' }
      }, h('span', {}, '📞 ' + (p.display_phone_number || p.phone_number_id || '')),
         isPrimary && !isDefault ? h('span', { style: { fontSize: '.66rem', background: '#dcfce7', color: '#166534', padding: '1px 5px', borderRadius: '4px', fontWeight: 600 } }, 'PRIMARY') : null);
    }

    // ---- Step 2: Knowledge base ----
    const kbBlock = h('div', { style: { marginTop: '.6rem', padding: '.6rem .75rem', background: '#f8fafc', borderRadius: '8px', border: '1px solid #e2e8f0' } });
    const myDocs = botKbDocs(bot);
    const globalDocsCount = kbDocs.filter(d => !d.phone_number_id).length;
    kbBlock.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '.4rem' } },
      h('div', { style: { fontWeight: 600, fontSize: '.9rem' } }, '📚 Knowledge base ',
        h('span', { class: 'muted', style: { fontWeight: 400, fontSize: '.78rem' } }, '(' + myDocs.length + ' assigned' + (!isDefault && globalDocsCount ? ' + ' + globalDocsCount + ' global' : '') + ')')),
      h('button', { class: 'btn xs ghost', onclick: () => openKbPicker(bot) }, 'Manage KB')
    ));
    const kbChips = h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '.3rem' } });
    if (!myDocs.length) {
      kbChips.appendChild(h('span', { class: 'muted', style: { fontSize: '.82rem' } },
        isDefault ? 'No global docs yet — global docs are used by every bot.' : 'No docs assigned. Global docs (' + globalDocsCount + ') will still be used.'));
    } else {
      myDocs.slice(0, 8).forEach(d => kbChips.appendChild(h('span', {
        style: { padding: '.2rem .5rem', background: '#fff', border: '1px solid #c7d2fe', borderRadius: '6px', fontSize: '.78rem' }
      }, '📄 ' + (d.title || 'Untitled').slice(0, 40))));
      if (myDocs.length > 8) kbChips.appendChild(h('span', { class: 'muted', style: { fontSize: '.78rem' } }, '+ ' + (myDocs.length - 8) + ' more'));
    }
    kbBlock.appendChild(kbChips);
    card.appendChild(kbBlock);

    // ---- Goal preview + tone ----
    const goalLine = (bot.system_prompt || '').slice(0, 140);
    if (goalLine) {
      card.appendChild(h('div', { style: { marginTop: '.6rem', fontSize: '.82rem', color: '#475569', fontStyle: 'italic' } },
        '🎯 ' + goalLine + (bot.system_prompt.length > 140 ? '…' : '')
      ));
    }

    // ---- Footer actions ----
    const footer = h('div', { style: { marginTop: '.85rem', display: 'flex', flexWrap: 'wrap', gap: '.4rem', borderTop: '1px solid #e2e8f0', paddingTop: '.6rem' } });
    footer.appendChild(h('button', { class: 'btn small primary', onclick: () => editBot(bot) }, '✏️ Edit full settings'));
    footer.appendChild(h('button', { class: 'btn small ghost', onclick: () => openKbPicker(bot) }, '📚 Manage KB'));
    if (!isDefault) footer.appendChild(h('button', { class: 'btn small ghost', onclick: () => openNumbersPicker(bot) }, '📱 Manage numbers'));
    footer.appendChild(h('div', { style: { flex: 1 } }));  // spacer
    if (!isDefault) {
      footer.appendChild(h('button', { class: 'btn small danger', onclick: () => deleteBot(bot) }, '🗑 Delete bot'));
    }
    card.appendChild(footer);

    wrap.appendChild(card);
  }

  // ---- Action handlers ----
  function editBot(bot) {
    window._aibotActivePhId = bot.phone_number_id || null;
    window._aibotInitialTab = 'settings';
    VIEWS.aibot(document.getElementById('view'));
  }

  async function deleteBot(bot) {
    if (!confirm('Delete this bot? Numbers it served will fall back to the Default bot. (KB docs scoped to this bot will become orphaned — re-assign them or they\'ll stop being used.)')) return;
    try {
      await api('api_aibot_settings_delete', bot.phone_number_id);
      toast('Bot deleted', 'ok');
      _aibotRefreshBots();
    } catch (e) { toast(e.message, 'err'); }
  }

  function openNumbersPicker(bot) {
    if (!bot.phone_number_id && bots.length === 1) {
      return toast('The default bot serves every number with no specific bot.', 'err');
    }
    const taken = new Set();
    bots.forEach(b => {
      if (b.id !== bot.id) {
        if (b.phone_number_id) taken.add(String(b.phone_number_id));
        (b.additional_phone_ids || []).forEach(x => taken.add(String(x)));
      }
    });
    const myPrimary = String(bot.phone_number_id || '');
    const myAddl = new Set((bot.additional_phone_ids || []).map(String));

    const modal = h('div', { class: 'modal-backdrop' });
    const dlg = h('div', { class: 'modal', style: { maxWidth: '520px' } });
    dlg.appendChild(h('h3', { style: { marginTop: 0 } }, '📱 Numbers for "' + (bot.bot_label || bot.bot_name || 'Bot') + '"'));
    dlg.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem' } }, 'Tick every WhatsApp number that should be answered by this bot. The first ticked one becomes the primary — that\'s where new KB docs will be scoped by default.'));

    const list = h('div', { style: { display: 'flex', flexDirection: 'column', gap: '.35rem', maxHeight: '320px', overflowY: 'auto' } });
    const chkMap = {};
    phones.forEach(p => {
      const id = String(p.phone_number_id || '');
      if (!id) return;
      const isTaken = taken.has(id);
      const isMine = (id === myPrimary) || myAddl.has(id);
      const chk = h('input', { type: 'checkbox', value: id, checked: isMine ? 'checked' : null, disabled: (isTaken && !isMine) ? 'disabled' : null });
      chkMap[id] = chk;
      list.appendChild(h('label', {
        style: { display: 'flex', alignItems: 'center', gap: '.55rem', padding: '.4rem .55rem', background: isTaken && !isMine ? '#fee2e2' : '#f8fafc', border: '1px solid #e2e8f0', borderRadius: '6px', opacity: isTaken && !isMine ? 0.55 : 1 }
      }, chk,
         h('div', { style: { flex: 1 } },
           h('div', {}, h('strong', {}, p.display_phone_number || id)),
           h('div', { class: 'muted', style: { fontSize: '.75rem' } }, p.verified_name || (p.label || ''),
             isTaken && !isMine ? h('span', { style: { marginLeft: '.4rem', fontSize: '.7rem', background: '#fca5a5', color: '#7f1d1d', padding: '1px 5px', borderRadius: '4px', fontWeight: 600 } }, 'IN USE BY ANOTHER BOT') : null)
         )
      ));
    });
    dlg.appendChild(list);

    const footer = h('div', { style: { display: 'flex', gap: '.4rem', justifyContent: 'flex-end', marginTop: '.85rem' } });
    footer.appendChild(h('button', { class: 'btn ghost', onclick: () => modal.remove() }, 'Cancel'));
    footer.appendChild(h('button', { class: 'btn primary', onclick: async () => {
      const picked = Object.entries(chkMap).filter(([_id, c]) => c.checked).map(([id]) => id);
      if (!picked.length) {
        if (!confirm('No numbers selected. Save anyway? This bot will sit idle until you add a number.')) return;
      }
      const primary = picked[0] || null;
      const additional = picked.slice(1);
      try {
        // Two-step: if primary changed, we need to write to the new phone_number_id.
        // The backend's per-phone upsert clones the existing config when the phone_number_id is new.
        await api('api_aibot_settings_save', { phone_number_id: primary, additional_phone_ids: additional });
        // If the bot's primary changed, the OLD per-phone row still exists. Clean it up.
        if (bot.phone_number_id && bot.phone_number_id !== primary) {
          try { await api('api_aibot_settings_delete', bot.phone_number_id); } catch (_) {}
        }
        toast('Numbers updated', 'ok');
        modal.remove();
        _aibotRefreshBots();
      } catch (e) { toast(e.message, 'err'); }
    } }, 'Save numbers'));
    dlg.appendChild(footer);
    modal.appendChild(dlg);
    document.body.appendChild(modal);
  }

  function openKbPicker(bot) {
    const isDefault = !bot.phone_number_id;
    const modal = h('div', { class: 'modal-backdrop' });
    const dlg = h('div', { class: 'modal', style: { maxWidth: '640px' } });
    dlg.appendChild(h('h3', { style: { marginTop: 0 } }, '📚 KB for "' + (bot.bot_label || bot.bot_name || 'Bot') + '"'));
    dlg.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem' } },
      isDefault
        ? 'Tick docs to make them GLOBAL (used by every bot). Untick to remove from global. To scope a doc to a specific bot, edit it from that bot.'
        : 'Tick docs to assign them ONLY to this bot. Untick to make them global (used by every bot). The bot also gets every global doc automatically.'
    ));

    if (!kbDocs.length) {
      dlg.appendChild(h('div', { class: 'muted', style: { padding: '1rem', textAlign: 'center' } },
        'No KB docs yet. Add some on the Knowledge Base tab.',
        h('button', { class: 'btn small ghost', style: { marginLeft: '.5rem' }, onclick: () => { modal.remove(); window._aibotInitialTab = 'kb'; VIEWS.aibot(document.getElementById('view')); }}, 'Go to Knowledge Base')
      ));
    } else {
      const myIds = new Set([String(bot.phone_number_id || ''), ...(bot.additional_phone_ids || []).map(String)].filter(Boolean));
      const list = h('div', { style: { display: 'flex', flexDirection: 'column', gap: '.3rem', maxHeight: '380px', overflowY: 'auto' } });
      const chkMap = {};
      kbDocs.forEach(d => {
        const docPh = String(d.phone_number_id || '');
        const isMine = isDefault ? !docPh : myIds.has(docPh);
        const ownedByOther = docPh && !isMine;
        const chk = h('input', { type: 'checkbox', checked: isMine ? 'checked' : null, disabled: ownedByOther ? 'disabled' : null });
        chkMap[d.id] = chk;
        list.appendChild(h('label', {
          style: { display: 'flex', alignItems: 'center', gap: '.55rem', padding: '.35rem .55rem', background: ownedByOther ? '#fef3c7' : '#f8fafc', border: '1px solid #e2e8f0', borderRadius: '6px', opacity: ownedByOther ? 0.55 : 1 }
        }, chk,
           h('div', { style: { flex: 1 } },
             h('div', {}, h('strong', {}, d.title)),
             h('div', { class: 'muted', style: { fontSize: '.74rem' } },
               (({ text: '📝 Text', url: '🌐 URL', pdf: '📄 PDF', docx: '📄 DOCX' })[d.source_type] || d.source_type),
               '  ·  ', (d.char_count || 0).toLocaleString('en-IN'), ' chars',
               ownedByOther ? h('span', { style: { marginLeft: '.4rem', fontSize: '.7rem', background: '#fde68a', color: '#92400e', padding: '1px 5px', borderRadius: '4px', fontWeight: 600 } }, 'OWNED BY ANOTHER BOT') : null)
           )
        ));
      });
      dlg.appendChild(list);
    }

    const footer = h('div', { style: { display: 'flex', gap: '.4rem', justifyContent: 'flex-end', marginTop: '.85rem' } });
    footer.appendChild(h('button', { class: 'btn ghost', onclick: () => modal.remove() }, 'Cancel'));
    if (kbDocs.length) {
      footer.appendChild(h('button', { class: 'btn primary', onclick: async () => {
        const myIds = new Set([String(bot.phone_number_id || ''), ...(bot.additional_phone_ids || []).map(String)].filter(Boolean));
        const targetPhId = bot.phone_number_id || (bot.additional_phone_ids && bot.additional_phone_ids[0]) || null;
        const toAssign = [];
        const toGlobal = [];
        kbDocs.forEach(d => {
          const docPh = String(d.phone_number_id || '');
          const isMineNow = isDefault ? !docPh : myIds.has(docPh);
          const wantsMine = (() => {
            const node = dlg.querySelector('input[type="checkbox"]:not([disabled])');
            // Inline check via chkMap - rebuilt below
            return null;
          })();
        });
        // Re-walk via chkMap captured in closure
        const all = dlg.querySelectorAll('input[type="checkbox"]:not([disabled])');
        // We don't have direct access to chkMap here from this closure; rebuild from data attrs.
        // Cleaner: iterate kbDocs and find matching chkMap by index.
        const decisions = [];
        kbDocs.forEach((d, idx) => {
          const docPh = String(d.phone_number_id || '');
          // Find this doc's checkbox in the list (skip disabled)
        });
        // Simpler: use the labels rendered earlier - inputs are in DOM order matching kbDocs
        const chks = dlg.querySelectorAll('input[type="checkbox"]');
        const chkArr = Array.from(chks);
        let cIdx = 0;
        kbDocs.forEach((d) => {
          const c = chkArr[cIdx++];
          if (!c) return;
          const docPh = String(d.phone_number_id || '');
          const ownedByOther = docPh && !(isDefault ? !docPh : myIds.has(docPh));
          if (ownedByOther) return;
          if (c.checked && !(isDefault ? !docPh : myIds.has(docPh))) {
            // Newly checked → assign to this bot
            toAssign.push(d.id);
          } else if (!c.checked && (isDefault ? !docPh : myIds.has(docPh))) {
            // Newly unchecked → unassign (move to global)
            toGlobal.push(d.id);
          }
        });
        try {
          if (toAssign.length) await api('api_aibot_kb_assign_bulk', { doc_ids: toAssign, phone_number_id: isDefault ? null : targetPhId });
          if (toGlobal.length) await api('api_aibot_kb_assign_bulk', { doc_ids: toGlobal, phone_number_id: null });
          toast('KB updated (' + (toAssign.length + toGlobal.length) + ' changes)', 'ok');
          modal.remove();
          _aibotRefreshBots();
        } catch (e) { toast(e.message, 'err'); }
      }}, 'Save KB'));
    }
    dlg.appendChild(footer);
    modal.appendChild(dlg);
    document.body.appendChild(modal);
  }

  // ---- + New Bot wizard ----
  newBtn.onclick = () => {
    const free = unassignedPhones();
    const modal = h('div', { class: 'modal-backdrop' });
    const dlg = h('div', { class: 'modal', style: { maxWidth: '480px' } });
    dlg.appendChild(h('h3', { style: { marginTop: 0 } }, '➕ Create a new bot'));
    if (!phones.length) {
      dlg.appendChild(h('div', { class: 'muted' }, 'No WhatsApp numbers connected yet. Connect a number on the WhatsApp page first.'));
      dlg.appendChild(h('button', { class: 'btn ghost', onclick: () => modal.remove() }, 'Close'));
      modal.appendChild(dlg);
      document.body.appendChild(modal);
      return;
    }
    if (!free.length) {
      dlg.appendChild(h('div', { class: 'muted' }, 'Every connected number is already assigned to a bot. To create another bot, first remove a number from an existing bot (Manage numbers → untick it).'));
      dlg.appendChild(h('div', { style: { display: 'flex', justifyContent: 'flex-end', marginTop: '.85rem' } },
        h('button', { class: 'btn ghost', onclick: () => modal.remove() }, 'Close')));
      modal.appendChild(dlg);
      document.body.appendChild(modal);
      return;
    }
    dlg.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem' } }, 'Step 1 — pick a name and the WhatsApp number this bot will reply on. You can add more numbers and customise its training afterwards.'));
    const nameInp = h('input', { type: 'text', placeholder: 'e.g. Sales Bot', style: { width: '100%' } });
    const phSel = h('select', { style: { width: '100%' } },
      ...free.map(p => h('option', { value: String(p.phone_number_id) }, '📱 ' + (p.display_phone_number || p.phone_number_id) + (p.label ? ' (' + p.label + ')' : ''))));
    dlg.appendChild(h('div', { class: 'field' }, h('label', {}, 'Bot name'), nameInp));
    dlg.appendChild(h('div', { class: 'field' }, h('label', {}, 'Number to assign'), phSel));
    const footer = h('div', { style: { display: 'flex', gap: '.4rem', justifyContent: 'flex-end', marginTop: '.85rem' } });
    footer.appendChild(h('button', { class: 'btn ghost', onclick: () => modal.remove() }, 'Cancel'));
    footer.appendChild(h('button', { class: 'btn primary', onclick: async () => {
      if (!nameInp.value.trim()) return toast('Give the bot a name', 'err');
      try {
        await api('api_aibot_settings_save', {
          phone_number_id: phSel.value,
          bot_label: nameInp.value.trim(),
          is_enabled: 1
        });
        toast('Bot created — opening editor', 'ok');
        modal.remove();
        window._aibotActivePhId = phSel.value;
        window._aibotInitialTab = 'settings';
        VIEWS.aibot(document.getElementById('view'));
      } catch (e) { toast(e.message, 'err'); }
    }}, 'Create bot'));
    dlg.appendChild(footer);
    modal.appendChild(dlg);
    document.body.appendChild(modal);
  };

  return wrap;
}

// Helper: re-paint the Bots tab from any nested action.
function _aibotRefreshBots() {
  window._aibotInitialTab = 'bots';
  VIEWS.aibot(document.getElementById('view'));
}

// ============================================================
// AI Bot — Settings sub-tab
// ============================================================
async function _aibotSettingsView(currentPhId) {
  const phIdParam = currentPhId || null;
  const data = await api('api_aibot_settings_get', phIdParam || null);
  const s = data.settings;
  const wrap = h('div', {});

  // ---- Editing context header ----
  // The Bots tab is the master list; this view is the deep editor for ONE bot.
  // Header tells the user which bot they're editing + offers a back-link.
  let phones = [];
  let perPhoneConfigs = [];
  try { phones = await api('api_wa_phones_listAll'); } catch (_) { phones = []; }
  try { perPhoneConfigs = ((await api('api_aibot_settings_listAll')).configs) || []; } catch (_) { perPhoneConfigs = []; }
  const configByPhId = new Map();
  perPhoneConfigs.forEach(c => { if (c.phone_number_id) configByPhId.set(String(c.phone_number_id), c); });

  const _activePh = phIdParam ? phones.find(p => String(p.phone_number_id || '') === phIdParam) : null;
  const _activeBot = phIdParam ? configByPhId.get(phIdParam) : (perPhoneConfigs.find(c => !c.phone_number_id) || null);
  const _editLabel = phIdParam
    ? ((_activeBot && _activeBot.bot_label) || (_activePh ? (_activePh.display_phone_number || phIdParam) : phIdParam))
    : ((_activeBot && _activeBot.bot_label) || 'Default bot (fallback)');

  const switcher = h('div', { class: 'card', style: { background: 'linear-gradient(135deg, #eef2ff 0%, #fdf4ff 100%)', border: '1px solid #c7d2fe', marginBottom: '.85rem', display: 'flex', alignItems: 'center', gap: '.6rem', flexWrap: 'wrap' } });
  const _backBtn = h('button', { class: 'btn small ghost', onclick: () => { window._aibotInitialTab = 'bots'; window._aibotActivePhId = null; VIEWS.aibot(document.getElementById('view')); } }, '← Back to Bots');
  switcher.appendChild(_backBtn);
  switcher.appendChild(h('div', { style: { flex: 1 } },
    h('div', { style: { fontWeight: 700, fontSize: '.95rem' } },
      (phIdParam ? '📱 Editing: ' : '🏠 Editing: ') + _editLabel),
    h('div', { class: 'muted', style: { fontSize: '.78rem' } },
      phIdParam
        ? ('This bot replies on ' + (_activePh ? _activePh.display_phone_number : phIdParam) + (_activeBot && _activeBot.additional_phone_ids && _activeBot.additional_phone_ids.length ? ' + ' + _activeBot.additional_phone_ids.length + ' more' : '') + '. To add/remove numbers, use "Manage numbers" on the bot card.')
        : 'Default bot is used as a fallback when an inbound arrives on a number that has no specific bot configured.')
  ));
  // Bot label editor (inline)
  const _labelInp = h('input', { type: 'text', placeholder: 'Bot name (label)', value: (_activeBot && _activeBot.bot_label) || '', style: { width: '180px', padding: '.3rem .5rem' } });
  const _labelBtn = h('button', { class: 'btn xs primary', onclick: async () => {
    try { await api('api_aibot_settings_save', { phone_number_id: phIdParam || null, bot_label: _labelInp.value }); toast('Label saved', 'ok'); }
    catch (e) { toast(e.message, 'err'); }
  } }, 'Save label');
  switcher.appendChild(_labelInp);
  switcher.appendChild(_labelBtn);

  wrap.appendChild(switcher);

  // (Old amber editing-context banner removed — replaced by the header above.)
  if (!data.global.is_active) {
    wrap.appendChild(h('div', { class: 'card', style: { background: '#fef3c7', borderLeft: '4px solid #f59e0b' } },
      h('div', { style: { fontWeight: '600' } }, '⚠️ Platform AI is disabled'),
      h('div', { class: 'muted', style: { fontSize: '.85rem' } },
        'Your CRM administrator has not yet activated the AI service. Contact support to enable AI replies for your workspace.')
    ));
  }

  // ---- master toggle ----
  const enableChk = h('input', { type: 'checkbox', checked: s.is_enabled ? 'checked' : null });
  const masterCard = h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, 'Master switch'),
    h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', fontSize: '1rem' } },
      enableChk, h('b', {}, ' Enable AI auto-reply on WhatsApp')),
    h('div', { class: 'muted', style: { fontSize: '.85rem', marginTop: '.4rem' } },
      'When enabled, customer messages on WhatsApp will be answered by Gemini using your knowledge base. Replies pause automatically when one of your agents jumps in on a thread.')
  );
  wrap.appendChild(masterCard);

  // ---- persona ----
  const botName = h('input', { type: 'text', value: s.bot_name || 'Assistant', style: { width: '100%' } });
  const bizName = h('input', { type: 'text', value: s.business_name || '', placeholder: 'e.g. Acme Realty Pvt Ltd', style: { width: '100%' } });

  // Multi-language: replace the single-select with checkboxes so the
  // bot can be told 'reply in Hindi OR English OR Marathi'. Stored as
  // a comma-joined string in `language` field for backward compat
  // (existing 'en+hi' values still work).
  const LANG_OPTIONS = [
    { code: 'en', label: 'English' },
    { code: 'hi', label: 'हिन्दी (Hindi)' },
    { code: 'mr', label: 'मराठी (Marathi)' },
    { code: 'gu', label: 'ગુજરાતી (Gujarati)' },
    { code: 'ta', label: 'தமிழ் (Tamil)' },
    { code: 'te', label: 'తెలుగు (Telugu)' },
    { code: 'bn', label: 'বাংলা (Bengali)' },
    { code: 'kn', label: 'ಕನ್ನಡ (Kannada)' },
    { code: 'ml', label: 'മലയാളം (Malayalam)' },
    { code: 'pa', label: 'ਪੰਜਾਬੀ (Punjabi)' },
    { code: 'ur', label: 'اردو (Urdu)' },
    { code: 'ar', label: 'العربية (Arabic)' }
  ];
  const currentLangs = String(s.language || 'en+hi')
    .split(/[+,\s]/).map(x => x.trim()).filter(Boolean);
  const langChks = {};
  const langGrid = h('div', {
    style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '.3rem', padding: '.5rem', background: '#f8fafc', borderRadius: '8px', border: '1px solid #e2e8f0' }
  });
  LANG_OPTIONS.forEach(o => {
    langChks[o.code] = h('input', { type: 'checkbox', value: o.code });
    if (currentLangs.includes(o.code)) langChks[o.code].checked = true;
    langGrid.appendChild(h('label', {
      style: { display: 'flex', alignItems: 'center', gap: '.4rem', padding: '.3rem .5rem', background: '#fff', borderRadius: '6px', border: '1px solid #e2e8f0', cursor: 'pointer', fontSize: '.85rem' }
    }, langChks[o.code], h('span', {}, o.label)));
  });

  // Goal templates — each one fills the system_prompt with a tested
  // template. Tenant can edit afterwards. {{BUSINESS_NAME}} placeholder
  // is auto-replaced when applied.
  const GOAL_TEMPLATES = {
    'sales': {
      label: '🛒 Sales — qualify and convert',
      prompt: `You are a friendly sales assistant for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: convert customer enquiries into qualified leads.\n\nFlow:\n1. Greet warmly and acknowledge their interest.\n2. Ask 2-3 short questions to understand their need (budget, timeline, specific requirement).\n3. Briefly explain how {{BUSINESS_NAME}} can help based on the knowledge base.\n4. ALWAYS end with a call-to-action: ask for a meeting, demo, or price quote.\n5. If they ask something not in the KB, say so politely and offer to connect with a human agent.\n\nKeep replies under 50 words. Be warm, never pushy.`
    },
    'support': {
      label: '🛠 Support — resolve issues fast',
      prompt: `You are a customer support agent for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: resolve customer issues quickly using the knowledge base.\n\nFlow:\n1. Acknowledge their issue with empathy.\n2. Ask for ANY missing details (order ID, account email, error message).\n3. Provide step-by-step solution from the knowledge base.\n4. If you can't solve it, escalate: 'Let me connect you with our support team — they'll reach you in [X] minutes.'\n5. Confirm the issue is resolved before ending.\n\nKeep replies short and clear. Use bullet points for steps.`
    },
    'appointment': {
      label: '📅 Appointment — book a meeting',
      prompt: `You are an appointment-booking assistant for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: schedule a meeting / consultation / call with the customer.\n\nFlow:\n1. Greet and confirm what kind of appointment they want.\n2. Ask for their preferred date AND time slot (offer 2-3 options based on business hours).\n3. Ask for their name + the topic of discussion if not clear.\n4. Confirm: 'I've noted [DATE] at [TIME] for [TOPIC]. Our team will call you. Anything else?'\n5. Hand off to a human if they want to talk to someone immediately.\n\nNever over-promise specific slots — say 'we'll confirm shortly' if you're unsure.`
    },
    'site_visit': {
      label: '🏠 Site visit — schedule a property tour',
      prompt: `You are a property-visit scheduler for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: book a site visit for the customer to see properties in person.\n\nFlow:\n1. Confirm which property/area they want to visit (use KB for available properties).\n2. Ask for preferred visit date + time.\n3. Ask for their name + how many people will visit.\n4. Confirm: 'Site visit booked: [PROPERTY] on [DATE] at [TIME]. Our agent will meet you at the location. Address coming on confirmation.'\n5. Tell them an agent will call to confirm + share map within 1 hour.\n\nIf they ask about pricing or availability, share what's in the KB but say final pricing is confirmed at the site.`
    },
    'qualify': {
      label: '🎯 Lead qualification — gather BANT',
      prompt: `You are a lead qualification assistant for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: gather BANT (Budget, Authority, Need, Timeline) info before passing to sales.\n\nFlow:\n1. Greet warmly.\n2. Ask conversationally:\n   - What problem are they trying to solve? (Need)\n   - When are they planning to act? (Timeline)\n   - What's their budget range? (Budget)\n   - Are they the decision-maker or part of a team? (Authority)\n3. Don't ask all four at once — spread across 2-3 messages.\n4. End with: 'Thanks! Our [SPECIALIST] will reach you within [TIMEFRAME] with a tailored proposal.'\n\nNever push a sale. You're a qualifier, not a closer.`
    },
    'onboarding': {
      label: '🎓 Onboarding — guide new customers',
      prompt: `You are an onboarding assistant for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: help new customers set up and start using our product/service.\n\nFlow:\n1. Welcome them and ask which product/plan they bought.\n2. Walk through the next 3 steps from the knowledge base.\n3. Send relevant resource links (videos, guides) when applicable.\n4. Ask if they have any questions or need a setup call.\n5. Set the right expectations: 'Most customers are up and running in [X] minutes/days.'\n\nKeep it encouraging. New users feel overwhelmed — break things into small wins.`
    },
    'faq': {
      label: '❓ FAQ — answer common questions',
      prompt: `You are an FAQ assistant for {{BUSINESS_NAME}} on WhatsApp.\n\nGoal: answer customer questions accurately from the knowledge base.\n\nRules:\n1. Use ONLY the knowledge base provided. If the answer isn't there, say: 'I don't have that info — let me get someone from our team to help.'\n2. Reply in 1-3 short sentences. Don't pad.\n3. If the question has multiple parts, answer each clearly.\n4. Always offer to escalate if they want more detail.\n\nNever guess. Never make up product features, prices, or policies.`
    }
  };
  // Detect which preset (if any) the current prompt matches
  let _activeGoal = '';
  Object.keys(GOAL_TEMPLATES).forEach(k => {
    const tpl = GOAL_TEMPLATES[k].prompt.replace(/\{\{BUSINESS_NAME\}\}/g, s.business_name || '');
    if ((s.system_prompt || '').slice(0, 200) === tpl.slice(0, 200)) _activeGoal = k;
  });

  const goalSel = h('select', { style: { width: '100%' } },
    h('option', { value: '', selected: !_activeGoal ? '' : null }, '— Custom (write your own below) —'),
    ...Object.entries(GOAL_TEMPLATES).map(([k, v]) =>
      h('option', { value: k, selected: _activeGoal === k ? '' : null }, v.label))
  );

  const sysPrompt = h('textarea', { rows: 8, style: { width: '100%' }, placeholder: 'Optional: override the default persona. Leave blank for the standard "helpful WhatsApp assistant" prompt.' }, s.system_prompt || '');

  goalSel.addEventListener('change', () => {
    const k = goalSel.value;
    if (!k) return;
    const tpl = GOAL_TEMPLATES[k];
    if (!tpl) return;
    const filled = tpl.prompt.replace(/\{\{BUSINESS_NAME\}\}/g, bizName.value || 'this business');
    if (sysPrompt.value && !confirm('Replace the current system prompt with the ' + tpl.label + ' template?')) return;
    sysPrompt.value = filled;
    toast('✅ Loaded ' + tpl.label + ' template — edit below to customise');
  });

  wrap.appendChild(h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, 'Bot persona & goal'),
    h('div', { class: 'field' }, h('label', {}, 'Bot name (shown in welcome message)'), botName),
    h('div', { class: 'field' }, h('label', {}, 'Business name'), bizName),
    h('div', { class: 'field' },
      h('label', {}, 'Reply languages (tick all that apply — bot will detect customer\'s language and reply in matching one)'),
      langGrid),
    h('div', { class: 'field' },
      h('label', {}, '🎯 Bot goal — pick a preset and customise below'),
      goalSel,
      h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } },
        'Picking a preset fills the system prompt with a tested template. Edit the prompt below to add your specific business rules, fees, common scenarios, etc.')
    ),
    h('div', { class: 'field' }, h('label', {}, 'System prompt (the bot\'s instructions)'), sysPrompt)
  ));

  // ---- quick reply buttons (static, max 3, titles <=20 chars) ----
  // When configured, the bot's outgoing reply is sent as a WhatsApp
  // interactive message with these buttons attached. Customers tap a button
  // to reply with that text — no typing needed.
  let qrSeed = [];
  try {
    const raw = s.quick_reply_buttons;
    qrSeed = typeof raw === 'string' ? JSON.parse(raw || '[]') : (Array.isArray(raw) ? raw : []);
  } catch (_) { qrSeed = []; }
  while (qrSeed.length < 3) qrSeed.push({ title: '' });
  const qrInputs = qrSeed.slice(0, 3).map((b, i) => h('input', {
    type: 'text',
    maxlength: 20,
    placeholder: i === 0 ? 'e.g. Yes, send details' : (i === 1 ? 'e.g. Call me' : 'e.g. Not interested'),
    value: String((b && b.title) || '')
  }));
  const qrTriggerSel = h('select', {},
    h('option', { value: 'always',     selected: (s.quick_reply_trigger || 'always') === 'always'     ? 'selected' : null }, 'Every bot reply (default)'),
    h('option', { value: 'first_only', selected: (s.quick_reply_trigger || 'always') === 'first_only' ? 'selected' : null }, 'Only on bot\'s first reply in a thread'),
    h('option', { value: 'keywords',   selected: (s.quick_reply_trigger || 'always') === 'keywords'   ? 'selected' : null }, 'Only when customer message contains keywords')
  );
  const qrKeywordsInp = h('input', {
    type: 'text',
    placeholder: 'e.g. price, cost, fees, plan, demo',
    value: String(s.quick_reply_keywords || '')
  });
  const qrKwField = h('div', { class: 'field' },
    h('label', {}, 'Trigger keywords (comma-separated)'),
    qrKeywordsInp,
    h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } },
      'Buttons attach only when the customer\'s last incoming message contains any of these words. Case-insensitive substring match.')
  );
  // Show/hide keyword field based on trigger selection
  const _qrKwToggle = () => { qrKwField.style.display = (qrTriggerSel.value === 'keywords') ? '' : 'none'; };
  qrTriggerSel.addEventListener('change', _qrKwToggle);
  setTimeout(_qrKwToggle, 0);

  const qrFilterChk = h('input', {
    type: 'checkbox',
    checked: Number(s.quick_reply_filter_tapped == null ? 1 : s.quick_reply_filter_tapped) === 1 ? 'checked' : null
  });
  const qrModeSel = h('select', {},
    h('option', { value: 'static',  selected: (s.quick_reply_mode || 'static') === 'static'  ? 'selected' : null }, 'Static — always send the same 3 buttons'),
    h('option', { value: 'dynamic', selected: (s.quick_reply_mode || 'static') === 'dynamic' ? 'selected' : null }, '🧠 Dynamic — AI picks best 1-3 from a pool (like a human)')
  );
  const qrPoolTa = h('textarea', {
    rows: 8,
    placeholder: 'One option per line, max 20 chars each. The bot will pick up to 3 most relevant based on customer message.\n\nExamples:\nBook a demo\nGet pricing\nCall me back\nSend brochure\nNot interested\nMore info\nBook a meeting\nSend sample',
    style: { width: '100%', minHeight: '140px', fontFamily: 'inherit', fontSize: '.9rem', padding: '.5rem' }
  });
  qrPoolTa.value = String(s.quick_reply_pool || '');

  // Show/hide blocks based on mode
  const _qrStaticBlock = h('div', {},
    h('div', { class: 'field' }, h('label', {}, 'Button 1 title'), qrInputs[0]),
    h('div', { class: 'field' }, h('label', {}, 'Button 2 title'), qrInputs[1]),
    h('div', { class: 'field' }, h('label', {}, 'Button 3 title'), qrInputs[2])
  );
  const _qrDynamicBlock = h('div', { class: 'field' },
    h('label', {}, '🧠 Button pool (AI picks the best 1-3 per message)'),
    qrPoolTa,
    h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } },
      'List every option the AI is allowed to offer. For each inbound message, the bot reads what the customer said and chooses the 1-3 most relevant from this list — like a human agent would. Example: customer asks "how much?" → bot picks "Get pricing" + "Book a demo". Customer asks "is this for retail?" → bot picks "Yes, retail" + "No, only B2B" + "Tell me more".')
  );
  const _toggleQrBlocks = () => {
    const isDyn = qrModeSel.value === 'dynamic';
    _qrStaticBlock.style.display = isDyn ? 'none' : '';
    _qrDynamicBlock.style.display = isDyn ? '' : 'none';
  };
  qrModeSel.addEventListener('change', _toggleQrBlocks);
  setTimeout(_toggleQrBlocks, 0);

  const qrCard = h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, '💬 Quick reply buttons'),
    h('p', { class: 'muted', style: { fontSize: '.85rem' } },
      'Up to 3 tap-to-reply buttons attached to bot messages. Choose Static (same 3 every time) or Dynamic (AI picks contextually like a human agent).'),
    h('div', { class: 'field' }, h('label', {}, 'Mode'), qrModeSel),
    _qrStaticBlock,
    _qrDynamicBlock,
    h('div', { class: 'field' }, h('label', {}, '⚡ When should buttons attach?'), qrTriggerSel),
    qrKwField,
    h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', padding: '.5rem 0' } },
      qrFilterChk,
      h('span', {}, 'Auto-hide buttons the customer has already tapped (Static mode only)')
    )
  );
  wrap.appendChild(qrCard);

  // ---- reply modes ----
  const modeChks = {};
  data.available_modes.forEach(m => {
    modeChks[m.id] = h('input', { type: 'checkbox', checked: (s.reply_modes || []).includes(m.id) ? 'checked' : null });
  });
  const modeCard = h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, 'When should the bot reply?'),
    h('p', { class: 'muted', style: { fontSize: '.85rem' } }, 'Pick any combination. The bot replies when at least one mode allows it. "Always reply" wins over the others.'),
    ...data.available_modes.map(m => h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', padding: '.3rem 0' } },
      modeChks[m.id], h('span', {}, m.label)
    ))
  );
  wrap.appendChild(modeCard);

  // ---- reply on which numbers? ----
  // Fetch all connected numbers; render a multi-select. Empty selection
  // = reply on every number (the default). Selected numbers ONLY -> bot
  // skips inbounds on other numbers and logs them as suppressed in
  // ai_chat_log so the activity tab shows what was filtered.
  const phonesCard = h('div', { class: 'card' });
  phonesCard.appendChild(h('h3', { style: { marginTop: 0 } }, '📱 Reply on which connected numbers?'));
  phonesCard.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem', margin: '0 0 .55rem' } },
    'Pick which WhatsApp numbers the bot should auto-reply on. Tick none to reply on ALL numbers (default). Useful when you want the bot only on a Sales line, not on Support.'));
  const activeIdsInitial = new Set((s.active_phone_number_ids || []).map(String));
  const phoneChkMap = {};
  let connectedPhones = [];
  try { connectedPhones = await api('api_wa_phones_listAll'); } catch (_) { connectedPhones = []; }
  if (!connectedPhones.length) {
    phonesCard.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem' } },
      'No connected WhatsApp numbers found. Connect a number in WhatsApp → Connect Account first.'));
  } else {
    const list = h('div', { style: { display: 'flex', flexDirection: 'column', gap: '.35rem' } });
    connectedPhones.forEach(ph => {
      const phId = String(ph.phone_number_id || '');
      const chk = h('input', { type: 'checkbox', value: phId, checked: activeIdsInitial.has(phId) ? 'checked' : null });
      phoneChkMap[phId] = chk;
      list.appendChild(h('label', { style: { display: 'flex', alignItems: 'center', gap: '.55rem', padding: '.4rem .55rem', background: '#f8fafc', border: '1px solid var(--border)', borderRadius: '6px' } },
        chk,
        h('div', { style: { flex: 1 } },
          h('div', {}, h('strong', {}, ph.display_phone_number || phId), Number(ph.is_default) === 1 ? h('span', { style: { marginLeft: '.4rem', fontSize: '.7rem', background: '#fef3c7', color: '#92400e', padding: '1px 6px', borderRadius: '999px', fontWeight: 600 } }, '⭐ DEFAULT') : null),
          h('div', { class: 'muted', style: { fontSize: '.78rem' } }, ph.verified_name || (ph.label || ''), '  ·  id ', h('code', { style: { fontSize: '.72rem' } }, phId))
        )
      ));
    });
    phonesCard.appendChild(list);
    phonesCard.appendChild(h('div', { style: { display: 'flex', gap: '.4rem', marginTop: '.45rem' } },
      h('button', { class: 'btn ghost small', type: 'button', onclick: () => { Object.values(phoneChkMap).forEach(c => c.checked = true); }}, 'Select all'),
      h('button', { class: 'btn ghost small', type: 'button', onclick: () => { Object.values(phoneChkMap).forEach(c => c.checked = false); }}, 'Clear (= reply on all)')
    ));
  }
  wrap.appendChild(phonesCard);

  // ---- business hours ----
  const bh = s.business_hours || { tz: 'Asia/Kolkata', days: [1,2,3,4,5], start: '09:00', end: '19:00' };
  const startInp = h('input', { type: 'time', value: bh.start || '09:00' });
  const endInp   = h('input', { type: 'time', value: bh.end || '19:00' });
  const dayChks = [0,1,2,3,4,5,6].map(d => ({
    el: h('input', { type: 'checkbox', checked: (bh.days || [1,2,3,4,5]).includes(d) ? 'checked' : null }),
    d
  }));
  const dayLabels = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  wrap.appendChild(h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, 'Business hours (used by "After business hours" mode)'),
    h('div', { style: { display: 'flex', gap: '.5rem', flexWrap: 'wrap', alignItems: 'center', marginBottom: '.5rem' } },
      h('label', {}, 'Start '), startInp,
      h('label', {}, ' End '),  endInp,
      h('span', { class: 'muted', style: { fontSize: '.8rem' } }, ' (' + (bh.tz || 'Asia/Kolkata') + ')')
    ),
    h('div', { style: { display: 'flex', gap: '.5rem', flexWrap: 'wrap' } },
      ...dayChks.map((c, i) => h('label', { style: { display: 'flex', alignItems: 'center', gap: '.25rem' } }, c.el, h('span', {}, dayLabels[i])))
    )
  ));

  // ---- triggers + escalation ----
  const trigKw = h('input', { type: 'text', value: s.trigger_keywords || '', placeholder: 'e.g. price, hours, menu', style: { width: '100%' } });
  const offKw = h('input', { type: 'text', value: s.off_keywords || '', placeholder: 'e.g. agent, human, complaint, refund', style: { width: '100%' } });
  const escKw = h('input', { type: 'text', value: s.escalation_keywords || '', placeholder: 'e.g. lawyer, refund, sue', style: { width: '100%' } });
  wrap.appendChild(h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, 'Triggers & escalation'),
    h('div', { class: 'field' }, h('label', {}, 'Trigger keywords (only used when "Only when keyword matches" mode is on)'), trigKw),
    h('div', { class: 'field' }, h('label', {}, 'Off keywords — bot stops replying on this thread once a customer says any of these'), offKw),
    h('div', { class: 'field' }, h('label', {}, 'Escalation keywords — flag for human review when bot\'s draft contains any'), escKw)
  ));

  // ---- safety / advanced ----
  // resume_after_idle_seconds is the new authoritative column (lets tenants
  // pick fine-grained values like 10s or 30s for testing). Falls back to
  // minutes \u00d7 60 for old rows pre-dating the column.
  const idleSecStart = (s.resume_after_idle_seconds != null && Number(s.resume_after_idle_seconds) >= 0)
    ? Number(s.resume_after_idle_seconds)
    : Number(s.resume_after_idle_minutes || 1440) * 60;
  const idleSec = h('input', { type: 'number', value: idleSecStart, min: 0, step: 1, style: { width: '8rem' } });
  const idleQuick = h('select', { style: { marginLeft: '.4rem' } },
    h('option', { value: '' }, 'Quick set\u2026'),
    h('option', { value: '10' }, '10 sec'),
    h('option', { value: '30' }, '30 sec'),
    h('option', { value: '60' }, '1 min'),
    h('option', { value: '300' }, '5 min'),
    h('option', { value: '1800' }, '30 min'),
    h('option', { value: '3600' }, '1 hour'),
    h('option', { value: '86400' }, '24 hours'));
  idleQuick.onchange = () => { if (idleQuick.value) { idleSec.value = idleQuick.value; idleQuick.value = ''; } };
  const pauseHumanChk = h('input', { type: 'checkbox', checked: Number(s.pause_after_human_handoff) === 1 ? 'checked' : null });
  const maxReplies = h('input', { type: 'number', value: s.max_replies_per_thread || 0, min: 0, style: { width: '8rem' } });
  const useKb = h('input', { type: 'checkbox', checked: s.use_kb ? 'checked' : null });
  const kbCap = h('input', { type: 'number', value: s.kb_max_chars || 8000, min: 2000, max: 120000, step: 5000, style: { width: '8rem' } });
  const histCount = h('input', { type: 'number', value: s.history_messages != null ? s.history_messages : 8, min: 0, max: 40, style: { width: '8rem' } });
  wrap.appendChild(h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, 'Safety & advanced'),
    h('div', { class: 'field' },
      h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
        pauseHumanChk,
        h('span', {}, ' Stop bot permanently once a human agent replies in a thread')),
      h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } }, 'When ON: the moment any agent (you or a teammate) sends a message in a chat, the bot stops replying on that thread for good — no auto-resume after silence. Use this if the bot should hand off cleanly without ever speaking over your team.')),
    h('div', { class: 'field' },
      h('label', {}, 'Otherwise, resume after agent silence (seconds) — 0 = never auto-resume'),
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.4rem', flexWrap: 'wrap' } }, idleSec, idleQuick),
      h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } }, 'Only used when the toggle above is OFF. How long after the last human-agent message before the bot may reply on this thread again. Use 10–20 sec for testing, 86400 (24h) for production.')),
    h('div', { class: 'field' }, h('label', {}, 'Max bot replies per conversation (0 = unlimited)'), maxReplies),
    h('div', { class: 'field' }, h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } }, useKb, h('span', {}, ' Use the knowledge base when answering'))),
    h('div', { class: 'field' }, h('label', {}, 'KB max chars per call (cap on prompt size)'), kbCap),
    h('div', { class: 'field' }, h('label', {}, 'How many recent messages to feed as context'), histCount)
  ));

  // ---- save ----
  // ---- Auto re-engagement ----
  // If the customer goes silent after the bot's last reply, the bot can send
  // a soft follow-up ping like "Sir, did you get a chance to look at this?"
  // Configurable per-bot (so different bots can have different cadences /
  // tones / max attempts).
  const reengageChk    = h('input', { type: 'checkbox', checked: Number(s.reengage_enabled) === 1 ? 'checked' : null });
  const reengageMins   = h('input', { type: 'number', value: s.reengage_after_minutes || 60, min: 5, max: 10080, step: 5, style: { width: '7rem' } });
  const reengageMsgInp = h('textarea', { rows: 3, style: { width: '100%' } }, s.reengage_message || 'Hi {{name}}, just checking — did you get a chance to look at our last message? Happy to help if you have any questions.');
  const reengageMaxInp = h('input', { type: 'number', value: s.reengage_max_attempts || 1, min: 1, max: 5, style: { width: '5rem' } });
  // Quick-set chips
  const reengageQuick = h('div', { style: { display: 'flex', gap: '.3rem', flexWrap: 'wrap', marginTop: '.3rem' } });
  [['10 min', 10], ['30 min', 30], ['1 hour', 60], ['3 hours', 180], ['1 day', 1440], ['3 days', 4320]].forEach(([lbl, mins]) => {
    const b = h('button', { type: 'button', class: 'btn xs ghost', onclick: () => { reengageMins.value = mins; } }, lbl);
    reengageQuick.appendChild(b);
  });
  wrap.appendChild(h('div', { class: 'card', style: { borderLeft: '4px solid #f59e0b' } },
    h('h3', { style: { marginTop: 0 } }, '🔔 Auto re-engagement'),
    h('p', { class: 'muted', style: { fontSize: '.85rem' } },
      'When a customer stops replying mid-conversation, the bot can send a soft check-in (like "Sir, did you get a chance to look at this?") after the silence threshold. The ping is automatically cancelled if the customer replies before the timer fires.'),
    h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', fontSize: '.95rem' } },
      reengageChk, h('b', {}, ' Enable auto re-engagement')),
    h('div', { class: 'field', style: { marginTop: '.5rem' } },
      h('label', {}, 'Send soft check-in after this much silence (minutes)'),
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.4rem', flexWrap: 'wrap' } }, reengageMins, h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'min')),
      reengageQuick),
    h('div', { class: 'field' },
      h('label', {}, 'Message template ',
        h('span', { class: 'muted', style: { fontWeight: 400, fontSize: '.78rem' } }, '— use {{name}} for the lead\'s name')),
      reengageMsgInp),
    h('div', { class: 'field' },
      h('label', {}, 'Max re-engagement attempts per customer (per 7 days)'),
      reengageMaxInp,
      h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } },
        'Stops the bot from spamming a customer who keeps going silent. Once this many pings have been sent in 7 days, no more.'))
  ));

  // ---- Hot lead alerts (May 2026) ----
  // Tenant-configurable: client picks their own high-intent keywords, sets
  // which heat levels fire a notification, and chooses recipients.
  const heatEnabledChk = h('input', { type: 'checkbox', checked: Number(s.heat_enabled == null ? 1 : s.heat_enabled) === 1 ? 'checked' : null });
  const heatLevels = ['warm', 'hot', 'very_hot', 'on_fire'];
  const heatLevelLabels = { warm: '✨ Warm', hot: '🔥 Hot', very_hot: '🔥🔥 Very hot', on_fire: '🔥🔥🔥 On fire' };
  const heatLevelChks = {};
  const currentLevels = String(s.heat_notify_levels || 'hot,very_hot,on_fire').split(',').map(x => x.trim()).filter(Boolean);
  const levelGrid = h('div', { style: { display: 'flex', gap: '.4rem', flexWrap: 'wrap', padding: '.4rem', background: '#fef3c7', borderRadius: '6px', border: '1px solid #fde68a' } });
  heatLevels.forEach(lv => {
    heatLevelChks[lv] = h('input', { type: 'checkbox', checked: currentLevels.includes(lv) ? 'checked' : null });
    levelGrid.appendChild(h('label', { style: { display: 'flex', alignItems: 'center', gap: '.3rem', padding: '.25rem .5rem', background: '#fff', borderRadius: '5px', border: '1px solid #fbbf24', cursor: 'pointer', fontSize: '.85rem' } },
      heatLevelChks[lv], h('span', {}, heatLevelLabels[lv])));
  });

  // Recipients
  const recipTokens = new Set(String(s.heat_notify_recipients || 'assigned,admins').split(',').map(x => x.trim()).filter(Boolean));
  const recipAssignedChk = h('input', { type: 'checkbox', checked: recipTokens.has('assigned') ? 'checked' : null });
  const recipAdminsChk   = h('input', { type: 'checkbox', checked: recipTokens.has('admins')   ? 'checked' : null });
  const recipManagersChk = h('input', { type: 'checkbox', checked: recipTokens.has('managers') ? 'checked' : null });
  const recipExtraInp    = h('input', { type: 'text', placeholder: 'extra user IDs (comma-separated, optional)', style: { width: '100%' },
    value: Array.from(recipTokens).filter(t => /^\d+$/.test(t)).join(',') });

  // Custom keyword editor — list of buckets, each with kws / weight / signal / action
  const heatBuckets = Array.isArray(s.heat_keywords) ? s.heat_keywords.slice() : [];
  const heatBucketsBox = h('div', { style: { display: 'flex', flexDirection: 'column', gap: '.4rem' } });

  function renderHeatBuckets() {
    heatBucketsBox.innerHTML = '';
    if (!heatBuckets.length) {
      heatBucketsBox.appendChild(h('p', { class: 'muted', style: { fontSize: '.82rem', margin: 0 } },
        'No custom keywords yet — defaults are still active. Add a row to add YOUR business-specific signals (e.g. "site visit" → very_hot).'));
    }
    heatBuckets.forEach((b, idx) => {
      const row = h('div', { style: { display: 'grid', gridTemplateColumns: '2.4fr 1fr 1.2fr 1fr auto', gap: '.4rem', alignItems: 'center', padding: '.45rem .55rem', background: '#fff', borderRadius: '6px', border: '1px solid #fde68a' } });
      const kwInp = h('input', { type: 'text', value: (b.kws || []).join(', '), placeholder: 'comma-separated keywords (e.g. "site visit, walk-in")', style: { width: '100%' } });
      const weightInp = h('select', { style: { width: '100%' } });
      [['Warm (10-24)', 15], ['Hot (25-39)', 30], ['Very hot (40-74)', 45], ['On fire (75+)', 80]].forEach(([lbl, w]) => {
        const o = h('option', { value: w }, lbl);
        weightInp.appendChild(o);
      });
      weightInp.value = String(b.weight || 30);
      const signalInp = h('input', { type: 'text', value: b.signal || '', placeholder: 'short label (e.g. "asked about site visit")', style: { width: '100%' } });
      const actionSel = h('select', { style: { width: '100%' } },
        h('option', { value: 'send_quote',     selected: b.action === 'send_quote' ? 'selected' : null }, 'Send quote'),
        h('option', { value: 'callback',       selected: b.action === 'callback' ? 'selected' : null }, 'Callback'),
        h('option', { value: 'send_brochure',  selected: b.action === 'send_brochure' ? 'selected' : null }, 'Send brochure'),
        h('option', { value: 'book_meeting',   selected: b.action === 'book_meeting' ? 'selected' : null }, 'Book meeting'),
        h('option', { value: 'urgent_followup',selected: b.action === 'urgent_followup' ? 'selected' : null }, 'Urgent follow-up'),
        h('option', { value: 'followup',       selected: !b.action ? 'selected' : null }, 'Generic follow-up'));
      const removeBtn = h('button', { type: 'button', class: 'btn xs danger ghost', onclick: () => {
        heatBuckets.splice(idx, 1); renderHeatBuckets();
      } }, '✕');
      kwInp.onblur     = () => { heatBuckets[idx].kws    = kwInp.value.split(',').map(s => s.trim()).filter(Boolean); };
      weightInp.onchange = () => { heatBuckets[idx].weight = Number(weightInp.value); };
      signalInp.onblur = () => { heatBuckets[idx].signal = signalInp.value; };
      actionSel.onchange = () => { heatBuckets[idx].action = actionSel.value; };
      row.appendChild(kwInp);
      row.appendChild(weightInp);
      row.appendChild(signalInp);
      row.appendChild(actionSel);
      row.appendChild(removeBtn);
      heatBucketsBox.appendChild(row);
    });
  }
  renderHeatBuckets();

  const addBucketBtn = h('button', { type: 'button', class: 'btn small ghost', onclick: () => {
    heatBuckets.push({ kws: [], weight: 30, signal: '', action: 'followup' });
    renderHeatBuckets();
  } }, '+ Add keyword group');

  wrap.appendChild(h('div', { class: 'card', style: { borderLeft: '4px solid #ef4444' } },
    h('h3', { style: { marginTop: 0 } }, '🔥 Hot lead alerts'),
    h('div', { style: { display: 'flex', justifyContent: 'flex-end', gap: '.4rem', marginTop: '-1.6rem', marginBottom: '.4rem' } },
      h('button', { type: 'button', class: 'btn small ghost', onclick: async () => { try { await openHeatTraceModal(); } catch (e) { toast(e.message, 'err'); } } }, '🔥 Heat trace'),
      h('button', { type: 'button', class: 'btn small ghost', onclick: async (ev) => {
        const btn = ev.currentTarget;
        btn.disabled = true; const _orig = btn.textContent;
        try {
          btn.textContent = '⏳ Sending\u2026';
          const r = await api('api_aibot_heat_test_alert');
          if (!r.ok) {
            toast('Test failed: ' + (r.error || 'unknown'), 'err');
            return;
          }
          // Trigger the in-app popup immediately by re-polling notifications.
          if (typeof refreshNotifs === 'function') { try { await refreshNotifs(); } catch (_) {} }
          const fcm = (r.fcm && r.fcm.sent) || 0;
          if (fcm > 0) {
            toast('✅ Test sent — bell drawer + ' + fcm + ' mobile device(s).', 'ok');
          } else {
            toast('✅ Test sent — check the bell icon (top-right) and the popup that just appeared. Install the mobile APK to also receive lock-screen alerts.', 'ok');
          }
        } catch (e) { toast(e.message, 'err'); }
        finally { btn.disabled = false; btn.textContent = _orig; }
      } }, '🔔 Send me a test alert')),
    h('p', { class: 'muted', style: { fontSize: '.85rem' } },
      'When a customer\'s WhatsApp message shows buying intent, the lead gets tagged hot and a push notification fires. Configure your own keywords + who gets notified below. Built-in defaults (price, demo, callback, comparison, etc.) are always active — your keywords add to them.'),
    h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', fontSize: '.95rem' } },
      heatEnabledChk, h('b', {}, ' Enable hot-lead detection + alerts')),
    h('div', { class: 'field', style: { marginTop: '.7rem' } },
      h('label', {}, 'Notify me when heat reaches'),
      levelGrid),
    h('div', { class: 'field' },
      h('label', {}, 'Who gets the push notification?'),
      h('div', { style: { display: 'flex', gap: '.5rem', flexWrap: 'wrap', alignItems: 'center' } },
        h('label', { style: { display: 'flex', alignItems: 'center', gap: '.3rem' } }, recipAssignedChk, h('span', {}, '👤 Assigned agent')),
        h('label', { style: { display: 'flex', alignItems: 'center', gap: '.3rem' } }, recipAdminsChk,   h('span', {}, '🛡 Admins')),
        h('label', { style: { display: 'flex', alignItems: 'center', gap: '.3rem' } }, recipManagersChk, h('span', {}, '👔 Managers'))
      ),
      h('div', { style: { marginTop: '.4rem' } }, recipExtraInp),
      h('div', { class: 'muted', style: { fontSize: '.77rem' } },
        'Extra user IDs in the box above also get notified (regardless of role).')),
    h('div', { class: 'field' },
      h('label', {}, 'Custom high-intent keywords'),
      heatBucketsBox,
      h('div', { style: { marginTop: '.4rem' } }, addBucketBtn),
      h('div', { class: 'muted', style: { fontSize: '.77rem', marginTop: '.4rem' } },
        'Each row: keywords (comma-separated) → weight (Warm/Hot/Very hot/On fire) → label shown to agent → suggested action. Single match on a "Very hot" or "On fire" weight goes straight to that level.'))
  ));

  const saveBtn = h('button', { class: 'btn primary', style: { padding: '.6rem 1.5rem' } }, '💾 Save bot settings');
  saveBtn.onclick = async () => {
    saveBtn.disabled = true;
    const payload = {
      is_enabled: enableChk.checked,
      heat_enabled: heatEnabledChk.checked ? 1 : 0,
      heat_keywords: heatBuckets,
      heat_notify_levels: heatLevels.filter(lv => heatLevelChks[lv].checked).join(','),
      heat_notify_recipients: (function(){
        const out = [];
        if (recipAssignedChk.checked) out.push('assigned');
        if (recipAdminsChk.checked)   out.push('admins');
        if (recipManagersChk.checked) out.push('managers');
        const extra = String(recipExtraInp.value || '').split(',').map(x => x.trim()).filter(x => /^\d+$/.test(x));
        out.push(...extra);
        return out.join(',');
      })(),
      reengage_enabled: reengageChk.checked ? 1 : 0,
      reengage_after_minutes: Number(reengageMins.value || 60),
      reengage_message: reengageMsgInp.value,
      reengage_max_attempts: Number(reengageMaxInp.value || 1),
      bot_name: botName.value, business_name: bizName.value,
      language: Object.keys(langChks).filter(k => langChks[k].checked).join('+') || 'en',
      system_prompt: sysPrompt.value,
      reply_modes: data.available_modes.filter(m => modeChks[m.id].checked).map(m => m.id),
      active_phone_number_ids: Object.entries(phoneChkMap).filter(([id, c]) => c.checked).map(([id]) => id),
      business_hours: {
        tz: bh.tz || 'Asia/Kolkata',
        days: dayChks.filter(c => c.el.checked).map(c => c.d),
        start: startInp.value, end: endInp.value
      },
      trigger_keywords: trigKw.value, off_keywords: offKw.value, escalation_keywords: escKw.value,
      resume_after_idle_seconds: Number(idleSec.value || 0),
      pause_after_human_handoff: pauseHumanChk.checked,
      max_replies_per_thread: Number(maxReplies.value || 0),
      use_kb: useKb.checked,
      kb_max_chars: Number(kbCap.value || 8000),
      history_messages: Number(histCount.value || 8),
      quick_reply_buttons: qrInputs
        .map(inp => ({ title: String(inp.value || '').slice(0, 20).trim() }))
        .filter(b => b.title),
      quick_reply_trigger: qrTriggerSel.value,
      quick_reply_keywords: qrKeywordsInp.value,
      quick_reply_filter_tapped: qrFilterChk.checked ? 1 : 0,
      quick_reply_mode: qrModeSel.value,
      quick_reply_pool: qrPoolTa.value
    };
    try {
      payload.phone_number_id = phIdParam || null;
      await api('api_aibot_settings_save', payload);
      toast('Bot settings saved', 'ok');
    } catch (e) {
      toast(e.message, 'err');
    } finally {
      saveBtn.disabled = false;
    }
  };
  wrap.appendChild(h('div', { style: { marginTop: '1rem', textAlign: 'right' } }, saveBtn));
  return wrap;
}

// ============================================================
// AI Bot — Knowledge Base sub-tab
// ============================================================
async function _aibotKbView() {
  const wrap = h('div', {});
  const card = h('div', { class: 'card' });
  card.appendChild(h('h3', { style: { marginTop: 0 } }, 'Add to knowledge base'));
  card.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem' } },
    'Anything you add here is fed into the bot\'s prompt at reply time. Keep entries focused — pricing, FAQs, services, hours. Avoid pasting your entire website; the bot reads better with curated context.'));

  // Paste text
  const titleInp = h('input', { type: 'text', placeholder: 'Title (e.g. "Service catalog")', style: { width: '100%', marginBottom: '.4rem' } });
  const textArea = h('textarea', { rows: 6, placeholder: 'Paste plain text here…', style: { width: '100%' } });
  const saveTextBtn = h('button', { class: 'btn primary', style: { marginTop: '.5rem' } }, '➕ Add as text doc');
  saveTextBtn.onclick = async () => {
    if (!textArea.value.trim()) return toast('Text is empty', 'err');
    saveTextBtn.disabled = true;
    try {
      await api('api_aibot_kb_save_text', { title: titleInp.value || 'Untitled', raw_text: textArea.value });
      titleInp.value = ''; textArea.value = '';
      toast('Added', 'ok'); refreshList();
    } catch (e) { toast(e.message, 'err'); }
    finally { saveTextBtn.disabled = false; }
  };
  card.appendChild(h('div', { style: { borderTop: '1px solid #e5e7eb', paddingTop: '.75rem' } },
    h('h4', {}, '📝 Paste plain text'),
    titleInp, textArea, saveTextBtn));

  // URL crawl
  const urlInp = h('input', { type: 'url', placeholder: 'https://your-website.com/about', style: { width: '100%', marginBottom: '.4rem' } });
  const crawlBtn = h('button', { class: 'btn primary', style: { marginTop: '.25rem' } }, '🌐 Crawl URL');
  crawlBtn.onclick = async () => {
    if (!/^https?:\/\//i.test(urlInp.value || '')) return toast('Enter a valid URL starting with http:// or https://', 'err');
    crawlBtn.disabled = true; crawlBtn.textContent = 'Fetching…';
    try {
      const r = await api('api_aibot_kb_crawl_url', { url: urlInp.value });
      urlInp.value = '';
      toast('Added — ' + r.char_count + ' chars extracted', 'ok'); refreshList();
    } catch (e) { toast(e.message, 'err'); }
    finally { crawlBtn.disabled = false; crawlBtn.textContent = '🌐 Crawl URL'; }
  };
  card.appendChild(h('div', { style: { borderTop: '1px solid #e5e7eb', paddingTop: '.75rem', marginTop: '.75rem' } },
    h('h4', {}, '🌐 Crawl a URL'),
    h('p', { class: 'muted', style: { fontSize: '.8rem' } }, 'Best for static pages (About, Services, FAQ). JS-heavy SPAs may not extract well.'),
    urlInp, crawlBtn));

  // ---- File attachment uploader (May 2026) ----
  // Lets users upload brochures / company profiles / PPTs etc. and tag them
  // with trigger keywords. When a customer says one of those keywords, the
  // bot sends the file via WhatsApp media.
  const attachWrap = h('div', { style: { borderTop: '1px solid #e5e7eb', paddingTop: '.75rem', marginTop: '.75rem' } });
  attachWrap.appendChild(h('h4', {}, '📎 Upload an attachment (brochure, PPT, profile)'));
  attachWrap.appendChild(h('p', { class: 'muted', style: { fontSize: '.8rem' } },
    'When a customer asks for one of the trigger keywords below, the bot will send this file via WhatsApp. Max 16 MB per file. PDF, PPT, DOCX, images, video and audio supported.'));
  const attachFile  = h('input', { type: 'file', accept: '.pdf,.ppt,.pptx,.doc,.docx,.xls,.xlsx,.png,.jpg,.jpeg,.webp,.mp4,.mp3,.m4a,.ogg,.wav', style: { width: '100%' } });
  const attachTitle = h('input', { type: 'text', placeholder: 'Display title (e.g. "Company brochure")', style: { width: '100%', marginTop: '.4rem' } });
  const attachKw    = h('input', { type: 'text', placeholder: 'Trigger keywords (comma-separated): brochure, catalog, profile', style: { width: '100%', marginTop: '.4rem' } });
  const attachBtn   = h('button', { class: 'btn primary', style: { marginTop: '.4rem' } }, '📤 Upload attachment');
  attachBtn.onclick = async () => {
    const f = attachFile.files && attachFile.files[0];
    if (!f) return toast('Pick a file first', 'err');
    if (f.size > 16 * 1024 * 1024) return toast('File too large (16 MB max)', 'err');
    attachBtn.disabled = true; attachBtn.textContent = 'Uploading…';
    try {
      const buf = await f.arrayBuffer();
      // Convert to base64 in chunks (avoid call-stack overflow on large files)
      let bin = ''; const bytes = new Uint8Array(buf);
      const chunk = 0x8000;
      for (let i = 0; i < bytes.length; i += chunk) bin += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk));
      const b64 = btoa(bin);
      await api('api_aibot_kb_save_attachment', {
        title: attachTitle.value || f.name,
        file_name: f.name,
        mime_type: f.type || 'application/octet-stream',
        file_base64: b64,
        trigger_keywords: attachKw.value || ''
      });
      attachFile.value = ''; attachTitle.value = ''; attachKw.value = '';
      toast('Attachment saved', 'ok'); refreshList();
    } catch (e) { toast(e.message, 'err'); }
    finally { attachBtn.disabled = false; attachBtn.textContent = '📤 Upload attachment'; }
  };
  attachWrap.appendChild(attachFile);
  attachWrap.appendChild(attachTitle);
  attachWrap.appendChild(attachKw);
  attachWrap.appendChild(attachBtn);
  card.appendChild(attachWrap);
  wrap.appendChild(card);

  // KB list
  const listCard = h('div', { class: 'card' });
  wrap.appendChild(listCard);
  async function refreshList() {
    listCard.innerHTML = '';
    let data;
    try { data = await api('api_aibot_kb_list'); }
    catch (e) { listCard.appendChild(h('div', { style: { color: '#dc2626' } }, e.message)); return; }
    listCard.appendChild(h('h3', { style: { marginTop: 0 } }, 'Knowledge base (' + data.docs.length + ' docs · ' + (data.total_active_chars || 0).toLocaleString('en-IN') + ' active chars)'));
    if (!data.docs.length) {
      listCard.appendChild(h('p', { class: 'muted' }, 'No KB docs yet. Add one above to start training your bot.'));
      return;
    }
    // Fetch connected phones once for the scope dropdown.
    let _connectedPhones = [];
    try { _connectedPhones = await api('api_wa_phones_listAll'); } catch (_) { _connectedPhones = []; }

    const tbl = h('table', { class: 'data-table', style: { width: '100%' } },
      h('thead', {}, h('tr', {},
        h('th', {}, 'Title'),
        h('th', {}, 'Source'),
        h('th', { title: 'Which bot uses this doc. Global = every bot. Pick a number to scope to that number\'s bot only.' }, 'Used by'),
        h('th', { title: 'Attachable: bot will SEND this file when inbound matches the trigger keywords' }, '📎 Attachable + triggers'),
        h('th', {}, 'Chars / Size'),
        h('th', {}, 'Active'),
        h('th', {}, 'Added'),
        h('th', {}, '')
      )),
      h('tbody', {}, ...data.docs.map(d => h('tr', {},
        h('td', {}, h('b', {}, d.title)),
        h('td', {}, ({ text: '📝 Text', url: '🌐 URL', pdf: '📄 PDF', docx: '📄 DOCX', attachment: '📎 Attachment' })[d.source_type] || d.source_type,
          d.file_name ? h('div', { class: 'muted', style: { fontSize: '.72rem' } }, d.file_name) : null),
        h('td', {}, (() => {
          // Multi-select: a doc can serve N phones at once. Empty = global (used by every bot).
          // Returns the assigned phones via primary phone_number_id + additional_phone_ids[].
          const assigned = [];
          if (d.phone_number_id) assigned.push(String(d.phone_number_id));
          let _addl = d.additional_phone_ids;
          if (typeof _addl === 'string') { try { _addl = JSON.parse(_addl); } catch (_) { _addl = []; } }
          if (Array.isArray(_addl)) _addl.forEach(x => { if (x && !assigned.includes(String(x))) assigned.push(String(x)); });
          const opts = _connectedPhones.map(ph => ({
            id: String(ph.phone_number_id || ''),
            name: '📱 ' + (ph.display_phone_number || ph.phone_number_id) + (ph.label ? ' (' + ph.label + ')' : '')
          }));
          return multiSelectDropdown({
            label: '',
            allLabel: '🏠 Global (all bots)',
            options: opts,
            values: assigned,
            onApply: async (picked) => {
              try { await api('api_aibot_kb_set_phone', d.id, picked); toast('Scope updated', 'ok'); refreshList(); }
              catch (e) { toast(e.message, 'err'); }
            }
          });
        })()),
        h('td', {}, d.source_type === 'attachment' || Number(d.is_attachable) === 1
          ? (() => {
              const onChk = h('input', { type: 'checkbox', checked: Number(d.is_attachable) === 1 ? 'checked' : null });
              const kwInp = h('input', { type: 'text', value: d.trigger_keywords || '', placeholder: 'brochure, catalog', style: { width: '180px', fontSize: '.78rem', padding: '.2rem .35rem', marginLeft: '.4rem' } });
              const save = async () => {
                try { await api('api_aibot_kb_set_attachment_meta', d.id, { is_attachable: onChk.checked ? 1 : 0, trigger_keywords: kwInp.value }); toast('Saved', 'ok'); }
                catch (e) { toast(e.message, 'err'); }
              };
              onChk.onchange = save;
              kwInp.onblur = save;
              return h('div', { style: { display: 'flex', alignItems: 'center', gap: '.3rem' } },
                h('label', { style: { display: 'flex', alignItems: 'center', gap: '.25rem', fontSize: '.78rem' } }, onChk, h('span', {}, 'On')),
                kwInp);
            })()
          : h('span', { class: 'muted', style: { fontSize: '.78rem' } }, '—')),
        h('td', {}, d.source_type === 'attachment'
          ? ((d.file_size_bytes || 0) / 1024).toFixed(0) + ' KB'
          : (d.char_count || 0).toLocaleString('en-IN')),
        h('td', {},
          h('input', { type: 'checkbox', checked: d.is_active ? 'checked' : null,
            onclick: async ev => { try { await api('api_aibot_kb_toggle', d.id, ev.target.checked); refreshList(); } catch (e) { toast(e.message, 'err'); } }
          })
        ),
        h('td', { class: 'muted', style: { fontSize: '.78rem' } }, fmtDate(d.created_at, 'relative')),
        h('td', {},
          h('button', { class: 'btn xs danger', onclick: async () => {
            if (!confirm('Delete "' + d.title + '"?')) return;
            try { await api('api_aibot_kb_delete', d.id); refreshList(); toast('Deleted', 'ok'); }
            catch (e) { toast(e.message, 'err'); }
          } }, '🗑')
        )
      )))
    );
    listCard.appendChild(tbl);
  }
  refreshList();
  return wrap;
}

// ============================================================
// AI Bot — Activity sub-tab
// ============================================================
async function _aibotActivityView() {
  const wrap = h('div', { class: 'card' });
  wrap.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', marginBottom: '.5rem' } },
    h('h3', { style: { margin: 0, flex: 1 } }, 'Recent bot activity'),
    /* BOT_DIAGNOSE_v1 */ h('button', { class: 'btn sm ghost', title: 'Trace why the bot replied / skipped for a specific phone', onclick: () => openAIBotDiagnose('') }, '🔎 Why no reply?')
  ));
  let rows;
  try { rows = await api('api_aibot_chatlog_list', { limit: 50 }); }
  catch (e) { wrap.appendChild(h('div', { style: { color: '#dc2626' } }, e.message)); return wrap; }
  if (!rows.length) {
    wrap.appendChild(h('p', { class: 'muted' }, 'No bot activity yet. Once you flip the bot on (Bot Settings → Master switch) and a customer messages, replies will appear here.'));
    return wrap;
  }
  const tbl = h('table', { class: 'data-table', style: { width: '100%', fontSize: '.86rem' } },
    h('thead', {}, h('tr', {},
      h('th', {}, 'When'), h('th', {}, 'Lead/phone'), h('th', {}, 'Status'),
      h('th', {}, 'Reply / draft / reason'), h('th', {}, 'Tokens'), h('th', {}, '₹'), h('th', {}, '')
    )),
    h('tbody', {}, ...rows.map(r => {
      const statusClass = ({ sent: 'ok', draft: 'warn', suppressed: 'muted', failed: 'err' })[r.status] || '';
      const text = r.reply_text || r.draft_text || r.suppressed_reason || r.error_text || '';
      return h('tr', {},
        h('td', { class: 'muted', style: { fontSize: '.78rem' } }, fmtDate(r.created_at, 'relative')),
        h('td', {}, r.lead_name || r.phone),
        h('td', { class: statusClass }, r.status),
        h('td', { style: { maxWidth: '420px' } },
          h('div', { style: { whiteSpace: 'pre-wrap', fontSize: '.84rem' } }, text)),
        h('td', { class: 'muted' }, ((r.input_tokens || 0) + (r.output_tokens || 0)).toLocaleString('en-IN')),
        h('td', {}, '₹' + Number(r.cost_inr_billed || 0).toFixed(3)),
        h('td', {},
          r.status === 'draft'
            ? h('div', { style: { display: 'flex', gap: '.25rem' } },
                h('button', { class: 'btn xs primary', onclick: async () => {
                  try { await api('api_aibot_send_draft', r.id); toast('Sent', 'ok'); _aibotActivityViewRefresh(wrap); }
                  catch (e) { toast(e.message, 'err'); }
                } }, 'Send'),
                h('button', { class: 'btn xs', onclick: async () => {
                  try { await api('api_aibot_discard_draft', r.id); _aibotActivityViewRefresh(wrap); }
                  catch (e) { toast(e.message, 'err'); }
                } }, 'Discard'))
            : null
        )
      );
    }))
  );
  wrap.appendChild(tbl);
  return wrap;
}
async function _aibotActivityViewRefresh(container) {
  const fresh = await _aibotActivityView();
  container.replaceWith(fresh);
}

// ============================================================
// AI Bot — Usage sub-tab
// ============================================================
async function _aibotUsageView() {
  const wrap = h('div', {});
  let u;
  try { u = await api('api_aibot_usage_summary', {}); }
  catch (e) { wrap.appendChild(h('div', { class: 'card', style: { color: '#dc2626' } }, e.message)); return wrap; }

  const kpis = h('div', { class: 'cards', style: { marginBottom: '1rem' } });
  function kpi(label, value, sub, klass) {
    return h('div', { class: 'card kpi ' + (klass || '') },
      h('div', { class: 'kpi-label' }, label),
      h('div', { class: 'kpi-value' }, value),
      sub ? h('div', { class: 'kpi-sub muted' }, sub) : null);
  }
  kpis.appendChild(kpi('💸 ' + u.month_label, '₹' + u.this_month.cost_inr.toLocaleString('en-IN'), 'Total bot cost this month', 'accent'));
  kpis.appendChild(kpi('💬 Replies sent', u.this_month.sent.toLocaleString('en-IN'), u.this_month.drafts ? (u.this_month.drafts + ' drafts pending') : 'Auto-sent', 'ok'));
  kpis.appendChild(kpi('📈 Forecast', '₹' + u.forecast_inr.toLocaleString('en-IN'), 'Projected at current pace', 'warn'));
  kpis.appendChild(kpi('🔢 All-time', '₹' + u.all_time.cost_inr.toLocaleString('en-IN'), u.all_time.sent + ' replies', 'accent'));
  if (u.this_month.suppressed) kpis.appendChild(kpi('⏸ Suppressed', u.this_month.suppressed, 'Times bot held back (agent active, off-keyword, etc.)', 'muted'));
  if (u.this_month.failed)     kpis.appendChild(kpi('⚠ Failed', u.this_month.failed, 'Gemini errors (not billed)', 'err'));
  wrap.appendChild(kpis);

  // Cost-saving advice — visible right under the KPIs so admins
  // can see what to do if the cost is high.
  if (u.this_month.input_tokens && (u.this_month.input_tokens / Math.max(1, u.this_month.sent)) > 5000) {
    wrap.appendChild(h('div', { class: 'card', style: { borderLeft: '4px solid #f59e0b', background: '#fffbeb' } },
      h('h4', { style: { marginTop: 0, color: '#92400e' } }, '💡 Cost-saving tip'),
      h('p', { class: 'muted', style: { margin: '.4rem 0' } },
        'Each reply is sending ', h('b', {}, Math.round(u.this_month.input_tokens / Math.max(1, u.this_month.sent)).toLocaleString('en-IN')),
        ' input tokens — most of that is your Knowledge Base being attached to every prompt.'),
      h('p', { class: 'muted', style: { margin: '.4rem 0' } },
        'Lower this in ', h('b', {}, 'AI Bot → Settings → "KB max chars per call"'),
        '. Recommended: ', h('b', {}, '8,000'), ' (about 2,000 tokens). Drops cost by up to 80% with minimal answer-quality loss.'),
    ));
  }

  // Estimator
  const repInp = h('input', { type: 'number', value: 500, min: 1, step: 50, style: { width: '8rem' } });
  const out = h('div', { style: { marginTop: '.5rem' } });
  const calcBtn = h('button', { class: 'btn primary' }, '🧮 Calculate');
  calcBtn.onclick = async () => {
    try {
      const r = await api('api_aibot_estimator', { replies: Number(repInp.value || 500) });
      out.innerHTML = '';
      out.appendChild(h('div', { style: { fontSize: '1.1rem', fontWeight: '700' } },
        '₹' + r.total_inr.toLocaleString('en-IN') + ' for ' + r.replies + ' bot replies'));
      out.appendChild(h('div', { class: 'muted', style: { fontSize: '.82rem', marginTop: '.25rem' } },
        'At ₹' + r.per_reply_inr.toFixed(3) + ' per reply · ' + r.derived_from));
    } catch (e) { toast(e.message, 'err'); }
  };
  wrap.appendChild(h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, '🧮 Cost forecast'),
    h('p', { class: 'muted', style: { fontSize: '.85rem' } }, 'How much would N customer replies cost?'),
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
      h('span', {}, 'Replies:'), repInp, calcBtn),
    out
  ));

  // Tokens detail
  wrap.appendChild(h('div', { class: 'card' },
    h('h3', { style: { marginTop: 0 } }, '📊 This month — token detail'),
    h('table', { class: 'mini-table' }, h('tbody', {},
      h('tr', {}, h('td', { class: 'muted' }, 'Replies sent'), h('td', {}, u.this_month.sent.toLocaleString('en-IN'))),
      h('tr', {}, h('td', { class: 'muted' }, 'Drafts (manual mode)'), h('td', {}, u.this_month.drafts.toLocaleString('en-IN'))),
      h('tr', {}, h('td', { class: 'muted' }, 'Suppressed'), h('td', {}, u.this_month.suppressed.toLocaleString('en-IN'))),
      h('tr', {}, h('td', { class: 'muted' }, 'Failed'), h('td', {}, u.this_month.failed.toLocaleString('en-IN'))),
      h('tr', {}, h('td', { class: 'muted' }, 'Input tokens'), h('td', {}, u.this_month.input_tokens.toLocaleString('en-IN'))),
      h('tr', {}, h('td', { class: 'muted' }, 'Output tokens'), h('td', {}, u.this_month.output_tokens.toLocaleString('en-IN'))),
      h('tr', {}, h('td', { class: 'muted' }, h('b', {}, 'Total cost')), h('td', {}, h('b', { style: { color: '#10b981' } }, '₹' + u.this_month.cost_inr.toLocaleString('en-IN'))))
    ))
  ));
  return wrap;
}


VIEWS.whatsbot = async (view) => {
  // Pre-warm the wa_phones cache so chat composer + initiate-chat
  // modal can render their 'Send from' picker without an extra wait.
  _loadWaPhones().catch(() => {});
  view.innerHTML = '';
  const tabs = [
    { id: 'connect',   label: '🔗 Connect Account' },
    { id: 'templates', label: '📋 Templates' },
    { id: 'flows',     label: '🗺️ Bot Flows' },
    { id: 'msgbots',   label: '💬 Message Bot' },
    { id: 'tplbots',   label: '🤖 Template Bot' },
    { id: 'campaigns', label: '📣 Campaigns' },
    { id: 'chat',      label: '💭 Chat' },
    { id: 'assign',    label: '👥 Auto-assign' },
    { id: 'activity',  label: '📑 Activity Log' }
  ];
  const nav = h('div', { class: 'subtabs' },
    ...tabs.map(t => h('button', { class: 'subtab', 'data-wbtab': t.id, onclick: () => showWbTab(t.id) }, t.label))
  );
  view.appendChild(nav);
  view.appendChild(h('div', { id: 'wb-body' }));
  const startTab = (location.hash.match(/whatsbot\/([a-z]+)/i) || [])[1] || 'connect';
  showWbTab(startTab);
};

async function showWbTab(id) {
  // Stop any running chat-polling timers if we're navigating away from chat.
  // Otherwise they'd keep firing every 4-8s in the background even after the
  // user has switched to e.g. Templates or Activity.
  if (id !== 'chat' && window._wbChatTimers) {
    clearInterval(window._wbChatTimers.threadList);
    clearInterval(window._wbChatTimers.activeThread);
    window._wbChatTimers = null;
  }
  $$('.subtab').forEach(b => b.classList.toggle('active', b.dataset.wbtab === id));
  const body = $('#wb-body');
  body.innerHTML = '<div class="loading">Loading…</div>';
  try {
    if (id === 'connect')   body.replaceChildren(await wbConnect());
    if (id === 'templates') body.replaceChildren(await wbTemplates());
    if (id === 'flows')     body.replaceChildren(await wbFlows());
    if (id === 'msgbots')   body.replaceChildren(await wbMessageBots());
    if (id === 'tplbots')   body.replaceChildren(await wbTemplateBots());
    if (id === 'campaigns') body.replaceChildren(await wbCampaigns());
    if (id === 'chat')      body.replaceChildren(await wbChat());
    if (id === 'assign')    body.replaceChildren(await wbAssignSettings());
    if (id === 'activity')  body.replaceChildren(await wbActivity());
    location.hash = '#/whatsbot/' + id;
  } catch (e) { body.innerHTML = `<div class="error-box">${esc(e.message)}</div>`; }
}

/* WA_CONVERT_LEAD_v1 (2026-05-24) — modal that pre-fills tenant defaults
   from api_wb_settings_get and lets the user adjust before saving. */
async function _wbOpenConvertToLeadModal(phone, threadMeta) {
  let s = {};
  try { s = await api('api_wb_settings_get'); } catch (_) { s = {}; }
  const users = CRM.cache.users || [];
  const statuses = CRM.cache.statuses || [];

  const nameInp   = h('input', { value: (threadMeta && threadMeta.lead_name) || phone, placeholder: phone, style: { width: '100%' } });
  const sourceInp = h('input', { value: s.autolead_source || 'WhatsApp', placeholder: 'WhatsApp', style: { width: '100%' } });
  const ownerSel  = h('select', { style: { width: '100%' } },
    h('option', { value: '' }, '— Use assignment rules —'),
    ...users.map(u => h('option', { value: u.id, selected: String(s.default_user_id || '') === String(u.id) ? 'selected' : null }, u.name))
  );
  const statusSel = h('select', { style: { width: '100%' } },
    h('option', { value: '' }, '— First status —'),
    ...statuses.map(st => h('option', { value: st.id, selected: String(s.default_status_id || '') === String(st.id) ? 'selected' : null }, st.name))
  );
  const notesInp  = h('textarea', { rows: 3, placeholder: 'Internal notes (optional)', style: { width: '100%' } });

  const m = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal', style: { maxWidth: '520px' } },
    h('div', { class: 'modal-head' },
      h('h3', {}, '🎯 Save WhatsApp chat as lead'),
      h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
    ),
    h('p', { class: 'muted', style: { fontSize: '.85rem', marginTop: 0 } },
      'Creates a CRM lead for ', h('b', {}, phone),
      ' and links the existing chat history to it. Defaults come from your WhatsApp auto-lead settings; tweak below before saving.'),
    h('div', { style: { display: 'grid', gridTemplateColumns: '1fr', gap: '.5rem' } },
      h('div', {}, h('label', { style: { fontSize: '.78rem', color: '#475569' } }, 'Lead name'), nameInp),
      h('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '.5rem' } },
        h('div', {}, h('label', { style: { fontSize: '.78rem', color: '#475569' } }, 'Assigned to'), ownerSel),
        h('div', {}, h('label', { style: { fontSize: '.78rem', color: '#475569' } }, 'Status'), statusSel)
      ),
      h('div', {}, h('label', { style: { fontSize: '.78rem', color: '#475569' } }, 'Lead source'), sourceInp),
      h('div', {}, h('label', { style: { fontSize: '.78rem', color: '#475569' } }, 'Notes (optional)'), notesInp)
    ),
    h('div', { class: 'actions', style: { display: 'flex', justifyContent: 'flex-end', gap: '.5rem', marginTop: '1rem' } },
      h('button', { class: 'btn', onclick: () => m.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', style: { background: '#16a34a', borderColor: '#16a34a' }, onclick: async (ev) => {
        const btn = ev.currentTarget;
        btn.disabled = true; btn.textContent = '⏳ Saving…';
        try {
          const r = await api('api_wb_thread_convertToLead', {
            phone, name: nameInp.value.trim() || phone,
            user_id: ownerSel.value, status_id: statusSel.value,
            source: sourceInp.value.trim() || 'WhatsApp',
            notes: notesInp.value.trim()
          });
          if (r.already_linked) {
            toast('Already a lead — opened it', 'info');
          } else {
            toast('✓ Lead created' + (r.messages_backfilled ? ' (' + r.messages_backfilled + ' message' + (r.messages_backfilled === 1 ? '' : 's') + ' linked)' : ''), 'ok');
          }
          m.remove();
          // Refresh the thread list so the lead_id/lead_name show up.
          if (typeof lastThreadsFingerprint !== 'undefined') lastThreadsFingerprint = '';
          if (typeof renderThreadList === 'function') renderThreadList();
          // Re-open the same thread so the chat header rebuilds with the new lead.
          if (typeof renderActiveThread === 'function') setTimeout(() => renderActiveThread(true), 400);
        } catch (e) {
          toast(e.message, 'err');
          btn.disabled = false; btn.textContent = '🎯 Save as lead';
        }
      } }, '🎯 Save as lead')
    )
  ));
  document.body.appendChild(m);
  setTimeout(() => nameInp.focus(), 50);
}

// ---------- Connect Account ----------
async function wbConnect() {
  const s = await api('api_wb_settings_get');
  const wrap = h('div', { class: 'wb-connect' });
  const isConnected = !!(s.access_token_present && s.waba_id && s.phone_number_id);
  const fbReady = !!(s.fb_app_id && s.fb_app_secret_set && s.fb_config_id);
  // Preload the FB SDK now so that when the user clicks "Connect with
  // Facebook" later, FB.login runs SYNCHRONOUSLY inside the click handler.
  // Without this, Chrome (and most browsers) block the popup because the
  // user-gesture has already expired by the time the async SDK fetch returns.
  if (s.fb_app_id) {
    ensureFbSdkLoaded(s.fb_app_id).catch(e => console.warn('[wb] FB SDK preload failed:', e.message));
  }

  // Embedded vs Manual mode toggle — matches the screenshot's layout.
  // Default ON unless the admin has explicitly stored a manual-only setup.
  const embKey = 'wb_emb_signin_on';
  let embOn = localStorage.getItem(embKey);
  embOn = embOn === null ? true : embOn === '1';

  // ---- Header: title + "Enable embedded SignIn" toggle on the right ----
  const header = h('div', { class: 'wb-conn-head' },
    h('h2', {}, 'WhatsApp business account'),
    h('label', { class: 'wb-emb-toggle' },
      h('span', {}, 'Enable embedded SignIn'),
      (() => {
        const sw = h('span', { class: 'switch' + (embOn ? ' on' : '') });
        const inp = h('input', { type: 'checkbox', checked: embOn ? 'checked' : null });
        inp.onchange = () => {
          embOn = inp.checked;
          localStorage.setItem(embKey, embOn ? '1' : '0');
          sw.classList.toggle('on', embOn);
          showWbTab('connect'); // re-render
        };
        sw.appendChild(inp);
        sw.appendChild(h('span', { class: 'slider' }));
        return sw;
      })()
    )
  );
  wrap.appendChild(header);

  // ---- 📱 Connected numbers (multi-phone support, Phase 1) ----
  // Card is ALWAYS rendered when WA is connected, even if wa_phones is
  // empty — otherwise the 'Connect another' / 'Sync from Meta' actions
  // would be hidden and the user couldn't recover from the case where
  // their initial Coexistence connect didn't write a row to wa_phones
  // (e.g. on vserve). The empty-state row inside the table tells them
  // exactly which button to press.
  let phones = [];
  try { phones = await api('api_wa_phones_listAll'); } catch (_) { phones = []; }
  if (phones.length || isConnected) {
    const phonesCard = h('div', { class: 'card', style: { marginBottom: '.8rem' } });
    phonesCard.appendChild(h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '.4rem', gap: '.5rem', flexWrap: 'wrap' } },
      h('h3', { style: { margin: 0 } }, '📱 Connected numbers (' + phones.length + ')'),
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
        h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'Default ⭐'),
        // Always-visible 'Add another' button. Uses Coexistence by
        // default so the existing connection isn't disturbed and the
        // new number can keep its WhatsApp Business mobile app active.
        h('button', { class: 'btn primary sm', title: 'Add a 2nd / 3rd WhatsApp number using Coexistence flow',
          onclick: () => {
            if (!s.fb_app_id || !s.fb_config_id) {
              return toast('Embedded Signin not configured (missing fb_app_id / fb_config_id). Tell support to enable it.', 'err');
            }
            startEmbeddedSignup(s.fb_app_id, s.fb_config_id, { coexistence: true, addAnother: true });
          }
        }, '➕ Connect another number'),
        h('button', { class: 'btn sm', title: 'Pull every phone Meta sees on your WABA into the connected-numbers table — useful when a Coexistence number was added but didn\'t auto-appear here',
          onclick: async ev => {
            const btn = ev.currentTarget;
            const orig = btn.textContent;
            btn.textContent = '⏳ Syncing…';
            btn.disabled = true;
            try {
              const r = await api('api_wa_phones_syncFromMeta');
              toast('✅ Meta sync: ' + r.added + ' added, ' + r.updated + ' updated (' + r.total + ' total)', 'ok');
              showWbTab('connect');
            } catch (e) {
              toast('Sync failed: ' + e.message, 'err');
              btn.textContent = orig; btn.disabled = false;
            }
          }
        }, '🔄 Sync from Meta')
      )
    ));
    const tbl = h('table', { class: 'data-table' },
      h('thead', {}, h('tr', {},
        h('th', {}, ''),
        h('th', {}, 'Phone'),
        h('th', {}, 'Verified name'),
        h('th', {}, 'Label'),
        h('th', {}, 'WABA'),
        h('th', {}, 'Status'),
        h('th', { title: 'WA_PERNUMBER_AUTOLEAD_v1 — per-number override of the global Auto-lead toggle. Inherit = use global setting; Always = always create a lead from inbound on this number; Never = never create a lead from inbound on this number.' }, 'Auto-lead'),
        h('th', { style: { textAlign: 'right' } }, '')
      )),
      h('tbody', {}, ...(phones.length ? phones : []).map(ph => h('tr', {},
        h('td', {}, Number(ph.is_default) === 1 ? '⭐' : ''),
        h('td', {}, h('code', {}, ph.display_phone_number || ph.phone_number_id)),
        h('td', {}, ph.verified_name || '—'),
        h('td', {},
          (() => {
            const inp = h('input', { type: 'text', value: ph.label || '', placeholder: 'e.g. Sales line', style: { width: '140px' } });
            let _t = null;
            inp.addEventListener('input', () => { clearTimeout(_t); _t = setTimeout(async () => {
              try { await api('api_wa_phones_save', { id: ph.id, label: inp.value }); } catch (e) { toast(e.message, 'err'); }
            }, 600); });
            return inp;
          })()
        ),
        h('td', { class: 'muted', style: { fontSize: '.78rem' } }, ph.business_account_id || '—'),
        h('td', {},
          Number(ph.is_active) === 1
            ? h('span', { class: 'badge ok' }, ph.status || 'active')
            : h('span', { class: 'badge warn' }, 'inactive')
        ),
        /* WA_PERNUMBER_AUTOLEAD_v1 — 3-state per-phone autolead picker.
           Saves inline on change via api_wa_phones_save. */
        h('td', {},
          (() => {
            const sel = h('select', { style: { fontSize: '.78rem', padding: '.18rem .35rem', borderRadius: '6px' }, title: 'Inherit = use the global Auto-lead toggle. Always = ALWAYS create a lead from inbound on this number. Never = NEVER create a lead from inbound on this number.' },
              h('option', { value: 'inherit', selected: (ph.autolead_mode || 'inherit') === 'inherit' ? 'selected' : null }, '↩ Inherit (global)'),
              h('option', { value: 'on',      selected: ph.autolead_mode === 'on'      ? 'selected' : null }, '✓ Always create'),
              h('option', { value: 'off',     selected: ph.autolead_mode === 'off'     ? 'selected' : null }, '✗ Never create')
            );
            sel.addEventListener('change', async () => {
              const prev = ph.autolead_mode || 'inherit';
              sel.disabled = true;
              try {
                await api('api_wa_phones_save', { id: ph.id, autolead_mode: sel.value });
                ph.autolead_mode = sel.value;
                toast('Auto-lead mode: ' + sel.value, 'ok');
              } catch (e) {
                sel.value = prev;
                toast(e.message, 'err');
              } finally {
                sel.disabled = false;
              }
            });
            return sel;
          })()
        ),
        h('td', { style: { textAlign: 'right' } },
          Number(ph.is_default) !== 1
            ? h('button', { class: 'btn sm', onclick: async () => {
                try { await api('api_wa_phones_setDefault', ph.id); toast('Default updated'); showWbTab('connect'); }
                catch (e) { toast(e.message, 'err'); }
              } }, 'Set default')
            : null,
          ' ',
          h('button', { class: 'btn sm danger', onclick: async () => {
              if (!await confirmDialog('Disconnect this number?')) return;
              try { await api('api_wa_phones_delete', ph.id); toast('Disconnected'); showWbTab('connect'); }
              catch (e) { toast(e.message, 'err'); }
            } }, '🗑')
        )
      )))
    );
    phonesCard.appendChild(tbl);
    phonesCard.appendChild(h('p', { class: 'muted', style: { marginTop: '.5rem', fontSize: '.85rem' } },
      'Each new number connected via Embedded Sign-In is appended here automatically. The default phone is the one used for sending unless an agent picks a different number on the chat composer.'));

    // Empty-state hint - shown when WA is connected but wa_phones is empty.
    // Almost always means the initial Coexistence connect skipped the row;
    // 'Sync from Meta' will pull every number Meta knows about into our table.
    if (!phones.length) {
      phonesCard.appendChild(h('div', { style: { marginTop: '.6rem', padding: '.75rem .9rem', background: '#fef3c7', border: '1px solid #f59e0b', borderRadius: '8px', fontSize: '.88rem', color: '#92400e' } },
        h('strong', {}, '⚠️ No phones in the connected-numbers table yet.'),
        h('div', { style: { marginTop: '.25rem' } },
          'Even though WhatsApp is connected (', h('code', {}, s.phone_number_id || '?'), '), no row was added to our wa_phones table — usually because the initial Coexistence sign-in didn\'t persist it. Click ',
          h('strong', {}, '🔄 Sync from Meta'),
          ' above to pull in every number Meta knows about for your WABA, or click ',
          h('strong', {}, '➕ Connect another number'),
          ' to add a new one.')
      ));
    }
    wrap.appendChild(phonesCard);
  }

  // ---- Connected status banner (always show if connected) ----
  if (isConnected) {
    wrap.appendChild(h('div', { class: 'card wb-conn-status' },
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', flexWrap: 'wrap' } },
        h('div', { style: { fontSize: '1.5rem' } }, '✅'),
        h('div', { style: { flex: 1, minWidth: '200px' } },
          h('b', {}, 'WhatsApp connected'),
          h('div', { class: 'muted', style: { fontSize: '.85rem' } },
            'WABA: ', h('code', {}, s.waba_id), ' · Phone ID: ', h('code', {}, s.phone_number_id))
        ),
        h('button', { class: 'btn sm', onclick: async () => {
          try {
            const r = await api('api_wb_connect_verify');
            if (r.ok) toast(`${r.display_phone_number} · Quality ${r.quality_rating || '—'} · ${r.status || ''}`);
            else toast(r.error || 'Verify failed', 'err');
          } catch (e) { toast(e.message, 'err'); }
        } }, 'Verify'),
        // Register the phone number with Cloud API — required once before
        // any send works. Without this, Meta returns 'account not registered'.
        h('button', { class: 'btn sm', title: 'Required once after connecting — registers the phone with WhatsApp Cloud API.',
          onclick: () => openRegisterPhoneModal()
        }, '🔐 Register phone'),
        h('button', { class: 'btn sm ghost danger', onclick: async () => {
          if (!await confirmDialog('Disconnect WhatsApp? Stored tokens will be cleared.')) return;
          try { await api('api_wb_disconnect'); toast('Disconnected'); showWbTab('connect'); }
          catch (e) { toast(e.message, 'err'); }
        } }, 'Disconnect')
      ),
      h('p', { class: 'muted', style: { fontSize: '.82rem', marginTop: '.5rem', marginBottom: 0 } },
        '⚠ If sending fails with "account not registered" — click 🔐 Register phone above. WhatsApp Cloud API needs each number registered once with a PIN (use 000000 if you don\'t have 2FA on the number).')
    ));

    // ---- Webhook health card — surfaces the most common reason for
    //      "messages send but no delivered/read/inbound" (webhook not
    //      configured in Meta dashboard or not subscribed to fields).
    const whCard = h('div', { class: 'card', style: { borderLeft: '4px solid #f59e0b' } });
    whCard.appendChild(h('h4', { style: { marginTop: 0 } }, '📡 Webhook health'));
    const whBody = h('div', {}, h('div', { class: 'muted' }, 'Loading…'));
    whCard.appendChild(whBody);
    wrap.appendChild(whCard);
    api('api_wb_webhook_status', location.origin).then(w => {
      whBody.innerHTML = '';
      const isHealthy = (w.recent_count_24h > 0) && Array.isArray(w.subscribed) && w.subscribed.length > 0;
      whCard.style.borderLeftColor = isHealthy ? '#10b981' : '#f59e0b';
      // Top status line
      whBody.appendChild(h('div', { style: { fontSize: '.95rem', marginBottom: '.75rem' } },
        isHealthy
          ? h('span', {}, '✅ Webhook is receiving events from Meta. Last inbound: ', h('b', {}, fmtDate(w.last_inbound?.recorded_on, 'relative')), ' · ', w.recent_count_24h, ' events in last 24 h.')
          : h('span', {}, '⚠️ Webhook is not delivering events from Meta. ',
              w.recent_count_24h ? '' : 'Zero events in the last 24 h. ',
              'You won\'t see delivered / read / inbound messages until this is fixed.')
      ));
      // Setup checklist
      whBody.appendChild(h('div', { style: { background: '#f8fafc', padding: '.75rem 1rem', borderRadius: '6px', fontSize: '.85rem' } },
        h('div', { style: { fontWeight: 600, marginBottom: '.5rem' } }, '🔧 Webhook setup checklist'),
        h('ol', { style: { paddingLeft: '1.2rem', margin: 0 } },
          h('li', { style: { marginBottom: '.4rem' } },
            'In ', h('a', { href: 'https://developers.facebook.com/apps/' + (s.fb_app_id || ''), target: '_blank' }, 'Meta App Dashboard'),
            ' → Left sidebar → ', h('b', {}, 'WhatsApp → Configuration'), '. ',
            'Click ', h('b', {}, 'Edit'), ' next to Webhook.'
          ),
          h('li', { style: { marginBottom: '.4rem' } },
            'Callback URL — copy and paste: ',
            h('input', { value: w.webhook_url || (location.origin + '/hook/whatsapp_webhook'), readonly: 'readonly',
              style: { fontFamily: 'monospace', width: '100%', marginTop: '.25rem', padding: '.4rem', fontSize: '.78rem' },
              onclick: ev => { ev.target.select(); document.execCommand && document.execCommand('copy'); toast('Copied'); }
            })
          ),
          h('li', { style: { marginBottom: '.4rem' } },
            'Verify Token — paste this exactly: ',
            h('input', { value: w.verify_token || s.verify_token || '', readonly: 'readonly',
              style: { fontFamily: 'monospace', width: '100%', marginTop: '.25rem', padding: '.4rem', fontSize: '.78rem' },
              onclick: ev => { ev.target.select(); document.execCommand && document.execCommand('copy'); toast('Copied'); }
            })
          ),
          h('li', { style: { marginBottom: '.4rem' } },
            'Click ', h('b', {}, 'Verify and save'), ' in Meta — they\'ll ping our endpoint and confirm.'
          ),
          h('li', { style: { marginBottom: '.4rem' } },
            'Then in the same Webhook section, ', h('b', {}, 'Subscribe to fields'), ' — tick at least:',
            h('ul', { style: { margin: '.25rem 0' } },
              h('li', {}, h('code', {}, 'messages'), ' — required for inbound messages and status updates'),
              h('li', {}, h('code', {}, 'message_template_status_update'), ' — optional, for template approval changes')
            )
          ),
          h('li', {}, 'Click the ', h('b', {}, '🔄 Subscribe app'), ' button below to attach our app to the WABA (one-click).')
        )
      ));
      // Action row
      whBody.appendChild(h('div', { style: { marginTop: '.75rem', display: 'flex', gap: '.5rem', flexWrap: 'wrap' } },
        h('button', { class: 'btn primary', onclick: async () => {
          try { const r = await api('api_wb_webhook_subscribe'); toast('App subscribed to WABA'); showWbTab('connect'); }
          catch (e) { toast(e.message, 'err'); }
        } }, '🔄 Subscribe app to WABA'),
        h('button', { class: 'btn', onclick: () => showWbTab('activity') }, '📑 View Activity Log'),
        h('button', { class: 'btn ghost', onclick: () => showWbTab('connect') }, '🔄 Refresh status')
      ));
      // Subscribed apps detail
      if (w.subscribe_error) {
        whBody.appendChild(h('div', { class: 'error-box', style: { marginTop: '.5rem' } },
          'Could not check subscription: ', w.subscribe_error));
      } else if (Array.isArray(w.subscribed)) {
        whBody.appendChild(h('div', { class: 'muted', style: { fontSize: '.82rem', marginTop: '.5rem' } },
          w.subscribed.length === 0
            ? '⚠ No app is subscribed to this WABA. Click "Subscribe app to WABA" above.'
            : '✓ ' + w.subscribed.length + ' app(s) subscribed: ' + w.subscribed.map(a => a.app_name || a.app_id).join(', ')
        ));
      }
    }).catch(e => {
      whBody.innerHTML = '';
      whBody.appendChild(h('div', { class: 'error-box' }, 'Could not load webhook status: ' + e.message));
    });

    // ---- All WABA phone numbers — pulled live from /phone_numbers ----
    const phonesCard = h('div', { class: 'card' });
    phonesCard.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '.5rem' } },
      h('h4', { style: { margin: 0 } }, '📞 Phone Numbers on this WABA'),
      h('button', { class: 'btn sm ghost', onclick: () => showWbTab('connect') }, '🔄 Refresh')
    ));
    const phonesList = h('div', {}, h('div', { class: 'muted' }, 'Loading…'));
    phonesCard.appendChild(phonesList);
    wrap.appendChild(phonesCard);
    // Fire async so the rest of the page renders immediately
    api('api_wb_phones_list').then(rows => {
      phonesList.innerHTML = '';
      if (!rows.length) { phonesList.appendChild(h('p', { class: 'muted' }, 'No phone numbers found on this WABA.')); return; }
      const qColor = q => q === 'GREEN' ? '#10b981' : q === 'YELLOW' ? '#f59e0b' : q === 'RED' ? '#ef4444' : '#94a3b8';
      const sColor = s => /CONNECTED|VERIFIED/i.test(String(s)) ? '#10b981'
                     : /UNVERIFIED|PENDING/i.test(String(s)) ? '#f59e0b'
                     : /OFFLINE|FLAGGED|RESTRICTED/i.test(String(s)) ? '#ef4444'
                     : '#64748b';
      phonesList.appendChild(h('div', { class: 'table-wrap' }, h('table', { class: 'mini-table' },
        h('thead', {}, h('tr', {},
          h('th', {}, 'Number'),
          h('th', {}, 'Verified name'),
          h('th', {}, 'Quality'),
          h('th', {}, 'Status'),
          h('th', {}, 'Name approval'),
          h('th', {}, 'Tier'),
          h('th', {}, 'Phone ID'),
          h('th', {}, 'Actions')
        )),
        h('tbody', {}, ...rows.map(p => h('tr', {},
          h('td', {}, p.is_current ? h('b', {}, p.display_phone_number, ' ', h('span', { style: { color: '#3b82f6', fontSize: '.7rem' } }, '★ current')) : (p.display_phone_number || '—')),
          h('td', {}, p.verified_name || '—'),
          h('td', {}, h('span', { class: 'tag', style: { background: qColor(p.quality_rating), color: '#fff' } }, p.quality_rating || 'UNKNOWN')),
          h('td', {}, h('span', { class: 'tag', style: { background: sColor(p.status), color: '#fff' } }, p.status || 'UNKNOWN')),
          h('td', { class: 'muted', style: { fontSize: '.78rem' } }, p.name_status || '—'),
          h('td', { class: 'muted', style: { fontSize: '.78rem' } }, p.messaging_limit_tier || '—'),
          h('td', {}, h('code', { style: { fontSize: '.72rem' } }, p.id)),
          h('td', { style: { whiteSpace: 'nowrap' } },
            !p.is_current ? h('button', { class: 'btn sm', onclick: async () => {
              try { await api('api_wb_phones_set_current', p.id); toast('Switched to ' + p.display_phone_number); showWbTab('connect'); }
              catch (e) { toast(e.message, 'err'); }
            } }, '★ Use this') : null,
            h('button', { class: 'btn sm wa-cloud-btn', style: { marginLeft: '.25rem' },
              onclick: () => openRegisterPhoneModal(p.id)
            }, '🔐 Register')
          )
        )))
      )));
    }).catch(e => {
      phonesList.innerHTML = '';
      phonesList.appendChild(h('div', { class: 'error-box' }, 'Could not load phone numbers: ' + e.message));
    });
  }

  /* WA_AUTOLEAD_CARD_v1 (2026-05-24) — standalone Auto-Lead Settings card.
     Previously the autolead_on / autolead_source / default_user_id /
     default_status_id / default_country_code controls lived ONLY inside the
     Manual-Entry credentials card (rendered when embOn === false). Since the
     default for every tenant is Embedded SignIn (embOn = true) AND the
     Embedded branch returns early at the bottom of this function, those
     controls were never reachable for normally-connected tenants — confirmed
     reproducible.

     Fix: render a self-contained card here, BEFORE the embOn gate, so any
     connected tenant can flip the auto-lead behaviour regardless of how
     they connected WhatsApp. Backend (api_wb_settings_save + cfg.autoLeadOn
     in whatsbot._handleInbound) already respects all these fields. */
  if (isConnected) {
    const aLead = h('div', { class: 'card', style: { marginBottom: '.8rem' } });
    aLead.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', marginBottom: '.4rem' } },
      h('h3', { style: { margin: 0 } }, '📥 Auto-lead from inbound WhatsApp'),
      h('span', { class: 'muted', style: { fontSize: '.75rem' } }, '— controls what happens when a number messages you')
    ));
    aLead.appendChild(h('p', { class: 'muted', style: { fontSize: '.82rem', marginTop: '.2rem', marginBottom: '.7rem' } },
      'OFF → inbound messages are still saved to the WhatsApp chat thread, but no lead is created. ',
      'ON → a fresh lead is auto-created for any unknown number (current behaviour). ',
      'Per-number whitelist (🚫 button on Lead modal / chat header) still works independently.'));
    const aForm = h('form', { class: 'form-grid', style: { marginTop: '.4rem' }, onsubmit: async ev => {
      ev.preventDefault();
      const fd = new FormData(ev.target);
      try {
        await api('api_wb_settings_save', {
          autolead_on: !!fd.get('autolead_on'),
          autolead_source: fd.get('autolead_source') || 'WhatsApp',
          default_country_code: fd.get('default_country_code') || '91',
          default_user_id: fd.get('default_user_id') || '',
          default_status_id: fd.get('default_status_id') || '',
          /* WA_AUTOLEAD_BC_v1 — business-hours + keyword gates */
          autolead_hours_on:    !!fd.get('autolead_hours_on'),
          autolead_hours_start: fd.get('autolead_hours_start') || '09:00',
          autolead_hours_end:   fd.get('autolead_hours_end')   || '19:00',
          autolead_keywords:    fd.get('autolead_keywords')    || ''
        });
        toast('Auto-lead settings saved', 'ok');
      } catch (e) { toast(e.message, 'err'); }
    }});
    const _alField = (label, inp) => h('div', { class: 'f-row' }, h('label', {}, label), inp);
    aForm.appendChild(h('div', { class: 'f-row full' },
      h('label', {}, 'Convert new messages to leads'),
      h('label', { class: 'qual-toggle' },
        h('input', { type: 'checkbox', name: 'autolead_on', checked: s.autolead_on ? 'checked' : null }),
        ' Enabled — turn OFF to stop auto-creating leads from inbound messages')
    ));
    aForm.appendChild(_alField('Lead source label',
      h('input', { name: 'autolead_source', value: s.autolead_source || 'WhatsApp', placeholder: 'WhatsApp' })));
    aForm.appendChild(_alField('Default country code (for 10-digit numbers)',
      h('input', { name: 'default_country_code', value: s.default_country_code || '91', placeholder: '91' })));
    const _users = CRM.cache.users || [];
    const _statuses = CRM.cache.statuses || [];
    aForm.appendChild(_alField('Default assignee for new WhatsApp leads',
      h('select', { name: 'default_user_id' },
        h('option', { value: '' }, '— Use assignment rules —'),
        ..._users.map(u => h('option', { value: u.id, selected: String(s.default_user_id || '') === String(u.id) ? 'selected' : null }, u.name))
      )
    ));
    aForm.appendChild(_alField('Default status for new WhatsApp leads',
      h('select', { name: 'default_status_id' },
        h('option', { value: '' }, '— First status —'),
        ..._statuses.map(st => h('option', { value: st.id, selected: String(s.default_status_id || '') === String(st.id) ? 'selected' : null }, st.name))
      )
    ));
    /* WA_AUTOLEAD_BC_v1 — business-hours + keyword gates UI.
       Sits between the existing default-status picker and the Save button. */
    aForm.appendChild(h('div', { class: 'f-row full', style: { marginTop: '.6rem', borderTop: '1px dashed #cbd5e1', paddingTop: '.6rem' } },
      h('div', { style: { fontWeight: '600', marginBottom: '.3rem' } }, '⏰ Business hours only'),
      h('p', { class: 'muted', style: { fontSize: '.78rem', margin: '.2rem 0' } },
        'When ON, only inbound messages received between Start and End time (IST) auto-create leads. Outside that window the chat still saves but no lead is created. Useful to stop after-hours spam-bot calls from becoming a 3-AM lead pile.')
    ));
    aForm.appendChild(h('div', { class: 'f-row full' },
      h('label', { class: 'qual-toggle' },
        h('input', { type: 'checkbox', name: 'autolead_hours_on', checked: s.autolead_hours_on ? 'checked' : null }),
        ' Enabled — only create leads during the time window below')
    ));
    aForm.appendChild(_alField('Start time (IST, 24-hour)',
      h('input', { name: 'autolead_hours_start', type: 'time', value: s.autolead_hours_start || '09:00' })));
    aForm.appendChild(_alField('End time (IST, 24-hour)',
      h('input', { name: 'autolead_hours_end',   type: 'time', value: s.autolead_hours_end   || '19:00' })));

    aForm.appendChild(h('div', { class: 'f-row full', style: { marginTop: '.6rem', borderTop: '1px dashed #cbd5e1', paddingTop: '.6rem' } },
      h('div', { style: { fontWeight: '600', marginBottom: '.3rem' } }, '🔑 Keyword filter (optional)'),
      h('p', { class: 'muted', style: { fontSize: '.78rem', margin: '.2rem 0' } },
        'When set, the inbound message body must contain at least one of these keywords (case-insensitive) to auto-create a lead. Comma-separated. Filters out "hi", "test", "wrong number" probes. Leave blank to disable the keyword check.')
    ));
    aForm.appendChild(_alField('Required keywords (comma-separated)',
      h('input', { name: 'autolead_keywords', value: s.autolead_keywords || '', placeholder: 'e.g. price, demo, interested, quote, buy' })));

    aForm.appendChild(h('div', { class: 'f-row full', style: { marginTop: '.6rem' } },
      h('button', { type: 'submit', class: 'btn primary' }, '💾 Save auto-lead settings')
    ));
    aLead.appendChild(aForm);
    wrap.appendChild(aLead);
  }

  if (embOn) {
    // ============ EMBEDDED SIGNIN MODE ============
    // Already connected → don't show the Connect button again, just an
    // unobtrusive "Connect a different account" link at the bottom.
    if (isConnected) {
      const reconnectWrap = h('div', { style: { textAlign: 'center', marginTop: '1rem' } });
      reconnectWrap.appendChild(h('a', {
        href: '#', style: { fontSize: '.85rem', color: 'var(--text-muted, #64748b)' },
        onclick: ev => { ev.preventDefault();
          if (confirm('Connect a different WhatsApp Business account? Current connection will be replaced.')) {
            startEmbeddedSignup(s.fb_app_id, s.fb_config_id, { coexistence: String(s.coexistence_mode || cfg.WHATSAPP_COEXISTENCE_MODE || '') === '1' });
          }
        }
      }, 'Connect a different WhatsApp account'));
      wrap.appendChild(reconnectWrap);
      return wrap;
    }

    // Platform-managed Facebook credentials — clients never see App ID,
    // Secret or Config ID. They just click one button and pick their
    // WABA / phone number inside Meta's dialog.
    const introCard = h('div', { class: 'card wb-fb-card', style: { textAlign: 'center', padding: '2rem 1.5rem' } });
    introCard.appendChild(h('h3', { style: { marginTop: 0 } }, 'Connect your WhatsApp Business account'));
    introCard.appendChild(h('p', { class: 'muted', style: { maxWidth: '460px', margin: '.25rem auto 1.25rem' } },
      'Click the button below to link your WhatsApp Business Account. You\'ll be asked to log into Facebook, pick the business and phone number you want to use, and Meta will send everything back to us automatically — no API keys to copy or paste.'));
    introCard.appendChild(h('button', {
      class: 'btn-fb-meta',
      onclick: () => {
        try {
          console.log('[wb-connect] click → fb_app_id=' + (s && s.fb_app_id) + ' fb_config_id=' + (s && s.fb_config_id) + ' coexistence=' + (s && s.coexistence_mode) + ' FBready=' + !!(window.FB && window.FB.login));
          if (!s || !s.fb_app_id || !s.fb_config_id) {
            toast('Embedded Login is not available — platform Facebook config is missing. Falling back to server-side OAuth…', 'warn');
            connectFacebookServerFlow();
            return;
          }
          startEmbeddedSignup(s.fb_app_id, s.fb_config_id, { coexistence: String(s.coexistence_mode || cfg.WHATSAPP_COEXISTENCE_MODE || '') === '1' });
        } catch (e) {
          console.error('[wb-connect] click error:', e);
          toast('Could not start embedded login: ' + (e && e.message ? e.message : String(e)) + ' — trying server OAuth fallback.', 'err');
          try { connectFacebookServerFlow(); } catch (_) {}
        }
      }
    },
      h('span', { class: 'fb-icon' }, '🅵'),
      ' Connect with Facebook'
    ));
    // Fallback link — if the embedded popup is blocked or doesn't open
    // (ad-blockers, popup blockers, restrictive enterprise browsers),
    // the user can use the server-side OAuth flow which is just a
    // full-page redirect (no popup involved).
    introCard.appendChild(h('p', { style: { marginTop: '.6rem', marginBottom: 0, fontSize: '.85rem' } },
      h('a', { href: '#', style: { color: '#1d4ed8' },
        onclick: ev => { ev.preventDefault(); connectFacebookServerFlow(); }
      }, 'Or use the server-side login (no popup) →')
    ));
    introCard.appendChild(h('p', { class: 'muted', style: { fontSize: '.78rem', marginTop: '1rem', marginBottom: 0 } },
      '🔒 You stay in control — Meta only shares the WABA and phone number you select.'));
    // Self-recovery: if the user already finished the dialog but the page
    // never refreshed, this re-fetches and reloads.
    introCard.appendChild(h('p', { style: { fontSize: '.8rem', marginTop: '.85rem', marginBottom: 0 } },
      h('a', { href: '#', style: { color: 'var(--text-muted, #64748b)' },
        onclick: ev => { ev.preventDefault(); location.reload(); }
      }, 'Already finished on Facebook? Click here to refresh status'),
    ));
    wrap.appendChild(introCard);
    return wrap;
  }

  // ============ MANUAL ENTRY MODE ============
  const manualCard = h('div', { class: 'card' });
  manualCard.appendChild(h('div', { class: 'wb-card-title' }, 'Manual WhatsApp credentials'));
  manualCard.appendChild(h('p', { class: 'muted', style: { marginTop: 0 } },
    'Paste WABA ID, Phone Number ID and Access Token directly. Use Embedded SignIn (toggle above) for the easier flow.'));
  const form = h('form', { class: 'form-grid', style: { marginTop: '.75rem' }, onsubmit: async ev => {
    ev.preventDefault();
    const fd = new FormData(ev.target);
    try {
      await api('api_wb_settings_save', {
        waba_id: fd.get('waba_id'),
        access_token: fd.get('access_token') || undefined,
        phone_number_id: fd.get('phone_number_id'),
        verify_token: fd.get('verify_token'),
        autolead_on: !!fd.get('autolead_on'),
        autolead_source: fd.get('autolead_source'),
        default_user_id: fd.get('default_user_id'),
        default_status_id: fd.get('default_status_id'),
        default_country_code: fd.get('default_country_code') || '91'
      });
      toast('Settings saved'); showWbTab('connect');
    } catch (e) { toast(e.message, 'err'); }
  }});
  form.appendChild(field('waba_id', 'WhatsApp Business Account ID *', s.waba_id, { required: true }));
  form.appendChild(field('phone_number_id', 'Phone Number ID *', s.phone_number_id, { required: true }));
  form.appendChild(h('div', { class: 'f-row full' },
    h('label', {}, 'Access Token *',
      s.access_token_present ? h('span', { class: 'muted', style: { fontSize: '.75rem', marginLeft: '.4rem' } }, '(saved — leave blank to keep)') : null),
    h('input', { name: 'access_token', type: 'password', autocomplete: 'new-password',
      placeholder: s.access_token_present ? '••••••••••••••' : 'paste from Meta App → System Users → Generate Token' })
  ));
  form.appendChild(field('verify_token', 'Webhook Verify Token', s.verify_token));
  form.appendChild(h('div', { class: 'f-row full' },
    h('label', {}, 'Webhook callback URL (paste this into Meta → WhatsApp → Webhooks)'),
    h('input', { value: s.webhook_url, readonly: 'readonly',
      style: { background: '#f1f5f9', fontFamily: 'monospace' },
      onclick: ev => ev.target.select() })
  ));
  form.appendChild(h('h4', { style: { gridColumn: '1 / -1', marginTop: '1rem' } }, 'Auto-lead from inbound message'));
  form.appendChild(h('div', { class: 'f-row' },
    h('label', {}, 'Convert new messages to leads'),
    h('label', { class: 'qual-toggle' },
      h('input', { type: 'checkbox', name: 'autolead_on', checked: s.autolead_on ? 'checked' : null }),
      ' Enabled')
  ));
  form.appendChild(field('autolead_source', 'Lead source (when auto-creating)', s.autolead_source || 'WhatsApp'));
  form.appendChild(field('default_country_code', 'Default country code (for 10-digit numbers)', s.default_country_code || '91'));
  // Lead defaults pickers
  const users = CRM.cache.users || [];
  const statuses = CRM.cache.statuses || [];
  form.appendChild(selectField('default_user_id', 'Default assignee for new WhatsApp leads', s.default_user_id,
    [{ value: '', label: '— Use assignment rules —' }, ...users.map(u => ({ value: u.id, label: u.name }))]));
  form.appendChild(selectField('default_status_id', 'Default status for new WhatsApp leads', s.default_status_id,
    [{ value: '', label: '— First status —' }, ...statuses.map(st => ({ value: st.id, label: st.name }))]));
  form.appendChild(h('div', { class: 'f-row full' },
    h('button', { type: 'submit', class: 'btn primary' }, '💾 Save settings')
  ));
  manualCard.appendChild(form);
  wrap.appendChild(manualCard);
  return wrap;
}

/**
 * Register the WABA phone number with Meta's Cloud API. This is a
 * one-time post-connect step required before any /messages call works.
 * Without it Meta returns "account is not registered" (error 133010).
 *
 * If the number doesn't have two-factor PIN set, leave the input as
 * 000000. If it does, the user must paste the 6-digit PIN they configured
 * when first claiming the number on whatsapp.com / Business Manager.
 */
/**
 * Push a "call this number" notification to the user's logged-in mobile
 * device(s). When they tap the notification, the APK opens our /#/dial
 * route which auto-fires `tel:` and launches the native dialer with the
 * number pre-filled. They just press the green call button on their phone.
 *
 * Requires the FCM Android APK to be installed and logged in as the same
 * user — desktop and mobile share the same user account.
 */
async function callViaMobile(lead) {
  const phone = String(lead?.phone || '').trim();
  if (!phone) { toast('Lead has no phone number', 'err'); return; }
  // Auto-prepend India country code if it's a 10-digit mobile, so the
  // dialer opens with a directly-callable number.
  let normalized = phone.replace(/\D/g, '');
  if (normalized.length === 10 && /^[6-9]/.test(normalized)) normalized = '91' + normalized;
  const dial = '+' + normalized;
  try {
    const r = await api('api_call_via_mobile', lead?.id || null, dial, lead?.name || '');
    const fcmCount = (r.push && r.push.fcm && r.push.fcm.sent) || 0;
    if (fcmCount === 0) {
      // FCM_USERDIAG_v1 — surface the precise reason via api_fcm_userDiag
      let detail = '';
      try {
        const diag = await api('api_fcm_userDiag');
        let attemptsStr = '';
        if (diag && Array.isArray(diag.recent_attempts) && diag.recent_attempts.length) {
          attemptsStr = '\n\nRecent APK register attempts:\n' + diag.recent_attempts.map(a => '• ' + (a.attempted_at || '?') + ' — ' + (Number(a.success) === 1 ? 'SUCCESS' : ('FAILED: ' + (a.error_text || 'unknown'))) + ' (prefix ' + (a.token_prefix || '?') + ')').join('\n');
        } else if (diag && diag.my_token_count === 0) {
          attemptsStr = '\n\nRecent APK register attempts: NONE (the APK never called the register endpoint for this user)';
        }
        if (diag && diag.cause) detail = '\n\n' + diag.cause + (diag.next_steps ? '\n\n' + diag.next_steps : '') + attemptsStr;
        if (typeof openInfoModal === 'function' && diag && !diag.ok) {
          openInfoModal('📱 Mobile push not ready', (diag.cause || 'Unknown issue') + (diag.next_steps ? '\n\n' + diag.next_steps : '') + attemptsStr);
          return;
        }
      } catch (_) {}
      toast('No mobile device registered for push.' + detail, 'warn');
    } else {
      toast('📱 Sent to your phone — tap the notification to open the dialer.');
    }
  } catch (e) { toast(e.message, 'err'); }
}

/**
 * Send a Calendly meeting link via WhatsApp.
 *
 * Reads the rep's calendly_url from CRM.user (set by api_me at login).
 * If unset, prompts the rep to paste it in their profile first. Otherwise
 * opens wa.me with a pre-filled message including the lead's name and
 * the booking URL — the rep just hits Send.
 *
 * Phase 2 will add a Calendly webhook that auto-creates a follow-up in
 * CRM the moment the prospect picks a slot.
 */
function sendCalendlyLink(lead) {
  const url = (CRM.user && CRM.user.calendly_url) || '';
  if (!url) {
    toast('Set your Calendly link in My Profile (top-right avatar → Edit profile) first.', 'warn');
    return;
  }
  const phone = String(lead?.phone || '').replace(/\D/g, '');
  if (!phone) { toast('Lead has no phone number', 'err'); return; }
  const dial = phone.length === 10 && /^[6-9]/.test(phone) ? '91' + phone : phone;
  const name = (lead?.name || 'there').split(/\s+/)[0]; // first name only
  const me = (CRM.user && CRM.user.name) ? (' — ' + CRM.user.name) : '';
  const text = `Hi ${name}, please pick a time that works for a quick call: ${url}${me}`;
  const waUrl = window._waShareUrl(dial, text);
  // Best-effort: log a remark so the team knows a meeting link went out.
  try { api('api_leads_addRemark', lead.id, { remark: '📅 Calendly meeting link sent via WhatsApp' }).catch(() => {}); } catch (_) {}
  window.open(waUrl, '_blank');
}

/**
 * Substitute {placeholders} in a personal WA template body with values
 * from the lead and current user. Unknown tokens are left in place so
 * the rep can spot mistakes.
 */
function _renderPersonalWaTemplate(body, lead) {
  const me = CRM.user || {};
  const ctx = {
    name:        lead?.name || '',
    first_name:  String(lead?.name || '').split(/\s+/)[0],
    phone:       lead?.phone || '',
    company:     lead?.company || '',
    value:       lead?.value ? '₹' + Number(lead.value).toLocaleString('en-IN') : '',
    next_followup: lead?.next_followup_at ? new Date(lead.next_followup_at).toLocaleString('en-IN') : '',
    my_name:     me.name || '',
    calendly:    me.calendly_url || ''
  };
  return String(body || '').replace(/\{(\w+)\}/g, (m, k) => ctx[k] != null ? ctx[k] : m);
}

/**
 * 💬 personal WhatsApp picker — opens a small modal with the rep's
 * saved templates. Picking one substitutes lead/user placeholders and
 * launches wa.me with the full message pre-filled. Includes a
 * "Blank — just open chat" shortcut and a "Manage templates" link.
 */
async function openPersonalWaPicker(lead) {
  const phone = String(lead?.phone || '').replace(/\D/g, '');
  if (!phone) { toast('Lead has no phone number', 'err'); return; }
  const dial = phone.length === 10 && /^[6-9]/.test(phone) ? '91' + phone : phone;

  let templates = [];
  try { templates = await api('api_personalWa_list'); } catch (_) {}

  const modal = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) modal.remove(); } });
  /* WA_TARGET_PICKER_v1 — user complained: 'if user wants Business WA, how does he choose a template?'
     Old flow had templates open the default chooser, and the 3 Personal/Business/Blank buttons sent
     EMPTY text. Now: target picker chips at top (Default / Personal / Business), persisted in
     localStorage, and tapping ANY template fires it into the selected target app. */
  let target = (function () {
    const stored = localStorage.getItem('crm_personal_wa_target');
    return ['chooser', 'personal', 'business'].includes(stored) ? stored : 'chooser';
  })();
  const targetChips = h('div', { style: { display: 'flex', gap: '.4rem', marginBottom: '.75rem', flexWrap: 'wrap' } });
  function renderChips() {
    targetChips.innerHTML = '';
    const items = [
      { kind: 'chooser',  label: '💬 Default',     hint: 'Android asks which WhatsApp to use' },
      { kind: 'personal', label: '🟢 Personal',    hint: 'Force open in WhatsApp', color: '#25D366' },
      { kind: 'business', label: '🟢 Business',    hint: 'Force open in WhatsApp Business', color: '#0a8055' }
    ];
    items.forEach(it => {
      const active = target === it.kind;
      targetChips.appendChild(h('button', {
        class: 'btn',
        title: it.hint,
        style: {
          background: active ? (it.color || '#4f46e5') : 'transparent',
          color: active ? '#fff' : (it.color || 'inherit'),
          border: '1px solid ' + (it.color || '#cbd5e1'),
          fontWeight: active ? 600 : 400
        },
        onclick: () => {
          target = it.kind;
          try { localStorage.setItem('crm_personal_wa_target', target); } catch (_) {}
          renderChips();
        }
      }, it.label));
    });
  }
  renderChips();

  const launch = (text) => {
    const tag = target === 'business' ? 'Business' : target === 'personal' ? 'Personal' : 'Default';
    try { if (lead?.id) api('api_leads_addRemark', lead.id, { remark: '💬 WhatsApp sent (' + tag + '): ' + (text || '(blank chat opened)').slice(0, 200) }).catch(() => {}); } catch (_) {}
    window._waOpenPinned(dial, text, target);
    modal.remove();
  };
  const list = h('div', { style: { display: 'flex', flexDirection: 'column', gap: '.4rem', maxHeight: '50vh', overflowY: 'auto' } });
  if (!templates.length) {
    list.appendChild(h('p', { class: 'muted', style: { margin: 0, fontSize: '.88rem' } },
      'No personal WhatsApp templates yet. Click "Manage templates" below to create your first — it saves typing on every chat.'));
  }
  templates.forEach(t => {
    const rendered = _renderPersonalWaTemplate(t.body, lead);
    list.appendChild(h('div', {
      class: 'card', style: { padding: '.6rem .8rem', cursor: 'pointer', borderLeft: '3px solid #25D366' },
      onclick: () => launch(rendered)
    },
      h('div', { style: { fontWeight: 600, marginBottom: '.2rem' } }, t.name),
      h('div', { class: 'muted', style: { fontSize: '.8rem', whiteSpace: 'pre-wrap' } },
        rendered.length > 180 ? rendered.slice(0, 180) + '…' : rendered)
    ));
  });
  modal.appendChild(h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, '💬 Send WhatsApp from your number'),
      h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
    ),
    h('p', { class: 'muted', style: { fontSize: '.8rem', margin: '0 0 .5rem' } },
      'Step 1 — Pick which WhatsApp to open. Step 2 — Tap a template (or "Open blank" below). The message opens pre-filled; you tap Send inside WhatsApp.'),
    targetChips,
    list,
    h('div', { class: 'actions', style: { marginTop: '.75rem', display: 'flex', gap: '.4rem', flexWrap: 'wrap' } },
      h('button', { class: 'btn', title: 'Open WhatsApp with no message — selected target above',
        onclick: () => launch('')
      }, '💬 Open blank'),
      h('button', { class: 'btn primary', onclick: () => { modal.remove(); openPersonalWaTemplatesModal(); } }, '✎ Manage templates')
    )
  ));
  document.body.appendChild(modal);
}

/**
 * CRUD modal for the rep's personal WhatsApp templates. Per-user.
 * Body supports placeholders documented in the help text.
 */
async function openPersonalWaTemplatesModal() {
  let templates = [];
  try { templates = await api('api_personalWa_list'); } catch (_) {}
  const modal = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) modal.remove(); } });
  const listWrap = h('div', { style: { display: 'flex', flexDirection: 'column', gap: '.5rem', maxHeight: '50vh', overflowY: 'auto', marginBottom: '1rem' } });
  const renderList = () => {
    listWrap.innerHTML = '';
    if (!templates.length) {
      listWrap.appendChild(h('p', { class: 'muted', style: { margin: 0 } }, 'No templates yet — add your first below.'));
    }
    templates.forEach(t => {
      listWrap.appendChild(h('div', { class: 'card', style: { padding: '.6rem .8rem' } },
        h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
          h('strong', { style: { flex: 1 } }, t.name),
          h('button', { class: 'btn sm', onclick: () => editOne(t) }, '✎'),
          h('button', { class: 'btn sm danger', onclick: async () => {
            if (!await confirmDialog('Delete "' + t.name + '"?')) return;
            try { await api('api_personalWa_delete', t.id); toast('Deleted'); templates = await api('api_personalWa_list'); renderList(); }
            catch (e) { toast(e.message, 'err'); }
          } }, '🗑')
        ),
        h('div', { class: 'muted', style: { fontSize: '.78rem', whiteSpace: 'pre-wrap', marginTop: '.25rem' } }, t.body)
      ));
    });
  };
  const editOne = (t) => {
    t = t || { name: '', body: '' };
    const formModal = h('div', { class: 'modal-backdrop', style: { zIndex: 9999 }, onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) formModal.remove(); } },
      h('div', { class: 'modal' },
        h('div', { class: 'modal-head' },
          h('h3', {}, t.id ? 'Edit template' : '+ New template'),
          h('button', { class: 'btn icon', onclick: () => formModal.remove() }, '✕')
        ),
        h('form', { id: 'pwa-tpl-form', class: 'form-grid' },
          h('div', { class: 'f-row full' },
            h('label', {}, 'Template name'),
            h('input', { name: 'name', value: t.name, placeholder: 'e.g. Site visit reminder', required: 'required' })
          ),
          h('div', { class: 'f-row full' },
            h('label', {}, 'Message body'),
            h('textarea', { name: 'body', rows: 6, placeholder: 'Hi {first_name}, this is {my_name} from Adbullet — just confirming our site visit tomorrow at 11 AM. Reply YES to confirm.' }, t.body || '')
          ),
          h('div', { class: 'f-row full' },
            h('p', { class: 'muted', style: { margin: 0, fontSize: '.78rem' } },
              'Placeholders auto-fill when you send: ',
              h('code', {}, '{name}'), ', ', h('code', {}, '{first_name}'), ', ',
              h('code', {}, '{phone}'), ', ', h('code', {}, '{company}'), ', ',
              h('code', {}, '{value}'), ', ', h('code', {}, '{next_followup}'), ', ',
              h('code', {}, '{my_name}'), ', ', h('code', {}, '{calendly}'))
          )
        ),
        h('div', { class: 'actions' },
          h('button', { class: 'btn', onclick: () => formModal.remove() }, 'Cancel'),
          h('button', { class: 'btn primary', onclick: async () => {
            const f = $('#pwa-tpl-form');
            const fd = new FormData(f);
            const payload = { id: t.id, name: fd.get('name'), body: fd.get('body') };
            if (!payload.name || !payload.body) return toast('Name and body required', 'err');
            try { await api('api_personalWa_save', payload); toast('Saved'); formModal.remove(); templates = await api('api_personalWa_list'); renderList(); }
            catch (e) { toast(e.message, 'err'); }
          } }, 'Save')
        )
      )
    );
    document.body.appendChild(formModal);
  };
  modal.appendChild(h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, '💬 My WhatsApp templates'),
      h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
    ),
    listWrap,
    h('div', { class: 'actions' },
      h('button', { class: 'btn primary', onclick: () => editOne(null) }, '+ New template')
    )
  ));
  document.body.appendChild(modal);
  renderList();
}

function openRegisterPhoneModal(phoneIdOverride) {
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal' });
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, '🔐 Register phone with Cloud API'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));
  body.appendChild(h('p', { class: 'muted' },
    'WhatsApp Cloud API requires each phone number to be registered ONCE before it can send messages. ',
    'If two-step verification is OFF for this number, leave the PIN as ', h('code', {}, '000000'), '. ',
    'If 2FA is ON, paste the 6-digit PIN you set on the WhatsApp app or Meta Business Manager.'));
  if (phoneIdOverride) {
    body.appendChild(h('p', { class: 'muted', style: { fontSize: '.8rem' } },
      'Registering phone ID ', h('code', {}, phoneIdOverride)));
  }
  const pinInput = h('input', {
    type: 'text', value: '000000', maxLength: 6,
    style: { fontFamily: 'monospace', fontSize: '1.2rem', textAlign: 'center', letterSpacing: '.5rem' }
  });
  body.appendChild(h('div', { class: 'f-row full' },
    h('label', {}, '6-digit PIN'),
    pinInput
  ));
  body.appendChild(h('div', { class: 'actions', style: { marginTop: '1rem' } },
    h('button', { class: 'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { class: 'btn primary', onclick: async () => {
      try {
        const pin = String(pinInput.value || '000000').replace(/\D/g, '').slice(0, 6) || '000000';
        await api('api_wb_register_phone', pin, phoneIdOverride || undefined);
        toast('✅ Phone registered with Cloud API. Try sending again.');
        m.remove();
      } catch (e) { toast(e.message, 'err'); }
    } }, 'Register')
  ));
  m.appendChild(body);
  document.body.appendChild(m);
}

/**
 * Embedded Signup launcher. Loads the Facebook JS SDK, calls FB.login with
 * the WhatsApp config_id and Embedded Signup `extras`, and listens for the
 * postMessage events that carry phone_number_id + waba_id while the user
 * goes through the dialog. When the user clicks Finish, we have all three:
 *   - the OAuth code (from FB.login callback)
 *   - phone_number_id + waba_id (from the postMessage WA_EMBEDDED_SIGNUP event)
 * → POST those to /api → server exchanges the code for an access token and
 * persists everything. Page reloads to show the connected state.
 */
function startEmbeddedSignup(appId, configId, opts) {
  if (!appId || !configId) { toast('App ID + Config ID required', 'err'); return; }
  // Hot path — SDK already preloaded by adminWhatsapp(). Calling FB.login
  // synchronously inside the click handler is critical or Chrome blocks
  // the popup as a "non-user-initiated" window.open. If SDK isn't ready
  // yet, kick off the load AND show a clear instruction. We can't auto-
  // open the dialog from a setTimeout because Chrome treats that as
  // non-user-initiated and blocks the popup.
  if (!(window.FB && typeof window.FB.login === 'function')) {
    toast('Loading Facebook SDK — click the button again in 2 seconds.', 'warn');
    ensureFbSdkLoaded(appId).then(() => {
      // Visual flash on the originating button so the user knows it's ready
      try {
        const btn = document.activeElement;
        if (btn && btn.tagName === 'BUTTON') {
          btn.style.boxShadow = '0 0 0 3px #10b981';
          setTimeout(() => { btn.style.boxShadow = ''; }, 1500);
        }
      } catch (_) {}
      toast('✅ Facebook SDK ready — click the button again to open the dialog.', 'ok');
    }).catch(e => toast('Facebook SDK load failed: ' + e.message, 'err'));
    return;
  }

  let phoneNumberId = '';
  let wabaId = '';
  // PostMessage listener — Meta sends phone_number_id + waba_id during the
  // dialog. Standard signup uses 'FINISH' event; Coexistence (v3) may use
  // FINISH_ONLY_WABA, FINISH_WITH_PHONE_NUMBER, etc. — we accept any event
  // that carries either id and capture the latest.
  const sessionInfoListener = (event) => {
    if (event.origin !== 'https://www.facebook.com') return;
    try {
      const data = (typeof event.data === 'string') ? JSON.parse(event.data) : event.data;
      // Verbose diagnostic — look in console for [emb-signup] entries to
      // see exactly what Meta sent. Critical when a Coexistence flow
      // doesn't auto-populate the wa_phones table.
      try { console.log('[emb-signup] Meta msg:', JSON.stringify(data)); } catch (_) {}
      if (data && data.type === 'WA_EMBEDDED_SIGNUP') {
        // Try all known shapes — Meta has shipped at least 3 variants over time.
        const inner = data.data || data.session_info || {};
        const pid = inner.phone_number_id || inner.phone_id || data.phone_number_id || '';
        const wid = inner.waba_id || inner.business_id || inner.business_account_id || data.waba_id || '';
        if (pid) phoneNumberId = String(pid);
        if (wid) wabaId       = String(wid);
      }
    } catch (_) { /* not JSON, ignore */ }
  };
  window.addEventListener('message', sessionInfoListener);

  toast('Opening Facebook…');
  // Track if we ever got a postMessage from facebook.com — if not after 12s,
  // the popup is likely being instantly closed by Facebook because the
  // redirect URI isn't whitelisted in the app's OAuth settings.
  let _gotMessage = false;
  const _origListener = sessionInfoListener;
  const wrapped = (event) => { if (event.origin === 'https://www.facebook.com') _gotMessage = true; _origListener(event); };
  window.removeEventListener('message', _origListener);
  window.addEventListener('message', wrapped);
  // The FB SDK rejects async functions as callbacks with the error
  // 'Expression is of type asyncfunction, not function'. Use a regular
  // function and wrap the body in an async IIFE so we can still await
  // the api() call inside.
  FB.login(function (response) {
    window.removeEventListener('message', wrapped);
    if (!response || !response.authResponse) {
      if (!_gotMessage) {
        toast('Facebook rejected the popup. Add "' + location.origin + '/" to Valid OAuth Redirect URIs in your Meta App → Facebook Login for Business → Settings, then save and try again.', 'err');
      } else {
        toast('Login cancelled by user.', 'warn');
      }
      return;
    }
    const code = response.authResponse.code;
    if (!code) {
      toast('No authorization code returned by Facebook.', 'err');
      return;
    }
    if (!phoneNumberId || !wabaId) {
      // Coexistence flows sometimes finish without sending the
      // phone_number_id postMessage (Meta is still provisioning). If we
      // have the OAuth code we can complete the WABA connection AND ask
      // the user to click 🔄 Sync from Meta in 1–2 min. Better than
      // silently dropping the connection.
      if (wabaId && !phoneNumberId) {
        toast('Connected to WABA — phone provisioning may take a few minutes. After it finishes, click 🔄 Sync from Meta.', 'warn');
      } else {
        toast('Did not receive WABA / phone number from the dialog. Check console for [emb-signup] log entries to see what Meta sent.', 'err');
        return;
      }
    }
    (async () => {
      try {
        toast('Exchanging credentials with Meta…');
        const r = await api('api_wb_emb_signin', code, phoneNumberId, wabaId, { addAnother: !!(opts && opts.addAnother), coexistence: !!(opts && opts.coexistence) });
        let msg = `✅ Connected (WABA ${r.waba_id}, Phone ${r.phone_number_id})`;
        if (r.templates_synced > 0) msg += ` · ${r.templates_synced} templates synced`;
        if (!r.subscribed && r.subscribe_error) msg += ` · ⚠ webhook subscribe failed: ${r.subscribe_error}`;
        toast(msg);
        // Hard reload so the post-connect cards (banner / webhook / phones)
        // render with a fully fresh fetch — a tab re-render alone has been
        // observed to occasionally miss the freshly-saved config rows.
        setTimeout(() => { location.hash = '#/whatsbot/connect'; location.reload(); }, 800);
      } catch (e) { toast(e.message, 'err'); }
    })();
  }, {
    config_id: configId,
    response_type: 'code',
    override_default_response_type: true,
    extras: {
      // When Coexistence is requested, Meta routes the dialog through the
      // 'whatsapp_business_app_onboarding' flow that lets the user keep the
      // same number on the WhatsApp Business mobile app while ALSO running
      // it on the Cloud API. Standard signup uses no featureType (default).
      setup: {},
      featureType: (opts && opts.coexistence) ? 'whatsapp_business_app_onboarding' : '',
      sessionInfoVersion: (opts && opts.coexistence) ? '3' : '2'
    }
  });
}

// ---------- Templates ----------
async function wbTemplates() {
  const wrap = h('div', {});
  const list = await api('api_wb_templates_list').catch(() => []);
  // Template creation/edit/submission lives on the Meta side — this CRM
  // can only consume APPROVED templates. We expose a one-click jump-off
  // to Meta's Template Manager so admins don't have to hunt for the URL.
  wrap.appendChild(h('div', { class: 'toolbar' },
    h('h3', { style: { margin: 0, flex: 1 } }, '\ud83d\udccb Templates (' + list.length + ')'),
    h('button', { class: 'btn primary', onclick: () => openCreateTemplateModal() }, '+ Create template'),
    h('a', {
      class: 'btn',
      href: 'https://business.facebook.com/wa/manage/message-templates/',
      target: '_blank', rel: 'noopener', style: { marginLeft: '.4rem' },
      title: 'Open Meta Business \u2014 manage templates directly in Meta'
    }, '\ud83d\udee0 Open Meta \u2197'),
    h('button', { class: 'btn ghost', style: { marginLeft: '.4rem' }, onclick: async () => {
      try { const r = await api('api_wb_templates_sync'); toast('Synced ' + r.count + ' templates'); showWbTab('templates'); }
      catch (e) { toast(e.message, 'err'); }
    } }, '\ud83d\udd04 Sync from Meta')
  ));
  wrap.appendChild(h('p', { class: 'muted', style: { fontSize: '.82rem', margin: '0 0 .75rem' } },
    'Click ',
    h('b', {}, '+ Create template'),
    ' to author a new template right here \u2014 we\'ll submit it to Meta for approval automatically. New templates land as ',
    h('b', {}, 'PENDING'),
    '; click ',
    h('b', {}, '\ud83d\udd04 Sync from Meta'),
    ' a few minutes later to pull the latest review status.'
  ));
  if (!list.length) {
    wrap.appendChild(h('p', { class: 'muted' }, 'No templates yet. Click "Sync from Meta" to pull your approved templates.'));
    return wrap;
  }
  wrap.appendChild(h('div', { class: 'table-wrap' }, h('table', { class: 'mini-table' },
    h('thead', {}, h('tr', {},
      h('th', {}, 'Name'), h('th', {}, 'Lang'), h('th', {}, 'Category'),
      h('th', {}, 'Status'), h('th', {}, 'Body params'), h('th', {}, 'Body preview'), h('th', {}, ''))),
    h('tbody', {}, ...list.map(t => h('tr', {},
      h('td', {}, h('code', {}, t.name)),
      h('td', {}, t.language),
      h('td', {}, t.category || '\u2014'),
      h('td', {},
        h('span', { class: t.status === 'APPROVED' ? 'tag' : 'tag err',
          style: t.status === 'APPROVED' ? { background: '#10b981', color: '#fff' } : (t.status === 'PENDING' ? { background: '#f59e0b', color: '#fff' } : null)
        }, t.status)
      ),
      h('td', {}, t.body_params),
      h('td', { style: { maxWidth: '420px' }, title: t.body_text || '' }, (t.body_text || '').slice(0, 100) + ((t.body_text || '').length > 100 ? '\u2026' : '')),
      h('td', {},
        h('button', { class: 'btn sm ghost danger', title: 'Delete from Meta + here', onclick: async () => {
          if (!await confirmDialog('Delete template "' + t.name + '"? It will be removed from Meta as well.')) return;
          try { await api('api_wb_templates_delete', { name: t.name, language: t.language }); toast('Deleted'); showWbTab('templates'); }
          catch (e) { toast(e.message, 'err'); }
        } }, '\ud83d\uddd1')
      )
    )))
  )));
  return wrap;
}

// ============================================================
// Create Template modal — author a template + submit to Meta
// ============================================================
function openCreateTemplateModal() {
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const card = h('div', { class: 'modal', style: { maxWidth: '720px' } });
  m.appendChild(card);

  card.appendChild(h('h3', { style: { marginTop: 0 } }, '\ud83d\udccb Create WhatsApp Template'));
  card.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem' } },
    'After submission, Meta typically reviews the template within a few minutes. Use ',
    h('code', {}, '{{1}}, {{2}}'),
    ' for placeholders in body / header / URL buttons \u2014 each placeholder needs a sample value below.'));

  // ---- Basics ----
  const nameInp = h('input', { type: 'text', placeholder: 'order_confirmation (lowercase, underscores only)', style: { width: '100%' } });
  const catSel = h('select', { style: { width: '100%' } },
    h('option', { value: 'UTILITY' }, 'UTILITY \u2014 transactional (order updates, OTPs that aren\'t auth)'),
    h('option', { value: 'MARKETING' }, 'MARKETING \u2014 promos, offers'),
    h('option', { value: 'AUTHENTICATION' }, 'AUTHENTICATION \u2014 OTP / verification codes'));
  const langSel = h('select', { style: { width: '100%' } },
    ...['en_US', 'en', 'en_GB', 'hi', 'mr', 'gu', 'ta', 'te', 'bn', 'pa', 'ml', 'kn']
      .map(l => h('option', { value: l, selected: l === 'en_US' ? 'selected' : null }, l)));
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Template name'), nameInp,
    h('div', { class: 'muted', style: { fontSize: '.78rem' } }, 'Lowercase + underscores only \u2014 e.g. order_confirmation, appointment_reminder.')));
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Category'), catSel));
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Language'), langSel));

  // ---- Header ----
  const hdrFmt = h('select', { style: { width: '100%' } },
    h('option', { value: 'NONE', selected: 'selected' }, 'No header'),
    h('option', { value: 'TEXT' }, 'Text header'),
    h('option', { value: 'IMAGE' }, 'Image header'),
    h('option', { value: 'VIDEO' }, 'Video header'),
    h('option', { value: 'DOCUMENT' }, 'Document header'));
  const hdrText = h('input', { type: 'text', placeholder: 'Header text \u2014 max 60 chars, can have one {{1}}', style: { width: '100%' }, hidden: 'hidden' });
  const hdrSample = h('input', { type: 'text', placeholder: 'Sample value for {{1}} (only if header has placeholder)', style: { width: '100%' }, hidden: 'hidden' });
  const hdrUrl = h('input', { type: 'url', placeholder: 'Public sample image/video/doc URL — or click Upload below', style: { width: '100%' }, hidden: 'hidden' });
  // WA_TPL_SAMPLE_UPLOAD_v1: file picker + helper so admins don\'t have to
  // host the sample themselves on S3/Drive. On pick we POST to
  // /api/wa-sample, receive a public URL, and auto-fill hdrUrl.
  const hdrFilePick = h('input', { type: 'file', accept: 'image/*,video/*,.pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx', style: { display: 'none' } });
  const hdrFileBtn = h('button', { type: 'button', class: 'btn ghost sm' }, '📎 Or upload a sample file…');
  const hdrFileNote = h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.25rem' } },
    'Meta needs a public URL Whatsapp can fetch for review. Pick a file and we\'ll host it for you.');
  const hdrFileRow = h('div', { style: { marginTop: '.4rem' }, hidden: 'hidden' }, hdrFileBtn, hdrFilePick, hdrFileNote);
  hdrFileBtn.onclick = () => hdrFilePick.click();
  hdrFilePick.onchange = async () => {
    const f = hdrFilePick.files && hdrFilePick.files[0];
    if (!f) return;
    if (f.size > 25 * 1024 * 1024) { toast('File too large (max 25 MB)', 'err'); return; }
    hdrFileBtn.disabled = true; hdrFileBtn.textContent = '⏳ Uploading ' + f.name + '…';
    try {
      const fd = new FormData(); fd.append('file', f);
      const r = await fetch('/api/wa-sample', {
        method: 'POST',
        headers: { 'x-auth-token': CRM.token },
        body: fd
      });
      if (!r.ok) { const j = await r.json().catch(() => ({})); throw new Error(j.error || 'Upload failed (HTTP ' + r.status + ')'); }
      const j = await r.json();
      hdrUrl.value = j.url || '';
      toast('✅ Sample hosted at ' + (j.url || ''), 'ok');
      hdrFileBtn.textContent = '📎 Replace file (' + f.name + ')';
    } catch (e) {
      toast('Upload failed: ' + e.message, 'err');
      hdrFileBtn.textContent = '📎 Or upload a sample file…';
    } finally { hdrFileBtn.disabled = false; }
  };
  function syncHeader() {
    hdrText.hidden = hdrFmt.value !== 'TEXT';
    hdrSample.hidden = hdrFmt.value !== 'TEXT';
    const isMedia = ['IMAGE', 'VIDEO', 'DOCUMENT'].includes(hdrFmt.value);
    hdrUrl.hidden = !isMedia;
    hdrFileRow.hidden = !isMedia;
  }
  hdrFmt.addEventListener('change', syncHeader);
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Header'), hdrFmt, hdrText, hdrSample, hdrUrl, hdrFileRow));

  // ---- Body ----
  const bodyArea = h('textarea', { rows: 4, placeholder: 'Hi {{1}}, your order #{{2}} is on the way!', style: { width: '100%' } });
  const bodySamples = h('input', { type: 'text', placeholder: 'Sample values, comma-separated. e.g. John, 12345', style: { width: '100%' } });
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Body (required)'), bodyArea, bodySamples,
    h('div', { class: 'muted', style: { fontSize: '.78rem' } }, 'Use {{1}}, {{2}} for variables. Sample values must match the count of placeholders.')));

  // ---- Footer ----
  const footerInp = h('input', { type: 'text', placeholder: 'Optional footer (max 60 chars). e.g. Reply STOP to opt out.', style: { width: '100%' }, maxlength: 60 });
  card.appendChild(h('div', { class: 'field' }, h('label', {}, 'Footer (optional)'), footerInp));

  // ---- Buttons ----
  const buttonsWrap = h('div', { class: 'field' });
  buttonsWrap.appendChild(h('label', {}, 'Buttons (optional, max 10)'));
  const btnRows = h('div', {});
  buttonsWrap.appendChild(btnRows);
  function addButtonRow(seed) {
    const seedB = seed || { type: 'QUICK_REPLY', text: '' };
    const row = h('div', { style: { display: 'flex', gap: '.4rem', alignItems: 'center', marginTop: '.3rem', flexWrap: 'wrap' } });
    const typeSel = h('select', {},
      h('option', { value: 'QUICK_REPLY', selected: seedB.type === 'QUICK_REPLY' ? 'selected' : null }, 'Quick reply'),
      h('option', { value: 'URL', selected: seedB.type === 'URL' ? 'selected' : null }, 'URL'),
      h('option', { value: 'PHONE_NUMBER', selected: seedB.type === 'PHONE_NUMBER' ? 'selected' : null }, 'Phone'));
    const textInp = h('input', { type: 'text', placeholder: 'Button text', value: seedB.text || '', style: { flex: '1', minWidth: '8rem' } });
    const urlInp = h('input', { type: 'url', placeholder: 'https://example.com/{{1}}', value: seedB.url || '', style: { flex: '1.5', minWidth: '12rem' } });
    const phoneInp = h('input', { type: 'tel', placeholder: '+919876543210', value: seedB.phone_number || '', style: { flex: '1', minWidth: '8rem' } });
    const sampleInp = h('input', { type: 'text', placeholder: 'Sample value (if URL has placeholder)', value: '', style: { flex: '1', minWidth: '8rem' } });
    const rmBtn = h('button', { class: 'btn sm ghost danger', type: 'button', onclick: () => row.remove() }, '\u2715');
    function syncBtnRow() {
      urlInp.hidden = typeSel.value !== 'URL';
      phoneInp.hidden = typeSel.value !== 'PHONE_NUMBER';
      sampleInp.hidden = typeSel.value !== 'URL';
    }
    typeSel.addEventListener('change', syncBtnRow);
    syncBtnRow();
    row.appendChild(typeSel); row.appendChild(textInp);
    row.appendChild(urlInp); row.appendChild(phoneInp); row.appendChild(sampleInp);
    row.appendChild(rmBtn);
    btnRows.appendChild(row);
    return { row, typeSel, textInp, urlInp, phoneInp, sampleInp };
  }
  const addBtn = h('button', { class: 'btn sm ghost', type: 'button', onclick: () => addButtonRow(), style: { marginTop: '.4rem' } }, '+ Add button');
  buttonsWrap.appendChild(addBtn);
  card.appendChild(buttonsWrap);

  // ---- Actions ----
  const submitBtn = h('button', { class: 'btn primary' }, 'Submit to Meta');
  submitBtn.onclick = async () => {
    submitBtn.disabled = true; submitBtn.textContent = 'Submitting\u2026';
    const buttons = [...btnRows.children].map(row => {
      const inputs = row.querySelectorAll('select, input');
      const type = inputs[0].value;
      const text = inputs[1].value;
      if (type === 'QUICK_REPLY') return { type, text };
      if (type === 'URL') {
        const url = inputs[2].value;
        const sampleStr = inputs[4].value.trim();
        const sample = sampleStr ? sampleStr.split(',').map(s => s.trim()) : [];
        return sample.length ? { type, text, url, sample } : { type, text, url };
      }
      if (type === 'PHONE_NUMBER') return { type, text, phone_number: inputs[3].value };
      return null;
    }).filter(Boolean);
    const headerSample = hdrSample.value.trim();
    const header = (hdrFmt.value === 'NONE') ? null
      : (hdrFmt.value === 'TEXT')
        ? { format: 'TEXT', text: hdrText.value, sample: headerSample ? [headerSample] : [] }
        : { format: hdrFmt.value, sample_url: hdrUrl.value };
    const bodySampleStr = bodySamples.value.trim();
    const body = {
      text: bodyArea.value,
      sample: bodySampleStr ? bodySampleStr.split(',').map(s => s.trim()) : []
    };
    try {
      const r = await api('api_wb_templates_create', {
        name: nameInp.value, category: catSel.value, language: langSel.value,
        header, body, footer: { text: footerInp.value }, buttons
      });
      toast('Submitted to Meta \u2014 status: ' + (r.status || 'PENDING'), 'ok');
      m.remove();
      showWbTab('templates');
    } catch (e) {
      toast(e.message, 'err');
      submitBtn.disabled = false; submitBtn.textContent = 'Submit to Meta';
    }
  };

  card.appendChild(h('div', { style: { display: 'flex', gap: '.5rem', marginTop: '1rem', justifyContent: 'flex-end' } },
    h('button', { class: 'btn ghost', onclick: () => m.remove() }, 'Cancel'),
    submitBtn
  ));
  document.body.appendChild(m);
}

