/**
 * Initiate Chat — sends an approved template to a single lead via the
 * green WhatsApp icon in the leads list.
 *
 * Layout:
 *   - Top: Template picker dropdown (only APPROVED templates).
 *   - Left card: Variables — one input per body_param, with @{merge}
 *     hints. If the template has no variables, shows "no variables".
 *   - Right card: Live preview of the template body with {{N}} swapped
 *     for the user's input AS THEY TYPE.
 *   - Bottom: Cancel / Send.
 *
 * On send, calls api_wb_initiate_chat which renders @{name}, @{phone},
 * etc. against the lead row, persists the message, and surfaces any
 * Meta error in a toast. Status / read receipts arrive via webhook
 * and update the chat thread automatically.
 */
async function openInitiateChatModal(lead) {
  // Lazy-load the templates cache
  let templates = CRM.cache.waTemplates;
  if (!templates) {
    try { templates = await api('api_wb_templates_list'); CRM.cache.waTemplates = templates; }
    catch (e) { toast('Could not load templates: ' + e.message, 'err'); return; }
  }
  const approved = (templates || []).filter(t => t.status === 'APPROVED');
  if (!approved.length) {
    toast('No approved templates yet. Settings → WhatsBot → Templates → Sync from Meta.', 'warn');
    return;
  }
  const phone = String(lead?.phone || lead?.whatsapp || '').replace(/\D/g, '');
  if (!phone) { toast('Lead has no phone number', 'err'); return; }

  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, 'Initiate Chat'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));
  // Show the actual phone number we'll send to (E.164) and any
  // normalisation warning. Catches the most common "single tick but
  // never delivered" case where the lead's stored phone is just
  // 10 digits without a country code.
  const phoneInfoBox = h('div', { class: 'muted', style: { padding: '.35rem .65rem', background: '#fef3c7', border: '1px solid #fbbf24', borderRadius: '6px', marginBottom: '.75rem', fontSize: '.82rem' } }, 'Resolving phone…');
  body.appendChild(phoneInfoBox);
  api('api_wb_phone_check', phone).then(r => {
    phoneInfoBox.style.background = r.looks_ok ? '#dcfce7' : '#fef2f2';
    phoneInfoBox.style.borderColor = r.looks_ok ? '#22c55e' : '#ef4444';
    phoneInfoBox.innerHTML = '';
    phoneInfoBox.appendChild(h('span', {}, '📞 Will send to: ',
      h('b', { style: { fontFamily: 'monospace' } }, '+' + r.normalised),
      r.original && r.original.replace(/\D/g, '') !== r.normalised
        ? h('span', { class: 'muted', style: { marginLeft: '.5rem', fontSize: '.78rem' } }, '(was: ' + r.original + ')')
        : null
    ));
    if (r.issues && r.issues.length) {
      r.issues.forEach(i => {
        phoneInfoBox.appendChild(h('div', { style: { fontSize: '.78rem', marginTop: '.2rem' } }, '• ' + i));
      });
    }
  }).catch(() => { phoneInfoBox.style.display = 'none'; });

  // Template picker
  const tplSel = h('select', {},
    h('option', { value: '' }, '— pick a template —'),
    ...approved.map(t => h('option', { value: t.name + '||' + t.language }, t.name + ' (' + t.language + ')'))
  );
  const tplRow = h('div', { class: 'f-row full' },
    h('label', {}, 'Template'),
    tplSel
  );
  body.appendChild(h('form', { class: 'form-grid' }, tplRow));

  // Two-column body: variables (left) + preview (right)
  const cols = h('div', { class: 'init-chat-grid' });
  const varsCol = h('div', { class: 'card' });
  varsCol.appendChild(h('div', { class: 'init-chat-col-head' }, 'Variables ',
    h('span', { class: 'muted', style: { fontWeight: 'normal', fontSize: '.78rem' } }, "Use '@' Sign for add merge fields.")));
  const varsBody = h('div', { class: 'init-chat-vars' });
  varsCol.appendChild(varsBody);

  const previewCol = h('div', { class: 'card' });
  previewCol.appendChild(h('div', { class: 'init-chat-col-head' }, 'Preview'));
  const previewBox = h('div', { class: 'init-chat-preview' }, h('div', { class: 'muted', style: { textAlign: 'center', padding: '2rem' } }, 'Pick a template above…'));
  previewCol.appendChild(previewBox);

  cols.appendChild(varsCol);
  cols.appendChild(previewCol);
  body.appendChild(cols);

  // Footer — Phase 2 multi-WhatsApp: 'Send from' picker.
  const _initPhones = await _loadWaPhones();
  const initPicker = _phonePickerSelect({ phones: _initPhones });
  const sendBtn = h('button', { class: 'btn primary', disabled: 'disabled' }, 'Send');
  body.appendChild(h('div', { class: 'actions' },
    h('button', { class: 'btn', onclick: () => m.remove() }, 'Close'),
    h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'From:'),
    initPicker,
    sendBtn
  ));
  m.appendChild(body);
  document.body.appendChild(m);

  let currentTpl = null;
  function refreshPreview() {
    if (!currentTpl) {
      previewBox.innerHTML = '';
      previewBox.appendChild(h('div', { class: 'muted', style: { textAlign: 'center', padding: '2rem' } }, 'Pick a template above…'));
      return;
    }
    let bodyText = currentTpl.body_text || '';
    const inputs = [...varsBody.querySelectorAll('input.var-input')];
    inputs.forEach((inp, idx) => {
      const placeholder = '{{' + (idx + 1) + '}}';
      const val = String(inp.value || '').trim() || placeholder;
      // Render @{merge} fields against the lead so the preview reflects what
      // the recipient will actually receive (e.g. @{name} → "Imran Khan")
      const merged = renderMergeClient(val, lead);
      bodyText = bodyText.split(placeholder).join(merged);
    });
    // Use existing template's full body — also render header/footer
    const components = currentTpl.components || [];
    const header = components.find(c => c.type === 'HEADER');
    const footer = components.find(c => c.type === 'FOOTER');
    const buttons = components.find(c => c.type === 'BUTTONS');
    previewBox.innerHTML = '';
    const card = h('div', { class: 'init-chat-card' });
    if (header && header.format === 'TEXT' && header.text) {
      card.appendChild(h('div', { class: 'tpl-header' }, header.text));
    }
    if (header && header.format === 'IMAGE') {
      card.appendChild(h('div', { class: 'tpl-header-img muted' }, '🖼 [Image header]'));
    }
    card.appendChild(h('div', { class: 'tpl-body' }, bodyText));
    if (footer && footer.text) {
      card.appendChild(h('div', { class: 'tpl-footer muted' }, footer.text));
    }
    if (buttons && Array.isArray(buttons.buttons)) {
      buttons.buttons.forEach(b => {
        card.appendChild(h('div', { class: 'tpl-btn' }, b.text || b.url || ''));
      });
    }
    previewBox.appendChild(card);
  }

  /* WA_TPL_SEND_INITIATE_v1 (2026-06-09) — track the uploaded media URL
     for IMAGE/VIDEO/DOCUMENT-header templates so it can be passed as
     image_url in the send payload. Without this, image-header templates
     get sent with an empty header → Meta rejects them or sends broken. */
  let currentMediaUrl = '';
  function setTemplate(combo) {
    const [name, lang] = String(combo || '').split('||');
    const t = approved.find(x => x.name === name && x.language === lang);
    currentTpl = t || null;
    currentMediaUrl = '';
    varsBody.innerHTML = '';
    if (!t) {
      sendBtn.disabled = 'disabled';
      refreshPreview();
      return;
    }
    /* WA_TPL_SEND_INITIATE_v1 — if header is IMAGE / VIDEO / DOCUMENT, show
       a file picker + URL input. Use header_type from the row (set by sync)
       and fall back to inspecting components_json shape. */
    const _components = t.components || [];
    const _hdrComp = Array.isArray(_components) ? _components.find(c => (c && (c.type || '').toUpperCase()) === 'HEADER') : null;
    const _hdrFmt = String(_hdrComp?.format || t.header_type || '').toUpperCase();
    const _isMediaHdr = ['IMAGE', 'VIDEO', 'DOCUMENT'].includes(_hdrFmt);
    if (_isMediaHdr) {
      const acceptMap = { IMAGE: 'image/*', VIDEO: 'video/*', DOCUMENT: '.pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx' };
      const hdrLabelMap = { IMAGE: '🖼️ Image header', VIDEO: '🎥 Video header', DOCUMENT: '📄 Document header' };
      const mediaWrap = h('div', { style: { padding: '.5rem', background: '#fffbeb', border: '1px solid #fde68a', borderRadius: '6px', marginBottom: '.6rem' } });
      mediaWrap.appendChild(h('div', { style: { fontWeight: 600, marginBottom: '.3rem' } }, hdrLabelMap[_hdrFmt] + ' — required'));
      const filePick = h('input', { type: 'file', accept: acceptMap[_hdrFmt] || '*/*', style: { width: '100%', marginBottom: '.3rem' } });
      const urlInp = h('input', { type: 'url', class: 'tpl-media-url', placeholder: 'Or paste a public URL…', style: { width: '100%', padding: '.3rem', border: '1px solid #cbd5e1', borderRadius: '4px', fontSize: '.78rem' } });
      const uploadNote = h('div', { class: 'muted', style: { fontSize: '.7rem', marginTop: '.25rem' } }, 'Pick a file (we host it for you) OR paste a public URL Meta can fetch.');
      filePick.onchange = async () => {
        const f = filePick.files && filePick.files[0];
        if (!f) return;
        if (f.size > 25 * 1024 * 1024) { toast('File too large (max 25 MB)', 'err'); return; }
        uploadNote.textContent = '⏳ Uploading ' + f.name + '…';
        try {
          const fd = new FormData(); fd.append('file', f);
          const r = await fetch('/api/wa-sample', { method: 'POST', headers: { 'x-auth-token': CRM.token }, body: fd });
          if (!r.ok) { const j = await r.json().catch(() => ({})); throw new Error(j.error || 'Upload failed (HTTP ' + r.status + ')'); }
          const j = await r.json();
          urlInp.value = j.url || '';
          currentMediaUrl = j.url || '';
          uploadNote.innerHTML = '✓ Hosted: <code style="font-size:.68rem">' + (j.url || '') + '</code>';
          refreshPreview();
        } catch (e) {
          toast('Upload failed: ' + e.message, 'err');
          uploadNote.textContent = 'Pick a file (we host it for you) OR paste a public URL Meta can fetch.';
        }
      };
      urlInp.addEventListener('input', () => { currentMediaUrl = urlInp.value || ''; refreshPreview(); });
      mediaWrap.appendChild(filePick);
      mediaWrap.appendChild(urlInp);
      mediaWrap.appendChild(uploadNote);
      varsBody.appendChild(mediaWrap);
    }
    if (!t.body_params) {
      if (!_isMediaHdr) {
        varsBody.appendChild(h('div', { class: 'muted', style: { padding: '.75rem' } },
          'Currently, the variable is not available for this template.'));
      }
    } else {
      for (let i = 0; i < t.body_params; i++) {
        varsBody.appendChild(h('div', { style: { marginBottom: '.5rem' } },
          h('label', { class: 'muted', style: { fontSize: '.8rem' } }, 'Variable ' + (i + 1)),
          h('input', { class: 'var-input', placeholder: '@{name}, @{firstname}, @{phone}, …', oninput: refreshPreview })
        ));
      }
    }
    sendBtn.disabled = null;
    refreshPreview();
  }
  tplSel.addEventListener('change', () => setTemplate(tplSel.value));

  sendBtn.addEventListener('click', async () => {
    if (!currentTpl) return;
    /* WA_TPL_SEND_INITIATE_v1 — block send if this is a media-header template
       but no URL was supplied (otherwise Meta will reject the message). */
    const _comps = currentTpl.components || [];
    const _hdrComp = Array.isArray(_comps) ? _comps.find(c => (c && (c.type || '').toUpperCase()) === 'HEADER') : null;
    const _hdrFmt = String(_hdrComp?.format || currentTpl.header_type || '').toUpperCase();
    if (['IMAGE','VIDEO','DOCUMENT'].includes(_hdrFmt) && !currentMediaUrl) {
      toast('Please upload an image/file or paste a URL for the header', 'err');
      return;
    }
    const variables = [...varsBody.querySelectorAll('input.var-input')].map(i => i.value);
    sendBtn.disabled = 'disabled';
    sendBtn.textContent = 'Sending…';
    try {
      const _payload = {
        lead_id: lead?.id,
        phone,
        template_name: currentTpl.name,
        template_language: currentTpl.language,
        variables,
        from_phone_number_id: initPicker.value || undefined
      };
      if (currentMediaUrl) _payload.image_url = currentMediaUrl;
      await api('api_wb_initiate_chat', _payload);
      toast('Sent — view delivery status in WhatsBot → Chat');
      m.remove();
    } catch (e) {
      toast(e.message, 'err');
      sendBtn.disabled = null;
      sendBtn.textContent = 'Send';
    }
  });
}

/** Replace @{merge_field} with values from the lead row — same syntax as
 *  the campaign worker server-side, just for the live preview here. */
function renderMergeClient(template, lead) {
  if (!template) return '';
  const ctx = lead || {};
  return String(template).replace(/@\{(\w+)\}/g, (_, key) => {
    const k = key.toLowerCase();
    if (k === 'firstname' || k === 'first_name') return String(ctx.name || '').split(' ')[0] || '';
    if (k === 'lastname' || k === 'last_name')   return String(ctx.name || '').split(' ').slice(1).join(' ') || '';
    if (k === 'name')   return String(ctx.name || '');
    if (k === 'phone')  return String(ctx.phone || '');
    if (k === 'email')  return String(ctx.email || '');
    if (k === 'source') return String(ctx.source || '');
    if (ctx[k] !== undefined) return String(ctx[k]);
    return '@{' + key + '}';
  });
}

function openCampaignModal(templates) {
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, '📣 Send new campaign'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));
  const approved = (templates || []).filter(t => t.status === 'APPROVED');
  const statuses = CRM.cache.statuses || [];
  const sources = CRM.cache.sources || [];
  const users = CRM.cache.users || [];
  const tplOpts = approved.map(t => ({ value: t.name + '||' + t.language, label: t.name + ' (' + t.language + ')' }));
  const form = h('form', { class: 'form-grid' });
  form.appendChild(field('name', 'Campaign name *', '', { required: true }));
  form.appendChild(selectField('template_combo', 'Template *', '',
    [{ value: '', label: '— pick a template —' }, ...tplOpts]));
  // Filter pickers
  form.appendChild(selectField('status_id', 'Filter — status', '',
    [{ value: '', label: 'Any status' }, ...statuses.map(s => ({ value: s.id, label: s.name }))]));
  form.appendChild(selectField('source', 'Filter — source', '',
    [{ value: '', label: 'Any source' }, ...sources.map(s => ({ value: s.name, label: s.name }))]));
  form.appendChild(selectField('assigned_to', 'Filter — assignee', '',
    [{ value: '', label: 'Any' }, ...users.map(u => ({ value: u.id, label: u.name }))]));
  form.appendChild(field('tag', 'Filter — tag', ''));

  // WA_CAMPAIGN_EXCEL_v1 — Direct number upload
  let _campExcelRows = null;
  const excelInfo = h('div', { class: 'muted', style: { fontSize: '.82rem' } }, 'No Excel uploaded. Optional — campaign will use the filter above if Excel is empty.');
  const excelBox = h('div', { class: 'f-row full', style: { background: '#f8fafc', border: '1px dashed #cbd5e1', borderRadius: '8px', padding: '.6rem', margin: '.4rem 0' } },
    h('label', { style: { fontWeight: 600, marginBottom: '.3rem', display: 'block' } }, '📊 Or upload Excel of recipients'),
    h('div', { style: { display: 'flex', gap: '.4rem', alignItems: 'center', flexWrap: 'wrap' } },
      h('input', { type: 'file', accept: '.xlsx,.xls,.csv', id: 'cm-excel', style: { flex: '1', minWidth: '200px' },
        onchange: async (ev) => {
          const f = ev.target.files[0]; if (!f) return;
          try {
            await ensureXLSX();
            const buf = await f.arrayBuffer();
            const wb = window.XLSX.read(buf, { type: 'array' });
            const sheet = wb.Sheets[wb.SheetNames[0]];
            const rows = window.XLSX.utils.sheet_to_json(sheet, { defval: '' });
            const mapped = rows.map(r => {
              const get = (k) => { for (const kk of Object.keys(r)) { if (String(kk).toLowerCase().trim() === k) return r[kk]; } return ''; };
              return { phone: String(get('phone') || get('mobile') || ''), name: String(get('name') || ''), var1: String(get('var1') || ''), var2: String(get('var2') || ''), var3: String(get('var3') || '') };
            }).filter(r => r.phone);
            _campExcelRows = mapped;
            excelInfo.textContent = '✓ ' + mapped.length + ' recipients ready. Filter above will be ignored.';
            excelInfo.style.color = '#16a34a';
          } catch (e) { toast('Excel parse failed: ' + e.message, 'err'); }
        } }),
      h('button', { type: 'button', class: 'btn ghost', onclick: () => {
        // Sample template download — uses SheetJS
        ensureXLSX().then(() => {
          const ws = window.XLSX.utils.json_to_sheet([
            { phone: '919876543210', name: 'Sample Name', var1: 'Variable 1 value', var2: 'Variable 2 value', var3: 'Variable 3 value' }
          ]);
          const wb = window.XLSX.utils.book_new();
          window.XLSX.utils.book_append_sheet(wb, ws, 'Recipients');
          window.XLSX.writeFile(wb, 'wa-campaign-template.xlsx');
        });
      } }, '⬇️ Download template')),
    excelInfo,
    h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.3rem' } },
      'Columns: phone (required), name, var1, var2, var3. Variables map to template {{1}} {{2}} {{3}}. Phones not in your Leads table are auto-added with source "WA Campaign Upload".')
  );
  form.appendChild(excelBox);
  form._getExcelRows = () => _campExcelRows;

  // Variables block
  const varsBox = h('div', { class: 'f-row full', id: 'cm-vars' });
  form.appendChild(varsBox);
  function renderVars(combo) {
    const [name, lang] = String(combo || '').split('||');
    const t = approved.find(x => x.name === name && x.language === lang);
    varsBox.innerHTML = '';
    if (!t) return;
    varsBox.appendChild(h('label', {}, 'Variables — use @{name}, @{firstname}, @{phone}, @{email}, @{source} for merge fields'));
    for (let i = 0; i < t.body_params; i++) {
      varsBox.appendChild(h('input', { name: 'cv_' + i, placeholder: 'Variable ' + (i + 1) }));
    }
  }
  form.querySelector('[name="template_combo"]')?.addEventListener('change', ev => renderVars(ev.target.value));
  // Schedule
  form.appendChild(field('scheduled_at', 'Scheduled send time (optional)', '', { type: 'datetime-local' }));
  form.appendChild(h('div', { class: 'f-row' },
    h('label', {}, 'Send now'),
    h('label', { class: 'qual-toggle' },
      h('input', { type: 'checkbox', name: 'send_now', checked: 'checked' }),
      ' Ignore schedule and send right away')
  ));
  body.appendChild(form);
  body.appendChild(h('div', { class: 'actions' },
    h('button', { class: 'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { class: 'btn primary', onclick: async () => {
      const combo = form.querySelector('[name="template_combo"]').value;
      const [name, lang] = combo.split('||');
      if (!name) { toast('Pick a template', 'err'); return; }
      const variables = [];
      [...form.querySelectorAll('input[name^="cv_"]')].forEach((i, idx) => variables.push({ name: 'V' + (idx + 1), value: i.value }));
      const filter = {
        status_id: form.status_id.value || undefined,
        source: form.source.value || undefined,
        assigned_to: form.assigned_to.value || undefined,
        tag: form.tag.value || undefined
      };
      const uploaded_rows = (typeof form._getExcelRows === 'function') ? form._getExcelRows() : null;
      try {
        const r = await api('api_wb_campaigns_create', {
          name: form.name.value,
          template_name: name, template_language: lang || 'en_US',
          variables, filter,
          uploaded_rows: uploaded_rows && uploaded_rows.length ? uploaded_rows : undefined,
          scheduled_at: form.scheduled_at.value ? new Date(form.scheduled_at.value).toISOString() : null,
          send_now: form.send_now.checked ? 1 : 0
        });
        toast(`Campaign created — ${r.recipients} recipients`);
        m.remove();
        showWbTab('campaigns');
      } catch (e) { toast(e.message, 'err'); }
    } }, 'Create campaign')
  ));
  m.appendChild(body);
  document.body.appendChild(m);
}

// ---------- Chat ----------
//
// The Chat tab auto-polls so inbound messages from the WhatsApp webhook show
// up live, without the user reloading. Two independent loops:
//
//   - Thread list: every 8s. Cheap query (last 1000 messages aggregated).
//   - Active thread: every 4s while a thread is open. Re-renders the message
//     log only if the message count or the last status field changed, so an
//     in-progress textarea is never disturbed.
//
// Polling is parked on `window._wbChatTimers` so showWbTab() can clear them
// when the user navigates to a different WhatsBot subtab.
/**
 * Translate a Meta API error string into a short, user-friendly hint.
 * The full original error stays in the bubble's `title` (hover tooltip)
 * so admins can still copy the raw text for support.
 */
function waFriendlyError(err) {
  const e = String(err || '').toLowerCase();
  if (!e) return '⚠ Send failed — no reason returned. Try again.';
  if (e.includes('131047') || e.includes('re-engagement') || e.includes('24 hours') || e.includes('outside the allowed window')) {
    return '⚠ 24-hour window expired — the customer hasn\'t messaged in 24h. Send a Template message instead (Templates tab).';
  }
  if (e.includes('131026') || e.includes('not a whatsapp user') || e.includes('recipient cannot be sent')) {
    return '⚠ Number is not on WhatsApp.';
  }
  if (e.includes('131051') || e.includes('unsupported')) {
    return '⚠ Message type not supported by WhatsApp.';
  }
  if (e.includes('131052') || e.includes('media download')) {
    return '⚠ Media download error — check the file URL.';
  }
  if (e.includes('rate limit') || e.includes('throttle')) {
    return '⚠ Rate limit hit — try again in a minute.';
  }
  if (e.includes('access token') || e.includes('expired') || e.includes('oauth')) {
    return '⚠ WhatsApp access token expired. Settings → WhatsBot → Connect Account.';
  }
  // Fall back to the raw message but trimmed
  return '⚠ ' + String(err).slice(0, 200);
}

/**
 * Render the inline media preview (image / document / video / audio) that
 * sits at the top of a WhatsApp message bubble. Returns null for plain
 * text messages so the caller can skip the slot.
 */
function renderWaMessageMedia(msg) {
  const t = String(msg.message_type || '').toLowerCase();
  if (!t || t === 'text') return null;
  // Inbound messages have a Meta media_id but no media_url. Build a
  // proxy URL the SPA fetch shim can route to /t/<slug>/api/wa/media/<id>
  // — that endpoint resolves the media_id to fresh Meta bytes per request.
  // Token is appended as a query param so <img src> can authenticate
  // without needing a header.
  let url = msg.media_url || '';
  if (!url && msg.media_id && msg.id && CRM.token) {
    url = _waMediaUrl(msg.id, CRM.token);
  }
  if (t === 'image') {
    if (!url) return h('div', { class: 'wb-msg-media muted' }, '🖼 [image]');
    return h('a', { href: url, target: '_blank', rel: 'noopener', class: 'wb-msg-image' },
      h('img', { src: url, alt: 'image', loading: 'lazy' })
    );
  }
  if (t === 'video') {
    if (!url) return h('div', { class: 'wb-msg-media muted' }, '🎬 [video]');
    return h('video', { class: 'wb-msg-video', controls: true, preload: 'none', src: url });
  }
  if (t === 'audio') {
    if (!url) return h('div', { class: 'wb-msg-media muted' }, '🎤 [audio]');
    return h('audio', { class: 'wb-msg-audio', controls: true, preload: 'none', src: url });
  }
  if (t === 'document') {
    return h('a', { href: url || '#', target: '_blank', rel: 'noopener',
      download: (msg.body && msg.body.length < 80) ? msg.body : 'document',
      class: 'wb-msg-doc' },
      h('span', { class: 'wb-msg-doc-icon' }, '📄'),
      h('span', { class: 'wb-msg-doc-name' }, msg.body || 'Document'),
      h('span', { class: 'wb-msg-doc-dl' }, ' ⬇')
    );
  }
  return h('div', { class: 'wb-msg-media muted' }, '[' + t + ']');
}

/**
 * Agent assignment picker for the chat header. Admins / managers / TLs
 * can pick any agent; reps get a "Claim chat" button that assigns the
 * chat to themselves. Fires api_wb_chat_assign and refreshes the list.
 */
function buildAgentPicker(phone, threadMeta) {
  const role = CRM.user.role;
  const isPriv = (role === 'admin' || role === 'manager' || role === 'team_leader');
  const wrap = h('div', { class: 'wb-agent-pick' });
  const labelText = threadMeta.assigned_name
    ? '👤 ' + threadMeta.assigned_name + (threadMeta.assignment_explicit ? '' : ' · auto')
    : '👤 Unassigned';
  const labelEl = h('span', { class: 'wb-agent-pick-label' }, labelText);
  wrap.appendChild(labelEl);

  if (!isPriv) {
    if (Number(threadMeta.assigned_to) !== Number(CRM.user.id)) {
      const claim = h('button', { class: 'btn xs primary', title: 'Claim this chat for me' }, 'Claim');
      claim.onclick = async () => {
        try {
          await api('api_wb_chat_assign', { phone, user_id: CRM.user.id });
          toast('✓ Chat assigned to you');
          if (window._wbChatTimers) window._wbChatTimers.threadList && window._wbChatTimers.threadList; // poll picks up
        } catch (e) { toast(e.message, 'err'); }
      };
      wrap.appendChild(claim);
    }
    return wrap;
  }

  // Privileged: dropdown of all users
  const sel = h('select', { class: 'wb-agent-pick-select' }, h('option', { value: '' }, '— Unassigned —'));
  // Lazily fetch users
  api('api_users_list').then(users => {
    sel.innerHTML = '';
    sel.appendChild(h('option', { value: '' }, '— Unassigned —'));
    users.forEach(u => {
      const opt = h('option', { value: String(u.id) }, u.name);
      if (Number(u.id) === Number(threadMeta.assigned_to)) opt.selected = true;
      sel.appendChild(opt);
    });
  }).catch(() => {});
  sel.onchange = async () => {
    try {
      await api('api_wb_chat_assign', { phone, user_id: sel.value || null });
      toast('✓ Assignment updated');
      // Update the label inline without a full re-render
      const opt = sel.options[sel.selectedIndex];
      labelEl.textContent = '👤 ' + (opt && opt.value ? opt.text : 'Unassigned');
    } catch (e) { toast(e.message, 'err'); }
  };
  wrap.appendChild(sel);
  return wrap;
}

/**
 * Compose bar for a single chat thread — textarea + 📎 attach + send.
 * Calls onSent after every successful send so the parent can redraw.
 */
function buildWaCompose(phone, onSent, opts) {
  opts = opts || {};
  const wrap = h('div', { class: 'wb-chat-compose' });
  let pending = null; // { id, wa_media_id, mime_type, filename, url }

  const previewSlot = h('div', { class: 'wb-compose-preview', hidden: 'hidden' });
  // WA_REPLY_v1: reply preview slot rendered above input when user clicks
  // ↩ Reply on a message.
  const replyPreviewSlot = h('div', { class: 'wb-compose-reply-preview', style: { display: 'none', padding: '.4rem .55rem', background: 'linear-gradient(90deg, #eef2ff, #ffffff)', borderLeft: '3px solid #6366f1', borderRadius: '6px', margin: '0 0 .35rem', fontSize: '.78rem', display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: '.4rem' } });
  window._renderWaReplyPreview = () => {
    const t = window._waReplyTarget;
    if (!t) { replyPreviewSlot.style.display = 'none'; replyPreviewSlot.innerHTML = ''; return; }
    replyPreviewSlot.style.display = 'flex';
    replyPreviewSlot.innerHTML = '';
    replyPreviewSlot.appendChild(h('div', { style: { flex: 1, minWidth: 0 } },
      h('div', { style: { fontWeight: 700, fontSize: '.65rem', color: '#3730a3', opacity: .85 } }, '↩ Replying to ' + (t.direction === 'out' ? 'yourself' : 'them')),
      h('div', { style: { whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', color: '#1e1b4b' } }, String(t.body || '').slice(0, 120))
    ));
    replyPreviewSlot.appendChild(h('button', {
      class: 'btn xs ghost', type: 'button', title: 'Cancel reply',
      onclick: () => { window._waReplyTarget = null; window._renderWaReplyPreview(); }
    }, '✕'));
  };

  const input = h('textarea', { rows: 2, placeholder: 'Type a message — Enter to send, Shift+Enter for newline' });
  // Phase 2 multi-WhatsApp: per-message 'Send from' picker on the
  // chat composer. Reads from CRM.cache.waPhones (pre-warmed by the
  // chat tab when it loads); the picker is inline above the textarea.
  // Phase 3: default the picker to opts.defaultPhoneId — i.e. the phone
  // the customer last messaged on this thread — so replies auto-route
  // back to the same number.
  const composerPicker = _phonePickerSelect({
    phones: (CRM.cache && CRM.cache.waPhones) || [],
    style: { fontSize: '.78rem', marginRight: '.4rem' }
  });
  if (opts.defaultPhoneId) {
    // Set after construction — a matching <option> has already been
    // appended by _phonePickerSelect. If no option matches (e.g. the
    // phone has been deleted) the value silently stays at '' = default.
    try { composerPicker.value = String(opts.defaultPhoneId); } catch (_) {}
  }
  const fileInput = h('input', { type: 'file', style: { display: 'none' }, accept: 'image/*,application/pdf,video/mp4,video/3gp,audio/aac,audio/mp4,audio/mpeg,audio/amr,audio/ogg,.pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.txt,.csv' });

  const renderPreview = () => {
    previewSlot.innerHTML = '';
    if (!pending) { previewSlot.hidden = true; return; }
    previewSlot.hidden = false;
    const isImg = String(pending.mime_type || '').startsWith('image/');
    previewSlot.appendChild(isImg
      ? h('img', { src: pending.url, alt: pending.filename, class: 'wb-compose-thumb' })
      : h('span', { class: 'wb-compose-doc' }, '📄 ', pending.filename || 'Document')
    );
    previewSlot.appendChild(h('button', {
      class: 'btn xs ghost', title: 'Remove attachment',
      onclick: () => { pending = null; fileInput.value = ''; renderPreview(); }
    }, '✕'));
  };

  const send = async () => {
    const text = input.value.trim();
    if (!text && !pending) return;
    input.disabled = true;
    try {
      const payload = { phone, text };
      if (composerPicker.value) payload.from_phone_number_id = composerPicker.value;
      // WA_REPLY_v1: include the reply_to wa_message_id if user is replying
      if (window._waReplyTarget && window._waReplyTarget.wa_message_id) {
        payload.reply_to = window._waReplyTarget.wa_message_id;
      }
      if (pending) {
        payload.media_id = pending.wa_media_id;
        payload.media_type = waMediaTypeFor(pending.mime_type);
        payload.media_url = pending.url; // for local rendering
        payload.filename = pending.filename || undefined;
      }
      await api('api_wb_chat_send', payload);
      input.value = '';
      pending = null; fileInput.value = ''; renderPreview();
      // WA_REPLY_v1: clear reply target after successful send
      window._waReplyTarget = null;
      if (typeof window._renderWaReplyPreview === 'function') window._renderWaReplyPreview();
      if (typeof onSent === 'function') onSent();
    } catch (e) { toast(e.message, 'err'); }
    finally { input.disabled = false; input.focus(); }
  };

  input.addEventListener('keydown', ev => {
    if (ev.key === 'Enter' && !ev.shiftKey) { ev.preventDefault(); send(); }
  });

  /* WA_PASTE_IMG_v1 — Ctrl/Cmd+V image from clipboard → attach as pending media */
  input.addEventListener('paste', async ev => {
    const items = (ev.clipboardData && ev.clipboardData.items) || [];
    let imgFile = null;
    for (const it of items) {
      if (it && it.kind === 'file' && /^image\//.test(it.type || '')) {
        const f = it.getAsFile();
        if (f) { imgFile = f; break; }
      }
    }
    if (!imgFile) return;            // not an image paste — let default handler run
    ev.preventDefault();
    if (imgFile.size > 25 * 1024 * 1024) {
      toast('Pasted image too large — WhatsApp images cap at 16 MB', 'err');
      return;
    }
    // Synth a friendly filename if the clipboard didn't give us one
    if (!imgFile.name || imgFile.name === 'image.png') {
      const ext = (imgFile.type || 'image/png').split('/')[1] || 'png';
      Object.defineProperty(imgFile, 'name', { value: 'pasted-' + Date.now() + '.' + ext, writable: false });
    }
    previewSlot.innerHTML = '';
    previewSlot.hidden = false;
    previewSlot.appendChild(h('span', { class: 'muted' }, 'Uploading pasted image…'));
    try {
      const fd = new FormData();
      fd.append('file', imgFile);
      const r = await fetch('/api/wa/upload', {
        method: 'POST',
        headers: { Authorization: 'Bearer ' + (CRM.token || '') },
        body: fd
      });
      const j = await r.json();
      if (!r.ok || j.error) throw new Error(j.error || ('upload failed (' + r.status + ')'));
      pending = j;
      renderPreview();
      input.focus();
    } catch (e) {
      pending = null;
      previewSlot.hidden = true;
      toast(e.message || 'Pasted image upload failed', 'err');
    }
  });

  fileInput.addEventListener('change', async () => {
    const f = fileInput.files && fileInput.files[0];
    if (!f) return;
    if (f.size > 25 * 1024 * 1024) {
      toast('File too large — WhatsApp allows up to 16 MB images and 100 MB docs, but our upload limit is 25 MB', 'err');
      fileInput.value = '';
      return;
    }
    const fd = new FormData();
    fd.append('file', f);
    previewSlot.innerHTML = '';
    previewSlot.hidden = false;
    previewSlot.appendChild(h('span', { class: 'muted' }, 'Uploading ' + f.name + '…'));
    try {
      const r = await fetch('/api/wa/upload', {
        method: 'POST',
        headers: { Authorization: 'Bearer ' + (CRM.token || '') },
        body: fd
      });
      const j = await r.json();
      if (!r.ok || j.error) throw new Error(j.error || ('upload failed (' + r.status + ')'));
      pending = j;
      renderPreview();
      input.focus();
    } catch (e) {
      pending = null; fileInput.value = '';
      previewSlot.hidden = true;
      toast(e.message || 'Upload failed', 'err');
    }
  });

  const attachBtn = h('button', { class: 'btn ghost wb-attach-btn', title: 'Attach a photo or document', onclick: () => fileInput.click() }, '📎');
  const tplBtn    = h('button', { class: 'btn ghost wb-tpl-btn',
    title: 'Send a pre-approved template — works even when the customer hasn\'t messaged in 24h',
    onclick: () => openWaTemplatePicker(phone, () => { if (typeof onSent === 'function') onSent(); })
  }, '📋');
  const sendBtn   = h('button', { class: 'btn primary wb-send-btn', title: 'Send', onclick: send }, 'Send');

  wrap.appendChild(previewSlot);
  // Multi-WA: when more than one connected number exists, show a 'Send from'
  // pill above the compose so the agent can pick which OUR number this
  // outbound goes from. Hidden when there's only one number (no UI clutter).
  const _waPhonesNow = (CRM.cache && CRM.cache.waPhones) || [];
  if (_waPhonesNow.length > 1) {
    const fromRow = h('div', { class: 'wb-compose-from-row',
      style: { padding: '.3rem .5rem', display: 'flex', alignItems: 'center', gap: '.4rem',
               fontSize: '.78rem', color: 'var(--text-soft)', background: '#f8fafc',
               borderTop: '1px solid var(--border)' } },
      h('span', {}, '📤 Send from:'),
      composerPicker
    );
    wrap.appendChild(fromRow);
  }
  wrap.appendChild(replyPreviewSlot);
  wrap.appendChild(h('div', { class: 'wb-compose-row' }, attachBtn, tplBtn, input, sendBtn, fileInput));
  return wrap;
}

/**
 * Modal that lists approved WhatsApp templates and lets the rep send one
 * to a contact. Used as a fallback when free-form text is blocked by the
 * 24-hour window or any other Meta error.
 */
async function openWaTemplatePicker(phone, onSent) {
  /* WA_TPL_SEND_v1 (2026-06-09) — rebuilt to support category filter +
     per-template Send form that asks for image/PDF when header_type
     requires it + inputs for body params. Plain text-only templates with
     no params still send in one click. */
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const card = h('div', { class: 'modal', style: { maxWidth: '640px', maxHeight: '85vh', overflow: 'auto' } },
    h('div', { class: 'modal-head' },
      h('h3', {}, '📋 Send a template to ', phone),
      h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
    )
  );
  const body = h('div', { class: 'modal-body-wrap', style: { padding: '.25rem 0' } });
  body.appendChild(h('p', { class: 'muted' }, 'Pre-approved templates can be sent any time — even outside the 24-hour reply window.'));

  /* Category filter chips */
  const filterRow = h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '.4rem', marginBottom: '.6rem' } });
  body.appendChild(filterRow);

  /* Search input */
  const searchInp = h('input', { type: 'search', placeholder: '🔍 Search by name…',
    style: { width: '100%', padding: '.4rem .6rem', marginBottom: '.6rem', border: '1px solid #cbd5e1', borderRadius: '6px' } });
  body.appendChild(searchInp);

  const listEl = h('div', { class: 'wb-tpl-list' });
  body.appendChild(listEl);
  card.appendChild(body);
  m.appendChild(card);
  document.body.appendChild(m);

  let tpls = [];
  try { tpls = await api('api_wb_templates_list'); }
  catch (e) {
    listEl.appendChild(h('div', { class: 'error-box' }, e.message));
    return;
  }
  const approved = (tpls || []).filter(t => String(t.status || '').toUpperCase() === 'APPROVED');
  if (!approved.length) {
    listEl.appendChild(h('p', { class: 'muted' },
      'No approved templates yet. Go to ', h('b', {}, 'WhatsBot → Templates'), ' to sync from Meta or create one.'));
    return;
  }

  /* Build category set from actual templates */
  const cats = Array.from(new Set(approved.map(t => String(t.category || '').toUpperCase()).filter(Boolean))).sort();
  let activeFilter = 'ALL';
  let activeSearch = '';
  const catLabel = (c) => ({ MARKETING: '📢 Marketing', UTILITY: '🔔 Utility', AUTHENTICATION: '🔐 Authentication' }[c] || c);
  const _drawFilters = () => {
    filterRow.innerHTML = '';
    const _chip = (label, value) => {
      const isActive = activeFilter === value;
      const c = h('button', { class: 'btn sm',
        style: {
          background: isActive ? '#4f46e5' : '#fff',
          color: isActive ? '#fff' : '#1e293b',
          border: '1px solid ' + (isActive ? '#4f46e5' : '#cbd5e1'),
          padding: '.2rem .7rem', borderRadius: '999px', fontWeight: 600, fontSize: '.78rem', cursor: 'pointer'
        }
      }, label);
      c.onclick = () => { activeFilter = value; _drawFilters(); _renderList(); };
      return c;
    };
    filterRow.appendChild(_chip('All (' + approved.length + ')', 'ALL'));
    cats.forEach(c => {
      const count = approved.filter(t => String(t.category || '').toUpperCase() === c).length;
      filterRow.appendChild(_chip(catLabel(c) + ' (' + count + ')', c));
    });
  };

  /* Header type → label helper */
  const hdrLabel = (t) => {
    const ht = String(t.header_type || '').toUpperCase();
    if (ht === 'IMAGE')    return '🖼️ Image header';
    if (ht === 'VIDEO')    return '🎥 Video header';
    if (ht === 'DOCUMENT') return '📄 Document header';
    if (ht === 'TEXT')     return '🅰️ Text header';
    return '';
  };
  const _bodyParamCount = (t) => {
    const params = (t.body_params || t.params || []);
    if (Array.isArray(params)) return params.length;
    const bt = String(t.body_text || '');
    return (bt.match(/\{\{\d+\}\}/g) || []).length;
  };
  const _needsMediaUpload = (t) => ['IMAGE','VIDEO','DOCUMENT'].includes(String(t.header_type || '').toUpperCase());

  const _renderList = () => {
    listEl.innerHTML = '';
    const filtered = approved.filter(t => {
      const cat = String(t.category || '').toUpperCase();
      if (activeFilter !== 'ALL' && cat !== activeFilter) return false;
      if (activeSearch && !String(t.name).toLowerCase().includes(activeSearch.toLowerCase())) return false;
      return true;
    });
    if (!filtered.length) {
      listEl.appendChild(h('p', { class: 'muted', style: { textAlign: 'center', padding: '1rem' } }, 'No templates match this filter.'));
      return;
    }
    filtered.forEach(t => {
      const needsMedia = _needsMediaUpload(t);
      const paramCount = _bodyParamCount(t);
      const hasExtra = needsMedia || paramCount > 0;
      const catTag = String(t.category || '').toUpperCase();
      const catColor = catTag === 'MARKETING' ? '#7c3aed' : catTag === 'UTILITY' ? '#0891b2' : catTag === 'AUTHENTICATION' ? '#059669' : '#64748b';
      const row = h('div', { class: 'wb-tpl-row',
        style: { borderBottom: '1px solid #e2e8f0', padding: '.6rem .2rem' } },
        h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '.5rem', flexWrap: 'wrap' } },
          h('div', { style: { flex: '1', minWidth: '200px' } },
            h('div', {}, h('b', {}, t.name),
              catTag ? h('span', {
                style: { marginLeft: '.4rem', fontSize: '.66rem', background: catColor, color: '#fff', padding: '1px 6px', borderRadius: '4px', fontWeight: 600 }
              }, catLabel(catTag)) : null
            ),
            h('div', { class: 'muted', style: { fontSize: '.72rem', marginTop: '.15rem' } },
              (t.language || 'en') + (hdrLabel(t) ? ' · ' + hdrLabel(t) : '') + (paramCount > 0 ? ' · {{' + paramCount + '}} variables' : '')
            ),
            t.body_text ? h('div', { class: 'muted', style: { fontSize: '.78rem', marginTop: '.2rem', whiteSpace: 'pre-wrap' } },
              String(t.body_text).slice(0, 100) + (t.body_text.length > 100 ? '…' : '')
            ) : null
          ),
          h('button', { class: 'btn sm primary' }, hasExtra ? 'Send →' : 'Send')
        )
      );
      const formSlot = h('div', { style: { marginTop: '.5rem', display: 'none', background: '#f8fafc', padding: '.6rem', borderRadius: '6px' } });
      row.appendChild(formSlot);

      row.querySelector('button').onclick = async () => {
        if (!hasExtra) {
          /* Plain template — instant send, original behaviour */
          try {
            await api('api_wb_initiate_chat', {
              phone, template_name: t.name, template_language: t.language || 'en_US', variables: []
            });
            toast('✓ Template sent');
            m.remove();
            if (typeof onSent === 'function') onSent();
          } catch (e) { toast(e.message, 'err'); }
          return;
        }
        /* Build the per-template Send form inline */
        if (formSlot.style.display === 'block') { formSlot.style.display = 'none'; return; }
        formSlot.style.display = 'block';
        formSlot.innerHTML = '';

        /* Media upload field for IMAGE / VIDEO / DOCUMENT header */
        let mediaUrl = '';
        let mediaInput = null;
        if (needsMedia) {
          const ht = String(t.header_type || '').toUpperCase();
          const acceptMap = { IMAGE: 'image/*', VIDEO: 'video/*', DOCUMENT: '.pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx' };
          formSlot.appendChild(h('div', { style: { fontWeight: 600, marginBottom: '.3rem' } }, hdrLabel(t) + ' (required)'));
          const filePick = h('input', { type: 'file', accept: acceptMap[ht] || '*/*', style: { width: '100%', marginBottom: '.4rem' } });
          mediaInput = filePick;
          const urlInp = h('input', { type: 'url', placeholder: 'Or paste a public URL', style: { width: '100%', padding: '.3rem', border: '1px solid #cbd5e1', borderRadius: '4px', fontSize: '.78rem' } });
          const uploadNote = h('div', { class: 'muted', style: { fontSize: '.72rem', marginTop: '.25rem' } }, 'Pick a file (we host it for you) OR paste a public URL.');
          filePick.onchange = async () => {
            const f = filePick.files && filePick.files[0];
            if (!f) return;
            if (f.size > 25 * 1024 * 1024) { toast('File too large (max 25 MB)', 'err'); return; }
            uploadNote.textContent = '⏳ Uploading ' + f.name + '…';
            try {
              const fd = new FormData(); fd.append('file', f);
              const r = await fetch('/api/wa-sample', { method: 'POST', headers: { 'x-auth-token': CRM.token }, body: fd });
              if (!r.ok) { const j = await r.json().catch(() => ({})); throw new Error(j.error || 'Upload failed (HTTP ' + r.status + ')'); }
              const j = await r.json();
              urlInp.value = j.url || '';
              mediaUrl = j.url || '';
              uploadNote.innerHTML = '✓ Hosted at <code style="font-size:.7rem">' + (j.url || '') + '</code>';
            } catch (e) {
              toast('Upload failed: ' + e.message, 'err');
              uploadNote.textContent = 'Pick a file (we host it for you) OR paste a public URL.';
            }
          };
          urlInp.addEventListener('input', () => { mediaUrl = urlInp.value || ''; });
          formSlot.appendChild(filePick);
          formSlot.appendChild(urlInp);
          formSlot.appendChild(uploadNote);
        }

        /* Body variable inputs */
        const varInputs = [];
        if (paramCount > 0) {
          formSlot.appendChild(h('div', { style: { fontWeight: 600, margin: '.6rem 0 .3rem' } }, 'Body variables'));
          for (let i = 0; i < paramCount; i++) {
            const inp = h('input', { type: 'text', placeholder: 'Value for {{' + (i + 1) + '}}',
              style: { width: '100%', padding: '.3rem', border: '1px solid #cbd5e1', borderRadius: '4px', marginBottom: '.3rem', fontSize: '.82rem' } });
            varInputs.push(inp);
            formSlot.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', gap: '.4rem' } },
              h('span', { class: 'muted', style: { minWidth: '40px', fontSize: '.72rem' } }, '{{' + (i + 1) + '}}'),
              inp
            ));
          }
        }

        const sendBtn = h('button', { class: 'btn primary', style: { marginTop: '.5rem', width: '100%' } }, '📤 Send template');
        sendBtn.onclick = async () => {
          if (needsMedia && !mediaUrl) { toast('Please upload an image/file or paste a URL for the header', 'err'); return; }
          for (let i = 0; i < varInputs.length; i++) {
            if (!varInputs[i].value.trim()) { toast('Please fill {{' + (i + 1) + '}}', 'err'); return; }
          }
          sendBtn.disabled = true; sendBtn.textContent = '⏳ Sending…';
          try {
            const payload = {
              phone, template_name: t.name, template_language: t.language || 'en_US',
              variables: varInputs.map(inp => inp.value)
            };
            if (mediaUrl) payload.image_url = mediaUrl;  /* backend handles IMAGE/VIDEO/DOCUMENT under the imageUrl param */
            await api('api_wb_initiate_chat', payload);
            toast('✓ Template sent');
            m.remove();
            if (typeof onSent === 'function') onSent();
          } catch (e) {
            toast(e.message, 'err');
            sendBtn.disabled = false; sendBtn.textContent = '📤 Send template';
          }
        };
        formSlot.appendChild(sendBtn);
      };
      listEl.appendChild(row);
    });
  };

  searchInp.addEventListener('input', () => { activeSearch = searchInp.value || ''; _renderList(); });
  _drawFilters();
  _renderList();
}

/**
 * Pick the correct WhatsApp `type` value for a given MIME. WhatsApp accepts
 * image / video / audio / document — anything we don't recognise falls
 * back to `document`.
 */
function waMediaTypeFor(mime) {
  const m = String(mime || '').toLowerCase();
  if (m.startsWith('image/')) return 'image';
  if (m.startsWith('video/')) return 'video';
  if (m.startsWith('audio/')) return 'audio';
  return 'document';
}

async function wbChat() {
  // Kill any previous timers if wbChat is mounted twice (e.g. tab reopened).
  if (window._wbChatTimers) {
    clearInterval(window._wbChatTimers.threadList);
    clearInterval(window._wbChatTimers.activeThread);
  }
  window._wbChatTimers = { threadList: null, activeThread: null };

  const wrap = h('div', { class: 'wb-chat' });
  const left = h('div', { class: 'wb-chat-list' });
  const right = h('div', { class: 'wb-chat-thread' },
    h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, '← Pick a contact'));
  wrap.appendChild(left);
  wrap.appendChild(right);

  // Track which thread is currently open + a fingerprint of its last render
  // so polling can decide whether to redraw.
  let openPhone = null;
  let openFingerprint = '';
  let lastThreadsFingerprint = '';

  function _threadFingerprint(threads) {
    return threads.map(t => `${t.phone}|${t.last_at}|${t.unread}|${t.assigned_to || 0}|${t.phone_number_id || ''}|${agentFilterId || ''}|${statusFilter || ''}|${searchQuery || ''}|${inboxPhoneId || ''}`).join(';');
  }
  // Admin / manager filter — when non-null, threads are limited to chats
  // assigned to that user. Persisted on `wbChat`'s closure so the filter
  // survives auto-polling redraws.
  let agentFilterId = '';
  // Status filter for the thread list — '' / 'unread' / 'unattended'
  // / 'unassigned' / 'mine'. Persisted across reloads so the agent's
  // last view is remembered.
  let statusFilter = '';
  try { statusFilter = localStorage.getItem('crm.wb.statusFilter') || ''; } catch (_) {}
  // Phase 3 multi-WA: per-phone inbox filter. '' / 'all' = every phone,
  // a phone_number_id string narrows the list to that connected number.
  // Persisted on the closure so polling redraws don't reset it. Restored
  // from localStorage so the user's choice sticks across reloads.
  let inboxPhoneId = '';
  try { inboxPhoneId = localStorage.getItem('crm.wb.inboxPhoneId') || ''; } catch (_) {}
  let unreadByPhone = {};      // phone_number_id -> count, refreshed every render
  let chatUsers = [];     // populated once per render
  // Free-text search across the chat list — matches name, phone, or
  // the last message preview, case-insensitively. Persists across
  // polling re-renders because it's bundled into _threadFingerprint
  // above (so a query change forces a redraw).
  let searchQuery = '';
  function _msgFingerprint(msgs) {
    return msgs.map(m => `${m.id}|${m.status || ''}|${m.read_at || ''}|${m.delivered_at || ''}`).join(';');
  }

  async function renderThreadList() {
    let threads;
    try {
      // Phase 3 multi-WA: server now accepts an optional phone_number_id
      // filter. We pass it so the server returns only threads belonging to
      // the selected inbox; the per-phone unread map (across ALL inboxes
      // the user can see) comes back as `unread_by_phone` on the array.
      threads = await api('api_wb_chat_threads', { phone_number_id: inboxPhoneId || 'all' });
    }
    catch (_) { threads = []; }
    // Capture per-phone unread map for the inbox-selector badges (server
    // returns it across ALL phones the user can see, not filtered).
    unreadByPhone = (threads && threads.unread_by_phone) || {};

    // Apply admin / manager agent filter if set
    let filtered = agentFilterId
      ? threads.filter(t => Number(t.assigned_to) === Number(agentFilterId))
      : threads;

    // Apply status filter on top of agent filter
    if (statusFilter === 'unread') {
      filtered = filtered.filter(t => Number(t.unread) > 0);
    } else if (statusFilter === 'unassigned') {
      filtered = filtered.filter(t => !t.assigned_to);
    } else if (statusFilter === 'mine') {
      filtered = filtered.filter(t => Number(t.assigned_to) === Number(CRM.user.id));
    } else if (statusFilter === 'unattended') {
      // Unattended = unread inbound chats that no agent has replied to yet.
      // Approximation: last_message_type set, last is inbound (unread > 0).
      filtered = filtered.filter(t => Number(t.unread) > 0);
    }

    // Apply free-text search across name / phone / last-message / agent
    if (searchQuery) {
      const q = searchQuery.toLowerCase().trim();
      filtered = filtered.filter(t => {
        return String(t.lead_name || '').toLowerCase().includes(q)
            || String(t.phone || '').toLowerCase().includes(q)
            || String(t.last_message || '').toLowerCase().includes(q)
            || String(t.assigned_name || '').toLowerCase().includes(q);
      });
    }

    const fp = _threadFingerprint(filtered);
    if (fp === lastThreadsFingerprint) return; // No change — preserve scroll
    lastThreadsFingerprint = fp;

    // Lazily fetch the user roster the FIRST time the list renders so we
    // can populate the agent-filter dropdown + assignment picker.
    if (!chatUsers.length && (CRM.user.role === 'admin' || CRM.user.role === 'manager' || CRM.user.role === 'team_leader')) {
      try { chatUsers = await api('api_users_list'); } catch (_) { chatUsers = []; }
    }

    left.innerHTML = '';
    left.appendChild(h('div', { style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '.5rem' } },
      h('h4', { style: { margin: 0 } }, '💭 Chats (' + filtered.length + (searchQuery ? ' / ' + threads.length : '') + ')'),
      h('button', { class: 'btn sm ghost', title: 'Refresh now', onclick: () => { lastThreadsFingerprint = ''; renderThreadList(); if (openPhone) renderActiveThread(true); } }, '↻')
    ));

    // ---- Inbox (per-phone) selector — Phase 3 multi-WA ----
    // Only renders when the tenant has more than one connected number.
    // 'All inboxes' shows the merged feed; each other option filters to
    // a single phone_number_id and shows its unread badge.
    const _allPhones = ((CRM.cache && CRM.cache.waPhones) || []).filter(p => Number(p.is_active) === 1);
    if (_allPhones.length > 1) {
      const totalUnread = Object.values(unreadByPhone).reduce((a, b) => a + Number(b || 0), 0);
      const inboxSel = h('select', {
        class: 'wb-inbox-filter',
        style: { width: '100%', marginBottom: '.5rem', fontWeight: '500' },
        title: 'Filter by which of your WhatsApp numbers received the chat'
      },
        h('option', { value: '', selected: inboxPhoneId === '' ? 'selected' : null },
          '📥 All inboxes' + (totalUnread ? '  •  ' + totalUnread + ' unread' : '')),
        ..._allPhones.map(p => {
          const u = Number(unreadByPhone[p.phone_number_id] || 0);
          const lbl = (Number(p.is_default) === 1 ? '⭐ ' : '') +
                      (p.display_phone_number || p.phone_number_id) +
                      (p.label ? ' (' + p.label + ')' : '') +
                      (u ? '  •  ' + u + ' unread' : '');
          return h('option', { value: p.phone_number_id, selected: inboxPhoneId === p.phone_number_id ? 'selected' : null }, lbl);
        })
      );
      inboxSel.onchange = () => {
        inboxPhoneId = inboxSel.value;
        try { localStorage.setItem('crm.wb.inboxPhoneId', inboxPhoneId); } catch (_) {}
        lastThreadsFingerprint = '';
        renderThreadList();
      };
      left.appendChild(inboxSel);
    }

    // ---- Search box (above the agent filter) ----
    // Debounced 200ms so each keystroke doesn't burn a re-render. The
    // input is re-mounted on every render but we restore focus + caret
    // position so typing feels smooth.
    const searchInput = h('input', {
      type: 'search', placeholder: '🔍 Search chats by name, phone, message…',
      value: searchQuery,
      style: { width: '100%', marginBottom: '.5rem', padding: '.45rem .6rem', borderRadius: '6px', border: '1px solid var(--border, #d1d5db)' }
    });
    let _searchTimer = null;
    searchInput.addEventListener('input', () => {
      clearTimeout(_searchTimer);
      _searchTimer = setTimeout(() => {
        searchQuery = searchInput.value;
        lastThreadsFingerprint = '';
        renderThreadList();
      }, 200);
    });
    // ESC clears the search
    searchInput.addEventListener('keydown', (ev) => {
      if (ev.key === 'Escape' && searchQuery) {
        ev.preventDefault();
        searchInput.value = '';
        searchQuery = '';
        lastThreadsFingerprint = '';
        renderThreadList();
      }
    });
    left.appendChild(searchInput);
    if (document.activeElement && document.activeElement.tagName === 'INPUT' && document.activeElement.type === 'search') {
      setTimeout(() => {
        searchInput.focus();
        try { searchInput.setSelectionRange(searchInput.value.length, searchInput.value.length); } catch (_) {}
      }, 0);
    }

    // Agent filter — admins/managers/TLs only
    const canFilter = (CRM.user.role === 'admin' || CRM.user.role === 'manager' || CRM.user.role === 'team_leader');
    if (canFilter && chatUsers.length) {
      const sel = h('select', { class: 'wb-agent-filter', style: { width: '100%', marginBottom: '.5rem' } },
        h('option', { value: '' }, 'All agents'),
        ...chatUsers.map(u => h('option', { value: String(u.id), selected: String(u.id) === String(agentFilterId) ? 'selected' : null }, u.name))
      );
      sel.onchange = () => {
        agentFilterId = sel.value;
        lastThreadsFingerprint = '';
        renderThreadList();
      };
      left.appendChild(sel);
    }

    // Status filter — visible to everyone. Lets reps quickly find
    // chats that need attention.
    const statusSel = h('select', { class: 'wb-status-filter',
      style: { width: '100%', marginBottom: '.5rem' } },
      h('option', { value: '',           selected: !statusFilter ? '' : null }, 'All chats'),
      h('option', { value: 'unread',     selected: statusFilter === 'unread' ? '' : null }, '🔵 Unread only'),
      h('option', { value: 'unattended', selected: statusFilter === 'unattended' ? '' : null }, '⏳ Unattended (no agent reply)'),
      h('option', { value: 'unassigned', selected: statusFilter === 'unassigned' ? '' : null }, '🆕 Unassigned'),
      h('option', { value: 'mine',       selected: statusFilter === 'mine' ? '' : null }, '👤 Mine')
    );
    statusSel.onchange = () => {
      statusFilter = statusSel.value;
      try { localStorage.setItem('crm.wb.statusFilter', statusFilter); } catch (_) {}
      lastThreadsFingerprint = '';
      renderThreadList();
    };
    left.appendChild(statusSel);

    if (!filtered.length) {
      left.appendChild(h('p', { class: 'muted' },
        agentFilterId ? 'No chats assigned to this agent.' : 'No conversations yet. Inbound WhatsApp messages will appear here automatically.'));
      return;
    }
    filtered.forEach(t => {
      const ownerLabel = t.assigned_name
        ? h('span', { class: 'wb-row-agent' + (t.assignment_explicit ? ' explicit' : '') },
            '👤 ' + t.assigned_name + (t.assignment_explicit ? '' : ' · auto')
          )
        : h('span', { class: 'wb-row-agent unassigned' }, '👤 Unassigned');
      // WA_CHAT_FIRSTLAST_v1 — show First/Last contact dates per number
      const _fmtFull = v => v ? new Date(v).toLocaleString([], { day: '2-digit', month: 'short', year: '2-digit', hour: '2-digit', minute: '2-digit' }) : '—';
      const row = h('div', { class: 'wb-chat-row' + (t.phone === openPhone ? ' active' : ''), onclick: () => openThread(t.phone) },
        h('div', {}, h('b', {}, t.lead_name || t.phone), t.unread ? h('span', { class: 'wb-unread' }, t.unread) : null),
        h('div', { class: 'muted', style: { fontSize: '.78rem' } }, t.phone),
        ownerLabel,
        h('div', { class: 'muted', style: { fontSize: '.78rem', maxWidth: '220px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' } }, t.last_message_type === 'text' ? t.last_message : ('[' + t.last_message_type + ']')),
        h('div', { class: 'muted', style: { fontSize: '.7rem' } }, fmtDate(t.last_at, 'relative')),
        // First + Last connected timestamps — shown on every thread row
        h('div', { style: { fontSize: '.68rem', color: '#64748b', marginTop: '4px', display: 'flex', gap: '8px', flexWrap: 'wrap' },
                   title: 'First contact: ' + _fmtFull(t.first_at) + '\nLast contact: ' + _fmtFull(t.last_at) },
          h('span', { style: { color: '#16a34a' } }, '🟢 First: ' + _fmtFull(t.first_at)),
          h('span', { style: { color: '#3b82f6' } }, '🔵 Last: ' + _fmtFull(t.last_at))
        )
      );
      left.appendChild(row);
    });
  }

  /**
   * Render the message log for the currently open thread.
   *
   * `force` re-renders even if the fingerprint is unchanged — used when the
   * user clicks ↻ Refresh manually.
   *
   * Re-renders ONLY the message log container, never the textarea, so the
   * user's in-progress draft is preserved.
   */
  async function renderActiveThread(force) {
    if (!openPhone) return;
    let msgs;
    try { msgs = await api('api_wb_chat_messages', openPhone); }
    catch (_) { msgs = []; }
    const fp = _msgFingerprint(msgs);
    if (!force && fp === openFingerprint) return;
    openFingerprint = fp;

    const log = right.querySelector('.wb-chat-log');
    if (!log) return; // The thread pane was torn down — bail.
    const wasNearBottom = (log.scrollHeight - log.scrollTop - log.clientHeight) < 80;
    log.innerHTML = '';
    msgs.forEach(msg => {
      const isFailed = msg.status === 'failed' || !!msg.error_text;
      const tickClass = msg.read_at ? 'read' : msg.delivered_at ? 'delivered' : 'sent';
      const tickGlyph = isFailed ? '⚠'
                      : msg.read_at ? '✓✓'
                      : msg.delivered_at ? '✓✓'
                      : '✓';
      // For media messages, show an inline preview / download chip on top
      // of the caption (msg.body holds the caption when it's a media msg).
      const mediaNode = renderWaMessageMedia(msg);
      // Multi-WA: small badge showing which connected number this msg
      // arrived on (or was sent from). Helps agents juggling 2+ inboxes.
      let _phoneBadge = null;
      try {
        const allPhones = (CRM.cache && CRM.cache.waPhones) || [];
        if (msg.phone_number_id && allPhones.length > 1) {
          const meta = allPhones.find(p => String(p.phone_number_id) === String(msg.phone_number_id));
          if (meta) {
            const label = meta.label
              || meta.display_phone_number
              || ('… ' + String(meta.phone_number_id).slice(-4));
            _phoneBadge = h('span', {
              class: 'wb-msg-phone-badge',
              title: 'Received on ' + (meta.display_phone_number || meta.phone_number_id),
              style: {
                fontSize: '.65rem', padding: '1px 6px', marginLeft: '.4rem',
                borderRadius: '999px', background: '#e0e7ff', color: '#3730a3',
                fontWeight: 600
              }
            }, msg.direction === 'in' ? '↘ ' + label : '↗ ' + label);
          }
        }
      } catch (_) {}
      // WA_REPLY_v1 (2026-05-21): if this message is a reply, render the
      // quoted parent as a small grey strip above the body.
      let _quotedNode = null;
      if (msg.reply_to) {
        const parent = msgs.find(x => x.wa_message_id === msg.reply_to);
        if (parent) {
          const pText = parent.body || ('[' + (parent.message_type || 'message') + ']');
          _quotedNode = h('div', { class: 'wb-msg-quote', style: {
            borderLeft: '3px solid #6366f1',
            background: 'rgba(99,102,241,.08)',
            padding: '.25rem .45rem',
            borderRadius: '4px',
            fontSize: '.75rem',
            color: '#3730a3',
            marginBottom: '.25rem',
            cursor: 'pointer',
            maxWidth: '90%'
          }, title: 'Scroll to original message', onclick: () => {
            const el = document.querySelector('[data-wam-id="' + parent.wa_message_id + '"]');
            if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'center' }); el.classList.add('wb-msg-highlight'); setTimeout(() => el.classList.remove('wb-msg-highlight'), 1500); }
          }},
            h('div', { style: { fontWeight: 700, fontSize: '.65rem', opacity: .8 }}, parent.direction === 'out' ? 'You' : 'Them'),
            h('div', { style: { whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}, pText.slice(0, 80))
          );
        }
      }
      // Reply button — hover-shown ↩ that sets _waReplyTarget so the
      // compose row can render a quoted preview + send with reply_to.
      const _replyBtn = h('button', {
        class: 'wb-msg-reply-btn',
        title: 'Reply to this message',
        style: {
          position: 'absolute', top: '4px', right: '4px',
          background: 'rgba(255,255,255,.85)', border: '1px solid #e5e7eb',
          borderRadius: '4px', padding: '1px 5px', fontSize: '.7rem',
          cursor: 'pointer', display: 'none'
        },
        onclick: (ev) => {
          ev.stopPropagation();
          window._waReplyTarget = {
            wa_message_id: msg.wa_message_id,
            body: msg.body || ('[' + (msg.message_type || 'message') + ']'),
            direction: msg.direction
          };
          // Render the reply preview above the input
          try { window._renderWaReplyPreview && window._renderWaReplyPreview(); } catch (_) {}
        }
      }, '↩ Reply');
      const _msgEl = h('div', {
        class: 'wb-msg ' + (msg.direction === 'in' ? 'in' : 'out') + (isFailed ? ' failed' : ''),
        'data-wam-id': msg.wa_message_id || '',
        style: { position: 'relative' },
        onmouseenter: () => { _replyBtn.style.display = 'block'; },
        onmouseleave: () => { _replyBtn.style.display = 'none'; }
      },
        _quotedNode,
        _replyBtn,
        mediaNode,
        h('div', { class: 'wb-msg-body' }, (function() {
          // Friendly fallback for already-saved messages with empty body
          // (old inbound rows where the type was 'unsupported' / 'sticker'
          // / 'reaction' etc. before the parser learned them).
          if (msg.body && String(msg.body).trim()) return msg.body;
          if (mediaNode) return '';
          const t = String(msg.message_type || '').toLowerCase();
          const labels = {
            sticker:     '\uD83C\uDFAD Sticker',
            reaction:    '\uD83D\uDC4D Reaction',
            location:    '\uD83D\uDCCD Location',
            contacts:    '\uD83D\uDCC7 Contact card',
            order:       '\uD83D\uDED2 Order',
            system:      '\u2139\uFE0F System message',
            unsupported: '\uD83D\uDCAC Unsupported message type',
            unknown:     '\uD83D\uDCAC Unknown message type'
          };
          return labels[t] || ('\uD83D\uDCAC ' + (t.charAt(0).toUpperCase() + t.slice(1) || 'Message'));
        })()),
        isFailed
          ? h('div', { class: 'wb-msg-error', title: msg.error_text || 'Send failed' },
              waFriendlyError(msg.error_text))
          : null,
        h('div', { class: 'wb-msg-meta muted' },
          fmtDate(msg.created_at, 'relative'),
          msg.direction === 'out'
            ? h('span', { class: 'wb-tick ' + (isFailed ? 'failed' : tickClass), title: isFailed ? (msg.error_text || 'failed') : tickClass }, ' · ' + tickGlyph)
            : null,
          _phoneBadge
        )
      );
      log.appendChild(_msgEl);
    });
    // Auto-scroll to bottom IF the user was already at/near the bottom.
    // If they had scrolled up to read history, leave them there.
    if (wasNearBottom) setTimeout(() => { log.scrollTop = log.scrollHeight; }, 50);
  }

  function backToList() {
    openPhone = null;
    openFingerprint = '';
    wrap.classList.remove('thread-open');
    [...left.querySelectorAll('.wb-chat-row')].forEach(r => r.classList.remove('active'));
    right.innerHTML = h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, '← Pick a contact').outerHTML;
  }


  // Helper: builds a status <select> for the WhatsApp chat header that
  // lets the user change the linked lead's status without leaving the
  // conversation. Returns the wrapping element. If the thread has no
  // linked lead (very rare — only un-saved leads), returns null.
  async function buildChatStatusPicker(leadId, opts) {
    if (!leadId) return null;
    opts = opts || {};
    try {
      // Fetch the lead + statuses in parallel
      const [lead, statuses] = await Promise.all([
        api('api_leads_get', leadId).catch(() => null),
        api('api_statuses_list').catch(() => [])
      ]);
      if (!lead || !Array.isArray(statuses) || !statuses.length) return null;
      const currentId = Number(lead.status_id || 0);
      const sel = document.createElement('select');
      sel.style.cssText = (opts.compact
        ? 'padding: .2rem .35rem; font-size: .72rem; border: 1px solid #cbd5e1; border-radius: 4px; max-width: 130px;'
        : 'padding: .3rem .45rem; font-size: .8rem; border: 1px solid #cbd5e1; border-radius: 6px; max-width: 200px;');
      sel.title = 'Change lead status';
      statuses
        .slice()
        .sort((a, b) => (Number(a.sort_order) || 0) - (Number(b.sort_order) || 0))
        .forEach(s => {
          const o = document.createElement('option');
          o.value = String(s.id);
          o.textContent = s.name;
          if (Number(s.id) === currentId) o.selected = true;
          sel.appendChild(o);
        });
      sel.onchange = async () => {
        const newId = Number(sel.value);
        if (!newId || newId === currentId) return;
        const prev = currentId;
        sel.disabled = true;
        try {
          await api('api_leads_update', leadId, { status_id: newId });
          if (typeof toast === 'function') toast('Status updated', 'ok');
          if (typeof opts.onChange === 'function') opts.onChange(newId);
        } catch (e) {
          if (typeof toast === 'function') toast('Status update failed: ' + e.message, 'err');
          // Revert UI on failure
          sel.value = String(prev);
        }
        sel.disabled = false;
      };
      const wrap = document.createElement('div');
      wrap.style.cssText = 'display: flex; align-items: center; gap: .3rem;';
      const label = document.createElement('span');
      label.textContent = opts.compact ? '' : 'Status:';
      label.style.cssText = 'font-size: .75rem; color: #64748b;';
      if (!opts.compact) wrap.appendChild(label);
      wrap.appendChild(sel);
      return wrap;
    } catch (_) {
      return null;
    }
  }

  async function openThread(phone) {
    openPhone = phone;
    openFingerprint = ''; // Force a render
    wrap.classList.add('thread-open');  // mobile: hide list, show thread
    // Mark thread row active
    [...left.querySelectorAll('.wb-chat-row')].forEach(r => r.classList.remove('active'));

    right.innerHTML = '';
    // Look up the thread row we have for this phone so we know who it's
    // currently assigned to. (Comes from the threads list we just fetched.)
    // Always fetch the FULL set ('all') here regardless of which inbox the
    // user is browsing — they may be opening a thread that lives in another
    // inbox (e.g. via deep-link). We just need the row with phone_number_id
    // for the composer auto-route default.
    const threadMeta = (await api('api_wb_chat_threads', { phone_number_id: 'all' }).catch(() => [])).find(t => t.phone === phone) || {};
    const head = h('div', { class: 'wb-chat-head', style: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '.5rem', flexWrap: 'wrap' } },
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
        h('button', { class: 'wb-chat-back', title: 'Back to list', onclick: backToList }, '← Back'),
        h('b', {}, threadMeta.lead_name || phone),
        threadMeta.lead_name ? h('span', { class: 'muted', style: { fontSize: '.78rem' } }, phone) : null
      ),
      h('div', { class: 'wb-chat-status-slot', style: { display: 'flex', alignItems: 'center' } }),
      buildAgentPicker(phone, threadMeta),
      // WA_WHITELIST_v1 — mark this phone as a personal contact so future
      // inbound messages are dropped (lead not created, message not saved).
      h('button', { class: 'btn sm ghost', title: 'Whitelist this number — future inbound messages will be silently dropped (personal contact)', style: { color: '#b91c1c' }, onclick: async () => {
        const note = prompt('Add a note (optional, e.g. "My brother", "Personal"):', '') || '';
        if (note === null) return;
        if (!confirm('Whitelist ' + phone + '?\n\n• Future inbound messages from this number will NOT create a lead and will NOT appear in WhatsApp chat.\n• Any existing auto-generated empty lead for this number will be removed.\n\nContinue?')) return;
        try {
          const r = await api('api_wb_whitelist_add', { phone, note });
          toast('✓ Whitelisted ' + phone + (r.leads_removed ? ' (removed ' + r.leads_removed + ' auto-lead)' : ''));
          // Refresh the thread list — the row will linger until next inbound; that\'s fine
          if (typeof renderThreadList === 'function') { lastThreadsFingerprint = ''; renderThreadList(); }
        } catch (e) { toast(e.message, 'err'); }
      } }, '🚫 Whitelist'),
      // WA_CONVERT_LEAD_v1 — 🎯 "Save as lead" button. Only shown when the
      // current chat isn't already linked to a lead (threadMeta.lead_id is
      // null). Opens a small modal with editable name/owner/status/source/
      // notes pre-filled with the tenant's WhatsApp auto-lead defaults.
      (!threadMeta.lead_id ? h('button', { class: 'btn sm primary', title: 'Convert this WhatsApp chat into a CRM lead', style: { background: '#16a34a', borderColor: '#16a34a', color: '#fff' }, onclick: () => _wbOpenConvertToLeadModal(phone, threadMeta) }, '🎯 Save as lead') : null),
      h('button', { class: 'btn sm ghost', title: 'Refresh this thread', onclick: () => renderActiveThread(true) }, '↻')
    );
    right.appendChild(head);
    // Async-populate the status picker (needs to fetch lead + statuses)
    (async () => {
      if (!threadMeta.lead_id) return;
      const picker = await buildChatStatusPicker(threadMeta.lead_id);
      if (!picker) return;
      const slot = head.querySelector('.wb-chat-status-slot');
      if (slot) slot.appendChild(picker);
    })();
    const log = h('div', { class: 'wb-chat-log' });
    log.innerHTML = '<div class="loading">Loading…</div>';
    right.appendChild(log);

    right.appendChild(buildWaCompose(phone, () => {
      // After a successful send: redraw thread + bump the list
      renderActiveThread(true);
      lastThreadsFingerprint = '';
      renderThreadList();
    }, { defaultPhoneId: threadMeta.phone_number_id || null }));

    await renderActiveThread(true);
    // Refresh the list too — opening a thread marks inbound as read on the
    // server, so unread badges should clear in the left pane.
    lastThreadsFingerprint = '';
    await renderThreadList();
  }

  // Initial render + auto-poll
  // WA_CHAT_REFRESH_SLOWDOWN_v1 — user reported visible refresh/flash every
  // ~5s on the chat page (8s list + 4s thread were running concurrently).
  // Even though both have fingerprint guards, the thread one fires every
  // 4s and on EVERY status-update (delivered_at/read_at) it rebuilds the
  // entire log via innerHTML='', causing visible flicker. Bumped to
  // 20s/15s respectively — still feels live for new inbound messages
  // (push notification surfaces those instantly), but no more constant
  // background re-render.
  await renderThreadList();
  window._wbChatTimers.threadList = setInterval(() => {
    // Pause polling when the tab is hidden — saves battery on mobile and
    // avoids piling up requests if the user steps away for an hour.
    if (document.visibilityState === 'hidden') return;
    renderThreadList().catch(() => {});
  }, 20000);
  window._wbChatTimers.activeThread = setInterval(() => {
    if (document.visibilityState === 'hidden') return;
    // Skip refresh while user is actively typing in the compose box —
    // a re-render mid-keystroke can blur the input and lose focus.
    const composer = document.querySelector('.wb-chat-compose textarea, .wb-chat-compose input[type=text]');
    if (composer && document.activeElement === composer) return;
    if (openPhone) renderActiveThread(false).catch(() => {});
  }, 15000);

  // WA_REPORT_DRILL_v2 — if a phone was stashed for auto-open (from
  // the WA Report drill, lead modal, or any other source), open that
  // thread once the thread list has rendered. Reads from THREE sources
  // so we don't lose the target to a router quirk:
  //   1. window._wbPendingOpen — set by the calling code just before nav
  //   2. sessionStorage 'wbPendingOpen' — survives a page reload
  //   3. ?phone= in the URL hash — last-resort deep-link
  try {
    let wantPhone = '';
    if (window._wbPendingOpen && window._wbPendingOpen.phone) {
      wantPhone = String(window._wbPendingOpen.phone).replace(/\D/g, '');
      window._wbPendingOpen = null; // consume once
    }
    if (!wantPhone) {
      try {
        const s = sessionStorage.getItem('wbPendingOpen');
        if (s) {
          const j = JSON.parse(s);
          if (j && j.phone && (Date.now() - (j.ts || 0)) < 30000) {
            wantPhone = String(j.phone).replace(/\D/g, '');
          }
          sessionStorage.removeItem('wbPendingOpen');
        }
      } catch (_) {}
    }
    if (!wantPhone) {
      const hashQs = (location.hash.split('?')[1] || '');
      const params = new URLSearchParams(hashQs);
      wantPhone = (params.get('phone') || '').replace(/\D/g, '');
    }
    if (wantPhone) {
      let tries = 0;
      const t = setInterval(() => {
        tries++;
        const row = [...left.querySelectorAll('.wb-chat-row')].find(r =>
          (r.textContent || '').replace(/\D/g, '').indexOf(wantPhone) !== -1);
        if (row) { clearInterval(t); try { openThread(wantPhone); } catch (_) {} }
        else if (tries > 8) { clearInterval(t); try { openThread(wantPhone); } catch (_) {} }
      }, 400);
    }
  } catch (_) {}

  return wrap;
}

// ---------- Auto-assign rules ----------
/**
 * Settings panel: how new inbound chats get routed to agents.
 *   - lead_owner   — give it to whoever owns the linked lead (default)
 *   - round_robin  — cycle through a pool of agents
 *   - least_busy   — give it to the agent with the fewest active chats
 *   - manual       — admin assigns by hand from the chat header dropdown
 */
async function wbAssignSettings() {
  const wrap = h('div', { class: 'card', style: { maxWidth: '720px' } });
  wrap.appendChild(h('h3', { style: { marginTop: 0 } }, '👥 Auto-assign rules'));
  wrap.appendChild(h('p', { class: 'muted' },
    'Decide how brand-new inbound WhatsApp chats are routed to agents. ',
    'These rules only apply when a chat doesn\'t already have an agent — once a chat is assigned (manually or by a rule) the assignment sticks until someone changes it.'
  ));

  let s;
  try { s = await api('api_wb_assign_settings_get'); }
  catch (e) {
    wrap.appendChild(h('div', { class: 'error-box' }, e.message));
    return wrap;
  }

  // Direct refs — `$()` would return null because wrap isn't in the DOM yet.
  const modeSel = h('select', {},
    h('option', { value: 'lead_owner', selected: s.mode === 'lead_owner' ? 'selected' : null },
      'Lead owner (default) — assign to whoever owns the linked lead'),
    h('option', { value: 'round_robin', selected: s.mode === 'round_robin' ? 'selected' : null },
      'Round-robin — cycle through the agent pool'),
    h('option', { value: 'least_busy', selected: s.mode === 'least_busy' ? 'selected' : null },
      'Least-busy — give it to the agent with fewest active chats'),
    h('option', { value: 'manual', selected: s.mode === 'manual' ? 'selected' : null },
      'Manual — admin assigns from the chat header')
  );
  wrap.appendChild(h('div', { class: 'form-row' }, h('label', {}, 'Mode'), modeSel));

  // Pool multi-select (only relevant for round_robin / least_busy)
  const poolList = h('div', { class: 'aa-pool-list' });
  const poolWrap = h('div', { class: 'form-row' },
    h('label', {},
      'Agent pool ',
      h('span', { class: 'muted' }, '(round-robin / least-busy only)')
    ),
    poolList
  );
  wrap.appendChild(poolWrap);

  s.users.forEach(u => {
    const checked = s.pool.includes(Number(u.id)) ? 'checked' : null;
    poolList.appendChild(h('label', { class: 'aa-pool-item' },
      h('input', { type: 'checkbox', class: 'aa-pool-cb', value: String(u.id), checked }),
      h('span', {}, u.name + ' '),
      h('span', { class: 'muted' }, u.role)
    ));
  });

  // Show / hide pool depending on mode
  const updatePoolVisibility = () => {
    const isPoolMode = (modeSel.value === 'round_robin' || modeSel.value === 'least_busy');
    poolWrap.style.opacity = isPoolMode ? '1' : '0.45';
    poolWrap.style.pointerEvents = isPoolMode ? 'auto' : 'none';
  };
  modeSel.onchange = updatePoolVisibility;
  updatePoolVisibility();

  // Save button
  const saveBtn = h('button', { class: 'btn primary' }, '💾 Save rules');
  saveBtn.onclick = async () => {
    const mode = modeSel.value;
    const pool = [...poolList.querySelectorAll('.aa-pool-cb:checked')].map(cb => Number(cb.value));
    if ((mode === 'round_robin' || mode === 'least_busy') && !pool.length) {
      toast('Pick at least one agent for the pool', 'err');
      return;
    }
    saveBtn.disabled = true;
    try {
      await api('api_wb_assign_settings_save', { mode, pool });
      toast('✓ Auto-assign rules saved');
    } catch (e) { toast(e.message, 'err'); }
    finally { saveBtn.disabled = false; }
  };
  wrap.appendChild(h('div', { style: { marginTop: '1rem' } }, saveBtn));

  // ---- Per-WhatsApp-number lead routing ----
  // When the tenant has multiple WA numbers connected, admins want
  // different default owners per phone (Sales line → Rahul, Support
  // line → Priya). This sits below the global rules above and acts
  // as a per-phone override — applied BEFORE the global rules when
  // an inbound auto-creates a new lead.
  let _phonesForRouting = [];
  let _usersForRouting = [];
  try { _phonesForRouting = await api('api_wa_phones_listAll'); } catch (_) { _phonesForRouting = []; }
  try { _usersForRouting  = await api('api_users_list'); }       catch (_) { _usersForRouting  = []; }
  if (_phonesForRouting.length) {
    const routingCard = h('div', { class: 'card', style: { marginTop: '1.25rem' } });
    routingCard.appendChild(h('h3', { style: { marginTop: 0 } }, '📞 Per-WhatsApp-number routing'));
    routingCard.appendChild(h('p', { class: 'muted' },
      'When a brand-new lead arrives via a specific connected WhatsApp number, send it to a specific agent. ',
      'Leave any row blank to fall back to the global rule above.'
    ));
    const routeTbl = h('table', { class: 'data-table' },
      h('thead', {}, h('tr', {},
        h('th', {}, 'Number'),
        h('th', {}, 'Label'),
        h('th', {}, 'Assign new leads to')
      )),
      h('tbody', {}, ..._phonesForRouting.map(ph => h('tr', {},
        h('td', {}, h('code', {}, ph.display_phone_number || ph.phone_number_id),
          Number(ph.is_default) === 1 ? h('span', { class: 'muted', style: { marginLeft: '.4rem' } }, '⭐ default') : null),
        h('td', { class: 'muted' }, ph.label || '—'),
        h('td', {},
          (() => {
            const sel = h('select', { style: { minWidth: '180px' } },
              h('option', { value: '' }, '— Use global rule —'),
              ...(_usersForRouting || []).map(u =>
                h('option', { value: String(u.id),
                  selected: String(u.id) === String(ph.default_owner_user_id || '') ? 'selected' : null },
                  (u.name || u.email || ('User #' + u.id)) + (u.role ? ' (' + u.role + ')' : '')
                )
              )
            );
            sel.onchange = async () => {
              try {
                await api('api_wa_phones_save', { id: ph.id, default_owner_user_id: sel.value || null });
                toast('Saved owner for ' + (ph.display_phone_number || 'this number'), 'ok');
              } catch (e) { toast(e.message, 'err'); }
            };
            return sel;
          })()
        )
      )))
    );
    routingCard.appendChild(routeTbl);
    wrap.appendChild(routingCard);
  }

  // Help text
  wrap.appendChild(h('details', { style: { marginTop: '1.25rem' } },
    h('summary', { class: 'muted' }, 'How does this work?'),
    h('ul', { style: { paddingLeft: '1.2rem', lineHeight: '1.6' } },
      h('li', {}, h('b', {}, 'Lead owner'), ' — when a new WhatsApp message arrives, the chat goes to whoever owns the lead with that phone number. If the lead has no owner, the chat stays unassigned (admin only).'),
      h('li', {}, h('b', {}, 'Round-robin'), ' — chats are distributed evenly across the agent pool. The system remembers who got the last one and gives the next chat to the next agent in line.'),
      h('li', {}, h('b', {}, 'Least-busy'), ' — counts how many chats each agent currently owns and gives the new chat to whoever has the fewest. Good for keeping load balanced when reps work different volumes.'),
      h('li', {}, h('b', {}, 'Manual'), ' — chats stay unassigned until an admin/manager picks an agent from the chat header dropdown.'),
      h('li', {}, 'Already-assigned chats are never re-assigned by these rules. Use the per-chat agent picker to move them.')
    )
  ));

  return wrap;
}

// ---------- Activity Log ----------
async function wbActivity() {
  const wrap = h('div', {});

  // Toolbar with category filter + search + auto-refresh + clear
  const catSel = h('select', { id: 'wb-act-cat' },
    h('option', { value: '' }, 'All categories'),
    h('option', { value: 'chat' }, '💬 Chat (outbound)'),
    h('option', { value: 'campaign' }, '📣 Campaigns'),
    h('option', { value: 'message_bot' }, '🤖 Message bots'),
    h('option', { value: 'template_bot' }, '🤖 Template bots'),
    h('option', { value: 'template_sync' }, '📋 Template sync'),
    h('option', { value: 'webhook_in' }, '📥 Webhook (raw)'),
    h('option', { value: 'webhook_status' }, '✅ Status updates'),
    h('option', { value: 'webhook_message' }, '📩 Inbound messages')
  );
  const searchInp = h('input', { id: 'wb-act-q', placeholder: 'Search name / template…', style: { flex: 1 } });
  const tbody = h('tbody', {});
  const reload = async () => {
    const data = await api('api_wb_activity_list', { category: catSel.value || undefined, q: searchInp.value || undefined }).catch(() => []);
    tbody.innerHTML = '';
    if (!data.length) {
      tbody.appendChild(h('tr', {}, h('td', { colspan: 8, class: 'muted', style: { textAlign: 'center', padding: '1.5rem' } }, 'No activity matching this filter.')));
      return;
    }
    data.forEach(r => {
      const codeColor = r.response_code === 200 ? '#10b981' : (r.response_code ? '#ef4444' : '#94a3b8');
      const catColor = {
        chat: '#3b82f6', campaign: '#8b5cf6',
        message_bot: '#06b6d4', template_bot: '#06b6d4',
        template_sync: '#64748b',
        webhook_in: '#fbbf24', webhook_status: '#10b981', webhook_message: '#14b8a6'
      }[r.category] || '#64748b';
      tbody.appendChild(h('tr', {},
        h('td', {}, r.id),
        h('td', {}, h('span', { class: 'tag', style: { background: catColor, color: '#fff', fontSize: '.7rem' } }, r.category)),
        h('td', {}, r.name || '—'),
        h('td', {}, r.template_name ? h('code', {}, r.template_name) : '—'),
        h('td', {}, h('span', { class: 'tag', style: { background: codeColor, color: '#fff' } }, r.response_code || '—')),
        h('td', { class: 'muted' }, r.type || '—'),
        h('td', { class: 'muted', style: { whiteSpace: 'nowrap' } }, fmtDate(r.recorded_on, 'relative')),
        h('td', {}, h('button', { class: 'btn sm', onclick: () => openWbActivityDetailModal(r.id) }, '🔍 View'))
      ));
    });
  };
  catSel.onchange = reload;
  let _searchTimer = null;
  searchInp.oninput = () => { clearTimeout(_searchTimer); _searchTimer = setTimeout(reload, 300); };

  wrap.appendChild(h('div', { class: 'toolbar' },
    h('h3', { style: { margin: 0 } }, '📑 Activity log'),
    catSel,
    searchInp,
    h('button', { class: 'btn', onclick: reload, title: 'Refresh' }, '🔄'),
    // Download raw webhook events as plain text (for offline analysis /
    // sharing). Uses api_wb_webhook_logs_text which dumps all webhook_in /
    // webhook_status / webhook_message entries with full JSON.
    h('button', { class: 'btn', title: 'Download raw webhook log as wa_webhook_logs.txt', onclick: async () => {
      try {
        toast('Building log…');
        const txt = await api('api_wb_webhook_logs_text');
        const blob = new Blob([txt], { type: 'text/plain' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'wa_webhook_logs_' + new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19) + '.txt';
        document.body.appendChild(a); a.click();
        setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 100);
        toast('Downloaded');
      } catch (e) { toast(e.message, 'err'); }
    } }, '⬇️ Download .txt'),
    h('button', { class: 'btn ghost danger', onclick: async () => {
      if (!await confirmDialog('Clear all activity log entries?')) return;
      await api('api_wb_activity_clear'); toast('Cleared'); showWbTab('activity');
    } }, '🗑️ Clear log')
  ));

  wrap.appendChild(h('p', { class: 'muted', style: { fontSize: '.85rem' } },
    'Every send to Meta and every webhook from Meta is logged here. ',
    'Click 🔍 View on any row to see the full request/response JSON. ',
    'Webhook URL: ', h('code', {}, location.origin + '/hook/whatsapp_webhook')
  ));

  wrap.appendChild(h('div', { class: 'table-wrap' }, h('table', { class: 'mini-table' },
    h('thead', {}, h('tr', {},
      h('th', {}, '#'), h('th', {}, 'Category'), h('th', {}, 'Name'),
      h('th', {}, 'Template'), h('th', {}, 'Code'), h('th', {}, 'Type'),
      h('th', {}, 'Recorded on'), h('th', {}, '')
    )),
    tbody
  )));
  await reload();
  return wrap;
}

/**
 * Detail modal — shows the full request and response JSON for a single
 * activity log row. Two-column layout (request / response) with clean
 * pretty-printing so the user can read what we sent to Meta and what
 * Meta sent back.
 */
async function openWbActivityDetailModal(id) {
  const m = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const body = h('div', { class: 'modal modal-lg' });
  body.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, '📑 Activity #' + id),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));
  const content = h('div', {}, h('div', { class: 'muted' }, 'Loading…'));
  body.appendChild(content);
  m.appendChild(body);
  document.body.appendChild(m);

  try {
    const r = await api('api_wb_activity_get', id);
    content.innerHTML = '';
    // Header row
    content.appendChild(h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '.5rem', marginBottom: '1rem' } },
      h('span', { class: 'tag', style: { background: '#3b82f6', color: '#fff' } }, r.category || ''),
      r.name ? h('span', { class: 'tag', style: { background: '#64748b', color: '#fff' } }, r.name) : null,
      r.template_name ? h('span', { class: 'tag', style: { background: '#10b981', color: '#fff' } }, r.template_name) : null,
      r.response_code ? h('span', { class: 'tag', style: { background: r.response_code === 200 ? '#10b981' : '#ef4444', color: '#fff' } }, 'HTTP ' + r.response_code) : null,
      h('span', { class: 'muted' }, fmtDate(r.recorded_on))
    ));
    // Two-column request/response viewer
    const grid = h('div', { class: 'wb-act-grid' });
    grid.appendChild(h('div', { class: 'card' },
      h('h4', { style: { marginTop: 0 } }, '📤 Request (we sent)'),
      h('pre', { class: 'wb-json' }, JSON.stringify(r.request || {}, null, 2))
    ));
    grid.appendChild(h('div', { class: 'card' },
      h('h4', { style: { marginTop: 0 } }, '📥 Response (Meta returned)'),
      h('pre', { class: 'wb-json' }, JSON.stringify(r.response || {}, null, 2))
    ));
    content.appendChild(grid);
    // Copy buttons
    content.appendChild(h('div', { style: { marginTop: '1rem' } },
      h('button', { class: 'btn sm', onclick: () => { navigator.clipboard.writeText(JSON.stringify(r, null, 2)); toast('Copied full JSON'); } }, '📋 Copy full JSON')
    ));
  } catch (e) {
    content.innerHTML = '';
    content.appendChild(h('div', { class: 'error-box' }, 'Could not load: ' + e.message));
  }
}

/**
 * TAT report view. Shows three sections:
 *   - Top KPI cards   (open violations, total leads, avg first-action min)
 *   - Per-user table  (avg time-to-1st-action, avg time-to-2nd-action)
 *   - Per-stage table (avg minutes leads spend in each stage)
 *   - Active violation list (escalation level, age, assignee)
 * Filters by date range + user.
 */
/* ===========================================================
 * Monthly Target dashboard — every metric requested by product:
 *   - Revenue Achieved        - Required Daily Target (Auto)
 *   - Target Remaining         - Conversion Rate
 *   - Days Left                - Forecasted Revenue
 *   - Achievement %            - Funnel Conversion
 *   - Weekly Trend             - Lead vs Sale Conversion Rate
 *   - Revenue Left (= Target Remaining alias)
 * Admins/managers can set targets per rep + org-wide.
 * Reps see their own scope by default.
 * =========================================================== */

function _tInr(v) {
  const n = Number(v);
  if (!isFinite(n) || n <= 0) return '—';
  if (n >= 10000000) return '₹' + (n / 10000000).toFixed(2) + ' Cr';
  if (n >= 100000)   return '₹' + (n / 100000).toFixed(2) + ' L';
  if (n >= 1000)     return '₹' + (n / 1000).toFixed(1) + 'k';
  return '₹' + n.toFixed(0);
}
function _tPct(v) { return v == null ? '—' : (Math.round(v * 10) / 10) + '%'; }

/* ---------------- Inventory ---------------- */
VIEWS.inventory = async (view) => {
  const isAdminMgr = ['admin', 'manager'].includes(CRM.user.role);
  view.innerHTML = '';
  let q = '';
  let statusFilter = 'available';
  let typeFilter = '';

  const head = h('div', { class: 'card', style: { padding: '1rem', display: 'flex', flexWrap: 'wrap', gap: '.75rem', alignItems: 'center', marginBottom: '1rem' } });
  head.appendChild(h('h3', { style: { margin: 0, flex: 1 } }, '📦 Inventory'));
  const searchInput = h('input', { type: 'search', placeholder: '🔍 Name, location, description…', style: { minWidth: '220px' } });
  const statusSel = h('select', {},
    h('option', { value: '' }, 'All statuses'),
    h('option', { value: 'available', selected: 'selected' }, 'Available'),
    h('option', { value: 'blocked' }, 'Blocked'),
    h('option', { value: 'sold' }, 'Sold'),
    h('option', { value: 'inactive' }, 'Inactive')
  );
  const typeInput = h('input', { type: 'text', placeholder: 'Type filter (e.g. Flat, Plot)', style: { minWidth: '160px' } });
  head.appendChild(searchInput);
  head.appendChild(statusSel);
  head.appendChild(typeInput);
  if (isAdminMgr) {
    head.appendChild(h('button', { class: 'btn primary', onclick: () => openInventoryEditModal(null, refresh) }, '+ Add item'));
  }
  view.appendChild(head);

  const listEl = h('div', { id: 'inventory-list' });
  view.appendChild(listEl);

  let _t;
  const debounced = () => { clearTimeout(_t); _t = setTimeout(refresh, 250); };
  searchInput.oninput = () => { q = searchInput.value || ''; debounced(); };
  statusSel.onchange = () => { statusFilter = statusSel.value; refresh(); };
  typeInput.oninput  = () => { typeFilter = typeInput.value || ''; debounced(); };

  async function refresh() {
    listEl.innerHTML = '<div class="loading">Loading…</div>';
    try {
      const filters = { q };
      if (statusFilter) filters.status = statusFilter;
      if (typeFilter)   filters.item_type = typeFilter;
      const rows = await api('api_inventory_list', filters);
      listEl.innerHTML = '';
      if (!rows.length) {
        listEl.appendChild(h('p', { class: 'muted' }, 'No matching inventory.'));
        return;
      }
      const grid = h('div', { class: 'cards', style: { gap: '.75rem' } });
      rows.forEach(r => grid.appendChild(inventoryCard(r, refresh, isAdminMgr)));
      listEl.appendChild(grid);
    } catch (e) {
      listEl.innerHTML = '';
      listEl.appendChild(h('div', { class: 'error-box' }, e.message));
    }
  }
  await refresh();
};

function inventoryCard(r, refresh, isAdminMgr) {
  const statusColors = { available: '#10b981', blocked: '#f59e0b', sold: '#6b7280', inactive: '#9ca3af' };
  const card = h('div', { class: 'card', style: { padding: '1rem', display: 'flex', flexDirection: 'column', gap: '.5rem', minWidth: '260px' } },
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', justifyContent: 'space-between' } },
      h('h4', { style: { margin: 0 } }, r.name),
      h('span', {
        style: { background: statusColors[r.status] || '#6b7280', color: '#fff', padding: '.15rem .55rem', borderRadius: '999px', fontSize: '.72rem', fontWeight: 600 }
      }, String(r.status).toUpperCase())
    ),
    r.item_type ? h('div', { class: 'muted', style: { fontSize: '.85rem' } }, '📁 ' + r.item_type) : null,
    h('div', { style: { fontSize: '1.1rem', fontWeight: 600 } }, '₹ ' + Number(r.price).toLocaleString('en-IN')),
    r.location ? h('div', { class: 'muted', style: { fontSize: '.85rem' } }, '📍 ' + r.location) : null,
    r.description ? h('div', { class: 'muted', style: { fontSize: '.8rem' } },
      String(r.description).slice(0, 140) + (String(r.description).length > 140 ? '…' : '')
    ) : null,
    isAdminMgr ? h('div', { class: 'actions', style: { marginTop: '.25rem' } },
      h('button', { class: 'btn sm', onclick: () => openInventoryEditModal(r, refresh) }, '✎ Edit'),
      h('button', { class: 'btn sm danger', onclick: async () => {
        if (!await confirmDialog('Mark "' + r.name + '" inactive? It stops appearing in match suggestions.')) return;
        try { await api('api_inventory_delete', r.id); toast('Marked inactive'); refresh(); }
        catch (e) { toast(e.message, 'err'); }
      } }, '🗑')
    ) : null
  );
  return card;
}

function openInventoryEditModal(r, onSaved) {
  r = r || {};
  const modal = h('div', { class: 'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) modal.remove(); } });
  const f = (name, label, val, opts) => {
    opts = opts || {};
    return h('div', { class: 'f-row' + (opts.full ? ' full' : '') },
      h('label', {}, label),
      h('input', Object.assign({ name, value: val == null ? '' : val }, opts.attrs || { type: opts.type || 'text' }))
    );
  };
  modal.appendChild(h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, r.id ? 'Edit inventory item' : '+ New inventory item'),
      h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
    ),
    h('form', { id: 'inv-form', class: 'form-grid' },
      f('name', 'Name *', r.name, { attrs: { type: 'text', required: 'required' } }),
      f('item_type', 'Type (Flat / Plot / Plan / Product)', r.item_type),
      f('price', 'Price (₹)', r.price, { attrs: { type: 'number', min: 0, step: 1 } }),
      h('div', { class: 'f-row' },
        h('label', {}, 'Status'),
        h('select', { name: 'status' },
          ...['available', 'blocked', 'sold', 'inactive'].map(s =>
            h('option', { value: s, selected: (r.status || 'available') === s ? 'selected' : null }, s)
          )
        )
      ),
      f('location', 'Location / Address', r.location, { full: true }),
      h('div', { class: 'f-row full' },
        h('label', {}, 'Description'),
        h('textarea', { name: 'description', rows: 3 }, r.description || '')
      )
    ),
    h('div', { class: 'actions' },
      h('button', { class: 'btn', onclick: () => modal.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        const form = $('#inv-form');
        const fd = new FormData(form);
        const payload = {
          id: r.id,
          name:        fd.get('name'),
          item_type:   fd.get('item_type'),
          price:       Number(fd.get('price')) || 0,
          status:      fd.get('status') || 'available',
          location:    fd.get('location'),
          description: fd.get('description')
        };
        if (!payload.name) return toast('Name is required', 'err');
        try { await api('api_inventory_save', payload); toast('Saved'); modal.remove(); onSaved && onSaved(); }
        catch (e) { toast(e.message, 'err'); }
      } }, 'Save')
    )
  ));
  document.body.appendChild(modal);
}

/* ---------------- Sale Final Closure (post-sale stage board) ---------------- */
VIEWS.projects = async (view) => {
  view.innerHTML = '';
  view.appendChild(h('div', { class: 'card', style: { padding: '1rem', display: 'flex', alignItems: 'center', gap: '.75rem', flexWrap: 'wrap', marginBottom: '1rem' } },
    h('h3', { style: { margin: 0, flex: 1 } }, '🚚 Sale Final Closure pipeline'),
    h('span', { class: 'muted', style: { fontSize: '.85rem' } },
      'Every lead that has entered the post-sale stage tracker, grouped by stage. Stalled cards are flagged.'),
    ['admin'].includes(CRM.user.role)
      ? h('a', { class: 'btn', href: '#/admin', onclick: () => setTimeout(() => showAdminTab('projstages'), 100) }, '⚙ Edit stages')
      : null
  ));

  /* SALE_CLOSURE_FILTERS_v1 — filter toolbar.
   * Date range filters by project_stage_started_at (entered closure).
   * Multi-select for users / sources / products mirrors the leads page UX.
   * State persists per-user in localStorage so filters survive page reloads. */
  const _filtersKey = 'crm_projects_filters_v1';
  let filtersState = {};
  try { filtersState = JSON.parse(localStorage.getItem(_filtersKey) || '{}'); } catch (_) {}

  const users    = (window.CRM && CRM.cache && CRM.cache.users)    || [];
  const sources  = (window.CRM && CRM.cache && CRM.cache.sources)  || [];
  const products = (window.CRM && CRM.cache && CRM.cache.products) || [];

  const fromInp = h('input', { type: 'date', class: 'input', value: filtersState.from || '', style: { width: '150px' } });
  const toInp   = h('input', { type: 'date', class: 'input', value: filtersState.to   || '', style: { width: '150px' } });
  // DATE_PRESETS_v1
  setTimeout(() => { try { window._attachDatePresets && window._attachDatePresets(fromInp, toInp, { key: 'activity', apply: () => { try { applyFilters && applyFilters(); } catch (_) {} } }); } catch (_) {} }, 0);
  const userSel = h('select', { class: 'input', multiple: 'multiple', style: { minWidth: '200px', height: '34px' }, title: 'Assigned to (multi-select)' },
    ...users.map(u => h('option', { value: String(u.id),
      selected: (filtersState.assigned_tos || []).map(String).includes(String(u.id)) ? 'selected' : null }, u.name))
  );
  const srcSel = h('select', { class: 'input', multiple: 'multiple', style: { minWidth: '200px', height: '34px' }, title: 'Source (multi-select)' },
    ...sources.map(sr => h('option', { value: String(sr.name || sr),
      selected: (filtersState.sources || []).map(String).includes(String(sr.name || sr)) ? 'selected' : null }, (sr.name || sr)))
  );
  const prodSel = h('select', { class: 'input', multiple: 'multiple', style: { minWidth: '200px', height: '34px' }, title: 'Product (multi-select)' },
    ...products.map(pr => h('option', { value: String(pr.id),
      selected: (filtersState.product_ids || []).map(String).includes(String(pr.id)) ? 'selected' : null }, pr.name))
  );
  const stalledChk = h('input', { type: 'checkbox', checked: filtersState.stalled_only ? 'checked' : null });

  function _collectFilters() {
    return {
      from: fromInp.value || null,
      to:   toInp.value   || null,
      assigned_tos: Array.from(userSel.selectedOptions).map(o => Number(o.value)),
      sources:      Array.from(srcSel.selectedOptions).map(o => o.value),
      product_ids:  Array.from(prodSel.selectedOptions).map(o => Number(o.value)),
      stalled_only: stalledChk.checked ? 1 : 0
    };
  }
  function _persistFilters() {
    try { localStorage.setItem(_filtersKey, JSON.stringify(_collectFilters())); } catch (_) {}
  }

  const applyBtn = h('button', { class: 'btn primary' }, '🔍 Apply');
  const clearBtn = h('button', { class: 'btn' }, '✖ Clear');
  const expBtn   = h('button', { class: 'btn', title: 'Export current view to CSV' }, '⬇ CSV');

  const filterBar = h('div', { class: 'card', style: { padding: '.7rem', display: 'flex', gap: '.5rem', flexWrap: 'wrap', alignItems: 'center', marginBottom: '.7rem', background: '#f8fafc' } },
    h('label', { class: 'muted', style: { fontSize: '.78rem' } }, 'From'), fromInp,
    h('label', { class: 'muted', style: { fontSize: '.78rem' } }, 'To'),   toInp,
    h('label', { class: 'muted', style: { fontSize: '.78rem' } }, 'Caller'), userSel,
    h('label', { class: 'muted', style: { fontSize: '.78rem' } }, 'Source'), srcSel,
    h('label', { class: 'muted', style: { fontSize: '.78rem' } }, 'Product'), prodSel,
    h('label', { style: { fontSize: '.85rem', display: 'flex', alignItems: 'center', gap: '.3rem' } }, stalledChk, ' Stalled only'),
    applyBtn, clearBtn, expBtn
  );
  view.appendChild(filterBar);

  const listEl = h('div', { id: 'proj-board' }, h('div', { class: 'loading' }, 'Loading…'));
  view.appendChild(listEl);

  async function _load() {
    listEl.innerHTML = '';
    listEl.appendChild(h('div', { class: 'loading' }, 'Loading…'));
    _persistFilters();
    let board;
    try { board = await api('api_projectStages_board', _collectFilters()); }
    catch (e) {
      listEl.innerHTML = '';
      listEl.appendChild(h('div', { class: 'error-box' }, e.message));
      return;
    }
    _renderBoard(board, listEl);
  }
  applyBtn.onclick = _load;
  clearBtn.onclick = () => {
    fromInp.value = ''; toInp.value = '';
    Array.from(userSel.options).forEach(o => o.selected = false);
    Array.from(srcSel.options).forEach(o  => o.selected = false);
    Array.from(prodSel.options).forEach(o => o.selected = false);
    stalledChk.checked = false;
    _load();
  };
  expBtn.onclick = async () => {
    try {
      const board = await api('api_projectStages_board', _collectFilters());
      const flat = [];
      board.board.forEach(col => col.leads.forEach(l => flat.push({
        stage: col.stage.name, name: l.name, phone: l.phone || '',
        assigned: l.assigned_name || '', source: l.source || '',
        product: l.product_name || '', value: l.value || 0,
        days_at_stage: l.days_at_stage == null ? '' : l.days_at_stage,
        stalled: l.stalled ? 'YES' : '', entered_at: l.project_stage_started_at || ''
      })));
      if (!flat.length) { toast('Nothing to export', 'err'); return; }
      const cols = Object.keys(flat[0]);
      const csv = [cols.join(',')].concat(flat.map(r => cols.map(c => '"' + String(r[c] || '').replace(/"/g, '""') + '"').join(','))).join('\n');
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob); const a = document.createElement('a');
      a.href = url; a.download = 'sale-closure-' + new Date().toISOString().slice(0,10) + '.csv';
      a.click(); URL.revokeObjectURL(url);
    } catch (e) { toast(e.message, 'err'); }
  };

  let board;
  try { board = await api('api_projectStages_board', _collectFilters()); }
  catch (e) {
    listEl.innerHTML = '';
    listEl.appendChild(h('div', { class: 'error-box' }, e.message));
    return;
  }

  _renderBoard(board, listEl);
};

/* SALE_CLOSURE_FILTERS_v1 — extracted renderer so initial + filter reloads share code. */
function _renderBoard(board, listEl) {
  listEl.innerHTML = '';
  if (!board.stages.length) {
    listEl.appendChild(h('p', { class: 'muted' },
      'No stages defined yet. Admin: head to Settings → 🚚 Sale Final Closure Stages to create your closure workflow.'));
    return;
  }
  const totalLeads = board.board.reduce((n, col) => n + col.leads.length, 0);
  if (!totalLeads) {
    listEl.appendChild(h('p', { class: 'muted' },
      'No leads match your filters (or no leads are in final closure yet).'));
    return;
  }
  // Show a small filter summary so users know what's active
  const wrap = h('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: '.75rem' } });
  board.board.forEach(col => {
    const stalledCount = col.leads.filter(l => l.stalled).length;
    const head = h('div', { style: { display: 'flex', alignItems: 'center', gap: '.4rem', padding: '.5rem .75rem', background: '#f3f4f6', borderRadius: '6px 6px 0 0', borderBottom: '2px solid #3b82f6' } },
      h('span', { style: { fontWeight: 600, flex: 1 } }, col.stage.name),
      h('span', { class: 'tag', style: { background: '#dbeafe', color: '#1e40af' } }, col.leads.length),
      stalledCount ? h('span', { class: 'tag', style: { background: '#fef2f2', color: '#991b1b' }, title: stalledCount + ' lead(s) stuck longer than expected' }, '⚠ ' + stalledCount) : null
    );
    const colWrap = h('div', { class: 'card', style: { padding: 0, display: 'flex', flexDirection: 'column', gap: 0 } });
    colWrap.appendChild(head);
    if (col.leads.length === 0) {
      colWrap.appendChild(h('p', { class: 'muted', style: { padding: '.75rem', margin: 0, fontSize: '.85rem' } }, 'No leads here.'));
    }
    col.leads.forEach(l => {
      colWrap.appendChild(h('div', {
        class: 'card', style: { margin: '.4rem .5rem', padding: '.6rem .75rem', cursor: 'pointer', borderLeft: l.stalled ? '3px solid #ef4444' : '3px solid #e5e7eb' },
        onclick: () => openLeadModal(l.id)
      },
        h('div', { style: { fontWeight: 600 } }, l.name),
        l.value ? h('div', { class: 'muted', style: { fontSize: '.8rem' } }, '₹ ' + Number(l.value).toLocaleString('en-IN')) : null,
        l.assigned_name ? h('div', { class: 'muted', style: { fontSize: '.78rem' } }, '👤 ' + l.assigned_name) : null,
        l.source ? h('div', { class: 'muted', style: { fontSize: '.78rem' } }, '🌐 ' + l.source) : null,
        l.product_name ? h('div', { class: 'muted', style: { fontSize: '.78rem' } }, '📦 ' + l.product_name) : null,
        l.days_at_stage != null ? h('div', { class: 'muted', style: { fontSize: '.78rem', color: l.stalled ? '#dc2626' : '#6b7280' } },
          '⏱ ' + l.days_at_stage + 'd' + (l.stalled ? ' · STALLED (>' + col.stage.expected_days + 'd)' : '')) : null
      ));
    });
    wrap.appendChild(colWrap);
  });
  listEl.appendChild(wrap);
}

VIEWS.targets = async (view) => {
  const isAdmin = ['admin', 'manager'].includes(CRM.user.role);
  const isManagerOrUp = ['admin', 'manager', 'team_leader'].includes(CRM.user.role);
  const filtersState = JSON.parse(localStorage.getItem('crm_targets_view') || '{}');
  const monthInput = filtersState.month || new Date().toISOString().slice(0, 7);
  const scopeState = filtersState.scope || (isAdmin ? '' : String(CRM.user.id));

  view.innerHTML = '';

  // ---- Toolbar -------------------------------------------------------
  const monthSel = h('input', { type: 'month', value: monthInput, style: { width: '160px' } });
  const scopeSel = h('select', { id: 'tg-scope' });
  scopeSel.appendChild(h('option', { value: '' }, '🏢 Org-wide'));
  (CRM.cache.users || []).filter(u => isManagerOrUp || Number(u.id) === Number(CRM.user.id)).forEach(u => {
    scopeSel.appendChild(h('option', { value: String(u.id), selected: String(u.id) === scopeState ? 'selected' : null }, u.name));
  });
  if (scopeState) scopeSel.value = scopeState;

  monthSel.addEventListener('change', () => {
    filtersState.month = monthSel.value;
    localStorage.setItem('crm_targets_view', JSON.stringify(filtersState));
    refresh();
  });
  scopeSel.addEventListener('change', () => {
    filtersState.scope = scopeSel.value;
    localStorage.setItem('crm_targets_view', JSON.stringify(filtersState));
    refresh();
  });

  const toolbar = h('div', { class: 'toolbar' },
    h('label', { class: 'muted', style: { marginRight: '4px' } }, 'Month'),
    monthSel,
    h('label', { class: 'muted', style: { marginLeft: '8px', marginRight: '4px' } }, 'Scope'),
    scopeSel,
    h('button', { class: 'btn', onclick: refresh }, '🔄'),
    isAdmin ? h('button', { class: 'btn primary', onclick: () => openSetTargetModal(monthSel.value, scopeSel.value, refresh) }, '🎯 Set target') : null
  );
  view.appendChild(toolbar);

  const body = h('div', {});
  view.appendChild(body);

  async function refresh() {
    body.innerHTML = '';
    body.appendChild(h('div', { class: 'muted', style: { padding: '2rem', textAlign: 'center' } }, 'Crunching numbers…'));
    let r;
    try {
      r = await api('api_targets_dashboard', monthSel.value, scopeSel.value || null);
    } catch (e) { body.innerHTML = ''; return body.appendChild(h('div', { class: 'error' }, e.message)); }
    body.innerHTML = '';
    renderDashboard(body, r);
  }
  refresh();
};

function renderDashboard(body, r) {
  const isAdmin = ['admin', 'manager'].includes(CRM.user.role);

  // ---- Header strip --------------------------------------------------
  body.appendChild(h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: '12px', flexWrap: 'wrap', gap: '8px' } },
    h('h2', { style: { margin: 0 } }, '🎯 ' + r.month + ' · ' + r.scope.label),
    h('div', { class: 'muted', style: { fontSize: '.85rem' } },
      r.days_passed + ' of ' + r.days_in_month + ' days passed · ',
      h('strong', { style: { color: 'var(--brand-dark)' } }, r.days_left + ' days left')
    )
  ));

  // ---- Big KPI grid (the metrics product asked for) -----------------
  const kpi = (label, value, sub, color) => h('div', { style: {
    background: color || 'var(--bg-alt)',
    padding: '14px 16px',
    borderRadius: '10px',
    minWidth: '0'
  } },
    h('div', { class: 'muted', style: { fontSize: '.7rem', textTransform: 'uppercase', letterSpacing: '.05em', fontWeight: 600 } }, label),
    h('div', { style: { fontSize: '1.7rem', fontWeight: 600, marginTop: '4px', lineHeight: '1.1' } }, value),
    sub ? h('div', { class: 'muted', style: { fontSize: '.72rem', marginTop: '4px' } }, sub) : null
  );

  body.appendChild(h('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '10px', marginBottom: '14px' } },
    kpi('Target', _tInr(r.target_revenue),
      r.target_revenue ? null : 'Not set yet — admin can set above',
      'var(--brand-soft)'),
    kpi('Revenue Achieved', _tInr(r.revenue_achieved), r.won_leads + ' deals closed', 'var(--ok-soft)'),
    kpi('Target Remaining', _tInr(r.target_remaining), 'a.k.a. Revenue Left', 'var(--warn-soft)'),
    kpi('Days Left', r.days_left, r.days_in_month + '-day month'),
    kpi('Required Daily', _tInr(r.required_daily_target), r.days_left > 0 ? 'to hit target' : 'month closed'),
    kpi('Achievement %',
      r.achievement_pct == null ? '—' : (r.achievement_pct + '%'),
      r.achievement_pct == null ? 'set a target to see' : null,
      r.achievement_pct == null ? 'var(--bg-alt)' : (r.achievement_pct >= 100 ? 'var(--ok-soft)' : r.achievement_pct >= 60 ? 'var(--warn-soft)' : 'var(--err-soft)')),
    kpi('Forecasted Revenue', _tInr(r.forecast_revenue),
      r.forecast_vs_target_pct != null ? (r.forecast_vs_target_pct + '% of target') : 'pace × days in month'),
    kpi('Conversion Rate', _tPct(r.conversion_rate),
      r.new_leads + ' new · ' + r.won_leads + ' won', 'var(--brand-soft)')
  ));

  // ---- Achievement progress bar -------------------------------------
  if (r.achievement_pct != null) {
    const pct = Math.min(100, Math.max(0, r.achievement_pct));
    body.appendChild(h('div', { style: { marginBottom: '18px' } },
      h('div', { style: { display: 'flex', justifyContent: 'space-between', fontSize: '.8rem', marginBottom: '4px' } },
        h('span', { class: 'muted' }, _tInr(r.revenue_achieved) + ' of ' + _tInr(r.target_revenue)),
        h('span', {}, h('strong', {}, _tPct(r.achievement_pct)))
      ),
      h('div', { style: { height: '14px', background: 'var(--bg-alt)', borderRadius: '7px', overflow: 'hidden' } },
        h('div', { style: {
          width: pct + '%', height: '100%',
          background: r.achievement_pct >= 100 ? 'var(--ok)' : r.achievement_pct >= 60 ? 'var(--warn)' : 'var(--err)',
          transition: 'width .4s'
        } })
      )
    ));
  }

  // ---- Weekly Trend chart -------------------------------------------
  if (r.weekly_trend && r.weekly_trend.length) {
    body.appendChild(h('h3', { style: { marginTop: '12px', marginBottom: '6px' } }, 'Weekly trend'));
    const wrap = h('div', { class: 'chart-wrap', style: { height: '220px', marginBottom: '20px' } });
    const canvas = h('canvas');
    wrap.appendChild(canvas);
    body.appendChild(wrap);
    setTimeout(() => {
      // eslint-disable-next-line no-undef
      const ctx = canvas.getContext('2d');
      // eslint-disable-next-line no-undef
      new Chart(ctx, {
        type: 'bar',
        data: {
          labels: r.weekly_trend.map(w => w.week_start),
          datasets: [
            { label: 'Revenue', data: r.weekly_trend.map(w => Math.round(w.revenue)), backgroundColor: '#10b981', yAxisID: 'y' },
            { label: 'Leads in', data: r.weekly_trend.map(w => w.leads), backgroundColor: '#6366f1', type: 'line', borderColor: '#6366f1', tension: .3, yAxisID: 'y1' }
          ]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          scales: {
            y:  { beginAtZero: true, position: 'left', ticks: { callback: v => _tInr(v) } },
            y1: { beginAtZero: true, position: 'right', grid: { display: false }, title: { display: true, text: 'Leads' } }
          }
        }
      });
    }, 10);
  }

  // ---- Funnel conversion --------------------------------------------
  if (r.funnel && r.funnel.length) {
    body.appendChild(h('h3', { style: { marginTop: '12px', marginBottom: '6px' } }, 'Funnel conversion'));
    body.appendChild(h('p', { class: 'muted', style: { fontSize: '.78rem', marginTop: 0, marginBottom: '8px' } },
      'Leads created in ' + r.month + ', currently in each stage. Drop-off is computed against the previous stage.'));
    const fTable = h('table', { class: 'leads-table', style: { fontSize: '.85rem' } },
      h('thead', {}, h('tr', {},
        h('th', {}, 'Stage'),
        h('th', { style: { textAlign: 'right' } }, 'Count'),
        h('th', { style: { textAlign: 'right' } }, '% of total'),
        h('th', { style: { textAlign: 'right' } }, 'Drop-off vs previous')
      )),
      h('tbody', {}, ...r.funnel.map(f => h('tr', {},
        h('td', {}, h('span', { class: 'tag', style: { background: f.color || 'var(--bg-alt)', color: '#fff' } }, f.name)),
        h('td', { style: { textAlign: 'right', fontWeight: 500 } }, f.count),
        h('td', { style: { textAlign: 'right' } }, _tPct(f.pct_of_total)),
        h('td', { style: { textAlign: 'right', color: f.drop_pct != null && f.drop_pct > 0 ? 'var(--err)' : 'var(--text-soft)' } },
          f.drop_pct == null ? '—' : ('-' + Math.round(f.drop_pct) + '%'))
      )))
    );
    body.appendChild(fTable);
  }

  // ---- Per-rep breakdown (org-wide view only) -----------------------
  if (r.rep_breakdown && r.rep_breakdown.length) {
    body.appendChild(h('h3', { style: { marginTop: '20px', marginBottom: '6px' } }, 'Per-rep performance'));
    const repTable = h('table', { class: 'leads-table', style: { fontSize: '.85rem' } },
      h('thead', {}, h('tr', {},
        h('th', {}, 'Rep'),
        h('th', { style: { textAlign: 'right' } }, 'Revenue'),
        h('th', { style: { textAlign: 'right' } }, 'Target'),
        h('th', { style: { textAlign: 'right' } }, 'Achievement'),
        h('th', { style: { textAlign: 'right' } }, 'New'),
        h('th', { style: { textAlign: 'right' } }, 'Won'),
        h('th', { style: { textAlign: 'right' } }, 'Conv. %')
      )),
      h('tbody', {}, ...r.rep_breakdown.map(rep => h('tr', {},
        h('td', {}, rep.name),
        h('td', { style: { textAlign: 'right', fontWeight: 500 } }, _tInr(rep.revenue_achieved)),
        h('td', { style: { textAlign: 'right' } }, rep.target_revenue ? _tInr(rep.target_revenue) : '—'),
        h('td', { style: { textAlign: 'right' } },
          rep.achievement_pct == null
            ? h('span', { class: 'muted' }, '—')
            : h('span', { class: 'tag', style: {
                background: rep.achievement_pct >= 100 ? 'var(--ok-soft)' : rep.achievement_pct >= 60 ? 'var(--warn-soft)' : 'var(--err-soft)',
                color:      rep.achievement_pct >= 100 ? 'var(--ok)'      : rep.achievement_pct >= 60 ? 'var(--warn)'      : 'var(--err)'
              } }, _tPct(rep.achievement_pct))
        ),
        h('td', { style: { textAlign: 'right' } }, rep.new_leads),
        h('td', { style: { textAlign: 'right' } }, rep.won_leads),
        h('td', { style: { textAlign: 'right' } }, _tPct(rep.conversion_rate))
      )))
    );
    body.appendChild(repTable);
  }
}

/**
 * Modal for admin/manager to set / edit a monthly target. user_id = ''
 * means org-wide; a numeric value means a specific rep.
 */
async function openSetTargetModal(month, userId, onDone) {
  let existing = null;
  try { existing = await api('api_targets_get', month, userId || null); }
  catch (e) { /* ignore */ }
  const e = existing || {};
  const userField = h('select', { id: 'tg-user' });
  userField.appendChild(h('option', { value: '', selected: !userId ? 'selected' : null }, '🏢 Org-wide target'));
  (CRM.cache.users || []).forEach(u => userField.appendChild(h('option', { value: String(u.id), selected: String(u.id) === String(userId) ? 'selected' : null }, u.name)));

  const monthField = h('input', { type: 'month', value: month || new Date().toISOString().slice(0, 7) });
  const revInput = h('input', { type: 'number', step: '0.01', min: '0', value: e.target_revenue || '' });
  const leadsInput = h('input', { type: 'number', min: '0', value: e.target_leads || '' });
  const salesInput = h('input', { type: 'number', min: '0', value: e.target_sales || '' });
  const callsInput = h('input', { type: 'number', min: '0', value: e.target_calls || '' });
  const notesInput = h('textarea', { rows: 2 }, e.notes || '');

  const modal = h('div', { class: 'modal-backdrop' }, h('div', { class: 'modal' },
    h('div', { class: 'modal-head' },
      h('h3', {}, '🎯 Set monthly target'),
      h('button', { class: 'btn icon', onclick: () => modal.remove() }, '✕')
    ),
    h('div', { class: 'form-grid' },
      h('div', { class: 'f-row' }, h('label', {}, 'Month'), monthField),
      h('div', { class: 'f-row' }, h('label', {}, 'Scope'), userField),
      h('div', { class: 'f-row' }, h('label', {}, 'Target revenue (₹)'), revInput),
      h('div', { class: 'f-row' }, h('label', {}, 'Target new leads'), leadsInput),
      h('div', { class: 'f-row' }, h('label', {}, 'Target sales count'), salesInput),
      h('div', { class: 'f-row' }, h('label', {}, 'Target calls'), callsInput),
      h('div', { class: 'f-row full' }, h('label', {}, 'Notes'), notesInput)
    ),
    h('div', { class: 'actions' },
      h('button', { class: 'btn', onclick: () => modal.remove() }, 'Cancel'),
      h('button', { class: 'btn primary', onclick: async () => {
        try {
          await api('api_targets_save', {
            month: monthField.value,
            user_id: userField.value || null,
            target_revenue: Number(revInput.value) || 0,
            target_leads:   Number(leadsInput.value) || 0,
            target_sales:   Number(salesInput.value) || 0,
            target_calls:   Number(callsInput.value) || 0,
            notes: notesInput.value
          });
          toast('Target saved');
          modal.remove();
          if (onDone) onDone();
        } catch (e) { toast(e.message, 'err'); }
      } }, 'Save target')
    )
  ));
  document.body.appendChild(modal);
}

/**
 * Call ratings report — rep-wise call quality summary.
 * Shows total calls, rated calls, manual avg, AI-suggested avg, and a
 * 1★→5★ distribution bar per rep. Supports date range + user filter.
 */
/**
 * AI usage report — month-to-date Gemini cost + per-rep breakdown.
 * Shows actual cost (vendor) and billable cost (with markup).
 * Plus a cost estimator that converts X minutes → ₹.
 */
/**
 * Call activity report — calls/talk-time/missed/idle/gap broken
 * down by user and manager with top + bottom performers.
 * Renders KPI cards + per-user table + per-manager rollup + a
 * daily trend chart. Filter by date + optional user picker.
 */

// BULK_AUDIT_HISTORY_v1 — reusable Bulk AI Audit toolbar (used by Call Activity + Recordings settings page)
function _buildBulkAuditBar(opts) {
  // Admins + managers only — same gate the Call Insights page uses.
  if (!['admin','manager'].includes((CRM.user || {}).role)) return null;
  const onDone = opts && opts.onDone;
  const bar = h('div', { class: 'card', style: { padding: '.7rem .9rem', margin: '0 0 1rem', display: 'flex', flexWrap: 'wrap', gap: '.5rem', alignItems: 'center', background: '#f1f5f9' } },
    h('span', { style: { fontWeight: 600 } }, '🤖 Bulk AI Audit'),
    h('span', { class: 'muted', style: { fontSize: '.82rem' } }, 'Queue many recordings at once.')
  );
  const scopeSel = h('select', { class: 'input', style: { maxWidth: '220px' } },
    h('option', { value: 'unprocessed', selected: 'selected' }, 'All unaudited recordings'),
    h('option', { value: 'failed' }, 'Previously failed only'),
    h('option', { value: 'all' }, 'Force re-audit ALL (last 2000)')
  );
  const userSel = h('select', { class: 'input', style: { maxWidth: '180px' } },
    h('option', { value: '' }, 'All reps'),
    ...((CRM.cache.users || []).map(u => h('option', { value: u.id }, u.name)))
  );
  const limitInp = h('input', { class: 'input', type: 'number', min: 1, max: 2000, value: 500, style: { width: '90px' }, title: 'Max number of recordings to process' });
  const runBtn = h('button', { class: 'btn primary' }, '🚀 Run audit');
  runBtn.onclick = async () => {
    const scope = scopeSel.value;
    if (scope === 'all' && !confirm('Re-audit ALL recordings? This wipes existing summaries and re-runs Gemini on every recording. Can be expensive.')) return;
    runBtn.disabled = true; runBtn.textContent = '⏳ Queueing…';
    try {
      const r = await api('api_recording_bulkAudit', {
        scope,
        limit: Number(limitInp.value) || 500,
        user_id: userSel.value ? Number(userSel.value) : null
      });
      if (typeof toast === 'function') toast('✅ Queued ' + r.queued + ' recordings — AI processing in background', 'ok');
      if (typeof onDone === 'function') setTimeout(onDone, 8000);
    } catch (e) {
      if (typeof toast === 'function') toast('⚠ ' + e.message, 'err');
    } finally {
      runBtn.disabled = false; runBtn.textContent = '🚀 Run audit';
    }
  };
  bar.appendChild(scopeSel);
  bar.appendChild(userSel);
  bar.appendChild(limitInp);
  bar.appendChild(runBtn);
  return bar;
}
window._buildBulkAuditBar = _buildBulkAuditBar;

VIEWS.callactivity = async (view) => {
  await ensureChartJs();
  view.innerHTML = '';
  const { users = [] } = CRM.cache;

  // Default range: last 30 days
  const today = new Date();
  const from30 = new Date(today.getTime() - 30 * 86400 * 1000);
  const isoDate = d => d.toISOString().slice(0, 10);

  const _caFrom = h('input', { type: 'date', id: 'ca-from', value: isoDate(from30) });
  const _caTo   = h('input', { type: 'date', id: 'ca-to',   value: isoDate(today) });
  const toolbar = h('div', { class: 'toolbar' },
    _caFrom,
    h('span', {}, 'to'),
    _caTo,
    h('select', { id: 'ca-user' },
      h('option', { value: '' }, 'All users'),
      ...users.map(u => h('option', { value: String(u.id) }, u.name))
    ),
    h('button', { class: 'btn primary', onclick: () => loadCallActivity() }, '🔎 Apply'),
    h('button', { class: 'btn', onclick: () => downloadCallActivityCsv() }, '⬇️ CSV')
  );
  view.appendChild(toolbar);
  setTimeout(() => { try { window._attachDatePresets && window._attachDatePresets(_caFrom, _caTo, { key: 'callactivity', apply: () => { try { loadCallActivity(); } catch (_) {} } }); } catch (_) {} }, 0);
  // BULK_AUDIT_HISTORY_v1 — Bulk AI Audit toolbar (admin/manager only).
  { const bar = _buildBulkAuditBar({ onDone: () => { try { loadCallActivity(); } catch(_) {} } }); if (bar) view.appendChild(bar); }

  view.appendChild(h('div', { id: 'ca-cards', class: 'cards' }));
  view.appendChild(h('div', { class: 'chart-grid' },
    h('div', { class: 'card card-wide' },
      h('h3', {}, 'Daily call activity'),
      h('div', { class: 'chart-wrap' }, h('canvas', { id: 'ca-chart' }))
    ),
    h('div', { class: 'card' },
      h('h3', {}, '🏆 Top performers'),
      h('div', { id: 'ca-top' })
    ),
    h('div', { class: 'card' },
      h('h3', {}, '🐢 Needs improvement'),
      h('div', { id: 'ca-bottom' })
    ),
  ));
  view.appendChild(h('div', { class: 'card' },
    h('h3', {}, 'By user'),
    h('div', { id: 'ca-byuser', style: { overflowX: 'auto' } })
  ));
  view.appendChild(h('div', { class: 'card' },
    h('h3', {}, 'By manager'),
    h('div', { id: 'ca-bymgr', style: { overflowX: 'auto' } })
  ));
  view.appendChild(h('div', { class: 'card' },
    h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '.4rem' } },
      h('h3', { style: { margin: 0 } }, '\uD83D\uDCDE Recent calls'),
      h('span', { class: 'muted', style: { fontSize: '.8rem' } }, 'last 200 events in selected window')
    ),
    h('div', { id: 'ca-recent', style: { overflowX: 'auto' } })
  ));

  await loadCallActivity();
};

function _caSecsToHuman(s) {
  s = Number(s) || 0;
  const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sec = s % 60;
  if (h) return h + 'h ' + m + 'm';
  if (m) return m + 'm ' + sec + 's';
  return sec + 's';
}

window._caData = null;

async function loadCallActivity() {
  const from = $('#ca-from')?.value;
  const to   = $('#ca-to')?.value;
  const userId = $('#ca-user')?.value;
  const filters = {};
  if (from)   filters.from = from + 'T00:00:00';
  if (to)     filters.to   = to   + 'T23:59:59';
  if (userId) filters.userId = Number(userId);

  const cards = $('#ca-cards');
  if (cards) cards.innerHTML = '<div class="loading">Loading…</div>';

  try {
    const r = await api('api_reports_callActivity', filters);
    window._caData = r;
    _renderCallActivity(r);
  } catch (e) {
    if (cards) cards.innerHTML = '<div class="error-box">' + esc(e.message) + '</div>';
  }
}

function _renderCallActivity(r) {
  const s = r.summary || {};
  const cards = $('#ca-cards');
  if (cards) {
    cards.innerHTML = '';
    const mk = (label, val, sub) => {
      const c = h('div', { class: 'card kpi' },
        h('div', { class: 'kpi-label' }, label),
        h('div', { class: 'kpi-val' }, val)
      );
      if (sub) c.appendChild(h('div', { class: 'kpi-sub' }, sub));
      return c;
    };
    /* CALL_UNIQUE_v1 — KPI subtitles show distinct phone counts */
    cards.appendChild(mk('📞 Total calls', s.total_calls || 0, '#️⃣ ' + (s.unique_total || 0) + ' unique numbers'));
    cards.appendChild(mk('📥 Incoming',    s.incoming || 0,    '#️⃣ ' + (s.unique_incoming || 0) + ' unique callers'));
    cards.appendChild(mk('📤 Outgoing',    s.outgoing || 0,    '#️⃣ ' + (s.unique_outgoing || 0) + ' unique dialled'));
    cards.appendChild(mk('❌ Missed',      s.missed || 0,      '#️⃣ ' + (s.unique_missed || 0) + ' unique missed'));
    cards.appendChild(mk('🗣️ Total talk',    _caSecsToHuman(s.total_talk_s), 'sum of recorded durations'));
    cards.appendChild(mk('⏱️ Avg call',       _caSecsToHuman(s.avg_talk_s), 'mean of non-zero calls'));
    cards.appendChild(mk('👥 Active users',  s.total_users || 0));
    cards.appendChild(mk('💤 Idle time',     _caSecsToHuman(s.idle_s), 'work hrs − talk time'));
  }

  // By-user table
  const u = $('#ca-byuser');
  if (u) {
    const rows = r.byUser || [];
    if (!rows.length) {
      u.innerHTML = '<div class="muted">No calls in this window.</div>';
    } else {
      u.innerHTML = '';
      const t = h('table', { class: 'table' });
      t.innerHTML = '<thead><tr>' +
        '<th>Rep</th><th>Manager</th>' +
        '<th>Total</th><th>In</th><th>Out</th><th>Missed</th>' +
        /* CALL_UNIQUE_v1 */ '<th title="Distinct phone numbers contacted by this rep">Unique #s</th>' +
        '<th>Talk</th><th>Avg call</th><th>Avg gap</th><th>Last call</th>' +
        '</tr></thead><tbody>' +
        rows.map(r => '<tr>' +
          '<td>' + esc(r.user_name || '—') + '<div class="muted" style="font-size:.75rem">' + esc(r.role || '') + '</div></td>' +
          '<td>' + esc(r.manager_name || '—') + '</td>' +
          '<td>' + (r.total_calls || 0) + '</td>' +
          '<td>' + (r.in_calls || 0) + '</td>' +
          '<td>' + (r.out_calls || 0) + '</td>' +
          '<td>' + (r.missed_calls || 0) + '</td>' +
          /* CALL_UNIQUE_v1 */ '<td><b>' + (r.unique_phones || 0) + '</b>' + (r.unique_out ? ' <span class="muted" style="font-size:.78em">(' + r.unique_out + ' out)</span>' : '') + '</td>' +
          '<td>' + _caSecsToHuman(r.talk_s) + '</td>' +
          '<td>' + _caSecsToHuman(r.avg_talk_s) + '</td>' +
          '<td>' + _caSecsToHuman(r.avg_gap_s) + '</td>' +
          '<td>' + (r.last_call_at ? new Date(r.last_call_at).toLocaleString('en-IN') : '—') + '</td>' +
          '</tr>').join('') +
        '</tbody>';
      u.appendChild(t);
    }
  }

  // By-manager table
  const m = $('#ca-bymgr');
  if (m) {
    const rows = r.byManager || [];
    if (!rows.length) {
      m.innerHTML = '<div class="muted">No data.</div>';
    } else {
      m.innerHTML = '';
      const t = h('table', { class: 'table' });
      t.innerHTML = '<thead><tr><th>Manager</th><th>Team size</th><th>Total calls</th><th>In</th><th>Out</th><th>Missed</th><th>Talk</th><th>Avg call</th></tr></thead><tbody>' +
        rows.map(r => '<tr>' +
          '<td>' + esc(r.manager_name) + '</td>' +
          '<td>' + (r.team_size || 0) + '</td>' +
          '<td>' + (r.total_calls || 0) + '</td>' +
          '<td>' + (r.in || 0) + '</td>' +
          '<td>' + (r.out || 0) + '</td>' +
          '<td>' + (r.missed || 0) + '</td>' +
          '<td>' + _caSecsToHuman(r.talk_s) + '</td>' +
          '<td>' + _caSecsToHuman(r.avg_talk_s) + '</td>' +
          '</tr>').join('') +
        '</tbody>';
      m.appendChild(t);
    }
  }

  // Top / bottom performers
  const top = $('#ca-top');
  const bot = $('#ca-bottom');
  const mkList = (arr) => {
    if (!arr || !arr.length) return '<div class="muted">No data.</div>';
    return '<ol style="padding-left:1.2rem;margin:0">' + arr.map(u =>
      '<li><strong>' + esc(u.user_name) + '</strong> — ' +
      (u.total_calls || 0) + ' calls · ' + _caSecsToHuman(u.talk_s) +
      '</li>').join('') + '</ol>';
  };
  if (top) top.innerHTML = mkList(r.topUsers);
  if (bot) bot.innerHTML = mkList(r.bottomUsers);

  // Daily trend chart
  const canvas = $('#ca-chart');
  if (canvas && window.Chart) {
    const labels = (r.dailySeries || []).map(d => String(d.day).slice(0, 10));
    const dataIn  = (r.dailySeries || []).map(d => d.in_count || 0);
    const dataOut = (r.dailySeries || []).map(d => d.out_count || 0);
    const dataMs  = (r.dailySeries || []).map(d => d.missed   || 0);
    if (window._caChart) try { window._caChart.destroy(); } catch (_) {}
    window._caChart = new Chart(canvas, {
      type: 'bar',
      data: {
        labels,
        datasets: [
          { label: 'Incoming', data: dataIn,  backgroundColor: '#4285F4' },
          { label: 'Outgoing', data: dataOut, backgroundColor: '#34A853' },
          { label: 'Missed',   data: dataMs,  backgroundColor: '#EA4335' }
        ]
      },
      options: { responsive: true, maintainAspectRatio: false,
        scales: { x: { stacked: true }, y: { stacked: true, beginAtZero: true } } }
    });
  }
  // Recent calls table
  _caRenderRecent(r.recentCalls || []);
}


function _caRenderRecent(rowsAll) {
  const el = document.getElementById('ca-recent');
  if (!el) return;
  const allRows = rowsAll || [];
  // CA_FILTERS_v1 - cache full list so chip clicks re-filter w/o reload.
  window._caAllRecent = allRows;
  window._caFilter = window._caFilter || { direction: '', duration: '' };
  const fState = window._caFilter;

  function _isMissed(r) {
    // CALL_ACTIVITY_UNKNOWN_v1 — recordings whose direction couldn't be confirmed.
    if (r.direction === 'unknown') return false;
    return r.direction === 'missed' || (r.direction === 'in' && !r.recording_id && r.event === 'incoming_ringing');
  }
  function _matchDir(r) {
    if (!fState.direction) return true;
    if (fState.direction === 'missed') return _isMissed(r);
    if (fState.direction === 'in')     return r.direction === 'in'  && !_isMissed(r);
    if (fState.direction === 'out')    return r.direction === 'out';
    return true;
  }
  function _matchDur(r) {
    if (!fState.duration) return true;
    const d = Number(r.rec_duration || r.duration_s) || 0;
    if (fState.duration === 'zero')    return d === 0;
    if (fState.duration === 'u30')     return d > 0 && d < 30;
    if (fState.duration === '30_120')  return d >= 30 && d < 120;
    if (fState.duration === '120_300') return d >= 120 && d < 300;
    if (fState.duration === 'gte300')  return d >= 300;
    return true;
  }
  const rows = allRows.filter(r => _matchDir(r) && _matchDur(r));

  window._caSelectedIds = window._caSelectedIds || new Set();
  const unlinkedCount = rows.filter(r => !r.lead_id).length;

  function _chipBtn(label, group, value) {
    const on = fState[group] === value;
    return h('button', { class: 'btn',
      style: {
        padding: '.28rem .65rem', fontSize: '.78rem',
        border: '1px solid ' + (on ? '#4f46e5' : '#cbd5e1'),
        borderRadius: '999px', background: on ? '#4f46e5' : '#fff',
        color: on ? '#fff' : '#0f172a', fontWeight: on ? '600' : '500', cursor: 'pointer'
      },
      onclick: () => { fState[group] = on ? '' : value; _caRenderRecent(allRows); }
    }, label);
  }
  const fbar = h('div', { id: 'ca-recent-filterbar', style: { display: 'flex', gap: '.35rem', alignItems: 'center', flexWrap: 'wrap', padding: '.45rem .55rem', background: '#fff', border: '1px solid #e2e8f0', borderRadius: '10px', marginBottom: '.4rem' } },
    h('span', { style: { fontWeight: 600, fontSize: '.82rem', marginRight: '.2rem' } }, '\uD83D\uDD0E Filter:'),
    h('span', { class: 'muted', style: { fontSize: '.76rem', marginRight: '.15rem' } }, 'Direction'),
    _chipBtn('\uD83D\uDCF2 Incoming', 'direction', 'in'),
    _chipBtn('\uD83D\uDCDE Outgoing', 'direction', 'out'),
    _chipBtn('\u274C Missed', 'direction', 'missed'),
    h('span', { style: { width: '1px', height: '20px', background: '#cbd5e1', margin: '0 .25rem' } }),
    h('span', { class: 'muted', style: { fontSize: '.76rem', marginRight: '.15rem' } }, 'Duration'),
    _chipBtn('No-answer (0s)', 'duration', 'zero'),
    _chipBtn('< 30s',     'duration', 'u30'),
    _chipBtn('30s-2m',    'duration', '30_120'),
    _chipBtn('2-5m',      'duration', '120_300'),
    _chipBtn('5m+',       'duration', 'gte300'),
    h('span', { style: { flex: 1 } }),
    h('span', { class: 'muted', style: { fontSize: '.76rem' } }, rows.length + ' / ' + allRows.length + ' calls'),
    (fState.direction || fState.duration)
      ? h('button', { class: 'btn sm ghost', style: { color: '#dc2626' },
          onclick: () => { window._caFilter = { direction: '', duration: '' }; _caRenderRecent(allRows); } }, '\u2716 Clear')
      : null
  );

  const tb = h('div', { id: 'ca-recent-toolbar', style: { display: 'flex', gap: '.4rem', flexWrap: 'wrap', alignItems: 'center', padding: '.5rem .35rem', background: '#f8fafc', border: '1px solid #e5e7eb', borderRadius: '8px', marginBottom: '.5rem' } },
    h('span', { style: { fontWeight: 600, fontSize: '.85rem', marginRight: '.4rem' } },
      'Bulk actions:'),
    h('span', { class: 'muted', style: { fontSize: '.78rem' } },
      unlinkedCount + ' unlinked call(s) below'),
    h('span', { style: { flex: 1 } }),
    h('button', { class: 'btn sm', onclick: () => { window._caSelectedIds = new Set(rows.filter(r => !r.lead_id).map(r => r.id)); _caRenderRecent(allRows); } }, '\u2611\uFE0F Select all unlinked'),
    h('button', { class: 'btn sm ghost', onclick: () => { window._caSelectedIds = new Set(); _caRenderRecent(allRows); } }, 'Clear'),
    (function(){
      const b = h('button', { class: 'btn sm primary', onclick: () => _caBulkConvert(rows) },
        '\u2795 Add ' + window._caSelectedIds.size + ' as lead' + (window._caSelectedIds.size === 1 ? '' : 's'));
      if (!window._caSelectedIds.size) { b.disabled = true; b.style.opacity = '0.55'; b.style.cursor = 'not-allowed'; }
      return b;
    })()
  );
  el.innerHTML = '';
  el.appendChild(fbar);
  el.appendChild(tb);
  if (!rows.length) { el.appendChild(h('div', { class: 'muted', style: { padding: '.5rem' } }, 'No calls match the current filters.')); return; }
  const dirIcon = (r) => {
    if (r.direction === 'missed' || (r.direction === 'in' && !r.recording_id && r.event === 'incoming_ringing')) return '\u274C';
    if (r.direction === 'in')  return '\uD83D\uDCF2';
    if (r.direction === 'out') return '\uD83D\uDCDE';
    return '\uD83D\uDCDE';
  };
  const fmtDur = (s) => { s = Number(s) || 0; if (!s) return '—'; const m = Math.floor(s/60), ss = String(s%60).padStart(2,'0'); return m + ':' + ss; };
  const t = h('table', { class: 'table' });
  t.innerHTML = '<thead><tr>' +
    '<th style="width:24px"></th><th></th><th>Name / Phone</th><th>Rep</th><th>Direction</th><th>Duration</th><th>When</th><th></th>' +
    '</tr></thead><tbody>' +
    rows.map(r => {
      const dur = Number(r.rec_duration || r.duration_s) || 0;
      const when = new Date(r.created_at).toLocaleString('en-IN');
      const direction = (r.direction === 'unknown')
        ? 'Unknown'
        : ((r.direction === 'missed' || (r.direction === 'in' && !r.recording_id && r.event === 'incoming_ringing'))
            ? 'Missed' : (r.direction === 'in' ? 'Incoming' : (r.direction === 'out' ? 'Outgoing' : (r.direction || ''))));
      const canSelect = !r.lead_id;
      const checked = window._caSelectedIds && window._caSelectedIds.has(r.id);
      return '<tr>' +
        '<td>' + (canSelect ? '<input type="checkbox" data-ce-id="' + r.id + '" ' + (checked ? 'checked' : '') + ' />' : '') + '</td>' +
        '<td style="font-size:1.2rem">' + dirIcon(r) + '</td>' +
        '<td><strong>' + esc(r.lead_name || r.phone || '—') + '</strong>' +
          (r.lead_name && r.phone ? '<div class="muted" style="font-size:.75rem">' + esc(r.phone) + '</div>' : '') +
        '</td>' +
        '<td>' + esc(r.rep_name || '—') + '</td>' +
        '<td>' + direction + '</td>' +
        '<td>' + fmtDur(dur) + '</td>' +
        '<td>' + when + '</td>' +
        '<td>' +
          (r.lead_id ? '<button class="btn sm" onclick="openLeadModal(' + r.lead_id + ')">Open lead</button>' : '') +
        '</td>' +
        '</tr>';
    }).join('') + '</tbody>';
  el.appendChild(t);
  t.querySelectorAll('input[type=checkbox][data-ce-id]').forEach(cb => {
    cb.addEventListener('change', () => {
      const id = Number(cb.getAttribute('data-ce-id'));
      if (cb.checked) window._caSelectedIds.add(id);
      else window._caSelectedIds.delete(id);
      // Just update the count label without re-rendering the whole table
      const btn = document.querySelector('#ca-recent-toolbar button.btn.sm.primary');
      if (btn) {
        const n = window._caSelectedIds.size;
        btn.textContent = '\u2795 Add ' + n + ' as lead' + (n === 1 ? '' : 's');
        btn.disabled = n === 0;
        btn.style.opacity = n === 0 ? '0.55' : '1';
        btn.style.cursor  = n === 0 ? 'not-allowed' : 'pointer';
      }
    });
  });
}

async function _caBulkConvert(allRows) {
  const ids = Array.from(window._caSelectedIds || []);
  if (!ids.length) return toast('Select at least one call first', 'err');
  if (!confirm('Convert ' + ids.length + ' call(s) into leads?')) return;
  try {
    const r = await api('api_call_events_convertToLeads', ids);
    const ok = (r && (r.created || 0)) || 0;
    const skipped = (r && (r.skipped || 0)) || 0;
    toast('Created ' + ok + ' lead' + (ok === 1 ? '' : 's') + (skipped ? ' \u00B7 ' + skipped + ' skipped' : ''), 'ok');
    window._caSelectedIds = new Set();
    // Reload the Call Activity data
    if (typeof loadCallActivity === 'function') loadCallActivity();
  } catch (e) {
    toast(e.message, 'err');
  }
}


function downloadCallActivityCsv() {
  const r = window._caData;
  if (!r) return toast('Apply a filter first', 'err');
  const rows = [['user_name', 'role', 'manager', 'total', 'in', 'out', 'missed', 'talk_seconds', 'avg_call_s', 'avg_gap_s', 'last_call_at']];
  (r.byUser || []).forEach(u => {
    rows.push([
      u.user_name || '', u.role || '', u.manager_name || '',
      u.total_calls || 0, u.in_calls || 0, u.out_calls || 0, u.missed_calls || 0,
      u.talk_s || 0, u.avg_talk_s || 0, u.avg_gap_s || 0,
      u.last_call_at || ''
    ]);
  });
  const csv = rows.map(r => r.map(c => '"' + String(c).replace(/"/g, '""') + '"').join(',')).join('\n');
  const blob = new Blob([csv], { type: 'text/csv' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'call-activity-' + Date.now() + '.csv';
  a.click();
}

/**
 * Call Insights — showcase view of AI call analysis.
 * Scrollable feed of every recent call with AI summary, action items,
 * sentiment, suggested status — across all leads + reps.
 */
// PROMISE_TRACK_v1
VIEWS.callinsights = async (view) => {
  view.innerHTML = '';
  const out = h('div', {});
  view.appendChild(out);
  const sentSel = h('select', {},
    h('option', { value: '' }, 'All sentiments'),
    h('option', { value: 'positive' }, '😊 Positive'),
    h('option', { value: 'neutral' }, '😐 Neutral'),
    h('option', { value: 'negative' }, '😟 Negative')
  );
  const userSel = h('select', {},
    h('option', { value: '' }, 'All reps'),
    ...((CRM.cache.users || []).map(u => h('option', { value: u.id }, u.name)))
  );
  const feedDiv = h('div', { class: 'insights-feed' });

  async function load() {
    feedDiv.innerHTML = '<div class="muted">Loading…</div>';
    const opts = { limit: 100 };
    if (sentSel.value) opts.sentiment = sentSel.value;
    if (userSel.value) opts.userId = userSel.value;
    try {
      const rows = await api('api_recording_recentInsights', opts);
      if (rows && rows.error) { feedDiv.innerHTML = '<div class="ai-error">' + esc(rows.error) + '</div>'; return; }
      if (!rows || rows.length === 0) {
        feedDiv.innerHTML = '<div class="muted">No call recordings yet. Once your team starts uploading recordings, AI summaries will appear here.</div>';
        return;
      }
      feedDiv.innerHTML = '';
      const total = rows.length;
      const pos = rows.filter(r => r.sentiment === 'positive').length;
      const neg = rows.filter(r => r.sentiment === 'negative').length;
      const totalMin = Math.round(rows.reduce((s, r) => s + (r.duration_s || 0), 0) / 60);
      feedDiv.appendChild(h('div', { class: 'cards', style: 'margin-bottom:1rem' },
        kpiCard('🎙 Calls analysed', total, totalMin + ' min total', 'accent'),
        kpiCard('😊 Positive',  pos + ' (' + Math.round(pos/total*100) + '%)', 'Strong intent', 'ok'),
        kpiCard('😟 Negative',  neg + ' (' + Math.round(neg/total*100) + '%)', 'Need review', 'warn'),
        kpiCard('🤖 AI accuracy', '~95%', 'Hindi-English code-mix', 'accent')
      ));
      // BULK_AUDIT_v1 — admin/manager-only bulk audit toolbar
      if (['admin','manager'].includes((CRM.user || {}).role)) {
        const _bulkBar = h('div', { class: 'card', style: { padding: '.7rem .9rem', margin: '0 0 1rem', display: 'flex', flexWrap: 'wrap', gap: '.5rem', alignItems: 'center', background: '#f1f5f9' } },
          h('span', { style: { fontWeight: 600 } }, '🤖 Bulk AI Audit'),
          h('span', { class: 'muted', style: { fontSize: '.82rem' } }, 'Queue many recordings at once.')
        );
        const _scopeSel = h('select', { class: 'input', style: { maxWidth: '220px' } },
          h('option', { value: 'unprocessed', selected: 'selected' }, 'All unaudited recordings'),
          h('option', { value: 'failed' }, 'Previously failed only'),
          h('option', { value: 'all' }, 'Force re-audit ALL (last 2000)')
        );
        const _userSel2 = h('select', { class: 'input', style: { maxWidth: '180px' } },
          h('option', { value: '' }, 'All reps'),
          ...((CRM.cache.users || []).map(u => h('option', { value: u.id }, u.name)))
        );
        const _limitInp = h('input', { class: 'input', type: 'number', min: 1, max: 2000, value: 500, style: { width: '90px' }, title: 'Max number of recordings to process' });
        const _runBtn = h('button', { class: 'btn primary' }, '🚀 Run audit');
        _runBtn.onclick = async () => {
          const scope = _scopeSel.value;
          if (scope === 'all' && !confirm('Re-audit ALL recordings? This wipes existing summaries and re-runs Gemini on every recording. Can be expensive.')) return;
          _runBtn.disabled = true; _runBtn.textContent = '⏳ Queueing…';
          try {
            const r = await api('api_recording_bulkAudit', {
              scope,
              limit: Number(_limitInp.value) || 500,
              user_id: _userSel2.value ? Number(_userSel2.value) : null
            });
            if (typeof toast === 'function') toast('✅ Queued ' + r.queued + ' recordings — AI processing in background', 'ok');
            setTimeout(() => load(), 8000); // re-load list after first batch starts settling
          } catch (e) {
            if (typeof toast === 'function') toast('⚠ ' + e.message, 'err');
          } finally {
            _runBtn.disabled = false; _runBtn.textContent = '🚀 Run audit';
          }
        };
        _bulkBar.appendChild(_scopeSel);
        _bulkBar.appendChild(_userSel2);
        _bulkBar.appendChild(_limitInp);
        _bulkBar.appendChild(_runBtn);
        feedDiv.appendChild(_bulkBar);
      }
      rows.forEach(r => feedDiv.appendChild(insightCard(r)));
    } catch (e) {
      feedDiv.innerHTML = '<div class="ai-error">Could not load: ' + esc(e.message) + '</div>';
    }
  }

  function insightCard(r) {
    const sentColor = { positive: '#10b981', neutral: '#64748b', negative: '#ef4444' }[r.sentiment] || '#64748b';
    const sentLabel = { positive: '😊', neutral: '😐', negative: '😟' }[r.sentiment] || '·';
    const dur = Number(r.duration_s) || 0;
    const mm = Math.floor(dur / 60), ss = (dur % 60).toString().padStart(2, '0');
    return h('div', { class: 'card insight-card' },
      h('div', { class: 'insight-header' },
        h('div', {},
          h('a', { href: '#/leads', onclick: e => { e.preventDefault(); openLeadModal(r.lead_id); } },
            h('b', {}, r.lead_name || r.phone || '—')
          ),
          h('span', { class: 'muted' }, ' · ' + (r.rep_name || '—') + ' · ' + mm + ':' + ss + ' · ' + fmtDate(r.created_at, 'relative')),
          // PROMISE_TRACK_v1 — second info row
          h('div', { class: 'pt-row', style: { display: 'flex', gap: '.6rem', flexWrap: 'wrap', alignItems: 'center', marginTop: '.3rem', fontSize: '.78rem' } },
            r.lead_status_name ? h('span', { style: { background: '#dbeafe', color: '#1e40af', padding: '.1rem .5rem', borderRadius: '999px', fontWeight: 600 } }, '📍 ' + r.lead_status_name) : null,
            r.last_activity_at ? h('span', { class: 'muted', title: new Date(r.last_activity_at).toLocaleString() }, '🕒 last activity ' + fmtDate(r.last_activity_at, 'relative')) : null,
            /* NEXT_ACTIVITY_v1 */ r.lead_next_followup_at ? h('span', { class: 'pill', style: 'background:#e0e7ff;color:#3730a3;padding:.1rem .5rem;border-radius:999px;font-weight:600', title: new Date(r.lead_next_followup_at).toLocaleString() }, '🗓 next activity ' + new Date(r.lead_next_followup_at).toLocaleString('en-IN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'short'})) : null,
            r.committed_callback_at ? h('span', { class: 'muted' }, '⏰ promised ' + new Date(r.committed_callback_at).toLocaleString('en-IN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'short'})) : null,
            r.actual_followup_at ? h('span', { class: 'muted' }, '✅ actual ' + new Date(r.actual_followup_at).toLocaleString('en-IN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'short'})) : null,
            (r.callback_gap_minutes != null) ? (() => {
              const g = Number(r.callback_gap_minutes);
              if (g <= 5)   return h('span', { style: { background: '#dcfce7', color: '#15803d', padding: '.1rem .5rem', borderRadius: '999px', fontWeight: 600 } }, '🎯 on time');
              if (g <= 60)  return h('span', { style: { background: '#fef3c7', color: '#92400e', padding: '.1rem .5rem', borderRadius: '999px', fontWeight: 600 } }, '⚠ ' + g + ' min late');
              return         h('span', { style: { background: '#fee2e2', color: '#b91c1c', padding: '.1rem .5rem', borderRadius: '999px', fontWeight: 600 } }, '🚨 ' + g + ' min late');
            })() : null
          )
        ),
        h('div', {},
          h('span', { class: 'ai-sentiment-pill', style: 'background:' + sentColor }, sentLabel + ' ' + (r.sentiment || '—')),
          r.ai_suggested_rating ? h('span', { class: 'ai-rating-pill', title: 'AI rating' }, '🤖 ' + r.ai_suggested_rating + '/5') : null,
          r.rating ? h('span', { class: 'ai-rating-pill', style: 'background:#fef3c7;color:#92400e' }, '★ ' + r.rating + '/5') : null
        )
      ),
      h('div', { class: 'insight-summary' }, r.summary || '—'),
      r.key_insight ? h('div', { class: 'insight-key' }, '💡 ' + r.key_insight) : null,
      r.action_items && r.action_items.length > 0
        ? h('div', { class: 'insight-actions' }, h('span', { class: 'insight-actions-title' }, '✓ Next steps:'), ' ', r.action_items.slice(0, 3).join(' · '))
        : null,
      r.suggested_status_name && r.suggested_status_name !== r.lead_status_name
        ? h('div', { class: 'insight-suggest' }, '🎯 AI suggests status: ', h('b', {}, r.suggested_status_name),
            r.next_followup_days != null ? ' · follow up in ' + r.next_followup_days + ' day(s)' : null)
        : null
    );
  }

  view.appendChild(h('div', { class: 'card' },
    h('h3', {}, '🎙 Call Insights — every call, AI-analysed'),
    h('p', { class: 'muted' }, 'Each call recording is automatically transcribed + summarised by AI. Click any lead below to see the full transcript.')
  ));
  view.appendChild(h('div', { class: 'toolbar' },
    h('span', {}, 'Filter:'), sentSel, userSel,  // (was a stray tatRuleBtn copy-paste — that lives in the TAT view only)
    h('button', { class: 'btn primary', onclick: load }, '🔎 Apply')
  ));
  view.appendChild(feedDiv);
  load();
};

VIEWS.aiusage = async (view) => {
  view.innerHTML = '';
  const out = h('div', {});
  view.appendChild(out);
  out.innerHTML = '<div class="muted">Loading AI usage…</div>';
  try {
    const u = await api('api_reports_aiUsage', {});
    if (u.error) { out.innerHTML = '<div class="ai-error">' + esc(u.error) + '</div>'; return; }
    out.innerHTML = '';
    const m = u.this_month || {}, a = u.all_time || {};
    out.appendChild(h('div', { class: 'cards', style: 'margin-bottom:1rem' },
      kpiCard('💸 This month', '₹' + (m.cost_inr_billable || 0).toFixed(2), 'Total AI transcription cost', 'accent'),
      kpiCard('📞 Calls analysed', m.calls || 0, (m.audio_minutes || 0) + ' min audio processed', 'ok'),
      kpiCard('📈 Forecast', '₹' + (u.forecast_monthly_inr || 0).toFixed(0), 'Projected monthly cost @ current pace', 'warn'),
      kpiCard('🔢 All-time', '₹' + (a.cost_inr_billable || 0).toFixed(2), a.calls + ' calls · ' + a.audio_minutes + ' min total', 'accent')
    ));
    const perMinInr = m.audio_minutes > 0 ? (m.cost_inr_billable / m.audio_minutes) : 0;
    const perCallInr = m.calls > 0 ? (m.cost_inr_billable / m.calls) : 0;
    out.appendChild(h('div', { class: 'card' },
      h('h3', {}, '📊 This month — ' + u.month),
      h('table', { class: 'mini-table' }, h('tbody', {},
        row('Calls analysed', m.calls),
        row('Audio processed', (m.audio_minutes || 0) + ' minutes'),
        row('Average per minute', '₹' + perMinInr.toFixed(3)),
        row('Average per call', '₹' + perCallInr.toFixed(2)),
        row('Total cost', h('b', { style: 'color:#10b981;font-size:16px' }, '₹' + (m.cost_inr_billable || 0).toFixed(2)))
      ))
    ));
    if (u.by_user && u.by_user.length > 0) {
      const tbl = h('table', { class: 'call-rating-report' });
      tbl.appendChild(h('thead', {}, h('tr', {},
        h('th', {}, 'Rep'),
        h('th', { style: 'text-align:right' }, 'Calls'),
        h('th', { style: 'text-align:right' }, 'Audio (min)'),
        h('th', { style: 'text-align:right' }, 'Cost')
      )));
      const tb = h('tbody', {});
      tbl.appendChild(tb);
      u.by_user.forEach(ru => tb.appendChild(h('tr', {},
        h('td', {}, h('b', {}, ru.user_name)),
        h('td', { style: 'text-align:right' }, ru.calls),
        h('td', { style: 'text-align:right' }, ru.audio_minutes),
        h('td', { style: 'text-align:right;color:#10b981;font-weight:600' }, '₹' + ru.cost_inr_billable.toFixed(2))
      )));
      out.appendChild(h('div', { class: 'card call-rating-report' }, h('h3', {}, '👥 By rep — this month'), tbl));
    }
    const estCard = h('div', { class: 'card' });
    estCard.appendChild(h('h3', {}, '🧮 Cost estimator'));
    estCard.appendChild(h('p', { class: 'muted' }, 'Forecast what N minutes of AI call analysis will cost.'));
    const minsInp = h('input', { type: 'number', value: 100, min: 1, step: 10, style: 'width:100px' });
    const callMinInp = h('input', { type: 'number', value: 5, min: 0.5, step: 0.5, style: 'width:80px' });
    const estOut = h('div', { style: 'margin-top:12px' });
    estCard.appendChild(h('div', { class: 'toolbar' },
      h('span', {}, 'Total minutes:'), minsInp,
      h('span', {}, 'Avg call (min):'), callMinInp,
      h('button', { class: 'btn primary', onclick: async () => {
        try {
          const r = await api('api_reports_aiCostEstimator', { minutes: Number(minsInp.value), avgCallMinutes: Number(callMinInp.value) });
          estOut.innerHTML = '';
          estOut.appendChild(h('div', { class: 'cards' },
            kpiCard('💰 Total cost', '₹' + r.cost_inr_billable.toFixed(2), 'For ' + r.minutes + ' min · ~' + r.calls + ' calls', 'ok'),
            kpiCard('Per minute', '₹' + r.per_minute_inr_billable.toFixed(3), '', 'warn'),
            kpiCard('Per call', '₹' + r.per_call_inr_billable.toFixed(3), '@ ' + r.avg_call_minutes + ' min/call', 'accent')
          ));
          const exTbl = h('table', { class: 'mini-table', style: 'margin-top:1rem' });
          exTbl.appendChild(h('thead', {}, h('tr', {},
            h('th', {}, 'Volume'), h('th', { style: 'text-align:right' }, 'Cost (₹)')
          )));
          const exB = h('tbody', {});
          exTbl.appendChild(exB);
          (r.examples || []).forEach(e => exB.appendChild(h('tr', {},
            h('td', {}, e.label),
            h('td', { style: 'text-align:right;color:#10b981;font-weight:600' }, '₹' + e.cost_inr_billable.toFixed(2))
          )));
          estOut.appendChild(h('h4', { style: 'margin-top:1rem' }, 'Quick reference'));
          estOut.appendChild(exTbl);
        } catch (e) { estOut.innerHTML = '<div class="ai-error">' + esc(e.message) + '</div>'; }
      } }, '🔢 Calculate')
    ));
    estCard.appendChild(estOut);
    out.appendChild(estCard);
  } catch (e) { out.innerHTML = '<div class="ai-error">Could not load: ' + esc(e.message) + '</div>'; }
};


// Helper for KPI cards in AI usage view (avoids polluting global card())
function kpiCard(label, value, sub, klass) {
  return h('div', { class: 'card kpi ' + (klass || '') },
    h('div', { class: 'kpi-label' }, label),
    h('div', { class: 'kpi-value' }, value),
    sub ? h('div', { class: 'kpi-sub muted' }, sub) : null
  );
}
function row(label, value) {
  return h('tr', {}, h('td', { class: 'muted' }, label), h('td', {}, value));
}

VIEWS.callratings = async (view) => {
  view.innerHTML = '';
  const { users = [] } = CRM.cache;
  const fromInp = h('input', { type: 'date' });
  const toInp   = h('input', { type: 'date' });
  setTimeout(() => { try { window._attachDatePresets && window._attachDatePresets(fromInp, toInp, { key: 'callratings', apply: () => { try { load && load(); } catch (_) {} } }); } catch (_) {} }, 0);
  const userSel = h('select', {},
    h('option', { value: '' }, 'All users'),
    ...users.map(u => h('option', { value: u.id }, u.name))
  );
  const out = h('div', { class: 'call-rating-report' });

  async function load() {
    out.innerHTML = '<div class="muted">Loading…</div>';
    const filters = {};
    if (fromInp.value) filters.from = fromInp.value + 'T00:00:00';
    if (toInp.value)   filters.to   = toInp.value   + 'T23:59:59';
    if (userSel.value) filters.userId = userSel.value;
    try {
      const rows = await api('api_reports_callRatingByUser', filters);
      if (rows && rows.error) {
        out.innerHTML = '<div class="ai-error">' + esc(rows.error) + '</div>';
        return;
      }
      if (!rows || rows.length === 0) {
        out.innerHTML = '<div class="muted">No call recordings in this range.</div>';
        return;
      }
      out.innerHTML = '';
      const tbl = h('table', {},
        h('thead', {},
          h('tr', {},
            h('th', {}, 'Rep'),
            h('th', { style: 'text-align:right' }, 'Total calls'),
            h('th', { style: 'text-align:right' }, 'Rated'),
            h('th', { style: 'text-align:right' }, 'Avg ★'),
            h('th', { style: 'text-align:right' }, 'AI avg'),
            h('th', {}, '1★ 2★ 3★ 4★ 5★'),
            h('th', {}, 'Last call')
          )
        )
      );
      const tb = h('tbody', {});
      tbl.appendChild(tb);
      rows.forEach(r => {
        const stars = (n, color) => {
          if (n == null) return h('span', { class: 'muted' }, '—');
          return h('span', { style: 'color:' + (color || '#f59e0b'), fontWeight: 600 },
            n.toFixed(1) + ' ' + '★'.repeat(Math.round(n)) + '☆'.repeat(5 - Math.round(n))
          );
        };
        tb.appendChild(h('tr', {},
          h('td', {}, h('b', {}, r.user_name || '—'),
            r.user_role ? h('span', { class: 'muted' }, ' · ' + r.user_role) : null),
          h('td', { style: 'text-align:right' }, h('span', { class: 'num-pill' }, r.total_calls)),
          h('td', { style: 'text-align:right' }, r.rated_calls),
          h('td', { style: 'text-align:right' }, stars(r.avg_rating)),
          h('td', { style: 'text-align:right' }, stars(r.avg_ai_rating, '#94a3b8')),
          h('td', {},
            h('span', { class: 'num-pill', style: 'background:#fee2e2;color:#991b1b' }, r.r1 || 0),
            ' ',
            h('span', { class: 'num-pill', style: 'background:#fed7aa;color:#9a3412' }, r.r2 || 0),
            ' ',
            h('span', { class: 'num-pill', style: 'background:#fef08a;color:#713f12' }, r.r3 || 0),
            ' ',
            h('span', { class: 'num-pill', style: 'background:#bbf7d0;color:#14532d' }, r.r4 || 0),
            ' ',
            h('span', { class: 'num-pill', style: 'background:#86efac;color:#14532d' }, r.r5 || 0)
          ),
          h('td', { class: 'muted' }, r.last_call_at ? fmtDate(r.last_call_at, 'relative') : '—')
        ));
      });
      out.appendChild(tbl);
    } catch (e) {
      out.innerHTML = '<div class="ai-error">Could not load: ' + esc(e.message) + '</div>';
    }
  }

  view.appendChild(h('div', { class: 'toolbar' },
    h('span', {}, 'From'), fromInp,
    h('span', {}, 'to'), toInp,
    h('span', {}, 'User'), userSel,
    h('button', { class: 'btn primary', onclick: load }, '🔎 Apply')
  ));
  view.appendChild(h('div', { class: 'card' },
    h('h3', {}, '⭐ Call ratings — rep-wise'),
    h('p', { class: 'muted' }, 'Manual ratings are 1-5 stars set by the rep or manager on each recording. AI-suggested ratings come from Gemini\'s call analysis. Use the rating panel on any recording to set / change a manual rating.'),
    out
  ));
  load();
};

VIEWS.tatreport = async (view) => {
  view.innerHTML = '';
  const { users = [] } = CRM.cache;
  const fromInp = h('input', { type: 'date' });
  const toInp   = h('input', { type: 'date' });
  setTimeout(() => { try { window._attachDatePresets && window._attachDatePresets(fromInp, toInp, { key: 'tatreport', apply: () => { try { load && load(); } catch (_) {} } }); } catch (_) {} }, 0);
  // Multi-select users + rule-builder for advanced filtering.
  const userSel = multiSelectDropdown({ id: 'tat-user', label: 'Users', allLabel: 'All users',
    options: users.map(u => ({ id: String(u.id), name: u.name })),
    values: (window._tatPicked && window._tatPicked.users) || [],
    onApply: (v) => { window._tatPicked = window._tatPicked || {}; window._tatPicked.users = v; load(); }
  });
  // Legacy single-value reader for the existing api_tat_report call.
  userSel.value = ((window._tatPicked && window._tatPicked.users) || [])[0] || '';
  const tatRuleBtn = ruleBuilderButton({ label: '+ Filter rule', storageKey: 'crm.tat.rules.v1',
    fields: [ { id: 'lead_name', label: 'Lead', type: 'text' }, { id: 'user_name', label: 'User', type: 'text' }, { id: 'status_name', label: 'Stage', type: 'text' } ],
    onChange: () => load()
  });
  window._tatRuleBtn = tatRuleBtn;
  const out = h('div', {});
  const fmtMin = m => m == null ? '—' : (m < 60 ? m + ' min' : (m / 60 < 24 ? (m / 60).toFixed(1) + ' hr' : (m / 1440).toFixed(1) + ' days'));
  const fmtSec = s => s == null ? '—' : fmtMin(Math.round(s / 60));
  async function load() {
    out.innerHTML = '<div class="loading">Loading…</div>';
    try {
      const r = await api('api_tat_report', { from: fromInp.value || undefined, to: toInp.value || undefined, user_id: userSel.value || undefined });
      out.innerHTML = '';
      // Apply client-side rule-builder rules
      try {
        const _rb = window._tatRuleBtn && window._tatRuleBtn.getRules ? window._tatRuleBtn.getRules() : [];
        if (_rb && _rb.length) {
          if (Array.isArray(r.by_user)) r.by_user = r.by_user.filter(x => _applyClientRules(x, _rb));
          if (Array.isArray(r.open_violation_rows)) r.open_violation_rows = r.open_violation_rows.filter(x => _applyClientRules(x, _rb));
          if (Array.isArray(r.by_stage)) r.by_stage = r.by_stage.filter(x => _applyClientRules(x, _rb));
        }
      } catch (_) {}


      // KPI cards
      out.appendChild(h('div', { class: 'cards' },
        h('div', { class: 'card stat accent' }, h('div', { class: 'stat-icon' }, '🎯'), h('div', { class: 'stat-body' }, h('div', { class: 'stat-label' }, 'Leads'), h('div', { class: 'stat-value' }, r.totals.leads))),
        h('div', { class: 'card stat ok' },     h('div', { class: 'stat-icon' }, '⚡'), h('div', { class: 'stat-body' }, h('div', { class: 'stat-label' }, 'Avg time to 1st action'), h('div', { class: 'stat-value' }, fmtMin(r.totals.avg_first_min)))),
        h('div', { class: 'card stat err' },    h('div', { class: 'stat-icon' }, '🚨'), h('div', { class: 'stat-body' }, h('div', { class: 'stat-label' }, 'Open violations'), h('div', { class: 'stat-value' }, r.open_violations)))
      ));

      // By user
      out.appendChild(h('div', { class: 'card card-wide' },
        h('h3', {}, 'By user — avg response time'),
        r.by_user.length === 0 ? h('p', { class: 'muted' }, 'No data in scope.') :
        h('div', { class: 'table-wrap' }, h('table', {},
          h('thead', {}, h('tr', {}, h('th', {}, 'User'), h('th', {}, 'Leads'), h('th', {}, 'Actioned'), h('th', {}, 'Avg → 1st action'), h('th', {}, 'Avg → 2nd action'))),
          h('tbody', {}, ...r.by_user.map(u => h('tr', {},
            h('td', {}, u.user_name || '—'),
            h('td', {}, u.leads),
            h('td', {}, u.actioned + ' / ' + u.leads),
            h('td', {}, fmtMin(u.avg_first_min)),
            h('td', {}, fmtMin(u.avg_second_min))
          )))
        ))
      ));

      // By stage
      out.appendChild(h('div', { class: 'card card-wide' },
        h('h3', {}, 'By stage — avg time leads spend before moving on'),
        r.by_stage.length === 0 ? h('p', { class: 'muted' }, 'No completed stage transitions yet. (Move some leads through stages and this will populate.)') :
        h('div', { class: 'table-wrap' }, h('table', {},
          h('thead', {}, h('tr', {}, h('th', {}, 'Stage'), h('th', {}, 'Transitions'), h('th', {}, 'Avg minutes in stage'))),
          h('tbody', {}, ...r.by_stage.map(s => h('tr', {},
            h('td', {}, s.status_name),
            h('td', {}, s.transitions),
            h('td', {}, fmtMin(s.avg_minutes))
          )))
        ))
      ));

      // Active violations
      out.appendChild(h('div', { class: 'card card-wide' },
        h('h3', {}, '🚨 Active TAT violations'),
        r.open_violation_rows.length === 0 ? h('p', { class: 'muted' }, 'No open violations. 🎉') :
        h('div', { class: 'table-wrap' }, h('table', {},
          h('thead', {}, h('tr', {}, h('th', {}, 'Lead'), h('th', {}, 'Stage'), h('th', {}, 'Owner'), h('th', {}, 'Threshold'), h('th', {}, 'Triggered'), h('th', {}, 'Escalation'))),
          h('tbody', {}, ...r.open_violation_rows.map(v => h('tr', {},
            h('td', {}, h('a', { href: '#', onclick: ev => { ev.preventDefault(); openLeadModal(v.lead_id); } }, v.lead_name || ('Lead #' + v.lead_id))),
            h('td', {}, v.status_name),
            h('td', {}, v.user_name || '—'),
            h('td', {}, v.threshold_minutes + ' min'),
            h('td', {}, fmtDate(v.triggered_at, 'relative')),
            h('td', {}, v.escalation_level === 3 ? '🚨 Admin (L3)' : v.escalation_level === 2 ? '⚠️ Manager (L2)' : '⏱️ Employee (L1)')
          )))
        ))
      ));
    } catch (e) {
      out.innerHTML = `<div class="error-box">${esc(e.message)}</div>`;
    }
  }
  view.append(
    h('div', { class: 'toolbar' },
      h('span', {}, 'From'), fromInp,
      h('span', {}, 'to'), toInp,
      userSel,
      h('button', { class: 'btn primary', onclick: load }, '🔎 Apply')
    ),
    out
  );
  await load();
};

